from models import Coupon

def calculate_discount(subtotal: float, coupon: Coupon) -> float:
    """
    Calculates the discount amount based on the subtotal and the coupon provided.
    Supports both percentage-based and fixed-amount discounts.
    """
    if not coupon:
        return 0.0

    discount_amount = 0.0

    # Standard coupon logic: assume coupon has 'type' (e.g., 'percentage', 'fixed') 
    # and 'value' (the numerical amount of the discount)
    if coupon.type == 'percentage':
        discount_amount = subtotal * (coupon.value / 100.0)
    elif coupon.type == 'fixed':
        discount_amount = float(coupon.value)
    else:
        # If the coupon type is unknown or invalid, no discount is applied
        discount_amount = 0.0

    # Ensure the discount does not exceed the subtotal (no negative prices)
