# Global state to track items in the current session's cart
# Format: { product_id: quantity }
_cart_items = {}

def add_item(product_id: str, quantity: int) -> bool:
    """
    Checks if the requested quantity is in stock and adds it to the cart.
    """
    if inventory_manager.check_stock(product_id, quantity):
        # Ensure the product exists before adding to cart
        product = models.get_product(product_id)
        if product:
            if product_id in _cart_items:
                _cart_items[product_id] += quantity
            else:
                _cart_items[product_id] = quantity
            return True
    return False

def get_cart_summary(coupon_code: str) -> dict:
    """
    Calculates the subtotal, applies an optional coupon discount, and returns the final total.
    """
    subtotal = 0.0

    # Calculate subtotal based on products in the cart
    for product_id, quantity in _cart_items.items():
        product = models.get_product(product_id)
        if product:
            # Assuming Product object has a 'price' attribute
            subtotal += product.price * quantity

    discount = 0.0
    if coupon_code:
        coupon = models.get_coupon(coupon_code)
        if coupon:
            discount = coupon_manager.calculate_discount(subtotal, coupon)

    total = subtotal - discount

    return {
        "subtotal": float(subtotal),
        "discount": float(discount),
        "total": float(max(0, total))
    }

