        raise ValueError(f"Insufficient stock for product {product.id}")

def calculate_total(coupon_code: str | None) -> float:
    subtotal = sum(item.product.price * item.quantity for item in _cart_items)

    if coupon_code:
        discount = coupon_service.calculate_discount_amount(subtotal, coupon_code)
