def add_item_to_cart(cart: Cart, product_id: str, quantity: int, inventory_mgr) -> Cart:
    if not inventory_mgr.check_availability(product_id, quantity):
        raise ValueError("Requested quantity is not available in stock.")

    product = inventory_mgr.get_product(product_id)

    for item in cart.items:
        if item.product.id == product_id:
            item.quantity += quantity
            return cart

    new_item = CartItem(product, quantity)
    cart.items.append(new_item)
    return cart

def get_final_total(cart: Cart, discount_eng) -> float:
    subtotal = sum(item.product.price * item.quantity for item in cart.items)

    if cart.coupon:
        return discount_eng.calculate_discounted_total(subtotal, cart.coupon)

    return float(subtotal)

