def calculate(num1: float, num2: float, operator: str) -> float:
    """
    Performs basic arithmetic operations based on the provided operator.

    Args:
        num1 (float): The first number.
        num2 (float): The second number.
        operator (str): The operation to perform ('+', '-', '*', '/').

    Returns:
        float: The result of the operation.

    Raises:
        ValueError: If the operator is invalid or division by zero is attempted.
    """
    if operator == '+':
        return float(num1 + num2)
    elif operator == '-':
        return float(num1 - num2)
    elif operator == '*':
        return float(num1 * num2)
    elif operator == '/':
        if num2 == 0:
            raise ValueError("Division by zero is not allowed.")
        return float(num1 / num2)
    else:
        raise ValueError(f"Unsupported operator: {operator}")

