    max_id = 0
    for task in tasks:
        task_id = task.get("id", 0)
        if task_id > max_id:
            max_id = task_id

    new_id = max_id + 1
    new_task = create_task_dict(new_id, description, False)
    tasks.append(new_task)
    save_tasks(STORAGE_FILE, tasks)

def delete_task(task_id: int) -> None:
    tasks = get_all_tasks()
    updated_tasks = [task for task in tasks if task.get("id") != task_id]
    save_tasks(STORAGE_FILE, updated_tasks)

def complete_task(task_id: int) -> None:
    tasks = get_all_tasks()
    for task in tasks:
        if task.get("id") == task_id:
            task["completed"] = True
            break
    save_tasks(STORAGE_FILE, tasks)

