COUPON_DATABASE = {
    "SAVE10": {"type": "percent", "value": 0.10},
    "SAVE20": {"type": "percent", "value": 0.20},
    "WELCOME5": {"type": "flat", "value": 5.0},
    "FLAT10": {"type": "flat", "value": 10.0},
}

def calculate_discount(subtotal: float, coupon_code: str) -> float:
    """
    Calculates the discount amount based on a coupon code and the order subtotal.
    Returns 0.0 if the coupon is invalid or not provided.
    """
    if not coupon_code:
        return 0.0

    # Normalize coupon code to uppercase for case-insensitive matching
    code = coupon_code.strip().upper()

    if code not in COUPON_DATABASE:
        return 0.0

    coupon = COUPON_DATABASE[code]
    coupon_type = coupon["type"]
    coupon_value = coupon["value"]

    if coupon_type == "percent":
        discount = subtotal * coupon_value
    elif coupon_type == "flat":
        # Flat discounts cannot exceed the subtotal
        discount = min(coupon_value, subtotal)
    else:
        discount = 0.0

    return float(discount)

