from models import Item

DATA_FILE = "inventory.json"

def inbound(item_id: str, amount: int, name: str = None) -> bool:
    data = load_data(DATA_FILE)
    if item_id in data:
        data[item_id]['quantity'] += amount
    else:
        item_name = name if name is not None else "Unknown Item"
        data[item_id] = Item(item_id, item_name, amount)

    save_data(DATA_FILE, data)
    return True

def outbound(item_id: str, amount: int) -> bool:
    data = load_data(DATA_FILE)
    if item_id in data and data[item_id]['quantity'] >= amount:
        data[item_id]['quantity'] -= amount
        save_data(DATA_FILE, data)
        return True
    return False

def get_quantity(item_id: str) -> int:
    data = load_data(DATA_FILE)
    item = data.get(item_id)
    return item['quantity'] if item else 0

def get_all_items() -> list[dict]:
    data = load_data(DATA_FILE)
    return list(data.values())

