from models import Coupon

def calculate_discount_amount(subtotal: float, coupon: Coupon) -> float:
    """
    Calculates the discount amount based on the coupon type.
    Supports 'percentage' and 'fixed' discount types.
    """
    if not coupon:
        return 0.0

    discount_amount = 0.0

    if coupon.discount_type == "percentage":
        # Calculate discount as a percentage of the subtotal
        discount_amount = subtotal * (coupon.value / 100.0)
    elif coupon.discount_type == "fixed":
        # Calculate discount as a flat fixed value
        discount_amount = float(coupon.value)
    else:
        # Unknown discount type
        discount_amount = 0.0

    # Ensure the discount does not exceed the subtotal
    return min(discount_amount, subtotal)

