DATA_FILE = "inventory.json"

def add_stock(item_id: str, name: str, amount: int) -> None:
    data = load_all(DATA_FILE)

    if item_id in data:
        data[item_id]['quantity'] += amount
    else:
        # Use the Item model to ensure structure consistency
        new_item = Item(item_id, name, amount)
        data[item_id] = {
            "id": new_item.id,
            "name": new_item.name,
            "quantity": new_item.quantity
        }

    save_all(DATA_FILE, data)

def remove_stock(item_id: str, amount: int) -> None:
    data = load_all(DATA_FILE)

    if item_id not in data:
        raise KeyError(f"Item with ID {item_id} not found in inventory.")

    current_qty = data[item_id]['quantity']
    if current_qty < amount:
        raise ValueError(f"Insufficient stock for item {item_id}. Available: {current_qty}")

    data[item_id]['quantity'] -= amount
    save_all(DATA_FILE, data)

def get_item_quantity(item_id: str) -> int:
    data = load_all(DATA_FILE)
    item = data.get(item_id)
    return item['quantity'] if item else 0

def get_all_items() -> list[dict]:
    data = load_all(DATA_FILE)
    return list(data.values())

