def calculate_discount(subtotal: float, coupon: dict) -> float:
    """
    Calculates the discount amount based on a subtotal and coupon rules.
    Supported coupon types:
    - 'percentage': value is a percentage (e.g., 20 for 20%)
    - 'fixed': value is a flat amount (e.g., 10.0 for $10 off)
    """
    if not coupon or not isinstance(coupon, dict):
        return 0.0

    coupon_type = coupon.get("type")
    value = coupon.get("value", 0.0)

    try:
        value = float(value)
    except (ValueError, TypeError):
        return 0.0

    discount_amount = 0.0

    if coupon_type == "percentage":
        discount_amount = subtotal * (value / 100.0)
    elif coupon_type == "fixed":
        discount_amount = value
    else:
        # If coupon type is unrecognized, no discount is applied
        return 0.0

    # The discount cannot be negative and cannot exceed the subtotal
    return max(0.0, min(discount_amount, subtotal))

