from exceptions import InvalidExpressionError

def parse_expression(expression_str: str):
    """
    Parses and validates the raw input string into a tuple of (left_operand, operator, right_operand).
    Expected format: "number operator number" (e.g., "10 + 5")
    """
    if not expression_str or not isinstance(expression_str, str):
        raise InvalidExpressionError("Input must be a non-empty string.")

    parts = expression_str.strip().split()

    if len(parts) != 3:
        raise InvalidExpressionError(
            f"Invalid expression format: '{expression_str}'. Expected 'number operator number'."
        )

    try:
        left_val = float(parts[0])
        operator = parts[1]
        right_val = float(parts[2])
    except ValueError:
        raise InvalidExpressionError(
            f"Operands must be numeric values. Received: '{parts[0]}' and '{parts[2]}'."
        )

    return left_val, operator, right_val

