def process_order_total(cart: list[CartItem], coupon: Coupon | None) -> float:
    if not check_stock(cart):
        raise ValueError("One or more items in the cart are out of stock.")

    subtotal = calculate_subtotal(cart)

    if coupon:
        discount = calculate_discount_amount(subtotal, coupon)
        total = subtotal - discount
    else:
        total = subtotal

    return max(0.0, total)

