def calculate_discount(subtotal, coupon):
    """
    Calculates the discount amount based on the subtotal and the coupon's rules.
    Supports 'percentage' and 'fixed' discount types.
    """
    if not coupon:
        return 0.0

    if coupon.discount_type == "percentage":
        return subtotal * (coupon.value / 100.0)
    elif coupon.discount_type == "fixed":
        # Ensure the discount does not exceed the subtotal
        return min(coupon.value, subtotal)

    return 0.0

