def calculate(num1: float, num2: float, operator: str) -> float:
    if operator == '+':
        return float(num1 + num2)
    elif operator == '-':
        return float(num1 - num2)
    elif operator == '*':
        return float(num1 * num2)
    elif operator == '/':
        if num2 == 0:
            raise ValueError("Cannot divide by zero.")
        return float(num1 / num2)
    else:
        raise ValueError(f"Unsupported operator: {operator}")

