def calculate_discount(subtotal: float, coupon: dict) -> float:
    if not coupon:
        return 0.0

    coupon_type = coupon.get('type')
    coupon_value = coupon.get('value', 0.0)

    if coupon_type == 'percentage':
        discount = subtotal * (coupon_value / 100.0)
    elif coupon_type == 'fixed':
        discount = coupon_value
    else:
        discount = 0.0

    # Ensure discount is not negative and does not exceed the subtotal
    return min(max(0.0, discount), subtotal)

