    for item in cart:
        price = item['product'].get('price', 0.0)
        quantity = item.get('quantity', 0)
        subtotal += price * quantity

    discount = 0.0
    if coupon:
        discount = coupon_engine.calculate_discount(subtotal, coupon)

    total = subtotal - discount
    return {
        'subtotal': subtotal,
        'discount': discount,
        'total': total
    }

