from storage import load_data, save_data

class AccountManager:
    def __init__(self, file_path: str):
        self.file_path = file_path
        self.records = load_data(file_path)

    def add_record(self, amount: float, type: str, description: str, date: str) -> None:
        record = {
            'amount': amount,
            'type': type,
            'description': description,
            'date': date
        }
        self.records.append(record)
        save_data(self.file_path, self.records)

    def get_balance(self) -> float:
        balance = 0.0
        for record in self.records:
            rec_type = record['type'].lower()
            if rec_type in ('income', 'credit', 'deposit'):
                balance += record['amount']
            elif rec_type in ('expense', 'debit', 'withdrawal'):
                balance -= record['amount']
            else:
                # If type is ambiguous, we treat the amount as a signed value
                balance += record['amount']
        return balance

    def get_history(self) -> list:
        return self.records

