from models import Memo
import storage

def add_memo(content: str) -> Memo:
    raw_data = storage.load_all_raw()
    new_id = max([item['id'] for item in raw_data], default=0) + 1
    new_memo_dict = {'id': new_id, 'content': content}
    raw_data.append(new_memo_dict)
    storage.save_all_raw(raw_data)
    return Memo(id=new_id, content=content)

def edit_memo(memo_id: int, content: str) -> bool:
    raw_data = storage.load_all_raw()
    found = False
    for item in raw_data:
        if item['id'] == memo_id:
            item['content'] = content
            found = True
            break
    if found:
        storage.save_all_raw(raw_data)
    return found

def delete_memo(memo_id: int) -> bool:
    raw_data = storage.load_all_raw()
    original_count = len(raw_data)
    updated_data = [item for item in raw_data if item['id'] != memo_id]
    if len(updated_data) < original_count:
        storage.save_all_raw(updated_data)
        return True
    return False

def get_all_memos() -> list[Memo]:
    raw_data = storage.load_all_raw()
    return [Memo(id=item['id'], content=item['content']) for item in raw_data]

