from models import Item

def add_stock(item_id: str, name: str, amount: int) -> bool:
    data = load_all()
    for item in data:
        if item['id'] == item_id:
            item['quantity'] += amount
            save_all(data)
            return True

    new_item = Item(item_id, name, amount)
    item_dict = {
        'id': new_item.id,
        'name': new_item.name,
        'quantity': new_item.quantity
    }
    data.append(item_dict)
    save_all(data)
    return True

def remove_stock(item_id: str, amount: int) -> bool:
    data = load_all()
    for item in data:
        if item['id'] == item_id:
            if item['quantity'] >= amount:
                item['quantity'] -= amount
                save_all(data)
                return True
            return False
    return False

def get_quantity(item_id: str) -> int:
    data = load_all()
    for item in data:
        if item['id'] == item_id:
            return item['quantity']
    return 0

def get_all_items() -> list[dict]:
    return load_all()

