def calculate_discount(subtotal: float, coupon: dict) -> float:
    """
    Calculates the discount amount based on the subtotal and the coupon provided.
    Expected coupon format: {'type': 'percentage'|'fixed', 'value': float}
    """
    if not coupon:
        return 0.0

    coupon_type = coupon.get('type')
    coupon_value = coupon.get('value', 0.0)

    try:
        value = float(coupon_value)
    except (ValueError, TypeError):
        return 0.0

    if coupon_type == 'percentage':
        discount = subtotal * (value / 100.0)
    elif coupon_type == 'fixed':
        discount = value
    else:
        discount = 0.0

    # Ensure the discount is not negative and does not exceed the subtotal
    return max(0.0, min(discount, subtotal))

