def calculate_total(cart, coupon_service):
    subtotal = sum(item['price'] * item['quantity'] for item in cart['items'])

    discount = 0.0
    coupon = cart.get('coupon')
    if coupon:
        discount = coupon_service.calculate_discount(subtotal, coupon)

    return subtotal - discount

