def convert(value: float, direction: str) -> float:
    """
    Handles the mathematical logic for unit conversion.
    Supported directions:
    - 'CtoF': Celsius to Fahrenheit
    - 'FtoC': Fahrenheit to Celsius
    - 'MtoFt': Meters to Feet
    - 'FtoM': Feet to Meters
    - 'KgtoLb': Kilograms to Pounds
    - 'LbtoKg': Pounds to Kilograms
    - 'KmtoMi': Kilometers to Miles
    - 'MitoKm': Miles to Kilometers
    """
    if direction == "CtoF":
        return (value * 9/5) + 32
    elif direction == "FtoC":
        return (value - 32) * 5/9
    elif direction == "MtoFt":
        return value * 3.28084
    elif direction == "FtoM":
        return value / 3.28084
    elif direction == "KgtoLb":
        return value * 2.20462
    elif direction == "LbtoKg":
        return value / 2.20462
    elif direction == "KmtoMi":
        return value * 0.621371
    elif direction == "MitoKm":
        return value / 0.621371
    else:
        raise ValueError(f"Unsupported conversion direction: {direction}")

