import json
import os
from typing import List, Dict, Any

def load_data(filepath: str) -> List[Dict[str, Any]]:
    """Loads todo list data from a JSON file.

    If the file does not exist or contains invalid JSON, returns an empty list.
    """
    if not os.path.exists(filepath):
        return []
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            data = json.load(f)
            if isinstance(data, list):
                # Ensure structure matches list of dicts with correct types
                validated_data = []
                for item in data:
                    if isinstance(item, dict) and "id" in item and "task" in item and "completed" in item:
                        validated_data.append({
                            "id": int(item["id"]),
                            "task": str(item["task"]),
                            "completed": bool(item["completed"])
                        })
                return validated_data
            return []
    except (json.JSONDecodeError, IOError, ValueError):
        return []

def save_data(filepath: str, data: List[Dict[str, Any]]) -> None:
    """Saves the todo list data to a JSON file.

    Creates destination directories if they do not exist.
    """
    dir_name = os.path.dirname(filepath)
    if dir_name and not os.path.exists(dir_name):
        os.makedirs(dir_name, exist_ok=True)

    with open(filepath, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=4, ensure_ascii=False)

