from storage import load_raw_data, save_raw_data

def add_memo(title: str, content: str) -> dict:
    memos = load_raw_data()
    next_id = max([memo['id'] for memo in memos], default=0) + 1
    new_memo = {
        'id': next_id,
        'title': title,
        'content': content,
        'created_at': datetime.now().isoformat()
    }
    memos.append(new_memo)
    save_raw_data(memos)
    return new_memo

def list_memos() -> list[dict]:
    return load_raw_data()

def update_memo(memo_id: int, title: str, content: str) -> bool:
    memos = load_raw_data()
    for memo in memos:
        if memo['id'] == memo_id:
            memo['title'] = title
            memo['content'] = content
            save_raw_data(memos)
            return True
    return False

def delete_memo(memo_id: int) -> bool:
    memos = load_raw_data()
    updated_memos = [memo for memo in memos if memo['id'] != memo_id]
    if len(updated_memos) < len(memos):
        save_raw_data(updated_memos)
        return True
    return False

