import json
import os
from typing import Any


def load_data(file_path: str) -> dict[str, dict[str, Any]]:
    """Loads JSON data from the specified file path.

    Returns an empty dictionary if the file does not exist or is empty.
    """
    if not os.path.exists(file_path):
        return {}
    try:
        with open(file_path, "r", encoding="utf-8") as f:
            if os.path.getsize(file_path) == 0:
                return {}
            data = json.load(f)
            if isinstance(data, dict):
                return data
            return {}
    except (json.JSONDecodeError, IOError):
        return {}


def save_data(file_path: str, data: dict[str, dict[str, Any]]) -> None:
    """Saves the provided data dictionary to the specified file path in JSON format."""
    dir_name = os.path.dirname(file_path)
    if dir_name and not os.path.exists(dir_name):
        os.makedirs(dir_name, exist_ok=True)
    with open(file_path, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=4)

