from storage import load_data, save_data

DATA_FILE = "inventory.json"

def _get_data() -> dict[str, dict[str, any]]:
    try:
        data = load_data(DATA_FILE)
        if data is None:
            return {}
        return data
    except Exception:
        return {}

def add_item(item_id: str, name: str) -> bool:
    data = _get_data()
    if item_id in data:
        return False
    data[item_id] = {"name": name, "quantity": 0}
    save_data(DATA_FILE, data)
    return True

def receive_item(item_id: str, quantity: int) -> bool:
    if quantity <= 0:
        return False
    data = _get_data()
    if item_id not in data:
        return False
    data[item_id]["quantity"] = data[item_id].get("quantity", 0) + quantity
    save_data(DATA_FILE, data)
    return True

def issue_item(item_id: str, quantity: int) -> bool:
    if quantity <= 0:
        return False
    data = _get_data()
    if item_id not in data:
        return False
    current_qty = data[item_id].get("quantity", 0)
    if current_qty < quantity:
        return False
    data[item_id]["quantity"] = current_qty - quantity
    save_data(DATA_FILE, data)
    return True

def get_quantity(item_id: str) -> int:
    data = _get_data()
    if item_id not in data:
        return -1
    return data[item_id].get("quantity", 0)

def get_item_list() -> dict[str, dict[str, any]]:
    return _get_data()

