VALID_ROLES: Set[str] = {"admin", "user", "guest"}

def create_user(username: str, role: str) -> Dict[str, str]:
    """
    Creates a user dictionary with a username and a valid role.

    :param username: The username of the user.
    :param role: The role of the user (e.g., 'admin', 'user', 'guest').
    :return: A dictionary representing the user.
    """
    if not isinstance(username, str) or not username.strip():
        raise ValueError("Username must be a non-empty string.")

    if not isinstance(role, str):
        raise TypeError("Role must be a string.")

    normalized_role = role.lower().strip()
    if normalized_role not in VALID_ROLES:
        raise ValueError(f"Invalid role '{role}'. Valid roles are: {VALID_ROLES}")

    return {
        "username": username.strip(),
        "role": normalized_role
    }

