def calculate_discount(coupon_code: str, amount: float) -> float:
    """
    Validates a promotional code and calculates the discount amount.

    Supported coupon codes:
    - 'SAVE10': 10% off the total amount
    - 'SAVE20': 20% off the total amount
    - 'FLAT15': Flat $15 off the total amount
    - 'FLAT50': Flat $50 off the total amount
    - 'FREE'  : 100% off the total amount

    If the coupon is invalid or expired, returns 0.0.
    The discount cannot exceed the original amount.
    """
    if not coupon_code or amount <= 0.0:
        return 0.0

    normalized_code = coupon_code.strip().upper()
    discount = 0.0

    if normalized_code == "SAVE10":
        discount = amount * 0.10
    elif normalized_code == "SAVE20":
        discount = amount * 0.20
    elif normalized_code == "FLAT15":
        discount = 15.0
    elif normalized_code == "FLAT50":
        discount = 50.0
    elif normalized_code == "FREE":
        discount = amount
    else:
        discount = 0.0

    # Ensure discount is within [0, amount]
    return max(0.0, min(discount, amount))

