def calculate(num1: float, operator: str, num2: float) -> float:
    """
    Performs core arithmetic calculations and handles mathematical validation rules.

    Supported operators: '+', '-', '*', '/', '**', '%', '//'
    """
    if operator == '+':
        return float(num1 + num2)
    elif operator == '-':
        return float(num1 - num2)
    elif operator == '*':
        return float(num1 * num2)
    elif operator == '/':
        if num2 == 0.0:
            raise ZeroDivisionError("Division by zero is not allowed.")
        return float(num1 / num2)
    elif operator == '**':
        try:
            return float(num1 ** num2)
        except OverflowError:
            raise OverflowError("Result of exponentiation is too large.")
    elif operator == '%':
        if num2 == 0.0:
            raise ZeroDivisionError("Modulo by zero is not allowed.")
        return float(num1 % num2)
    elif operator == '//':
        if num2 == 0.0:
            raise ZeroDivisionError("Floor division by zero is not allowed.")
        return float(num1 // num2)
    else:
        raise ValueError(f"Unsupported operator: {operator}")

