import argparse

def parse_arguments(args: list[str]) -> dict[str, float | str]:
    """
    Parses command-line arguments and validates inputs.
    Supports both positional arguments: [<value>, <direction>]
    and option flags: [-v/--value <value>, -d/--direction <direction>]
    """
    has_flags = any(arg.startswith('-') for arg in args)

    if has_flags:
        parser = argparse.ArgumentParser(description="CLI Parser")
        parser.add_argument("-v", "--value", type=float, required=True)
        parser.add_argument("-d", "--direction", type=str, required=True)
        try:
            parsed_args = parser.parse_args(args)
        except SystemExit as e:
            raise ValueError("Invalid arguments provided.") from e
        value = parsed_args.value
        direction = parsed_args.direction
    else:
        if len(args) < 2:
            raise ValueError("Missing arguments. Expected: <value> <direction>")
        try:
            value = float(args[0])
        except ValueError as e:
            raise ValueError(f"Value must be a float, got: {args[0]}") from e
        direction = args[1]

    return {
        "value": value,
        "direction": direction
    }

