    new_id = max([memo["id"] for memo in memos], default=0) + 1
    created_at = datetime.now().isoformat()

    new_memo = {
        "id": new_id,
        "title": title,
        "content": content,
        "created_at": created_at
    }

    memos.append(new_memo)
    save_data(DATA_FILE, memos)
    return new_memo

def update_memo(memo_id: int, title: str, content: str) -> dict:
    memos = _load_memos_safe()
    for memo in memos:
        if memo["id"] == memo_id:
            memo["title"] = title
            memo["content"] = content
            save_data(DATA_FILE, memos)
            return memo
    raise ValueError(f"Memo with ID {memo_id} does not exist.")

def delete_memo(memo_id: int) -> bool:
    memos = _load_memos_safe()
    original_length = len(memos)
    filtered_memos = [memo for memo in memos if memo["id"] != memo_id]

    if len(filtered_memos) < original_length:
        save_data(DATA_FILE, filtered_memos)
        return True
    return False

