def stock_in(item_name: str, quantity: int) -> int:
    if quantity < 0:
        raise ValueError("Quantity to stock in must be non-negative")

    data = load_data()
    current_quantity = data.get(item_name, 0)
    new_quantity = current_quantity + quantity
    data[item_name] = new_quantity
    save_data(data)
    return new_quantity

def stock_out(item_name: str, quantity: int) -> Tuple[bool, int]:
    if quantity < 0:
        raise ValueError("Quantity to stock out must be non-negative")

    data = load_data()
    current_quantity = data.get(item_name, 0)

    if current_quantity < quantity:
        return False, current_quantity

    new_quantity = current_quantity - quantity
    data[item_name] = new_quantity
    save_data(data)
    return True, new_quantity

def get_quantity(item_name: str) -> int:
    data = load_data()
    return data.get(item_name, 0)

