    """
    Attempts to redeem a specified number of points from the member's balance.
    Returns a tuple of (success, current_balance).
    """
    if points_to_use < 0:
        return False, get_points(member_id)

    current_balance = get_points(member_id)
    if current_balance >= points_to_use:
        new_balance = update_points(member_id, -points_to_use)
        return True, new_balance

    return False, current_balance

