COUPONS = {
    "SAVE10": {"type": "percent", "value": 10.0},
    "SAVE20": {"type": "percent", "value": 20.0},
    "FLAT5": {"type": "flat", "value": 5.0},
    "FLAT15": {"type": "flat", "value": 15.0},
    "FREE": {"type": "percent", "value": 100.0}
}

def is_valid_coupon(coupon_code: str) -> bool:
    if not isinstance(coupon_code, str):
        return False
    return coupon_code.upper() in COUPONS

def get_discount_amount(coupon_code: str, subtotal: float) -> float:
    if not is_valid_coupon(coupon_code):
        return 0.0

    if subtotal <= 0.0:
        return 0.0

    coupon = COUPONS[coupon_code.upper()]
    coupon_type = coupon["type"]
    value = coupon["value"]

    if coupon_type == "percent":
        discount = subtotal * (value / 100.0)
    elif coupon_type == "flat":
        discount = value
    else:
        discount = 0.0

    # Ensure discount does not exceed the subtotal and is not negative
    discount = min(discount, subtotal)
    return round(max(0.0, discount), 2)

