from inventory import check_stock, get_price, reduce_stock
from coupon import is_valid_coupon, get_discount_amount

_cart: dict[str, int] = {}
_applied_coupon: str | None = None

def add_to_cart(item_id: str, quantity: int) -> bool:
    if quantity <= 0:
        return False

    current_qty = _cart.get(item_id, 0)
    target_qty = current_qty + quantity

    if check_stock(item_id, target_qty):
        _cart[item_id] = target_qty
        return True
    return False

def apply_coupon(coupon_code: str) -> bool:
    global _applied_coupon
    if is_valid_coupon(coupon_code):
        _applied_coupon = coupon_code
        return True
    return False

def get_checkout_summary() -> dict:
    items_list = []
    subtotal = 0.0

    for item_id, qty in _cart.items():
        price = get_price(item_id)
        items_list.append({
            "item_id": item_id,
            "quantity": qty,
            "price": price
        })
        subtotal += price * qty

    discount = 0.0
    if _applied_coupon is not None:
        discount = get_discount_amount(_applied_coupon, subtotal)

    total = max(0.0, subtotal - discount)

    return {
        "items": items_list,
        "subtotal": subtotal,
        "discount": discount,
        "total": total
    }

def checkout() -> bool:
    global _cart, _applied_coupon
    if not _cart:
        return False

    # Verify stock is still available for all items
    for item_id, qty in _cart.items():
        if not check_stock(item_id, qty):
            return False

    # Reduce stock for all items
    for item_id, qty in _cart.items():
        reduce_stock(item_id, qty)

    # Clear cart and coupon state
    _cart = {}
    _applied_coupon = None
    return True

