def calculate(num1: float, num2: float, operator: str) -> float:
    """
    Performs core mathematical computations and validations.

    Args:
        num1 (float): The first operand.
        num2 (float): The second operand.
        operator (str): The operator to apply ('+', '-', '*', '/', '%', '**').

    Returns:
        float: The result of the mathematical operation.

    Raises:
        ValueError: If an invalid operator is provided or if division/modulo by zero is attempted.
    """
    # Ensure inputs are treated as floats
    try:
        val1 = float(num1)
        val2 = float(num2)
    except (ValueError, TypeError) as e:
        raise ValueError("Operands must be numeric values.") from e

    op = operator.strip()

    if op == '+':
        return val1 + val2
    elif op == '-':
        return val1 - val2
    elif op == '*':
        return val1 * val2
    elif op == '/':
        if val2 == 0.0:
            raise ValueError("Division by zero is not allowed.")
        return val1 / val2
    elif op == '%':
        if val2 == 0.0:
            raise ValueError("Modulo by zero is not allowed.")
        return val1 % val2
    elif op == '**':
        try:
            return val1 ** val2
        except OverflowError as e:
            raise ValueError("The result of the exponentiation is too large.") from e
    else:
        raise ValueError(f"Unsupported operator: '{operator}'. Supported operators are +, -, *, /, %, **")

