from storage import load_inventory, save_inventory

def add_stock(item_id: str, name: str, quantity: int) -> Dict[str, Dict[str, Union[str, int]]]:
    if quantity < 0:
        raise ValueError("Quantity to add must be non-negative")

    inv = load_inventory()
    if item_id in inv:
        inv[item_id]["quantity"] = inv[item_id].get("quantity", 0) + quantity
        if name:
            inv[item_id]["name"] = name
    else:
        inv[item_id] = {"name": name, "quantity": quantity}

    save_inventory(inv)
    return inv

def remove_stock(item_id: str, quantity: int) -> Dict[str, Dict[str, Union[str, int]]]:
    if quantity < 0:
        raise ValueError("Quantity to remove must be non-negative")

    inv = load_inventory()
    if item_id not in inv:
        raise ValueError(f"Item {item_id} not found in inventory")

    current_quantity = inv[item_id].get("quantity", 0)
    if current_quantity < quantity:
        raise ValueError(f"Insufficient stock for item {item_id}. Available: {current_quantity}, Requested: {quantity}")

    inv[item_id]["quantity"] = current_quantity - quantity
    save_inventory(inv)
    return inv

def get_stock(item_id: str) -> Optional[Dict[str, Union[str, int]]]:
    inv = load_inventory()
    return inv.get(item_id)

def get_all_items() -> Dict[str, Dict[str, Union[str, int]]]:
    return load_inventory()

