# Mock inventory database
# Structure: product_id -> {"price": float, "stock": int}
_INVENTORY_DB: Dict[str, Dict[str, Any]] = {
    "prod_001": {"price": 10.99, "stock": 50},
    "prod_002": {"price": 24.50, "stock": 10},
    "prod_003": {"price": 5.00, "stock": 0},
    "prod_004": {"price": 150.00, "stock": 5},
}


def is_stock_available(product_id: str, quantity: int) -> bool:
    """
    Checks if the requested quantity of a product is available in stock.
    Returns False if quantity is less than or equal to 0, or if the product does not exist.
    """
    if quantity <= 0:
        return False
    product = _INVENTORY_DB.get(product_id)
    if not product:
        return False
    return product["stock"] >= quantity


def get_price(product_id: str) -> float:
    """
    Returns the price of the specified product.
    Raises ValueError if the product is not found in the inventory.
    """
    product = _INVENTORY_DB.get(product_id)
    if not product:
        raise ValueError(f"Product with ID '{product_id}' does not exist in the inventory.")
    return float(product["price"])

