def get_discount(coupon_code: str, original_price: float) -> float:
    if original_price <= 0:
        return 0.0

    if not isinstance(coupon_code, str):
        return 0.0

    normalized_code = coupon_code.strip().upper()
    discount = 0.0

    # Fixed percentage discounts
    if normalized_code == "SAVE10":
        discount = original_price * 0.10
    elif normalized_code == "SAVE20":
        discount = original_price * 0.20
    elif normalized_code == "SAVE30":
        discount = original_price * 0.30
    elif normalized_code == "HALFPRICE":
        discount = original_price * 0.50
    # Fixed flat amount discounts
    elif normalized_code == "FLAT5":
        discount = 5.0
    elif normalized_code == "FLAT10":
        discount = 10.0
    elif normalized_code == "FLAT20":
        discount = 20.0
    # Dynamic percentage coupons, e.g., "PCT15" -> 15% discount
    elif normalized_code.startswith("PCT") and normalized_code[3:].isdigit():
        try:
            percentage = float(normalized_code[3:])
            if 0 <= percentage <= 100:
                discount = original_price * (percentage / 100.0)
        except ValueError:
            discount = 0.0
    else:
        discount = 0.0

    # Discount cannot be negative and cannot exceed the original price
    return max(0.0, min(discount, original_price))

