from inventory import is_stock_available, get_price
from coupon import get_discount

def calculate_total(cart: dict[str, int], coupon_code: str) -> dict[str, float]:
    """
    Calculates the final cost of the shopping cart.
    Validates item stock and quantities, then applies coupon discounts if applicable.

    Returns a dictionary with 'subtotal', 'discount', and 'total'.
    """
    subtotal = 0.0

    for product_id, quantity in cart.items():
        if quantity < 0:
            raise ValueError(f"Quantity for product '{product_id}' cannot be negative.")
        if quantity == 0:
            continue

        if not is_stock_available(product_id, quantity):
            raise ValueError(f"Insufficient stock for product '{product_id}' with quantity {quantity}.")

        price = get_price(product_id)
        subtotal += price * quantity

    discount = 0.0
    if coupon_code and subtotal > 0:
        discount = get_discount(coupon_code, subtotal)
        # Sanity check: discount should not be negative or exceed the subtotal
        if discount < 0:
            discount = 0.0
        elif discount > subtotal:
            discount = subtotal

    total = subtotal - discount

    return {
        "subtotal": round(subtotal, 2),
        "discount": round(discount, 2),
        "total": round(total, 2)
    }

def calculate(num1: float, num2: float, operator: str) -> float:
    """
    Performs core arithmetic operations and handles math-related validation.

    Supported operators: '+', '-', '*', '/'
    """
    if operator == '+':
        return float(num1 + num2)
    elif operator == '-':
        return float(num1 - num2)
    elif operator == '*':
        return float(num1 * num2)
    elif operator == '/':
        if num2 == 0.0:
            raise ValueError("Division by zero is not allowed.")
        return float(num1 / num2)
    else:
        raise ValueError(f"Unsupported operator: '{operator}'. Supported operators are +, -, *, /.")

