import json
import os
from typing import Any, Dict

def load_data(file_path: str) -> Dict[str, Dict[str, Any]]:
    """
    Loads inventory data from a local JSON file.
    If the file does not exist, is empty, or contains invalid JSON, 
    returns an empty dictionary.
    """
    if not os.path.exists(file_path):
        return {}

    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            content = f.read().strip()
            if not content:
                return {}
            data = json.loads(content)
            if isinstance(data, dict):
                return data
            return {}
    except (json.JSONDecodeError, IOError):
        return {}

def save_data(file_path: str, data: Dict[str, Dict[str, Any]]) -> bool:
    """
    Saves inventory data to a local JSON file.
    Creates any necessary parent directories.
    Returns True if the save operation was successful, False otherwise.
    """
    try:
        dir_name = os.path.dirname(file_path)
        if dir_name and not os.path.exists(dir_name):
            os.makedirs(dir_name, exist_ok=True)

        with open(file_path, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=4, ensure_ascii=False)
        return True
    except IOError:
        return False

