from storage import load_data, save_data

DATA_FILE = "inventory.json"

def add_stock(item_id: str, name: str, quantity: int) -> Dict[str, Any]:
    """
    Adds stock to the inventory. If the item already exists, its quantity is increased.
    Saves the updated inventory to persistent storage.
    """
    data = load_data(DATA_FILE)
    if data is None:
        data = {}

    if item_id in data:
        data[item_id]["quantity"] = data[item_id].get("quantity", 0) + quantity
        if name:
            data[item_id]["name"] = name
    else:
        data[item_id] = {"name": name, "quantity": quantity}

    save_data(DATA_FILE, data)

    return {
        "item_id": item_id,
        "name": data[item_id]["name"],
        "quantity": data[item_id]["quantity"]
    }

def remove_stock(item_id: str, quantity: int) -> Dict[str, Any]:
    """
    Removes stock from the inventory. Raises ValueError if the item does not exist
    or if there is insufficient stock.
    Saves the updated inventory to persistent storage.
    """
    data = load_data(DATA_FILE)
    if not data or item_id not in data:
        raise ValueError(f"Item '{item_id}' not found in inventory.")

    current_quantity = data[item_id].get("quantity", 0)
    if current_quantity < quantity:
        raise ValueError(
            f"Insufficient stock for item '{item_id}'. "
            f"Requested: {quantity}, Available: {current_quantity}."
        )

    data[item_id]["quantity"] = current_quantity - quantity
    save_data(DATA_FILE, data)

    return {
        "item_id": item_id,
        "name": data[item_id]["name"],
        "quantity": data[item_id]["quantity"]
    }

