    """
    Retrieves the current stock quantity for a given item.
    Returns 0 if the item is not found.
    """
    data = load_data(DATA_FILE)
    if not data or item_id not in data:
        return 0
    return data[item_id].get("quantity", 0)

def list_all_items() -> List[Dict[str, Any]]:
    """
    Lists all items in the inventory, returning them as a list of dictionaries.
    """
    data = load_data(DATA_FILE)
    if not data:
