COUPONS = {
    "WELCOME10": {"type": "percent", "value": 0.10},
    "SUPER20": {"type": "percent", "value": 0.20},
    "HALFPRICE": {"type": "percent", "value": 0.50},
    "FLAT15": {"type": "flat", "value": 15.0},
}

def validate_coupon(coupon_code: str) -> bool:
    if not isinstance(coupon_code, str):
        return False
    return coupon_code.strip().upper() in COUPONS

def calculate_discount(coupon_code: str, subtotal: float) -> float:
    if not validate_coupon(coupon_code):
        return 0.0

    if subtotal <= 0.0:
        return 0.0

    code = coupon_code.strip().upper()
    coupon = COUPONS[code]

    if coupon["type"] == "percent":
        discount = subtotal * coupon["value"]
    elif coupon["type"] == "flat":
        discount = min(coupon["value"], subtotal)
    else:
        discount = 0.0

    return round(float(discount), 2)

