from inventory import get_price
from coupon import validate_coupon, calculate_discount

def calculate_totals(cart: dict[str, int], coupon_code: str | None) -> dict[str, float]:
    subtotal = 0.0
    for product_id, quantity in cart.items():
        if quantity > 0:
            subtotal += get_price(product_id) * quantity

    discount = 0.0
    if coupon_code and validate_coupon(coupon_code):
        discount = calculate_discount(coupon_code, subtotal)

    total = max(0.0, subtotal - discount)

    return {
        "subtotal": subtotal,
        "discount": discount,
        "total": total
    }

def calculate(num1: float, num2: float, operator: str) -> float:
    """
    Performs core mathematical calculations and handles arithmetic validations.

    Supported operators: '+', '-', '*', '/', '%', '**'
    """
    # Ensure inputs are treated as floats
    val1 = float(num1)
    val2 = float(num2)

    if operator == '+':
        return val1 + val2
    elif operator == '-':
        return val1 - val2
    elif operator == '*':
        return val1 * val2
    elif operator == '/':
        if val2 == 0.0:
            raise ZeroDivisionError("Division by zero is not allowed.")
        return val1 / val2
    elif operator == '%':
        if val2 == 0.0:
            raise ZeroDivisionError("Modulo by zero is not allowed.")
        return val1 % val2
    elif operator == '**':
        return val1 ** val2
    else:
        raise ValueError(f"Unsupported operator: '{operator}'")

