    if initial_qty < 0:
        return False
    data = load_data(DATA_FILE_PATH)
    if data is None:
        data = {}
    if item_id in data:
        return False
    data[item_id] = {"name": name, "quantity": initial_qty}
    return save_data(DATA_FILE_PATH, data)

def stock_in(item_id: str, quantity: int) -> bool:
    if quantity <= 0:
        return False
    data = load_data(DATA_FILE_PATH)
    if not data or item_id not in data:
        return False
    data[item_id]["quantity"] = data[item_id].get("quantity", 0) + quantity
    return save_data(DATA_FILE_PATH, data)

def stock_out(item_id: str, quantity: int) -> bool:
    if quantity <= 0:
        return False
    data = load_data(DATA_FILE_PATH)
    if not data or item_id not in data:
        return False
    current_qty = data[item_id].get("quantity", 0)
    if current_qty < quantity:
        return False
    data[item_id]["quantity"] = current_qty - quantity
    return save_data(DATA_FILE_PATH, data)

def get_quantity(item_id: str) -> int:
