}


def check_stock(item_id: str, quantity: int) -> bool:
    """Check if the requested quantity of the item is available in stock."""
    if quantity <= 0:
        return False
    if item_id not in _INVENTORY:
        return False
    return _INVENTORY[item_id]["stock"] >= quantity


def deduct_stock(item_id: str, quantity: int) -> bool:
    """Deduct the specified quantity from the item's stock if available."""
    if not check_stock(item_id, quantity):
        return False
    _INVENTORY[item_id]["stock"] -= quantity
    return True


def get_price(item_id: str) -> float:
    """Get the unit price of the specified item."""
    if item_id not in _INVENTORY:
        raise ValueError(f"Item '{item_id}' not found in inventory.")
    return float(_INVENTORY[item_id]["price"])

