COUPONS = {
    "SAVE10": {"type": "percent", "value": 10.0},
    "SAVE20": {"type": "percent", "value": 20.0},
    "SAVE50": {"type": "percent", "value": 50.0},
    "FLAT10": {"type": "flat", "value": 10.0},
    "FLAT25": {"type": "flat", "value": 25.0},
    "FREE": {"type": "percent", "value": 100.0}
}

def validate_coupon(coupon_code: str) -> bool:
    """
    Validates if a coupon code exists in the system.
    Matches are case-insensitive and whitespace-trimmed.
    """
    if not isinstance(coupon_code, str):
        return False
    return coupon_code.strip().upper() in COUPONS

def calculate_discount(coupon_code: str, original_total: float) -> float:
    """
    Calculates the discount amount based on the coupon code and original total.
    Returns 0.0 if the coupon is invalid or the total is 0 or less.
    The returned discount will not exceed the original total.
    """
    if original_total <= 0.0:
        return 0.0

    if not validate_coupon(coupon_code):
        return 0.0

    normalized_code = coupon_code.strip().upper()
    coupon_rule = COUPONS[normalized_code]

    if coupon_rule["type"] == "percent":
        discount = original_total * (coupon_rule["value"] / 100.0)
    elif coupon_rule["type"] == "flat":
        discount = coupon_rule["value"]
    else:
        discount = 0.0

    # Ensure discount does not exceed original total and is not negative
    final_discount = max(0.0, min(discount, original_total))
    return round(final_discount, 2)

