import inventory
import coupons

def calculate_cart_total(cart: dict[str, int], coupon_code: str | None) -> float:
    total = 0.0
    for item_id, quantity in cart.items():
        price = inventory.get_price(item_id)
        total += price * quantity

    if coupon_code and coupons.validate_coupon(coupon_code):
        discount = coupons.calculate_discount(coupon_code, total)
        total = max(0.0, total - discount)

    return total

def process_checkout(cart: dict[str, int], coupon_code: str | None) -> dict[str, bool | float | str]:
    if coupon_code is not None:
        if not coupons.validate_coupon(coupon_code):
            return {
                "success": False,
                "total": 0.0,
                "message": "Invalid coupon code"
            }

    for item_id, quantity in cart.items():
        if not inventory.check_stock(item_id, quantity):
            return {
                "success": False,
                "total": 0.0,
                "message": f"Insufficient stock for item {item_id}"
            }

    for item_id, quantity in cart.items():
        inventory.deduct_stock(item_id, quantity)

    total = calculate_cart_total(cart, coupon_code)

    return {
        "success": True,
        "total": total,
        "message": "Checkout completed successfully"
    }

