def calculate(num1: float, num2: float, operator: str) -> float:
    """
    Performs basic mathematical operations: addition, subtraction, multiplication, and division.

    :param num1: The first operand.
    :param num2: The second operand.
    :param operator: The operator as a string ('+', '-', '*', '/').
    :return: The result of the calculation as a float.
    :raises ValueError: If division by zero is attempted or an invalid operator is provided.
    """
    val1 = float(num1)
    val2 = float(num2)

    if operator == '+':
        return val1 + val2
    elif operator == '-':
        return val1 - val2
    elif operator == '*':
        return val1 * val2
    elif operator == '/':
        if val2 == 0.0:
            raise ValueError("Division by zero is not allowed.")
        return val1 / val2
    else:
        raise ValueError(f"Invalid operator '{operator}'. Supported operators are '+', '-', '*', '/'.")

