    items = get_all_items()
    new_id = max([item["id"] for item in items], default=0) + 1
    new_item = {
        "id": new_id,
        "title": title,
        "completed": False
    }
    items.append(new_item)
    save_data(DATA_FILE, items)
    return new_item

def delete_item(item_id: int) -> bool:
    items = get_all_items()
    original_length = len(items)
    filtered_items = [item for item in items if item["id"] != item_id]
    if len(filtered_items) < original_length:
        save_data(DATA_FILE, filtered_items)
        return True
    return False

def complete_item(item_id: int) -> bool:
    items = get_all_items()
    found = False
    for item in items:
        if item["id"] == item_id:
            item["completed"] = True
            found = True
            break
    if found:
        save_data(DATA_FILE, items)
        return True
    return False

