DATA_FILE = "memos.json"

def list_memos() -> list[dict]:
    try:
        data = load_data(DATA_FILE)
        if data is None:
            return []
        return data
    except Exception:
        return []

def add_memo(content: str) -> dict:
    memos = list_memos()
    next_id = max([memo["id"] for memo in memos], default=0) + 1
    new_memo = {"id": next_id, "content": content}
    memos.append(new_memo)
    save_data(DATA_FILE, memos)
    return new_memo

def update_memo(memo_id: int, new_content: str) -> bool:
    memos = list_memos()
    for memo in memos:
        if memo["id"] == memo_id:
            memo["content"] = new_content
            save_data(DATA_FILE, memos)
            return True
    return False

def delete_memo(memo_id: int) -> bool:
    memos = list_memos()
    initial_length = len(memos)
    memos = [memo for memo in memos if memo["id"] != memo_id]
    if len(memos) < initial_length:
        save_data(DATA_FILE, memos)
        return True
    return False

