import uuid
from datetime import datetime

def add_record(records: list[dict], record_type: str, amount: int, description: str) -> list[dict]:
    new_record = {
        "id": str(uuid.uuid4()),
        "type": record_type,
        "amount": amount,
        "description": description,
        "date": datetime.now().isoformat()
    }
    records.append(new_record)
    return records

def calculate_balance(records: list[dict]) -> int:
    balance = 0
    for record in records:
        r_type = record.get("type", "").lower()
        amount = record.get("amount", 0)
        if r_type in ("income", "deposit", "credit"):
            balance += amount
        elif r_type in ("expense", "withdrawal", "debit"):
            balance -= amount
        else:
            balance += amount
    return balance

