from storage import load_data, save_data

def stock_in(item_id: str, name: str, quantity: int) -> bool:
    if quantity <= 0:
        return False

    data = load_data()
    if data is None:
        data = {}

    if item_id in data:
        current_qty = data[item_id].get("quantity", 0)
        if isinstance(current_qty, int):
            data[item_id]["quantity"] = current_qty + quantity
        else:
            data[item_id]["quantity"] = quantity
        data[item_id]["name"] = name
    else:
        data[item_id] = {
            "name": name,
            "quantity": quantity
        }

    save_data(data)
    return True

def stock_out(item_id: str, quantity: int) -> bool:
    if quantity <= 0:
        return False

    data = load_data()
    if not data or item_id not in data:
        return False

    current_qty = data[item_id].get("quantity", 0)
    if not isinstance(current_qty, int) or current_qty < quantity:
        return False

    data[item_id]["quantity"] = current_qty - quantity
    save_data(data)
    return True

def get_stock(item_id: str) -> dict[str, int | str] | None:
    data = load_data()
    if not data or item_id not in data:
        return None
    return data[item_id]

def list_items() -> dict[str, dict[str, int | str]]:
    data = load_data()
    if not data:
        return {}
    return data

