def earn_points(user_id: str, purchase_amount: int) -> int:
    if purchase_amount < 0:
        raise ValueError("Purchase amount must be non-negative")

    current_balance = get_points(user_id)
    if current_balance is None:
        current_balance = 0

    # Earn 1 point per unit of purchase amount
    points_earned = purchase_amount
    new_balance = current_balance + points_earned
    save_points(user_id, new_balance)
    return new_balance

def pay_with_points(user_id: str, point_amount: int) -> int:
    if point_amount < 0:
        raise ValueError("Point amount must be non-negative")

    current_balance = get_points(user_id)
    if current_balance is None:
        current_balance = 0

    if current_balance < point_amount:
        raise ValueError("Insufficient points balance")

    new_balance = current_balance - point_amount
    save_points(user_id, new_balance)
    return new_balance

def get_balance(user_id: str) -> int:
    balance = get_points(user_id)
    if balance is None:
        return 0
    return balance

