COUPONS = {
    "SAVE10": {"type": "percent", "value": 10.0},
    "SAVE20": {"type": "percent", "value": 20.0},
    "FLAT15": {"type": "flat", "value": 15.0},
    "WELCOME5": {"type": "flat", "value": 5.0}
}

def validate_coupon(coupon_code: str) -> bool:
    """
    Validates if a coupon code exists in the system.
    """
    if not isinstance(coupon_code, str):
        return False
    return coupon_code.strip().upper() in COUPONS

def calculate_discount(coupon_code: str, total_amount: float) -> float:
    """
    Calculates the discount amount based on the coupon code and total amount.
    Returns 0.0 if the coupon is invalid. The discount is capped at the total amount.
    """
    if not isinstance(total_amount, (int, float)) or total_amount <= 0:
        return 0.0

    if not validate_coupon(coupon_code):
        return 0.0

    code = coupon_code.strip().upper()
    coupon = COUPONS[code]
    discount = 0.0

    if coupon["type"] == "percent":
        discount = total_amount * (coupon["value"] / 100.0)
    elif coupon["type"] == "flat":
        discount = coupon["value"]

    # Limit discount to not exceed the total amount
    discount = min(discount, total_amount)
    return round(float(discount), 2)

