from inventory import check_stock, get_price
from coupon import validate_coupon, calculate_discount

def add_to_cart(cart: dict, product_id: str, quantity: int) -> dict:
    existing_qty = 0
    for item in cart.get('items', []):
        if item.get('product_id') == product_id:
            existing_qty = item.get('quantity', 0)
            break

    total_requested_qty = existing_qty + quantity

    if check_stock(product_id, total_requested_qty):
        new_items = []
        updated = False
        for item in cart.get('items', []):
            if item.get('product_id') == product_id:
                new_items.append({'product_id': product_id, 'quantity': total_requested_qty})
                updated = True
            else:
                new_items.append({'product_id': item.get('product_id'), 'quantity': item.get('quantity')})

        if not updated:
            new_items.append({'product_id': product_id, 'quantity': quantity})

        new_cart = {
            'items': new_items,
            'coupon_code': cart.get('coupon_code', '')
        }
        return {'cart': new_cart, 'success': True}
    else:
        return {'cart': cart, 'success': False}

def apply_coupon(cart: dict, coupon_code: str) -> dict:
    if validate_coupon(coupon_code):
        new_cart = {
            'items': [dict(item) for item in cart.get('items', [])],
            'coupon_code': coupon_code
        }
        return {'cart': new_cart, 'success': True}
    else:
        return {'cart': cart, 'success': False}

def calculate_bill(cart: dict) -> dict:
    subtotal = 0.0
    for item in cart.get('items', []):
        product_id = item.get('product_id')
        quantity = item.get('quantity', 0)
        price = get_price(product_id)
        subtotal += price * quantity

    coupon_code = cart.get('coupon_code', '')
    discount_applied = 0.0
    if coupon_code:
        discount_applied = calculate_discount(coupon_code, subtotal)

    total = max(0.0, subtotal - discount_applied)

    return {
        'subtotal': subtotal,
        'discount_applied': discount_applied,
        'total': total
    }

