def calculate(operand1: float, operand2: float, operator: str) -> float:
    """
    Performs core arithmetic operations and handles calculation-related validation.

    Supported operators:
        '+'  : Addition
        '-'  : Subtraction
        '*'  : Multiplication
        '/'  : Division (raises ZeroDivisionError if operand2 is 0)
        '%'  : Modulo (raises ZeroDivisionError if operand2 is 0)
        '**' : Exponentiation

    :param operand1: The first number.
    :param operand2: The second number.
    :param operator: The arithmetic operator as a string.
    :return: The result of the calculation as a float.
    :raises ValueError: If the operator is unsupported.
    :raises ZeroDivisionError: If division or modulo by zero is attempted.
    """
    if operator == '+':
        return float(operand1 + operand2)
    elif operator == '-':
        return float(operand1 - operand2)
    elif operator == '*':
        return float(operand1 * operand2)
    elif operator == '/':
        if operand2 == 0:
            raise ZeroDivisionError("Division by zero is not allowed.")
        return float(operand1 / operand2)
    elif operator == '%':
        if operand2 == 0:
            raise ZeroDivisionError("Modulo by zero is not allowed.")
        return float(operand1 % operand2)
    elif operator == '**':
        try:
            return float(operand1 ** operand2)
        except OverflowError:
            raise ValueError("Result of exponentiation is too large.")
    else:
        raise ValueError(f"Unsupported operator: '{operator}'. Supported operators are +, -, *, /, %, **")

