import argparse

def parse_arguments(args: list[str]) -> dict[str, any]:
    """
    Parses command-line arguments to extract a numeric value and a direction string.
    Supports positional arguments as well as explicit flags (--value/-v, --direction/-d).

    Args:
        args: A list of command-line argument strings.

    Returns:
        A dictionary with "value" (float) and "direction" (str).

    Raises:
        ValueError: If parsing fails or the required inputs cannot be identified.
    """
    # 1. Quick positional check for simple inputs like ['180', 'to_radians'] or ['to_degrees', '3.14']
    if len(args) == 2 and not args[0].startswith('-') and not args[1].startswith('-'):
        try:
            val = float(args[0])
            direction = args[1]
            return {"value": val, "direction": direction}
        except ValueError:
            try:
                val = float(args[1])
                direction = args[0]
                return {"value": val, "direction": direction}
            except ValueError:
                pass

    # 2. Robust parsing with argparse for standard flagged arguments
    parser = argparse.ArgumentParser(description="Parse value and direction arguments.")
    parser.add_argument("--value", "-v", type=float, default=None)
    parser.add_argument("--direction", "-d", type=str, default=None)

    try:
        parsed_args, unknown = parser.parse_known_args(args)
        val = parsed_args.value
        direction = parsed_args.direction

        # Fallback to search unknown/positional arguments if flags are missing
        if val is None:
            for item in unknown:
                try:
                    val = float(item)
                    unknown.remove(item)
                    break
                except ValueError:
                    continue

        if direction is None:
            for item in unknown:
                if not item.startswith('-'):
                    try:
                        # Ensure it's not actually a float represented as a string
                        float(item)
                    except ValueError:
                        direction = item
                        break

        if val is None or direction is None:
            raise ValueError("Both a numeric value and a direction string must be provided.")

        return {
            "value": float(val),
            "direction": str(direction)
        }

    except Exception as e:
        raise ValueError(f"Failed to parse arguments {args}: {e}") from e

