def update_memo(memo_id: int, title: str, content: str) -> bool:
    memos = load_data()
    updated = False

    for memo in memos:
        if memo["id"] == memo_id:
            memo["title"] = title
            memo["content"] = content
            updated = True
            break

    if updated:
        save_data(memos)

    return updated


def delete_memo(memo_id: int) -> bool:
    memos = load_data()
    initial_length = len(memos)

    memos = [memo for memo in memos if memo["id"] != memo_id]

    if len(memos) < initial_length:
        save_data(memos)
        return True

    return False

