def stock_out(item_name: str, qty: int) -> int:
    if qty < 0:
        raise ValueError("Quantity to stock out must be non-negative")

    items = get_all_items()
    current_qty = items.get(item_name, 0)

    if current_qty < qty:
        raise ValueError(f"Insufficient stock for '{item_name}'. Available: {current_qty}, Requested: {qty}")

    new_qty = current_qty - qty
    items[item_name] = new_qty

    save_data(INVENTORY_FILE, items)
    return new_qty

