        raise ValueError(f"Member with ID '{member_id}' does not exist.")
    if purchase_amount < 0:
        raise ValueError("Purchase amount cannot be negative.")

    points_earned = purchase_amount // 10
    current_points = get_points(member_id)
    new_points = current_points + points_earned
    update_points(member_id, new_points)
    return new_points

def pay_with_points(member_id: str, amount: int) -> int:
