COUPONS = {
    "WELCOME10": {"type": "percentage", "value": 10.0, "min_amount": 0.0},
    "SAVE20": {"type": "percentage", "value": 20.0, "min_amount": 50.0},
    "FLAT15": {"type": "flat", "value": 15.0, "min_amount": 30.0},
    "SUPER50": {"type": "percentage", "value": 50.0, "min_amount": 200.0},
}


def validate_coupon(coupon_code: str) -> bool:
    if not isinstance(coupon_code, str):
        return False
    normalized_code = coupon_code.strip().upper()
    return normalized_code in COUPONS


def calculate_discount(coupon_code: str, total_amount: float) -> float:
    if not isinstance(total_amount, (int, float)) or total_amount <= 0:
        return 0.0

    if not validate_coupon(coupon_code):
        return 0.0

    normalized_code = coupon_code.strip().upper()
    coupon = COUPONS[normalized_code]

    if total_amount < coupon["min_amount"]:
        return 0.0

    if coupon["type"] == "percentage":
        discount = total_amount * (coupon["value"] / 100.0)
    elif coupon["type"] == "flat":
        discount = coupon["value"]
    else:
        discount = 0.0

    # Ensure the discount does not exceed the total amount and is rounded
    actual_discount = min(discount, total_amount)
    return round(actual_discount, 2)

