def calculate(num1: float, num2: float, operator: str) -> float:
    """
    Performs core arithmetic operations and handles calculation-related error checking.

    Supported operators: '+', '-', '*', '/'
    """
    # Standardize types to float
    try:
        val1 = float(num1)
        val2 = float(num2)
    except (ValueError, TypeError) as e:
        raise ValueError("Inputs must be numeric values.") from e

    if operator == '+':
        return val1 + val2
    elif operator == '-':
        return val1 - val2
    elif operator == '*':
        return val1 * val2
    elif operator == '/':
        if val2 == 0:
            raise ZeroDivisionError("Division by zero is not allowed.")
        return val1 / val2
    else:
        raise ValueError(f"Invalid operator '{operator}'. Supported operators are +, -, *, /.")

