import storage

DATA_FILE = "inventory.json"

def _load_data() -> dict[str, dict[str, str | int]]:
    try:
        data = storage.load_data(DATA_FILE)
        if data is None:
            return {}
        return data
    except Exception:
        return {}

def _save_data(data: dict[str, dict[str, str | int]]) -> None:
    storage.save_data(DATA_FILE, data)

def register_item(item_id: str, name: str) -> bool:
    data = _load_data()
    if item_id in data:
        return False
    data[item_id] = {
        "name": name,
        "quantity": 0
    }
    _save_data(data)
    return True

def receive_stock(item_id: str, quantity: int) -> int:
    if quantity < 0:
        raise ValueError("Quantity to receive must be non-negative.")

    data = _load_data()
    if item_id not in data:
        raise ValueError(f"Item '{item_id}' is not registered.")

    current_qty = int(data[item_id].get("quantity", 0))
    new_qty = current_qty + quantity
    data[item_id]["quantity"] = new_qty
    _save_data(data)
    return new_qty

def release_stock(item_id: str, quantity: int) -> int:
    if quantity < 0:
        raise ValueError("Quantity to release must be non-negative.")

    data = _load_data()
    if item_id not in data:
        raise ValueError(f"Item '{item_id}' is not registered.")

    current_qty = int(data[item_id].get("quantity", 0))
    if current_qty < quantity:
        raise ValueError(f"Insufficient stock for item '{item_id}'. Available: {current_qty}, requested: {quantity}.")

    new_qty = current_qty - quantity
    data[item_id]["quantity"] = new_qty
    _save_data(data)
    return new_qty

def get_stock_level(item_id: str) -> int:
    data = _load_data()
    if item_id not in data:
        raise ValueError(f"Item '{item_id}' is not registered.")
    return int(data[item_id].get("quantity", 0))

def get_all_items() -> list[dict[str, str | int]]:
    data = _load_data()
    items_list = []
    for item_id, info in data.items():
        items_list.append({
            "item_id": item_id,
            "name": info.get("name", ""),
            "quantity": info.get("quantity", 0)
        })
    return items_list

