    if success:
        print(f"Success: Item '{name}' ({item_id}) registered.")
    else:
        print(f"Failure: Item ID '{item_id}' might already exist or registration failed.")

def handle_receive():
    item_id = input("Enter Item ID: ").strip()
    qty_str = input("Enter Quantity to Receive: ").strip()
    try:
        quantity = int(qty_str)
        if quantity <= 0:
            print("Error: Quantity must be a positive integer.")
            return
    except ValueError:
        print("Error: Quantity must be a valid integer.")
        return

    try:
        new_level = receive_stock(item_id, quantity)
        if new_level < 0:
            print("Failure: Could not receive stock. Check if the item ID is registered.")
        else:
            print(f"Success: Stock received. New stock level: {new_level}")
