        if quantity <= 0:
            print("Error: Quantity must be a positive integer.")
            return
    except ValueError:
        print("Error: Quantity must be a valid integer.")
        return

    try:
        new_level = release_stock(item_id, quantity)
        if new_level < 0:
            print("Failure: Could not release stock. Ensure the item is registered and has enough stock.")
        else:
            print(f"Success: Stock released. New stock level: {new_level}")
    except Exception as e:
        print(f"An error occurred: {e}")

