COUPONS = {
    "SAVE10": {"type": "percentage", "value": 0.10},
    "SAVE20": {"type": "percentage", "value": 0.20},
    "FIFTY": {"type": "percentage", "value": 0.50},
    "FLAT5": {"type": "fixed", "value": 5.00},
    "FLAT15": {"type": "fixed", "value": 15.00},
}


def is_valid_coupon(coupon_code: str) -> bool:
    if not isinstance(coupon_code, str):
        return False
    return coupon_code.strip().upper() in COUPONS


def get_coupon_discount(coupon_code: str, subtotal: float) -> float:
    if subtotal <= 0:
        return 0.0

    if not is_valid_coupon(coupon_code):
        return 0.0

    code = coupon_code.strip().upper()
    coupon = COUPONS[code]

    if coupon["type"] == "percentage":
        discount = subtotal * coupon["value"]
    elif coupon["type"] == "fixed":
        discount = min(coupon["value"], subtotal)
    else:
        discount = 0.0

    return round(discount, 2)

