import inventory
import coupon

# Module-level state representing the active shopping cart
_cart: dict[str, int] = {}
_applied_coupon: str = ""

def add_item(product_id: str, quantity: int) -> bool:
    if quantity <= 0:
        return False

    current_quantity = _cart.get(product_id, 0)
    target_quantity = current_quantity + quantity

    if inventory.has_sufficient_stock(product_id, target_quantity):
        _cart[product_id] = target_quantity
        return True
    return False

def apply_coupon(coupon_code: str) -> bool:
    global _applied_coupon
    if coupon.is_valid_coupon(coupon_code):
        _applied_coupon = coupon_code
        return True
    return False

def get_cart_summary() -> dict:
    items = []
    subtotal = 0.0

    for product_id, quantity in _cart.items():
        unit_price = inventory.get_price(product_id)
        items.append({
            "product_id": product_id,
            "quantity": quantity,
            "unit_price": unit_price
        })
        subtotal += unit_price * quantity

    discount = 0.0
    if _applied_coupon:
        discount = coupon.get_coupon_discount(_applied_coupon, subtotal)

    total = max(0.0, subtotal - discount)

    return {
        "items": items,
        "subtotal": subtotal,
        "discount": discount,
        "total": total,
        "applied_coupon": _applied_coupon
    }

def checkout() -> bool:
    global _applied_coupon
    if not _cart:
        return False

    # Verify stock sufficiency for all items in the cart before making changes
    for product_id, quantity in _cart.items():
        if not inventory.has_sufficient_stock(product_id, quantity):
            return False

    # Reduce stock for all items
    for product_id, quantity in _cart.items():
        inventory.reduce_stock(product_id, quantity)

    # Clear the cart and reset applied coupon upon successful checkout
    _cart.clear()
    _applied_coupon = ""
    return True

