def calculate(a: float, b: float, op: str) -> float:
    """Performs mathematical computations and arithmetic validation.

    Supported operators: '+', '-', '*', '/', '%', '**'
    """
    if op == '+':
        return float(a + b)
    elif op == '-':
        return float(a - b)
    elif op == '*':
        return float(a * b)
    elif op == '/':
        if b == 0:
            raise ZeroDivisionError("Division by zero")
        return float(a / b)
    elif op == '%':
        if b == 0:
            raise ZeroDivisionError("Modulo by zero")
        return float(a % b)
    elif op == '**':
        return float(a ** b)
    else:
        raise ValueError(f"Unsupported operator: {op}")

