INVENTORY_FILE = "inventory.json"

def _load_inventory() -> dict[str, dict[str, str | int]]:
    try:
        data = load_data(INVENTORY_FILE)
        if data is None:
            return {}
        return data
    except (FileNotFoundError, ValueError):
        return {}

def stock_in(item_id: str, name: str, quantity: int) -> bool:
    if quantity <= 0:
        return False
    data = _load_inventory()
    if item_id in data:
        current_qty = int(data[item_id].get("quantity", 0))
        data[item_id]["quantity"] = current_qty + quantity
        if name:
            data[item_id]["name"] = name
    else:
        data[item_id] = {"name": name, "quantity": quantity}
    save_data(INVENTORY_FILE, data)
    return True

def stock_out(item_id: str, quantity: int) -> bool:
    if quantity <= 0:
        return False
    data = _load_inventory()
    if item_id not in data:
        return False
    current_qty = int(data[item_id].get("quantity", 0))
    if current_qty < quantity:
        return False
    data[item_id]["quantity"] = current_qty - quantity
    save_data(INVENTORY_FILE, data)
    return True

def get_stock(item_id: str) -> int | None:
    data = _load_inventory()
    if item_id in data:
        return int(data[item_id].get("quantity", 0))
    return None

def list_inventory() -> list[dict[str, str | int]]:
    data = _load_inventory()
    inventory_list = []
    for item_id, details in data.items():
        inventory_list.append({
            "item_id": item_id,
            "name": details.get("name", ""),
            "quantity": details.get("quantity", 0)
        })
    return inventory_list

