COUPONS = {
    "SAVE10": {"type": "percent", "value": 10.0},
    "SAVE20": {"type": "percent", "value": 20.0},
    "SAVE50": {"type": "percent", "value": 50.0},
    "FLAT5": {"type": "flat", "value": 5.00},
    "FLAT10": {"type": "flat", "value": 10.00},
    "FREE": {"type": "percent", "value": 100.0},
}

def is_valid_coupon(coupon_code: str) -> bool:
    if not isinstance(coupon_code, str):
        return False
    return coupon_code.upper().strip() in COUPONS

def calculate_discounted_price(coupon_code: str, original_total: float) -> float:
    safe_total = max(0.0, float(original_total))

    if not isinstance(coupon_code, str):
        return round(safe_total, 2)

    code_clean = coupon_code.upper().strip()
    if not is_valid_coupon(code_clean):
        return round(safe_total, 2)

    coupon = COUPONS[code_clean]
    if coupon["type"] == "percent":
        discount = safe_total * (coupon["value"] / 100.0)
    elif coupon["type"] == "flat":
        discount = coupon["value"]
    else:
        discount = 0.0

    discounted_total = max(0.0, safe_total - discount)
    return round(discounted_total, 2)

