from inventory import check_stock, reduce_stock, get_price
from coupon import is_valid_coupon, calculate_discounted_price

def process_checkout(cart: dict[str, int], coupon_code: str) -> dict[str, float | bool | str]:
    if not cart:
        return {
            "success": False,
            "total": 0.0,
            "message": "Cart is empty"
        }

    # Verify stock for all items first
    for product_id, qty in cart.items():
        if qty <= 0:
            return {
                "success": False,
                "total": 0.0,
                "message": f"Invalid quantity {qty} for product {product_id}"
            }
        if not check_stock(product_id, qty):
            return {
                "success": False,
                "total": 0.0,
                "message": f"Insufficient stock for product {product_id}"
            }

    # Calculate total price
    original_total = 0.0
    for product_id, qty in cart.items():
        price = get_price(product_id)
        original_total += price * qty

    # Apply coupon if provided
    total = original_total
    if coupon_code:
        if is_valid_coupon(coupon_code):
            total = calculate_discounted_price(coupon_code, original_total)
        else:
            return {
                "success": False,
                "total": 0.0,
                "message": "Invalid coupon code"
            }

    # Deduct inventory stock
    for product_id, qty in cart.items():
        success = reduce_stock(product_id, qty)
        if not success:
            return {
                "success": False,
                "total": 0.0,
                "message": f"Failed to reduce stock for product {product_id}"
            }

    return {
        "success": True,
        "total": total,
        "message": "Checkout completed successfully"
    }

