def _load_inventory() -> dict[str, dict[str, int | str]]:
    try:
        return load_data(DATA_FILE)
    except Exception:
        return {}

def _save_inventory(data: dict[str, dict[str, int | str]]) -> None:
    save_data(DATA_FILE, data)

def add_item(item_id: str, name: str) -> bool:
    data = _load_inventory()
    if item_id in data:
        return False
    data[item_id] = {"name": name, "quantity": 0}
    _save_inventory(data)
    return True

def receive_item(item_id: str, quantity: int) -> bool:
    if quantity <= 0:
        return False
    data = _load_inventory()
    if item_id not in data:
        return False
    data[item_id]["quantity"] = int(data[item_id].get("quantity", 0)) + quantity
    _save_inventory(data)
    return True

def release_item(item_id: str, quantity: int) -> bool:
    if quantity <= 0:
        return False
    data = _load_inventory()
    if item_id not in data:
        return False
    current_qty = int(data[item_id].get("quantity", 0))
    if current_qty < quantity:
        return False
    data[item_id]["quantity"] = current_qty - quantity
    _save_inventory(data)
    return True

def get_quantity(item_id: str) -> int:
    data = _load_inventory()
    if item_id not in data:
        return -1
    return int(data[item_id].get("quantity", 0))

def list_items() -> list[dict[str, int | str]]:
    data = _load_inventory()
    items_list = []
    for item_id, info in data.items():
        items_list.append({
            "id": item_id,
            "name": info.get("name", ""),
            "quantity": info.get("quantity", 0)
        })
    return items_list

