def validate_coupon(coupon: dict, total_amount: float) -> bool:
    if not coupon or not isinstance(coupon, dict):
        return False

    min_order_value = coupon.get("min_order_value", 0.0)
    if min_order_value is not None:
        try:
            if total_amount < float(min_order_value):
                return False
        except (ValueError, TypeError):
            return False

    return True

def calculate_discount(coupon: dict, total_amount: float) -> float:
    if not validate_coupon(coupon, total_amount):
        return 0.0

    coupon_type = coupon.get("type")
    try:
        value = float(coupon.get("value", 0.0))
    except (ValueError, TypeError):
        return 0.0

    if coupon_type == "percentage":
        discount = total_amount * (value / 100.0)
    elif coupon_type in ("fixed", "fixed_amount"):
        discount = value
    else:
        discount = 0.0

    # Ensure discount is not negative and does not exceed the total amount
    return float(max(0.0, min(discount, total_amount)))

