from inventory_service import check_stock
from discount_service import validate_coupon, calculate_discount

def create_cart() -> Dict[str, Any]:
    return {
        "items": [],
        "coupon": None
    }

def add_to_cart(cart: Dict[str, Any], product_id: str, price: float, quantity: int) -> Dict[str, Any]:
    existing_item = next((item for item in cart["items"] if item["product_id"] == product_id), None)
    current_qty = existing_item["quantity"] if existing_item else 0
    new_qty = current_qty + quantity

    if not check_stock(product_id, new_qty):
        raise ValueError("Insufficient stock available for this product.")

    if existing_item:
        existing_item["quantity"] = new_qty
    else:
        cart["items"].append({
            "product_id": product_id,
            "price": price,
            "quantity": quantity
        })
    return cart

def apply_coupon(cart: Dict[str, Any], coupon: Dict[str, Any]) -> Dict[str, Any]:
    subtotal = sum(item["price"] * item["quantity"] for item in cart["items"])
    if not validate_coupon(coupon, subtotal):
        raise ValueError("Coupon is not valid for the current cart.")
    cart["coupon"] = coupon
    return cart

def calculate_totals(cart: Dict[str, Any]) -> Dict[str, float]:
    subtotal = sum(item["price"] * item["quantity"] for item in cart["items"])
    discount_amount = 0.0

    coupon = cart.get("coupon")
    if coupon and validate_coupon(coupon, subtotal):
        discount_amount = calculate_discount(coupon, subtotal)

    final_total = max(0.0, subtotal - discount_amount)
    return {
        "subtotal": float(subtotal),
        "discount_amount": float(discount_amount),
        "final_total": float(final_total)
    }

