def calculate(num1: float, num2: float, operator: str) -> float:
    """
    Performs core arithmetic operations and handles math-related validation.

    Supported operators: '+', '-', '*', '/', '%', '**'
    """
    if operator == '+':
        return float(num1 + num2)
    elif operator == '-':
        return float(num1 - num2)
    elif operator == '*':
        return float(num1 * num2)
    elif operator == '/':
        if num2 == 0:
            raise ValueError("Division by zero is not allowed.")
        return float(num1 / num2)
    elif operator == '%':
        if num2 == 0:
            raise ValueError("Modulo by zero is not allowed.")
        return float(num1 % num2)
    elif operator == '**':
        try:
            return float(num1 ** num2)
        except OverflowError:
            raise ValueError("Result of exponentiation is too large.")
    else:
        raise ValueError(f"Unsupported operator: '{operator}'")

