from typing import List, Dict, Any

def load_memos(file_path: str) -> List[Dict[str, Any]]:
    """
    Reads raw memo data from the local JSON file.
    Returns a list of dictionaries with structure: {'id': int, 'title': str, 'content': str}.
    """
    if not os.path.exists(file_path):
        return []

    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            data = json.load(f)
            if not isinstance(data, list):
                return []

            memos = []
            for item in data:
                if isinstance(item, dict) and 'id' in item and 'title' in item and 'content' in item:
                    memos.append({
                        'id': int(item['id']),
                        'title': str(item['title']),
                        'content': str(item['content'])
                    })
            return memos
    except (json.JSONDecodeError, IOError, ValueError, TypeError):
        return []

def save_memos(file_path: str, memos: List[Dict[str, Any]]) -> bool:
    """
    Writes raw memo data to the local JSON file.
    Returns True if successfully saved, False otherwise.
    """
    try:
        dir_name = os.path.dirname(file_path)
        if dir_name and not os.path.exists(dir_name):
            os.makedirs(dir_name, exist_ok=True)

        formatted_memos = []
        for memo in memos:
            formatted_memos.append({
                'id': int(memo['id']),
                'title': str(memo['title']),
                'content': str(memo['content'])
            })

        with open(file_path, 'w', encoding='utf-8') as f:
            json.dump(formatted_memos, f, indent=4, ensure_ascii=False)
        return True
    except (IOError, TypeError, KeyError, ValueError):
        return False

