            if not isinstance(data, dict):
                return {}

            # Ensure proper structure and type casting
            sanitized: Dict[str, Dict[str, Union[str, int]]] = {}
            for key, val in data.items():
                if isinstance(val, dict) and "name" in val and "quantity" in val:
                    sanitized[str(key)] = {
                        "name": str(val["name"]),
                        "quantity": int(val["quantity"])
                    }
            return sanitized
    except (json.JSONDecodeError, IOError, ValueError, TypeError):
        return {}

def save_data(file_path: str, data: Dict[str, Dict[str, Union[str, int]]]) -> bool:
    """
    Writes the structured dictionary to a JSON file.
    Returns True if successful, False otherwise.
    """
    try:
        # Create directory if it doesn't exist
        dir_name = os.path.dirname(file_path)
        if dir_name and not os.path.exists(dir_name):
            os.makedirs(dir_name, exist_ok=True)

        with open(file_path, "w", encoding="utf-8") as f:
            json.dump(data, f, indent=4)
        return True
    except (IOError, TypeError):
        return False

