        return False
    data = load_data(file_path)
    if data is None:
        data = {}
    if item_id in data:
        data[item_id]["quantity"] = data[item_id].get("quantity", 0) + quantity
        data[item_id]["name"] = name
    else:
        data[item_id] = {"name": name, "quantity": quantity}
    return save_data(file_path, data)

def release_stock(file_path: str, item_id: str, quantity: int) -> bool:
    if quantity < 0:
        return False
    data = load_data(file_path)
    if not data or item_id not in data:
        return False
    current_quantity = data[item_id].get("quantity", 0)
    if current_quantity < quantity:
        return False
    data[item_id]["quantity"] = current_quantity - quantity
    return save_data(file_path, data)

def get_stock_quantity(file_path: str, item_id: str) -> int:
