def earn_points(member_id: str, purchase_amount: int) -> Dict[str, int]:
    """
    Earns points for a member based on the purchase amount.
    Points earned are calculated on a 1-to-1 ratio with the purchase amount.
    """
    earned = max(0, purchase_amount)
    current_balance = get_points(member_id)
    new_balance = current_balance + earned
    set_points(member_id, new_balance)
    return {"earned": earned, "balance": new_balance}

def pay_with_points(member_id: str, amount_to_pay: int) -> Dict[str, Any]:
    """
    Attempts to pay a specific amount using the member's accumulated points.
    Returns success status, the amount paid, and the remaining balance.
    """
    current_balance = get_points(member_id)
    if amount_to_pay < 0:
        return {"success": False, "paid": 0, "balance": current_balance}

    if current_balance >= amount_to_pay:
        new_balance = current_balance - amount_to_pay
        set_points(member_id, new_balance)
        return {"success": True, "paid": amount_to_pay, "balance": new_balance}
    else:
        return {"success": False, "paid": 0, "balance": current_balance}

def get_balance(member_id: str) -> int:
    """
    Retrieves the current point balance for a member.
    """
    return get_points(member_id)

