def calculate_discount(coupon_code: str, amount: float) -> float:
    if not coupon_code or amount <= 0:
        return 0.0

    code = coupon_code.strip().upper()
    discount = 0.0

    if code == "SAVE10":
        discount = amount * 0.10
    elif code == "SAVE20":
        discount = amount * 0.20
    elif code == "SAVE50":
        discount = amount * 0.50
    elif code == "FLAT5":
        discount = 5.00
    elif code == "FLAT10":
        discount = 10.00
    elif code == "FLAT20":
        discount = 20.00
    elif code == "FREE":
        discount = amount
    else:
        discount = 0.0

    # Discount cannot exceed the actual amount
    if discount > amount:
        discount = amount

    return float(round(discount, 2))

