from inventory import check_stock, get_price
from coupon import calculate_discount

def calculate_total(cart_items: dict[str, int], coupon_code: str) -> float:
    subtotal = 0.0
    for product_id, quantity in cart_items.items():
        if quantity > 0 and check_stock(product_id, quantity):
            price = get_price(product_id)
            subtotal += price * quantity

    discount = calculate_discount(coupon_code, subtotal)
    total = subtotal - discount
    return max(0.0, total)

def calculate(a: float, b: float, operator: str) -> float:
    """
    Performs basic arithmetic calculations and handles division by zero.

    Supported operators: '+', '-', '*', '/'
    """
    if operator == '+':
        return float(a + b)
    elif operator == '-':
        return float(a - b)
    elif operator == '*':
        return float(a * b)
    elif operator == '/':
        if b == 0.0:
            raise ZeroDivisionError("Division by zero is not allowed.")
        return float(a / b)
    else:
        raise ValueError(f"Unsupported operator: {operator}")

