def add_memo(title: str, content: str) -> Dict[str, Union[int, str]]:
    memos = load_data(DATA_FILE)
    if not isinstance(memos, list):
        memos = []

    new_id = 1
    if memos:
        ids = [memo.get('id') for memo in memos if isinstance(memo.get('id'), int)]
        if ids:
            new_id = max(ids) + 1

    new_memo = {
        "id": new_id,
        "title": title,
        "content": content
    }
    memos.append(new_memo)
    save_data(DATA_FILE, memos)
    return new_memo

def list_memos() -> List[Dict[str, Union[int, str]]]:
    memos = load_data(DATA_FILE)
    if not isinstance(memos, list):
        return []
    return memos

def update_memo(memo_id: int, title: str, content: str) -> bool:
    memos = load_data(DATA_FILE)
    if not isinstance(memos, list):
        return False

    found = False
    for memo in memos:
        if memo.get('id') == memo_id:
            memo['title'] = title
            memo['content'] = content
            found = True
            break

    if found:
        return save_data(DATA_FILE, memos)
    return False

def delete_memo(memo_id: int) -> bool:
    memos = load_data(DATA_FILE)
    if not isinstance(memos, list):
        return False

    initial_length = len(memos)
    memos = [memo for memo in memos if memo.get('id') != memo_id]

    if len(memos) < initial_length:
        return save_data(DATA_FILE, memos)
    return False

