COUPONS = {
    "SAVE10": {"type": "percentage", "value": 0.10},
    "SAVE20": {"type": "percentage", "value": 0.20},
    "FLAT5": {"type": "flat", "value": 5.00},
    "FLAT10": {"type": "flat", "value": 10.00},
}

def validate_coupon(coupon_code: str) -> bool:
    """
    Validates if a coupon code exists in the system.
    Coupon codes are case-insensitive.
    """
    if not isinstance(coupon_code, str):
        return False
    return coupon_code.upper() in COUPONS

def calculate_discount(coupon_code: str, total_amount: float) -> float:
    """
    Calculates the discount amount based on the coupon code and the total amount.
    Returns the discount amount (float). If the coupon is invalid or total_amount <= 0, returns 0.0.
    The discount will not exceed the total amount.
    """
    if not validate_coupon(coupon_code):
        return 0.0

    if total_amount <= 0.0:
        return 0.0

    coupon = COUPONS[coupon_code.upper()]
    discount = 0.0

    if coupon["type"] == "percentage":
        discount = total_amount * coupon["value"]
    elif coupon["type"] == "flat":
        discount = coupon["value"]

    # Ensure the discount is positive and does not exceed the total amount
    discount = max(0.0, min(discount, total_amount))
    return round(discount, 2)

