from datetime import datetime

def parse_time(dt_str: str) -> datetime:
    dt_str = dt_str.strip()
    for fmt in ("%Y-%m-%d %H:%M:%S", "%Y-%m-%d %H:%M", "%Y-%m-%dT%H:%M:%S", "%Y-%m-%dT%H:%M"):
        try:
            return datetime.strptime(dt_str, fmt)
        except ValueError:
            continue
    return datetime.fromisoformat(dt_str)

def format_time(dt: datetime, reference_str: str) -> str:
    sep = "T" if "T" in reference_str else " "
    has_seconds = len(reference_str.split(':')) == 3
    if has_seconds:
        return dt.strftime(f"%Y-%m-%d{sep}%H:%M:%S")
    else:
        return dt.strftime(f"%Y-%m-%d{sep}%H:%M")

def is_overlapping(existing_schedules: list[dict], new_start: str, new_end: str) -> bool:
    try:
        ns = parse_time(new_start)
        ne = parse_time(new_end)
    except ValueError:
        return True  # Invalid formats treated as overlapping/invalid

    if ns >= ne:
        return True

    for sched in existing_schedules:
        try:
            es = parse_time(sched['start'])
            ee = parse_time(sched['end'])
        except ValueError:
            continue

        if max(ns, es) < min(ne, ee):
            return True

    return False

def add_schedule(existing_schedules: list[dict], title: str, start: str, end: str) -> tuple[bool, list[dict]]:
    try:
        ns = parse_time(start)
        ne = parse_time(end)
    except ValueError:
        return False, list(existing_schedules)

    if ns >= ne:
        return False, list(existing_schedules)

    if is_overlapping(existing_schedules, start, end):
        return False, list(existing_schedules)

    new_sched = {
        'title': title,
        'start': start,
        'end': end
    }
    return True, list(existing_schedules) + [new_sched]

def get_free_slots(existing_schedules: list[dict], limit_start: str, limit_end: str) -> list[dict]:
    try:
        l_start = parse_time(limit_start)
        l_end = parse_time(limit_end)
    except ValueError:
        return []

    if l_start >= l_end:
        return []

    intervals = []
    for sched in existing_schedules:
        try:
            s = parse_time(sched['start'])
            e = parse_time(sched['end'])
        except ValueError:
            continue

        if s >= e:
            continue

        clip_s = max(s, l_start)
        clip_e = min(e, l_end)
        if clip_s < clip_e:
            intervals.append((clip_s, clip_e))

    intervals.sort(key=lambda x: x[0])

    merged = []
    for s, e in intervals:
        if not merged:
            merged.append([s, e])
        else:
            last_s, last_e = merged[-1]
            if s <= last_e:
                merged[-1][1] = max(last_e, e)
            else:
                merged.append([s, e])

    free_slots = []
    curr = l_start
    for s, e in merged:
        if s > curr:
            free_slots.append({
                'start': format_time(curr, limit_start),
                'end': format_time(s, limit_start)
            })
        curr = max(curr, e)

    if curr < l_end:
        free_slots.append({
            'start': format_time(curr, limit_start),
            'end': format_time(l_end, limit_end)
        })

    return free_slots

