import json

def parse_fsm_definition(json_data: str) -> dict[str, list[dict[str, str]]]:
    """
    Loads and validates the FSM configurations from a JSON string.

    The JSON structure is expected to be a dictionary where keys are categories
    (such as 'transitions' or 'states') and values are lists of dictionaries 
    representing the configurations (where both keys and values are strings).

    Example:
    {
        "transitions": [
            {"from": "locked", "trigger": "coin", "to": "unlocked"},
            {"from": "unlocked", "trigger": "push", "to": "locked"}
        ]
    }
    """
    if not isinstance(json_data, str):
        raise ValueError("Input must be a JSON string.")

    try:
        data = json.loads(json_data)
    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON data: {e}")

    if not isinstance(data, dict):
        raise ValueError("FSM definition must be a JSON object (dictionary) at the top level.")

    parsed_config: dict[str, list[dict[str, str]]] = {}

    for category, items in data.items():
        if not isinstance(category, str):
            raise ValueError("All top-level keys in the FSM definition must be strings.")

        if not isinstance(items, list):
            raise ValueError(f"The value for '{category}' must be a list of dictionaries.")

        category_list: list[dict[str, str]] = []
        for item in items:
            if not isinstance(item, dict):
                raise ValueError(f"Items in the list under '{category}' must be dictionaries.")

            validated_item: dict[str, str] = {}
            for key, val in item.items():
                if not isinstance(key, str):
                    raise ValueError(f"Keys in the dictionary under '{category}' must be strings.")
                if not isinstance(val, str):
                    raise ValueError(f"Values in the dictionary under '{category}' must be strings. Found type: {type(val).__name__}")
                validated_item[key] = val

            category_list.append(validated_item)

        parsed_config[category] = category_list

    return parsed_config

