def process_transition(fsm_def: dict[str, list[dict[str, str]]], current_state: str, event: str) -> dict[str, str]:
    # 1. Try treating keys of fsm_def as source states
    transitions = fsm_def.get(current_state, [])
    for trans in transitions:
        if trans.get("event") == event:
            next_state = trans.get("next_state") or trans.get("target") or trans.get("to") or trans.get("dest")
            if next_state:
                return {
                    "status": "success",
                    "current_state": current_state,
                    "event": event,
                    "next_state": next_state
                }

    # 2. Try looking for transitions list inside fsm_def if keys are not state names (e.g. {"transitions": [...]})
    for key, trans_list in fsm_def.items():
        for trans in trans_list:
            source_matches = (
                trans.get("from") == current_state or 
                trans.get("from_state") == current_state or 
                trans.get("source") == current_state or
                trans.get("current_state") == current_state
            )
            if source_matches and trans.get("event") == event:
                next_state = trans.get("next_state") or trans.get("target") or trans.get("to") or trans.get("dest")
                if next_state:
                    return {
                        "status": "success",
                        "current_state": current_state,
                        "event": event,
                        "next_state": next_state
                    }

    # 3. Default failure case if transition is not found
    return {
        "status": "error",
        "current_state": current_state,
        "event": event,
        "next_state": current_state,
        "message": f"Transition not found for event '{event}' in state '{current_state}'"
    }

