def multiply_matrices(mat_a: list[list[float]], mat_b: list[list[float]]) -> list[list[float]]:
    """Multiplies two 4x4 matrices and returns the result."""
    result = [[0.0] * 4 for _ in range(4)]
    for i in range(4):
        for j in range(4):
            result[i][j] = (
                mat_a[i][0] * mat_b[0][j] +
                mat_a[i][1] * mat_b[1][j] +
                mat_a[i][2] * mat_b[2][j] +
                mat_a[i][3] * mat_b[3][j]
            )
    return result

def apply_matrix_to_point(mat: list[list[float]], point: list[float]) -> list[float]:
    """Applies a 4x4 matrix to a 3D point using homogeneous coordinates."""
    # Convert 3D point to homogeneous 4D coordinates [x, y, z, 1.0]
    if len(point) == 3:
        x, y, z = point
        w_in = 1.0
    elif len(point) == 4:
        x, y, z, w_in = point
    else:
        raise ValueError("Point must have 3 or 4 coordinates.")

    # Perform matrix-vector multiplication
    rx = mat[0][0] * x + mat[0][1] * y + mat[0][2] * z + mat[0][3] * w_in
    ry = mat[1][0] * x + mat[1][1] * y + mat[1][2] * z + mat[1][3] * w_in
    rz = mat[2][0] * x + mat[2][1] * y + mat[2][2] * z + mat[2][3] * w_in
    rw = mat[3][0] * x + mat[3][1] * y + mat[3][2] * z + mat[3][3] * w_in

    # Perspective divide to project back into 3D
    if abs(rw) > 1e-9:
        return [rx / rw, ry / rw, rz / rw]
    else:
        return [rx, ry, rz]

