import math

def add(v1: tuple[float, float], v2: tuple[float, float]) -> tuple[float, float]:
    """Adds two 2D vectors."""
    return (v1[0] + v2[0], v1[1] + v2[1])

def sub(v1: tuple[float, float], v2: tuple[float, float]) -> tuple[float, float]:
    """Subtracts the second 2D vector from the first."""
    return (v1[0] - v2[0], v1[1] - v2[1])

def dot(v1: tuple[float, float], v2: tuple[float, float]) -> float:
    """Calculates the dot product of two 2D vectors."""
    return v1[0] * v2[0] + v1[1] * v2[1]

def mult(v: tuple[float, float], s: float) -> tuple[float, float]:
    """Multiplies a 2D vector by a scalar."""
    return (v[0] * s, v[1] * s)

def mag(v: tuple[float, float]) -> float:
    """Calculates the magnitude of a 2D vector."""
    return math.sqrt(v[0] ** 2 + v[1] ** 2)

def normalize(v: tuple[float, float]) -> tuple[float, float]:
    """Normalizes a 2D vector. Returns (0.0, 0.0) if magnitude is 0."""
    m = mag(v)
    if m == 0.0:
        return (0.0, 0.0)
    return (v[0] / m, v[1] / m)

