    resolved_bodies = [body.copy() for body in bodies]
    n = len(resolved_bodies)

    for _ in range(iterations):
        for i in range(n):
            for j in range(i + 1, n):
                if check_collision(resolved_bodies[i], resolved_bodies[j]):
                    b1_resolved, b2_resolved = resolve_collision_pair(resolved_bodies[i], resolved_bodies[j])
