import re

def parse_time(time_str: str) -> dict:
    """
    Parses a time string in 'HH:MM:SS' or 'HH:MM' format and validates the values.
    Returns a dictionary: {'hour': int, 'minute': int, 'second': int}
    Raises ValueError if the format is invalid or values are out of range.
    """
    if not isinstance(time_str, str):
        raise ValueError("Time input must be a string")

    # Matches HH:MM or HH:MM:SS with optional leading/trailing whitespace
    pattern = re.compile(r'^\s*(\d{1,2}):(\d{1,2})(?::(\d{1,2}))?\s*$')
    match = pattern.match(time_str)

    if not match:
        raise ValueError(f"Time '{time_str}' does not match expected format 'HH:MM' or 'HH:MM:SS'")

    h_str, m_str, s_str = match.groups()

    hour = int(h_str)
    minute = int(m_str)
    second = int(s_str) if s_str is not None else 0

    if not (0 <= hour <= 23):
        raise ValueError(f"Hour {hour} is out of range [0-23]")
    if not (0 <= minute <= 59):
        raise ValueError(f"Minute {minute} is out of range [0-59]")
    if not (0 <= second <= 59):
        raise ValueError(f"Second {second} is out of range [0-59]")

    return {
        "hour": hour,
        "minute": minute,
        "second": second
    }

