import os

def load_vectors(filepath: str) -> list[dict]:
    """
    Loads a list of 2D vectors from a JSON file.

    If the file does not exist, returns an empty list.
    Each vector in the returned list is guaranteed to have 'x' and 'y' keys with float values.
    """
    if not os.path.exists(filepath):
        return []

    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            data = json.load(f)
            if not isinstance(data, list):
                return []

            vectors = []
            for item in data:
                if isinstance(item, dict) and "x" in item and "y" in item:
                    try:
                        vectors.append({
                            "x": float(item["x"]),
                            "y": float(item["y"])
                        })
                    except (ValueError, TypeError):
                        continue
            return vectors
    except (json.JSONDecodeError, IOError):
        return []

def save_vectors(filepath: str, vectors: list[dict]) -> None:
    """
    Saves a list of 2D vectors to a JSON file.

    Creates any missing directories in the filepath.
    """
    dir_name = os.path.dirname(filepath)
    if dir_name and not os.path.exists(dir_name):
        os.makedirs(dir_name, exist_ok=True)

    formatted_vectors = []
    for v in vectors:
        if isinstance(v, dict) and "x" in v and "y" in v:
            try:
                formatted_vectors.append({
                    "x": float(v["x"]),
                    "y": float(v["y"])
                })
            except (ValueError, TypeError):
                continue

    with open(filepath, 'w', encoding='utf-8') as f:
        json.dump(formatted_vectors, f, indent=4)

