import json
import os
from typing import Any, Dict


def save_to_file(canvas: Dict[str, Any], filepath: str) -> bool:
    """Saves the canvas state to a JSON file.

    Args:
        canvas (dict): A dictionary structured as {"shapes": list[dict]}.
        filepath (str): The destination file path.

    Returns:
        bool: True if save succeeded, False otherwise.
    """
    try:
        # Ensure directory exists if path contains directories
        directory = os.path.dirname(filepath)
        if directory and not os.path.exists(directory):
            os.makedirs(directory, exist_ok=True)

        with open(filepath, "w", encoding="utf-8") as f:
            json.dump(canvas, f, indent=4)
        return True
    except (IOError, TypeError, ValueError):
        return False


def load_from_file(filepath: str) -> Dict[str, Any]:
    """Loads the canvas state from a JSON file.

    Args:
        filepath (str): The source file path.

    Returns:
        dict: A dictionary structured as {"shapes": list[dict]}.
              Returns {"shapes": []} if loading fails or file does not exist.
    """
    try:
        if not os.path.exists(filepath):
            return {"shapes": []}

        with open(filepath, "r", encoding="utf-8") as f:
            data = json.load(f)

        if isinstance(data, dict) and "shapes" in data and isinstance(data["shapes"], list):
            return data
        return {"shapes": []}
    except (IOError, json.JSONDecodeError):
        return {"shapes": []}

