def apply_forces(particles: list[dict], forces: list[list[float]], dt: float) -> list[dict]:
    for i, p in enumerate(particles):
        if i >= len(forces):
            break
        mass = p.get("mass", 1.0)
        if mass <= 0:
            mass = 1.0
        vel = p.get("velocity", [])
        force = forces[i]
        p["velocity"] = [v + (f / mass) * dt for v, f in zip(vel, force)]
    return particles

def update_positions(particles: list[dict], dt: float) -> list[dict]:
    for p in particles:
        pos = p.get("position", [])
        vel = p.get("velocity", [])
        p["position"] = [x + v * dt for x, v in zip(pos, vel)]
    return particles

def handle_collisions(particles: list[dict], boundaries: dict) -> list[dict]:
    b_min = boundaries.get("min", [])
    b_max = boundaries.get("max", [])
    for p in particles:
        pos = p.get("position", [])
        vel = p.get("velocity", [])
        for d in range(min(len(pos), len(b_min), len(b_max))):
            if pos[d] < b_min[d]:
                pos[d] = b_min[d]
                if vel[d] < 0:
                    vel[d] = -vel[d]
            elif pos[d] > b_max[d]:
                pos[d] = b_max[d]
                if vel[d] > 0:
                    vel[d] = -vel[d]
    return particles

