import json

def parse_fsm_definition(config_json: str) -> dict[str, list[dict[str, str]]]:
    """
    Parses a JSON string representing the FSM definition.
    Validates that it conforms to the dict[str, list[dict[str, str]]] structure.
    """
    try:
        data = json.loads(config_json)
    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON format: {e}")

    if not isinstance(data, dict):
        raise ValueError("FSM configuration must be a JSON object (dictionary).")

    validated: dict[str, list[dict[str, str]]] = {}

    for key, val in data.items():
        if not isinstance(key, str):
            raise ValueError("FSM configuration keys must be strings.")
        if not isinstance(val, list):
            raise ValueError(f"Value for key '{key}' must be a list of transition objects.")

        transition_list = []
        for item in val:
            if not isinstance(item, dict):
                raise ValueError(f"Items in the list under '{key}' must be dictionaries representing transitions.")

            str_dict = {}
            for item_key, item_val in item.items():
                if not isinstance(item_key, str) or not isinstance(item_val, str):
                    raise ValueError(f"All keys and values in transition definitions must be strings.")
                str_dict[item_key] = item_val
            transition_list.append(str_dict)

        validated[key] = transition_list

    return validated


def parse_events(events_json: str) -> list[str]:
    """
    Parses a JSON string representing an event sequence.
    Can be a direct JSON list of strings, or a JSON object containing an "events" key with a list of strings.
    """
    try:
        data = json.loads(events_json)
    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON format: {e}")

    # Support both raw list structure and wrapped object structure
    if isinstance(data, dict) and "events" in data:
        data = data["events"]

    if not isinstance(data, list):
        raise ValueError("Event input must be a JSON list of strings or an object containing an 'events' list.")

    for item in data:
        if not isinstance(item, str):
            raise ValueError("All events in the sequence must be strings.")

    return data

