class Node:
    def __init__(self, key: int):
        self.key: int = key
        self.left: Node | None = None
        self.right: Node | None = None


class BST:
    def __init__(self):
        self.root: Node | None = None


def create_tree() -> BST:
    return BST()


def insert(tree: BST, key: int) -> None:
    def _insert(node: Node | None, val: int) -> Node:
        if node is None:
            return Node(val)
        if val < node.key:
            node.left = _insert(node.left, val)
        elif val > node.key:
            node.right = _insert(node.right, val)
        return node

    tree.root = _insert(tree.root, key)


def find(tree: BST, key: int) -> bool:
    curr = tree.root
    while curr is not None:
        if key == curr.key:
            return True
        elif key < curr.key:
            curr = curr.left
        else:
            curr = curr.right
    return False


def delete(tree: BST, key: int) -> None:
    def _min_value_node(node: Node) -> Node:
        current = node
        while current.left is not None:
            current = current.left
        return current

    def _delete(node: Node | None, val: int) -> Node | None:
        if node is None:
            return None

        if val < node.key:
            node.left = _delete(node.left, val)
        elif val > node.key:
            node.right = _delete(node.right, val)
        else:
            if node.left is None:
                return node.right
            elif node.right is None:
                return node.left

            temp = _min_value_node(node.right)
            node.key = temp.key
            node.right = _delete(node.right, temp.key)

        return node

    tree.root = _delete(tree.root, key)


def inorder(tree: BST) -> list[int]:
    result: list[int] = []

    def _inorder(node: Node | None) -> None:
        if node is not None:
            _inorder(node.left)
            result.append(node.key)
            _inorder(node.right)

    _inorder(tree.root)
    return result

