def is_balanced(text: str) -> bool:
    """
    Verifies if the brackets in a string are balanced using stack operations.
    Supports (), [], and {}.

    Args:
        text (str): The input string to validate.

    Returns:
        bool: True if brackets are balanced, False otherwise.
    """
    stack = []
    brackets_map = {")": "(", "]": "[", "}": "{"}

    for char in text:
        if char in brackets_map.values():
            stack.append(char)
        elif char in brackets_map:
            if not stack or stack[-1] != brackets_map[char]:
                return False
            stack.pop()

    return len(stack) == 0

