        graph[vertex] = []
    return graph

def delete_vertex(graph: dict[str, list[str]], vertex: str) -> dict[str, list[str]]:
    if vertex in graph:
        del graph[vertex]
    for source in graph:
        if vertex in graph[source]:
            graph[source] = [v for v in graph[source] if v != vertex]
    return graph

