def add_edge(graph: dict[str, list[str]], source: str, target: str) -> dict[str, list[str]]:
    if source not in graph:
        graph[source] = []
    if target not in graph:
        graph[target] = []
    if target not in graph[source]:
        graph[source].append(target)
    return graph

def delete_edge(graph: dict[str, list[str]], source: str, target: str) -> dict[str, list[str]]:
    if source in graph and target in graph[source]:
        graph[source] = [v for v in graph[source] if v != target]
    return graph

def list_edges(graph: dict[str, list[str]]) -> list[tuple[str, str]]:
    edges = []
    for source, targets in graph.items():
        for target in targets:
            edges.append((source, target))
    return edges

