from typing import Dict, List

STORAGE_FILE = "tags_data.json"

def load_data() -> Dict[str, List[str]]:
    """
    Loads the tag hierarchy data from a local JSON file.
    If the file does not exist or is invalid, returns an empty dictionary.
    """
    if not os.path.exists(STORAGE_FILE):
        return {}
    try:
        with open(STORAGE_FILE, "r", encoding="utf-8") as f:
            data = json.load(f)
            if isinstance(data, dict):
                # Ensure structure matches dict[str, list[str]]
                validated_data: Dict[str, List[str]] = {}
                for k, v in data.items():
                    if isinstance(v, list):
                        validated_data[str(k)] = [str(item) for item in v]
                    else:
                        validated_data[str(k)] = []
                return validated_data
            return {}
    except (json.JSONDecodeError, IOError):
        return {}

def save_data(data: Dict[str, List[str]]) -> bool:
    """
    Saves the tag hierarchy data to a local JSON file.
    Returns True if saving was successful, False otherwise.
    """
    try:
        with open(STORAGE_FILE, "w", encoding="utf-8") as f:
            json.dump(data, f, indent=4, ensure_ascii=False)
        return True
    except IOError:
        return False

