from storage import load_data, save_data

def _has_path(data: dict[str, list[str]], start: str, target: str) -> bool:
    """Helper function to check if there is a path from start to target in the hierarchy."""
    if start == target:
        return True
    queue = list(data.get(start, []))
    visited = set(queue)
    idx = 0
    while idx < len(queue):
        curr = queue[idx]
        idx += 1
        if curr == target:
            return True
        for child in data.get(curr, []):
            if child not in visited:
                visited.add(child)
                queue.append(child)
    return False

def add_tag(tag_name: str, parent_name: str | None) -> bool:
    if not tag_name:
        return False

    data = load_data()

    # Collect all existing tags to validate parent presence
    all_tags = set(data.keys())
    for children in data.values():
        all_tags.update(children)

    if parent_name is not None:
        # Parent must exist in the system
        if parent_name not in all_tags:
            return False
        # Prevent self-loop and cyclic relationship
        if tag_name == parent_name or _has_path(data, tag_name, parent_name):
            return False

        # Add relation if not already present
        if tag_name not in data.get(parent_name, []):
            data.setdefault(parent_name, []).append(tag_name)

    # Ensure the tag itself exists as a key in the database
    if tag_name not in data:
        data[tag_name] = []

    return save_data(data)

def delete_tag(tag_name: str) -> bool:
    if not tag_name:
        return False

    data = load_data()

    # Check if the tag exists
    all_tags = set(data.keys())
    for children in data.values():
        all_tags.update(children)

    if tag_name not in all_tags:
        return False

    # Find all descendants to cascade delete
    descendants = get_all_descendants(tag_name)
    to_delete = {tag_name} | set(descendants)

    # Remove from keys
    for t in to_delete:
        if t in data:
            del data[t]

    # Remove from children lists of remaining tags
    for parent in list(data.keys()):
        data[parent] = [child for child in data[parent] if child not in to_delete]

    return save_data(data)

def get_hierarchy() -> dict[str, list[str]]:
    return load_data()

def get_all_descendants(tag_name: str) -> list[str]:
    data = load_data()

    # Check if tag exists at all
    all_tags = set(data.keys())
    for children in data.values():
        all_tags.update(children)

    if tag_name not in all_tags:
        return []

    descendants = []
    queue = list(data.get(tag_name, []))
    visited = set(queue)
    idx = 0
    while idx < len(queue):
        curr = queue[idx]
        idx += 1
        descendants.append(curr)
        for child in data.get(curr, []):
            if child not in visited:
                visited.add(child)
                queue.append(child)

    return descendants

