class Parser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def peek(self):
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self, expected_type=None):
        token = self.peek()
        if token is None:
            raise SyntaxError("Unexpected end of input")
        if expected_type and token['type'] != expected_type:
            raise SyntaxError(f"Expected {expected_type}, got {token['type']}")
        self.pos += 1
        return token

    def parse_expression(self, precedence=0):
        token = self.peek()
        if token is None:
            raise SyntaxError("Unexpected end of expression")

        if token['type'] == 'NUMBER':
            self.consume()
            val_str = token['value']
            if '.' in val_str:
                val = float(val_str)
            else:
                try:
                    val = int(val_str)
                except ValueError:
                    val = float(val_str)
            left = {'type': 'Number', 'value': val}
        elif token['type'] == 'VARIABLE':
            self.consume()
            left = {'type': 'Variable', 'value': token['value']}
        elif token['type'] == 'LPAREN':
            self.consume()
            left = self.parse_expression(0)
            self.consume('RPAREN')
        elif token['type'] == 'OPERATOR' and token['value'] in ('+', '-'):
            op_token = self.consume()
            operand = self.parse_expression(5)
            left = {'type': 'UnaryOp', 'op': op_token['value'], 'operand': operand}
        else:
            raise SyntaxError(f"Unexpected token: {token}")

        while True:
            next_token = self.peek()
            if next_token is None or next_token['type'] != 'OPERATOR':
                break

            op = next_token['value']
            op_prec = self.get_precedence(op)
            if op_prec < precedence:
                break

            is_right = (op == '^')
            if op_prec > precedence or (op_prec == precedence and is_right):
                self.consume()
                right = self.parse_expression(op_prec)
                left = {'type': 'BinaryOp', 'op': op, 'left': left, 'right': right}
            else:
                break

        return left

    def get_precedence(self, op):
        if op in ('+', '-'):
            return 2
        if op in ('*', '/'):
            return 3
        if op == '^':
            return 4
        return 0


def parse(tokens: list[dict]) -> dict:
    if not tokens:
        return {}
    parser = Parser(tokens)
    result = parser.parse_expression()
    if parser.pos < len(tokens):
        raise SyntaxError("Unexpected tokens at end of expression")
    return result

