import math

def evaluate(ast: dict) -> float:
    """
    Recursively evaluates an Abstract Syntax Tree (AST) dictionary and returns the numerical result.

    Supports:
    - Numbers: {'type': 'number', 'value': float}
    - Binary Ops: {'type': 'binary', 'op': str, 'left': dict, 'right': dict}
    - Unary Ops: {'type': 'unary', 'op': str, 'operand': dict}
    - Functions: {'type': 'function', 'name': str, 'args': list[dict]}
    """
    if not isinstance(ast, dict):
        if isinstance(ast, (int, float)):
            return float(ast)
        raise ValueError(f"Invalid AST node format: {ast}")

    # Standardize node type checking (case-insensitive)
    node_type = ast.get("type", "").lower()

    # Number / Literal node
    if node_type in ("number", "literal", "num") or "value" in ast and len(ast) == 1:
        if "value" in ast:
            return float(ast["value"])
        raise ValueError(f"Malformed number node: {ast}")

    # Binary Operation
    elif node_type in ("binary", "binop") or ("left" in ast and "right" in ast):
        op = ast.get("op") or ast.get("operator")
        if not op:
            raise ValueError(f"Missing operator in binary node: {ast}")

        left_val = evaluate(ast["left"])
        right_val = evaluate(ast["right"])

        if op == "+":
            return left_val + right_val
        elif op == "-":
            return left_val - right_val
        elif op == "*":
            return left_val * right_val
        elif op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        elif op in ("^", "**"):
            try:
                return left_val ** right_val
            except OverflowError:
                return float('inf') if left_val > 0 else float('-inf')
        else:
            raise ValueError(f"Unsupported binary operator: '{op}'")

    # Unary Operation
    elif node_type in ("unary", "unaryop") or ("operand" in ast or ("right" in ast and "left" not in ast)):
        op = ast.get("op") or ast.get("operator")
        if not op:
            raise ValueError(f"Missing operator in unary node: {ast}")

        operand_key = "operand" if "operand" in ast else "right"
        val = evaluate(ast[operand_key])

        if op == "+":
            return +val
        elif op == "-":
            return -val
        else:
            raise ValueError(f"Unsupported unary operator: '{op}'")

    # Function Call
    elif node_type in ("function", "func", "call") or "name" in ast:
        func_name = ast.get("name", "").lower()
        args = ast.get("args") or ast.get("arguments")

        if args is None and "expr" in ast:
            args = [ast["expr"]]
        elif args is None:
            raise ValueError(f"Missing arguments for function: {func_name}")

        arg_values = [evaluate(arg) for arg in args]

        if not arg_values:
            raise ValueError(f"Function '{func_name}' requires at least one argument")

        if func_name == "sin":
            return math.sin(arg_values[0])
        elif func_name == "cos":
            return math.cos(arg_values[0])
        elif func_name == "tan":
            return math.tan(arg_values[0])
        elif func_name == "sqrt":
            if arg_values[0] < 0:
                raise ValueError("Cannot calculate square root of a negative number")
            return math.sqrt(arg_values[0])
        elif func_name == "abs":
            return abs(arg_values[0])
        elif func_name == "log":
            if arg_values[0] <= 0:
                raise ValueError("Logarithm domain error (must be positive)")
            if len(arg_values) > 1:
                return math.log(arg_values[0], arg_values[1])
            return math.log(arg_values[0])
        elif func_name == "exp":
            return math.exp(arg_values[0])
        else:
            raise ValueError(f"Unknown function: '{func_name}'")

    # Parentheses grouping fallback
    elif node_type in ("group", "parentheses", "paren"):
        expr_key = "expr" if "expr" in ast else "expression"
        return evaluate(ast[expr_key])

    else:
        # Final fallback to handle raw dictionaries missing explicit 'type' but having 'value'
        if "value" in ast:
            return float(ast["value"])
        raise ValueError(f"Unable to parse or evaluate AST node: {ast}")

