import re

def tokenize(code: str) -> list[str]:
    # Matches:
    # 1. Double quoted strings: "..." (including escaped characters)
    # 2. Semicolon comments: ; ...
    # 3. Parentheses: ( or )
    # 4. Symbols/Numbers/Operators: non-whitespace, non-paren characters
    pattern = re.compile(r'("(?:[^"\\]|\\.)*")|(;.*)|([()])|([^\s()]+)')
    tokens = []
    for match in pattern.finditer(code):
        string_literal, comment, paren, symbol = match.groups()
        if comment is not None:
            continue
        elif string_literal is not None:
            tokens.append(string_literal)
        elif paren is not None:
            tokens.append(paren)
        elif symbol is not None:
            tokens.append(symbol)
    return tokens

