def parse(tokens: list[str]) -> list | str | int | float:
    if not tokens:
        return []

    def atom(token: str) -> str | int | float:
        try:
            return int(token)
        except ValueError:
            pass
        try:
            return float(token)
        except ValueError:
            pass
        if len(token) >= 2 and (
            (token.startswith('"') and token.endswith('"')) or
            (token.startswith("'") and token.endswith("'"))
        ):
            return token[1:-1]
        return token

    index = 0
    n = len(tokens)

    def parse_expr() -> list | str | int | float:
        nonlocal index
        if index >= n:
            raise ValueError("Unexpected EOF")

        token = tokens[index]
        index += 1

        if token == '(':
            lst = []
            while index < n and tokens[index] != ')':
                lst.append(parse_expr())
            if index >= n:
                raise ValueError("Expected ')' but reached EOF")
            index += 1  # Skip the closing ')'
            return lst
        elif token == ')':
            raise ValueError("Unexpected ')'")
        else:
            return atom(token)

    expressions = []
    while index < n:
        expressions.append(parse_expr())

    if len(expressions) == 1:
        return expressions[0]
    return expressions

