ASTType = Union[list, tuple, str, int, float]

def evaluate(ast: ASTType) -> Union[int, float]:
    if isinstance(ast, (int, float)):
        return ast

    if isinstance(ast, str):
        val = ast.strip()
        try:
            if '.' in val or 'e' in val.lower():
                return float(val)
            return int(val)
        except ValueError:
            raise ValueError(f"Unknown variable or invalid number: {ast}")

    if isinstance(ast, (list, tuple)):
        if not ast:
            raise ValueError("Empty AST node")

        # Single element wrapped in a list/tuple
        if len(ast) == 1:
            return evaluate(ast[0])

        # Unary operations: [op, operand]
        if len(ast) == 2:
            op, val = ast
            evaluated_val = evaluate(val)
            if op in ('-', 'u-', 'neg'):
                return -evaluated_val
            if op in ('+', 'u+', 'pos'):
                return evaluated_val
            if op == 'abs':
                return abs(evaluated_val)
            if op == 'sin':
                return math.sin(evaluated_val)
            if op == 'cos':
                return math.cos(evaluated_val)
            if op == 'tan':
                return math.tan(evaluated_val)
            if op == 'sqrt':
                return math.sqrt(evaluated_val)
            if op == 'log':
                return math.log(evaluated_val)
            raise ValueError(f"Unknown unary operator or function: {op}")

        # Binary operations: [op, left, right] or [left, op, right]
        if len(ast) == 3:
            op = ast[0]
            left = ast[1]
            right = ast[2]

            valid_ops = {'+', '-', '*', '/', '^', '**', 'mod', '%'}

            # Detect infix notation: [left, op, right]
            if op not in valid_ops and ast[1] in valid_ops:
                left, op, right = ast[0], ast[1], ast[2]

            eval_left = evaluate(left)
            eval_right = evaluate(right)

            if op == '+':
                return eval_left + eval_right
            elif op == '-':
                return eval_left - eval_right
            elif op == '*':
                return eval_left * eval_right
            elif op == '/':
                return eval_left / eval_right
            elif op in ('^', '**'):
                return eval_left ** eval_right
            elif op in ('%', 'mod'):
                return eval_left % eval_right
            else:
                raise ValueError(f"Unknown binary operator: {op}")

    raise ValueError(f"Invalid AST structure: {ast}")

