def parse_to_tree(text: str) -> list[dict]:
    if not text:
        return []

    roots = []
    stack = []  # stores tuples of (indent_level, node_dict)

    for line in text.splitlines():
        if not line.strip():
            continue

        # Expand tabs to spaces for consistent indentation measurement
        expanded = line.expandtabs(4)
        indent = len(expanded) - len(expanded.lstrip())
        content = line.strip()

        node = {
            'text': content,
            'children': []
        }

        # Pop from stack until we find the parent (which must have strictly less indent)
        while stack and stack[-1][0] >= indent:
            stack.pop()

        if not stack:
            roots.append(node)
        else:
            stack[-1][1]['children'].append(node)

        stack.append((indent, node))

    return roots

