def serialize_tree(nodes: list[dict], indent_char: str) -> str:
    """
    Serializes an annotated hierarchical tree back into an indented text format.

    Each node in the list has the structure:
    {
        'text': str,
        'depth': int,
        'children': list[dict]
    }
    """
    lines = []

    def traverse(node_list: list[dict]) -> None:
        for node in node_list:
            depth = node.get('depth', 0)
            text = node.get('text', '')
            lines.append(f"{indent_char * depth}{text}")

            children = node.get('children', [])
            if children:
                traverse(children)

    traverse(nodes)
    return "\n".join(lines)

