class Parser:
    def __init__(self, tokens_generator):
        self.tokens = list(tokens_generator)
        self.pos = 0

    def current_token(self) -> Token:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return Token('EOF', '')

    def consume(self, expected_type: str) -> Token:
        tok = self.current_token()
        if tok.type == expected_type:
            self.pos += 1
            return tok
        raise RuntimeError(f"Expected {expected_type} but got {tok.type}")

    def parse(self) -> dict:
        node = self.expr()
        if self.current_token().type != 'EOF':
            raise RuntimeError("Unexpected token at end of expression")
        return node

    def expr(self) -> dict:
        node = self.term()
        while self.current_token().type in ('PLUS', 'MINUS'):
            tok = self.current_token()
            self.pos += 1
            right = self.term()
            node = create_node('operator', tok.value, node, right)
        return node

    def term(self) -> dict:
        node = self.factor()
        while self.current_token().type in ('MUL', 'DIV'):
            tok = self.current_token()
            self.pos += 1
            right = self.factor()
            node = create_node('operator', tok.value, node, right)
        return node

    def factor(self) -> dict:
        tok = self.current_token()
        if tok.type == 'PLUS':
            self.pos += 1
            return self.factor()
        elif tok.type == 'MINUS':
            self.pos += 1
            operand = self.factor()
            return create_node('operator', '-', None, operand)
        elif tok.type == 'LPAREN':
            self.pos += 1
            node = self.expr()
            self.consume('RPAREN')
            return node
        elif tok.type == 'NUMBER':
            self.pos += 1
            return create_node('number', tok.value, None, None)
        else:
            raise RuntimeError(f"Unexpected token {tok.value}")

def parse(expression: str) -> dict:
    tokens = tokenize(expression)
    parser = Parser(tokens)
    return parser.parse()

