def parse_num(val_str: str):
    try:
        if '.' in val_str or 'e' in val_str.lower():
            return float(val_str)
        return int(val_str)
    except ValueError:
        return float(val_str)

def is_constant(node: dict | None) -> bool:
    if node is None:
        return False
    t = node.get("type", "").upper()
    if t in ("NUMBER", "INT", "FLOAT", "INTEGER", "LITERAL"):
        try:
            parse_num(node.get("value", ""))
            return True
        except (ValueError, TypeError):
            return False
    return False

def is_operator_node(node: dict) -> bool:
    t = node.get("type", "").upper()
    if t in ("BINOP", "BINARY_OP", "OPERATOR", "OP"):
        return True
    if node.get("value") in ("+", "-", "*", "/", "//", "%", "**"):
        return True
    return False

def is_unary_operator(node: dict) -> bool:
    t = node.get("type", "").upper()
    if t in ("UNARYOP", "UNARY_OP", "OPERATOR", "OP"):
        return True
    if node.get("value") in ("+", "-"):
        return True
    return False

def fold_constants(tree: dict) -> dict:
    if tree is None:
        return None

    left = fold_constants(tree.get("left")) if tree.get("left") is not None else None
    right = fold_constants(tree.get("right")) if tree.get("right") is not None else None

    node_type = tree.get("type", "")
    node_value = tree.get("value", "")

    # Unary operator folding
    if left is not None and right is None and is_unary_operator(tree) and is_constant(left):
        try:
            val = parse_num(left["value"])
            op = node_value
            res = None
            if op == "-":
                res = -val
            elif op == "+":
                res = +val

            if res is not None:
                res_type = left.get("type", "NUMBER")
                return create_node(res_type, str(res), None, None)
        except Exception:
            pass

    # Binary operator folding
    if left is not None and right is not None and is_operator_node(tree):
        if is_constant(left) and is_constant(right):
            try:
                val_l = parse_num(left["value"])
                val_r = parse_num(right["value"])
                op = node_value
                res = None

                if op == "+":
                    res = val_l + val_r
                elif op == "-":
                    res = val_l - val_r
                elif op == "*":
                    res = val_l * val_r
                elif op == "/":
                    if val_r != 0:
                        res = val_l / val_r
                elif op == "//":
                    if val_r != 0:
                        res = val_l // val_r
                elif op == "%":
                    if val_r != 0:
                        res = val_l % val_r
                elif op == "**":
                    if val_r < 100:  # Prevent extremely large numbers / hangs
                        res = val_l ** val_r

                if res is not None:
                    # Keep type consistent with operands
                    if isinstance(res, int):
                        res_type = left.get("type", "INT")
                    else:
                        res_type = "FLOAT" if "FLOAT" in (left.get("type", "").upper(), right.get("type", "").upper()) else "NUMBER"
                    return create_node(res_type, str(res), None, None)
            except Exception:
                pass

    return create_node(node_type, node_value, left, right)

