def build_adjacency_list(edges: list[tuple[int, int]]) -> dict[int, list[int]]:
    """
    Builds an adjacency list representation of a directed graph from raw edge data.
    Ensures all vertices mentioned in edges are present as keys in the dictionary.
    """
    adj: dict[int, list[int]] = {}
    for u, v in edges:
        if u not in adj:
            adj[u] = []
        if v not in adj:
            adj[v] = []
        adj[u].append(v)
    return adj

