from collections import defaultdict
from typing import Any, Dict, List

def find_connected_components(adj_list: Dict[int, List[int]]) -> List[List[int]]:
    # Build an undirected representation to find weakly connected components
    undirected = defaultdict(set)
    all_nodes = set(adj_list.keys())
    for u, neighbors in adj_list.items():
        all_nodes.add(u)
        for v in neighbors:
            all_nodes.add(v)
            undirected[u].add(v)
            undirected[v].add(u)

    visited = set()
    components = []

    # Traverse graph using BFS
    for node in sorted(all_nodes):
        if node not in visited:
            component = []
            queue = [node]
            visited.add(node)
            while queue:
                curr = queue.pop(0)
                component.append(curr)
                for neighbor in undirected[curr]:
                    if neighbor not in visited:
                        visited.add(neighbor)
                        queue.append(neighbor)
            components.append(sorted(component))

    # Sort components by their first element to ensure deterministic output
    components.sort(key=lambda x: x[0] if x else 0)
    return components

def summarize_components(components: List[List[int]]) -> List[Dict[str, Any]]:
    summaries = []
    for comp in components:
        if not comp:
            continue
        summaries.append({
            "representative": min(comp),
            "size": len(comp),
            "members": list(comp)
        })
    return summaries

