def build_graph(raw_dependencies: dict[str, list[str]]) -> dict[str, list[str]]:
    """
    Constructs and validates the dependency graph representation from raw input data.
    Ensures that all nodes referenced in dependency lists are also present as keys 
    in the returned dictionary, initializing them with an empty list of dependencies 
    if they were not explicitly defined.

    Args:
        raw_dependencies: A dictionary mapping a node to its list of dependencies.

    Returns:
        A validated dependency graph dictionary where every referenced node is a key.

    Raises:
        TypeError: If the input types are invalid.
    """
    if not isinstance(raw_dependencies, dict):
        raise TypeError("Input dependencies must be a dictionary.")

    graph: dict[str, list[str]] = {}

    for node, dependencies in raw_dependencies.items():
        if not isinstance(node, str):
            raise TypeError(f"Graph node key must be a string, got {type(node).__name__}")
        if not isinstance(dependencies, list):
            raise TypeError(f"Dependencies for node '{node}' must be a list, got {type(dependencies).__name__}")

        validated_deps = []
        for dep in dependencies:
            if not isinstance(dep, str):
                raise TypeError(f"Dependency element in node '{node}' must be a string, got {type(dep).__name__}")
            validated_deps.append(dep)

        graph[node] = validated_deps

    # Ensure all referenced nodes exist as keys in the graph
    referenced_nodes = set()
    for deps in graph.values():
        referenced_nodes.update(deps)

    for node in referenced_nodes:
        if node not in graph:
            graph[node] = []

    return graph

