def topological_sort(graph: dict[str, list[str]]) -> tuple[list[str], list[str]]:
    # Identify all unique nodes in the graph
    all_nodes = set(graph.keys())
    for deps in graph.values():
        all_nodes.update(deps)

    # Kahn's algorithm setup
    # If A depends on B, B must be resolved before A (edge: B -> A)
    adj = {node: set() for node in all_nodes}
    in_degree = {node: 0 for node in all_nodes}

    for node, deps in graph.items():
        for dep in deps:
            if node not in adj[dep]:
                adj[dep].add(node)
                in_degree[node] += 1

    # Initialize queue with nodes having no dependencies (in-degree 0)
    queue = [node for node in all_nodes if in_degree[node] == 0]
    queue.sort()  # Sorting for deterministic behavior

    resolved_order = []
    while queue:
        curr = queue.pop(0)
        resolved_order.append(curr)
        for neighbor in sorted(adj[curr]):
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    # DFS cycle detection to find the exact nodes involved in any cycle
    visited = {}  # 0: unvisited, 1: visiting, 2: visited
    cycle_nodes = set()

    def dfs(node: str, path: list[str]) -> None:
        visited[node] = 1
        path.append(node)
        for dep in graph.get(node, []):
            if visited.get(dep, 0) == 1:
                try:
                    idx = path.index(dep)
                    cycle_nodes.update(path[idx:])
                except ValueError:
                    pass
            elif visited.get(dep, 0) == 0:
                dfs(dep, path)
        path.pop()
        visited[node] = 2

    for node in sorted(all_nodes):
        if visited.get(node, 0) == 0:
            dfs(node, [])

    return resolved_order, sorted(list(cycle_nodes))

