def insert(tree: dict | None, key: int) -> dict:
    if tree is None:
        return {"key": key, "left": None, "right": None}

    if key < tree["key"]:
        return {
            "key": tree["key"],
            "left": insert(tree["left"], key),
            "right": tree["right"]
        }
    elif key > tree["key"]:
        return {
            "key": tree["key"],
            "left": tree["left"],
            "right": insert(tree["right"], key)
        }
    else:
        # Key already exists, return a copy of the current node
        return {
            "key": tree["key"],
            "left": tree["left"],
            "right": tree["right"]
        }


def find(tree: dict | None, key: int) -> bool:
    if tree is None:
        return False
    if key == tree["key"]:
        return True
    elif key < tree["key"]:
        return find(tree["left"], key)
    else:
        return find(tree["right"], key)


def _find_min_key(tree: dict) -> int:
    current = tree
    while current["left"] is not None:
        current = current["left"]
    return current["key"]


def delete(tree: dict | None, key: int) -> dict | None:
    if tree is None:
        return None

    if key < tree["key"]:
        return {
            "key": tree["key"],
            "left": delete(tree["left"], key),
            "right": tree["right"]
        }
    elif key > tree["key"]:
        return {
            "key": tree["key"],
            "left": tree["left"],
            "right": delete(tree["right"], key)
        }
    else:
        # Node to delete found
        if tree["left"] is None and tree["right"] is None:
            return None
        elif tree["left"] is None:
            return tree["right"]
        elif tree["right"] is None:
            return tree["left"]
        else:
            # Node has two children: get successor
            min_val = _find_min_key(tree["right"])
            return {
                "key": min_val,
                "left": tree["left"],
                "right": delete(tree["right"], min_val)
            }


def inorder(tree: dict | None) -> list[int]:
    if tree is None:
        return []
    return inorder(tree["left"]) + [tree["key"]] + inorder(tree["right"])

