def validate_brackets(text: str) -> bool:
    """
    Validates the balance of bracket pairs (), [], and {} using a stack-based algorithm.
    Returns True if brackets are balanced, False otherwise. Ignore other characters.
    """
    stack = []
    mapping = {")": "(", "]": "[", "}": "{"}
    opening = set(mapping.values())
    closing = set(mapping.keys())

    for char in text:
        if char in opening:
            stack.append(char)
        elif char in closing:
            if not stack:
                return False
            top_element = stack.pop()
            if mapping[char] != top_element:
                return False

    return len(stack) == 0

