def create_graph() -> Dict:
    return {
        'vertices': [],
        'edges': []
    }

def add_vertex(graph: Dict, vertex: str) -> Dict:
    if vertex not in graph['vertices']:
        graph['vertices'].append(vertex)
    return graph

def delete_vertex(graph: Dict, vertex: str) -> Dict:
    if vertex in graph['vertices']:
        graph['vertices'].remove(vertex)
    graph['edges'] = [edge for edge in graph['edges'] if edge[0] != vertex and edge[1] != vertex]
    return graph

def add_edge(graph: Dict, source: str, target: str) -> Dict:
    if source not in graph['vertices']:
        graph['vertices'].append(source)
    if target not in graph['vertices']:
        graph['vertices'].append(target)

    edge = [source, target]
    if edge not in graph['edges']:
        graph['edges'].append(edge)
    return graph

def delete_edge(graph: Dict, source: str, target: str) -> Dict:
    edge = [source, target]
    if edge in graph['edges']:
        graph['edges'].remove(edge)
    return graph

def get_vertices(graph: Dict) -> List[str]:
    return list(graph['vertices'])

def get_edges(graph: Dict) -> List[List[str]]:
    return [list(edge) for edge in graph['edges']]

def get_neighbors(graph: Dict, vertex: str) -> List[str]:
    neighbors = []
    for edge in graph['edges']:
        if edge[0] == vertex:
            neighbors.append(edge[1])
    return neighbors

