class Parser:
    def __init__(self, tokens: list[dict]):
        self.tokens = tokens
        self.pos = 0

    def current_token(self) -> dict | None:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self) -> dict | None:
        tok = self.current_token()
        self.pos += 1
        return tok

    def parse(self) -> dict | None:
        if not self.tokens:
            return None
        return self.expr()

    def expr(self) -> dict | None:
        return self.binary_expr(self.term, ['+', '-'])

    def term(self) -> dict | None:
        return self.binary_expr(self.factor, ['*', '/', '%'])

    def factor(self) -> dict | None:
        # Right-associative exponentiation (e.g. 2 ^ 3 ^ 2 is 2 ^ (3 ^ 2))
        left = self.unary()
        tok = self.current_token()
        if tok and tok.get('value') == '^':
            self.consume()
            right = self.factor()
            return {
                'type': tok.get('type', 'OPERATOR'),
                'value': '^',
                'left': left,
                'right': right
            }
        return left

    def unary(self) -> dict | None:
        tok = self.current_token()
        if tok and tok.get('value') in ['+', '-']:
            self.consume()
            operand = self.unary()
            return {
                'type': tok.get('type', 'OPERATOR'),
                'value': tok.get('value'),
                'left': operand,
                'right': None
            }
        return self.primary()

    def primary(self) -> dict | None:
        tok = self.current_token()
        if not tok:
            return None

        if tok.get('value') == '(':
            self.consume()  # Consume '('
            node = self.expr()
            next_tok = self.current_token()
            if next_tok and next_tok.get('value') == ')':
                self.consume()  # Consume ')'
            return node

        self.consume()
        return {
            'type': tok.get('type', 'LITERAL'),
            'value': tok.get('value', ''),
            'left': None,
            'right': None
        }

    def binary_expr(self, next_level, ops: list[str]) -> dict | None:
        left = next_level()
        while True:
            tok = self.current_token()
            if tok and tok.get('value') in ops:
                self.consume()
                right = next_level()
                left = {
                    'type': tok.get('type', 'OPERATOR'),
                    'value': tok.get('value'),
                    'left': left,
                    'right': right
                }
            else:
                break
        return left


def parse(tokens: list[dict]) -> dict | None:
    parser = Parser(tokens)
    return parser.parse()

