def evaluate(ast: dict) -> float:
    if not ast:
        raise ValueError("Empty AST node")

    node_type = ast.get('type')
    value = ast.get('value')
    left = ast.get('left')
    right = ast.get('right')

    # Leaf node (Number)
    if left is None and right is None:
        try:
            return float(value)
        except (ValueError, TypeError):
            raise ValueError(f"Invalid numeric value: {value}")

    # Unary Operator
    if left is None and right is not None:
        right_val = evaluate(right)
        op = value if value else node_type
        if op in ('-', 'unary_minus', 'neg', 'Negate'):
            return -right_val
        if op in ('+', 'unary_plus', 'pos', 'Positive'):
            return right_val
        raise ValueError(f"Unsupported unary operator: {op}")

    # Binary Operator
    if left is not None and right is not None:
        left_val = evaluate(left)
        right_val = evaluate(right)

        op = value if value else node_type

        if op in ('+', 'add', 'Add', 'Addition'):
            return left_val + right_val
        elif op in ('-', 'sub', 'Sub', 'Subtract', 'Subtraction'):
            return left_val - right_val
        elif op in ('*', 'mul', 'Mul', 'Multiply', 'Multiplication'):
            return left_val * right_val
        elif op in ('/', 'div', 'Div', 'Divide', 'Division'):
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        elif op in ('^', '**', 'pow', 'Pow', 'Power', 'Exponentiation'):
            return left_val ** right_val
        else:
            raise ValueError(f"Unsupported binary operator: {op}")

    raise ValueError("Invalid AST node configuration")

