def parse_atom(token: str) -> str | int | float:
    try:
        return int(token)
    except ValueError:
        pass
    try:
        return float(token)
    except ValueError:
        pass
    if len(token) >= 2 and (
        (token.startswith('"') and token.endswith('"')) or
        (token.startswith("'") and token.endswith("'"))
    ):
        return token[1:-1]
    return token


def parse(tokens: list[str]) -> list | str | int | float:
    if not tokens:
        return []

    def parse_nodes(index: int) -> tuple[list | str | int | float, int]:
        if index >= len(tokens):
            raise SyntaxError("Unexpected EOF")

        token = tokens[index]
        if token in ('(', '['):
            closing = ')' if token == '(' else ']'
            elements = []
            index += 1
            while index < len(tokens) and tokens[index] != closing:
                expr, index = parse_nodes(index)
                elements.append(expr)
            if index >= len(tokens):
                raise SyntaxError(f"Expected '{closing}', got EOF")
            return elements, index + 1
        elif token in (')', ']'):
            raise SyntaxError(f"Unexpected '{token}'")
        else:
            return parse_atom(token), index + 1

    res = []
    idx = 0
    while idx < len(tokens):
        expr, idx = parse_nodes(idx)
        res.append(expr)

    if len(res) == 1:
        return res[0]
    return res

