def evaluate(node) -> int | float:
    """
    Recursively evaluates a parsed nested expression structure.
    Supports both prefix (Lisp-style) and infix structures, as well as raw numeric values.

    Examples:
        evaluate(5) -> 5
        evaluate("3.14") -> 3.14
        evaluate(['+', 1, 2]) -> 3 (Prefix)
        evaluate([1, '+', 2]) -> 3 (Infix)
        evaluate(['*', ['+', 1, 2], 3]) -> 9
    """
    if isinstance(node, (int, float)):
        return node

    if isinstance(node, str):
        try:
            if '.' in node or 'e' in node.lower():
                return float(node)
            return int(node)
        except ValueError:
            raise ValueError(f"Cannot evaluate string symbol to number: {node}")

    if isinstance(node, list):
        if not node:
            raise ValueError("Cannot evaluate an empty list")

        # Normalize operations using a dictionary mapping
        ops = {
            '+': lambda a, b: a + b,
            '-': lambda a, b: a - b,
            '*': lambda a, b: a * b,
            '/': lambda a, b: a / b,
            '//': lambda a, b: a // b,
            '%': lambda a, b: a % b,
            '**': lambda a, b: a ** b,
            '^': lambda a, b: a ** b,
        }

        unary_ops = {
            '+': lambda a: +a,
            '-': lambda a: -a,
        }

        # Case 1: Single element list [expr]
        if len(node) == 1:
            return evaluate(node[0])

        # Case 2: Infix representation [left, op, right]
        if len(node) == 3 and isinstance(node[1], str) and node[1] in ops:
            left = evaluate(node[0])
            op = node[1]
            right = evaluate(node[2])
            return ops[op](left, right)

        # Case 3: Prefix representation [op, ...]
        op = node[0]
        if isinstance(op, str):
            # Unary prefix: ['-', val]
            if len(node) == 2 and op in unary_ops:
                return unary_ops[op](evaluate(node[1]))

            # Binary or N-ary prefix: ['+', val1, val2, ...]
            if len(node) >= 3 and op in ops:
                if op == '+':
                    return sum(evaluate(x) for x in node[1:])
                elif op == '*':
                    result = 1
                    for x in node[1:]:
                        result *= evaluate(x)
                    return result
                elif len(node) == 3:
                    return ops[op](evaluate(node[1]), evaluate(node[2]))
                else:
                    raise ValueError(f"Operator '{op}' is not supported with {len(node) - 1} operands")

        raise ValueError(f"Unrecognized expression structure: {node}")

    raise TypeError(f"Unsupported node type: {type(node)}")

