import re
from models import create_numeric_node, create_operator_node

def tokenize(expression: str):
    token_specification = [
        ('NUMBER',   r'\d+(?:\.\d+)?'),
        ('OP',       r'[+\-*/]'),
        ('LPAREN',   r'\('),
        ('RPAREN',   r'\)'),
        ('SKIP',     r'[ \t\r\n]+'),
        ('MISMATCH', r'.'),
    ]
    tok_regex = '|'.join('(?P<%s>%s)' % pair for pair in token_specification)
    for mo in re.finditer(tok_regex, expression):
        kind = mo.lastgroup
        value = mo.group()
        if kind == 'NUMBER':
            yield ('NUMBER', float(value))
        elif kind == 'OP':
            yield ('OP', value)
        elif kind == 'LPAREN':
            yield ('LPAREN', value)
        elif kind == 'RPAREN':
            yield ('RPAREN', value)
        elif kind == 'SKIP':
            continue
        elif kind == 'MISMATCH':
            raise ValueError(f'Unexpected character {value!r}')

class ExpressionParser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def peek(self):
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self, expected_type=None):
        tok = self.peek()
        if not tok:
            raise ValueError("Unexpected end of expression")
        if expected_type and tok[0] != expected_type:
            raise ValueError(f"Expected token type {expected_type}, got {tok[0]}")
        self.pos += 1
        return tok

    def parse_expression(self) -> dict:
        return self.parse_addition()

    def parse_addition(self) -> dict:
        node = self.parse_multiplication()
        while True:
            tok = self.peek()
            if tok and tok[0] == 'OP' and tok[1] in ('+', '-'):
                op = self.consume()[1]
                right = self.parse_multiplication()
                node = create_operator_node(op, node, right)
            else:
                break
        return node

    def parse_multiplication(self) -> dict:
        node = self.parse_primary()
        while True:
            tok = self.peek()
            if tok and tok[0] == 'OP' and tok[1] in ('*', '/'):
                op = self.consume()[1]
                right = self.parse_primary()
                node = create_operator_node(op, node, right)
            else:
                break
        return node

    def parse_primary(self) -> dict:
        tok = self.peek()
        if not tok:
            raise ValueError("Unexpected end of expression")

        if tok[0] == 'OP' and tok[1] == '-':
            self.consume()
            right = self.parse_primary()
            return create_operator_node('-', create_numeric_node(0.0), right)
        elif tok[0] == 'OP' and tok[1] == '+':
            self.consume()
            return self.parse_primary()
        elif tok[0] == 'NUMBER':
            val = self.consume()[1]
            return create_numeric_node(val)
        elif tok[0] == 'LPAREN':
            self.consume('LPAREN')
            node = self.parse_expression()
            self.consume('RPAREN')
            return node
        else:
            raise ValueError(f"Unexpected token {tok}")

def parse(expression: str) -> dict:
    tokens = list(tokenize(expression))
    if not tokens:
        raise ValueError("Empty expression")
    parser = ExpressionParser(tokens)
    node = parser.parse_expression()
    if parser.pos < len(tokens):
        raise ValueError(f"Unparsed tokens remaining: {tokens[parser.pos:]}")
    return node

