def fold(tree: dict) -> dict:
    if not tree:
        return tree

    node_type = tree.get("type")

    # If it is already a numeric node, return as is.
    if node_type == "numeric" or ("value" in tree and "operator" not in tree):
        return tree

    # Handle operator nodes
    if "operator" in tree:
        op = tree["operator"]
        left_folded = fold(tree.get("left"))
        right_folded = fold(tree.get("right"))

        # Check if both folded subtrees are numeric nodes
        left_is_num = left_folded is not None and (
            left_folded.get("type") == "numeric" or ("value" in left_folded and "operator" not in left_folded)
        )
        right_is_num = right_folded is not None and (
            right_folded.get("type") == "numeric" or ("value" in right_folded and "operator" not in right_folded)
        )

        if left_is_num and right_is_num:
            left_val = left_folded["value"]
            right_val = right_folded["value"]

            try:
                if op == '+':
                    result = left_val + right_val
                elif op == '-':
                    result = left_val - right_val
                elif op == '*':
                    result = left_val * right_val
                elif op == '/':
                    if right_val == 0:
                        return create_operator_node(op, left_folded, right_folded)
                    result = left_val / right_val
                elif op == '//':
                    if right_val == 0:
                        return create_operator_node(op, left_folded, right_folded)
                    result = left_val // right_val
                elif op == '%':
                    if right_val == 0:
                        return create_operator_node(op, left_folded, right_folded)
                    result = left_val % right_val
                elif op in ('**', '^'):
