    precedence = {
        "+": 1, "-": 1,
        "*": 2, "/": 2,
        "^": 3, "**": 3
    }

    curr_prec = precedence.get(op, 0)

    def get_node_prec(node):
        if not node or node.get("type") == "number" or "value" in node:
            return 99
        return precedence.get(node.get("operator"), 0)

    left_str = serialize(left_node)
    right_str = serialize(right_node)

    left_prec = get_node_prec(left_node)
    right_prec = get_node_prec(right_node)

    # Left child needs parentheses if its operator has lower precedence
    if left_prec < curr_prec:
        left_str = f"({left_str})"

    # Right child needs parentheses if its operator has lower precedence,
    # or if it has the same precedence (to respect left-to-right associativity)
    if right_prec < curr_prec or (right_prec == curr_prec and op in ("-", "/", "+", "*")):
        right_str = f"({right_str})"

    return f"{left_str} {op} {right_str}"

