def build_graph(dependencies: dict[str, list[str]]) -> dict[str, list[str]]:
    """
    Parses, normalizes, and validates the raw input dependency structure
    into a standardized directed graph representation.

    - Normalizes node names by stripping whitespace.
    - Removes self-loops.
    - Eliminates duplicate dependencies.
    - Ensures all referenced dependency nodes exist as keys in the returned dictionary.
    - Sorts keys and values for a deterministic representation.
    """
    if not isinstance(dependencies, dict):
        raise TypeError("Input dependencies must be a dictionary.")

    normalized: dict[str, list[str]] = {}

    for node, edges in dependencies.items():
        if not isinstance(node, str):
            raise TypeError("Graph nodes must be strings.")
        if not isinstance(edges, list):
            raise TypeError("Dependencies must be provided as a list of strings.")

        node_clean = node.strip()
        if not node_clean:
            continue

        clean_edges = []
        for edge in edges:
            if not isinstance(edge, str):
                raise TypeError("Graph edges must be strings.")
            edge_clean = edge.strip()
            if edge_clean and edge_clean != node_clean:
                if edge_clean not in clean_edges:
                    clean_edges.append(edge_clean)

        if node_clean in normalized:
            # Merge dependencies if the normalized node already exists
            for edge_clean in clean_edges:
                if edge_clean not in normalized[node_clean]:
                    normalized[node_clean].append(edge_clean)
        else:
            normalized[node_clean] = clean_edges

    # Ensure all target nodes exist as keys in the graph (closure property)
    all_referenced = {edge for edges in normalized.values() for edge in edges}
    for ref in all_referenced:
        if ref not in normalized:
            normalized[ref] = []

    # Return a deterministically sorted graph representation
    return {key: sorted(normalized[key]) for key in sorted(normalized.keys())}

