import collections

def resolve_dependencies(graph: dict[str, list[str]]) -> tuple[list[str], list[list[str]]]:
    # Ensure all nodes mentioned in dependencies are also keys in the graph
    all_nodes = set(graph.keys())
    for deps in graph.values():
        all_nodes.update(deps)
    full_graph = {node: list(graph.get(node, [])) for node in all_nodes}

    # Tarjan's algorithm for finding Strongly Connected Components (SCCs)
    index = 0
    indices = {}
    lowlink = {}
    on_stack = set()
    stack = []
    sccs = []

    def strongconnect(v):
        nonlocal index
        indices[v] = index
        lowlink[v] = index
        index += 1
        stack.append(v)
        on_stack.add(v)

        for w in full_graph[v]:
            if w not in indices:
                strongconnect(w)
                lowlink[v] = min(lowlink[v], lowlink[w])
            elif w in on_stack:
                lowlink[v] = min(lowlink[v], indices[w])

        if lowlink[v] == indices[v]:
            scc = []
            while True:
                w = stack.pop()
                on_stack.remove(w)
                scc.append(w)
                if w == v:
                    break
            sccs.append(scc)

    for node in full_graph:
        if node not in indices:
            strongconnect(node)

    # Identify cyclic components (SCCs of size > 1, or size 1 with a self-loop)
    cycles = []
    for scc in sccs:
        if len(scc) > 1:
            cycles.append(sorted(scc))
        elif len(scc) == 1:
            node = scc[0]
            if node in full_graph[node]:
                cycles.append([node])

    # Sort cycles for deterministic output
    cycles.sort(key=lambda x: x[0] if x else "")

    if cycles:
        # If there are cycles, a valid global topological sort is impossible
        return [], cycles

    # Kahn's algorithm for topological sorting of the DAG
    # u depends on v means v must be built before u (v -> u)
    adj = {node: [] for node in full_graph}
    in_degree = {node: 0 for node in full_graph}
    for u, deps in full_graph.items():
        for v in deps:
            adj[v].append(u)
            in_degree[u] += 1

    # Start with nodes that have 0 in-degree (no dependencies)
    start_nodes = sorted([node for node in full_graph if in_degree[node] == 0])
    queue = collections.deque(start_nodes)
    build_order = []

    while queue:
        u = queue.popleft()
        build_order.append(u)
        for v in sorted(adj[u]):
            in_degree[v] -= 1
            if in_degree[v] == 0:
                queue.append(v)

    return build_order, []

