def parse_command(user_input: str) -> Tuple[str, Optional[int]]:
    """
    Parses an interactive command-line input into a command and an optional integer argument.

    Args:
        user_input (str): The raw input string from the command line.

    Returns:
        Tuple[str, Optional[int]]: A tuple containing the command string (lowercased)
                                   and an optional integer argument.
    """
    if not isinstance(user_input, str):
        return ("", None)

    tokens = user_input.strip().split()
    if not tokens:
        return ("", None)

    command = tokens[0].lower()

    if len(tokens) > 1:
        try:
            return (command, int(tokens[1]))
        except ValueError:
            return (command, None)

    return (command, None)

