def check_brackets(text: str) -> bool:
    """
    Checks if the brackets in the given string are matched and nested correctly.
    Supports standard brackets: (), [], and {}.
    """
    stack = []
    bracket_map = {")": "(", "]": "[", "}": "{"}
    opening_brackets = set(bracket_map.values())
    closing_brackets = set(bracket_map.keys())

    for char in text:
        if char in opening_brackets:
            stack.append(char)
        elif char in closing_brackets:
            if not stack:
                return False
            top = stack.pop()
            if bracket_map[char] != top:
                return False

    return len(stack) == 0

