DATA_FILE = "hierarchy.json"

def _load() -> dict[str, list[str]]:
    try:
        return load_hierarchy(DATA_FILE)
    except Exception:
        return {}

def _save(data: dict[str, list[str]]) -> None:
    save_hierarchy(DATA_FILE, data)

def _get_descendants_helper(hierarchy: dict[str, list[str]], tag: str) -> list[str]:
    if tag not in hierarchy:
        return []
    visited = set()
    queue = list(hierarchy.get(tag, []))
    descendants = []
    while queue:
        current = queue.pop(0)
        if current not in visited:
            visited.add(current)
            descendants.append(current)
            queue.extend(hierarchy.get(current, []))
    return descendants

def add_tag(tag: str) -> bool:
    hierarchy = _load()
    if tag in hierarchy:
        return False
    hierarchy[tag] = []
    _save(hierarchy)
    return True

def delete_tag(tag: str) -> bool:
    hierarchy = _load()
    if tag not in hierarchy:
        return False
    del hierarchy[tag]
    for parent, children in hierarchy.items():
        if tag in children:
            hierarchy[parent] = [c for c in children if c != tag]
    _save(hierarchy)
    return True

def add_relation(parent: str, child: str) -> bool:
    hierarchy = _load()
    if parent not in hierarchy or child not in hierarchy:
        return False
    if child in hierarchy[parent]:
        return False
    if parent == child:
        return False
    if parent in _get_descendants_helper(hierarchy, child):
        return False
    hierarchy[parent].append(child)
    _save(hierarchy)
    return True

def delete_relation(parent: str, child: str) -> bool:
    hierarchy = _load()
    if parent not in hierarchy:
        return False
    if child not in hierarchy[parent]:
        return False
    hierarchy[parent].remove(child)
    _save(hierarchy)
    return True

def get_all_tags() -> list[str]:
    hierarchy = _load()
    return list(hierarchy.keys())

def get_descendants(tag: str) -> list[str]:
    hierarchy = _load()
    return _get_descendants_helper(hierarchy, tag)

def get_hierarchy_view() -> dict[str, list[str]]:
    return _load()

