def parse(tokens: list[dict]) -> dict:
    idx = 0

    def peek():
        nonlocal idx
        if idx < len(tokens):
            return tokens[idx]
        return None

    def consume(expected_value=None):
        nonlocal idx
        token = peek()
        if not token:
            raise SyntaxError("Unexpected end of input")
        if expected_value is not None and token.get("value") != expected_value:
            raise SyntaxError(f"Expected '{expected_value}', got '{token.get('value')}'")
        idx += 1
        return token

    def expr() -> dict:
        node = term()
        while True:
            token = peek()
            if token and token.get("value") in ("+", "-"):
                op_token = consume()
                right_node = term()
                node = {
                    "type": "binary_op",
                    "value": op_token["value"],
                    "left": node,
                    "right": right_node
                }
            else:
                break
        return node

    def term() -> dict:
        node = factor()
        while True:
            token = peek()
            if token and token.get("value") in ("*", "/"):
                op_token = consume()
                right_node = factor()
                node = {
                    "type": "binary_op",
                    "value": op_token["value"],
                    "left": node,
                    "right": right_node
                }
            else:
                break
        return node

    def factor() -> dict:
        token = peek()
        if not token:
            raise SyntaxError("Unexpected end of input")

        if token.get("value") in ("+", "-"):
            op_token = consume()
            operand = factor()
            return {
                "type": "unary_op",
                "value": op_token["value"],
                "left": operand,
                "right": None
            }

        if token.get("value") == "(" or token.get("type") == "LPAREN":
            consume("(")
            node = expr()
            consume(")")
            return node

        token = consume()
        return {
            "type": "number",
            "value": token["value"],
            "left": None,
            "right": None
        }

    if not tokens:
        raise ValueError("No tokens to parse")

    result = expr()
    if idx < len(tokens):
        raise SyntaxError(f"Unparsed tokens remaining starting from index {idx}: {tokens[idx:]}")
    return result

