import math

def evaluate(ast: dict) -> float:
    if ast is None:
        return 0.0

    node_type = ast.get("type", "").upper()
    value = ast.get("value")
    left = ast.get("left")
    right = ast.get("right")

    if node_type in ("NUMBER", "NUM", "LITERAL", "INT", "FLOAT"):
        return float(value)

    # Leaf node check
    if left is None and right is None:
        return float(value)

    # Unary operators (only one child exists)
    if (left is None) != (right is None):
        operand_node = left if left is not None else right
        operand_val = evaluate(operand_node)

        if value == "-":
            return -operand_val
        elif value == "+":
            return operand_val

        # Support basic math functions if parsed as unary nodes
        funcs = {
            "sin": math.sin,
            "cos": math.cos,
            "tan": math.tan,
            "sqrt": math.sqrt,
            "log": math.log,
            "exp": math.exp,
            "abs": abs
        }
        if value in funcs:
            return float(funcs[value](operand_val))

        raise ValueError(f"Unknown unary operator/function: {value}")

    # Binary operators (both children exist)
    if left is not None and right is not None:
        left_val = evaluate(left)
        right_val = evaluate(right)

        if value == "+":
            return left_val + right_val
        elif value == "-":
            return left_val - right_val
        elif value == "*":
            return left_val * right_val
        elif value == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        elif value in ("^", "**"):
            return left_val ** right_val
        elif value == "%":
            return left_val % right_val
        else:
            raise ValueError(f"Unknown binary operator: {value}")

    raise ValueError(f"Invalid AST node representation: {ast}")

