def parse(tokens: list[str]) -> list | str | int | float:
    if not tokens:
        return []

    idx = 0

    def parse_atom(token: str) -> str | int | float:
        if (token.startswith('"') and token.endswith('"')) or (token.startswith("'") and token.endswith("'")):
            if len(token) >= 2:
                return token[1:-1]
        try:
            return int(token)
        except ValueError:
            pass
        try:
            return float(token)
        except ValueError:
            pass
        return token

    def parse_expr() -> list | str | int | float:
        nonlocal idx
        if idx >= len(tokens):
            raise ValueError("Unexpected end of tokens")

        token = tokens[idx]
        if token == "(" or token == "[":
            closing = ")" if token == "(" else "]"
            idx += 1  # consume opening bracket
            sub_exprs = []
            while idx < len(tokens) and tokens[idx] != closing:
                sub_exprs.append(parse_expr())
            if idx >= len(tokens):
                raise ValueError(f"Expected closing '{closing}', reached end of tokens")
            idx += 1  # consume closing bracket
            return sub_exprs
        elif token == ")" or token == "]":
            raise ValueError(f"Unexpected closing token: '{token}'")
        else:
            idx += 1
            return parse_atom(token)

    results = []
    while idx < len(tokens):
        results.append(parse_expr())

    if len(results) == 1:
        return results[0]
    return results

