import operator
import math
from functools import reduce

OP_MAP = {
    '+': operator.add,
    '-': operator.sub,
    '*': operator.mul,
    '/': operator.truediv,
    '//': operator.floordiv,
    '%': operator.mod,
    '**': operator.pow,
    '^': operator.pow,
}

FUNCS = {
    'sin': math.sin,
    'cos': math.cos,
    'tan': math.tan,
    'sqrt': math.sqrt,
    'log': math.log,
    'exp': math.exp,
    'abs': abs,
    'ceil': math.ceil,
    'floor': math.floor,
    'round': round,
}

def evaluate(ast: Union[list, tuple, str, int, float]) -> Union[int, float]:
    """
    Recursively evaluates the parsed nested expression structure and returns the numerical result.
    Supports infix [left, op, right], prefix [op, arg1, arg2, ...], unary operators, and basic math functions.
    """
    if isinstance(ast, (int, float)):
        return ast

    if isinstance(ast, str):
        try:
            if '.' in ast or 'e' in ast.lower():
                return float(ast)
            return int(ast)
        except ValueError:
            lowered = ast.lower()
            if lowered == 'pi':
                return math.pi
            elif lowered == 'e':
                return math.e
            raise ValueError(f"Unknown variable or invalid number: '{ast}'")

    if isinstance(ast, (list, tuple)):
        if not ast:
            raise ValueError("Empty expression cannot be evaluated")

        if len(ast) == 1:
            return evaluate(ast[0])

        # Unary operations (e.g. ['-', 5] or ['sin', 1.57])
        if len(ast) == 2:
            op = ast[0]
            if isinstance(op, str):
                if op == '-':
                    return -evaluate(ast[1])
                elif op == '+':
                    return evaluate(ast[1])
                elif op in FUNCS:
                    return FUNCS[op](evaluate(ast[1]))
            raise ValueError(f"Unsupported unary expression: {ast}")

        # Infix binary operation: [left, op, right]
        if len(ast) == 3 and isinstance(ast[1], str) and ast[1] in OP_MAP:
            op = ast[1]
            left = evaluate(ast[0])
            right = evaluate(ast[2])
            return OP_MAP[op](left, right)

        # Prefix multi-arg operation: [op, arg1, arg2, ...]
        op = ast[0]
        if isinstance(op, str):
            if op in OP_MAP:
                args = [evaluate(x) for x in ast[1:]]
                return reduce(OP_MAP[op], args)
            elif op in FUNCS and len(ast) == 2:
                return FUNCS[op](evaluate(ast[1]))

        raise ValueError(f"Cannot evaluate expression: {ast}")

    raise TypeError(f"Invalid AST node type: {type(ast)}")

