def serialize_tree(node: dict, indent_char: str) -> str:
    lines = []

    def dfs(curr: dict):
        depth = curr.get('depth', -1)
        value = curr.get('value')

        # If the node is not a dummy root (typically depth < 0), serialize it
        if depth >= 0 and value is not None:
            lines.append(f"{indent_char * depth}{value}")

        for child in curr.get('children', []):
            dfs(child)

