import re
from typing import Dict, Any, List, Optional

def tokenize(expr: str) -> List[str]:
    # Remove all whitespace
    squeezed = "".join(expr.split())
    # Regex to match float/int, variables/identifiers, and single-character operators
    pattern = re.compile(r'(\d+(?:\.\d+)?|[a-zA-Z_]\w*|[\+\-\*\/\^\(\)])')
    tokens = pattern.findall(squeezed)

    # Check if there were any invalid characters by reconstructing the string
    reconstructed = "".join(tokens)
    if len(reconstructed) != len(squeezed):
        raise SyntaxError("Expression contains invalid characters")

    return tokens

class Parser:
    def __init__(self, tokens: List[str]):
        self.tokens = tokens
        self.pos = 0

    def current(self) -> Optional[str]:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self, expected: Optional[str] = None) -> str:
        token = self.current()
        if token is None:
            raise SyntaxError("Unexpected end of input")
        if expected is not None and token != expected:
            raise SyntaxError(f"Expected '{expected}', got '{token}'")
        self.pos += 1
        return token

    def parse_expr(self) -> Dict[str, Any]:
        # expr -> term ((+ | -) term)*
        node = self.parse_term()
        while self.current() in ('+', '-'):
            op = self.consume()
            right = self.parse_term()
            node = {
                'type': 'OPERATOR',
                'value': op,
                'left': node,
                'right': right
            }
        return node

    def parse_term(self) -> Dict[str, Any]:
        # term -> factor ((* | /) factor)*
        node = self.parse_factor()
        while self.current() in ('*', '/'):
            op = self.consume()
            right = self.parse_factor()
            node = {
                'type': 'OPERATOR',
                'value': op,
                'left': node,
                'right': right
            }
        return node

    def parse_factor(self) -> Dict[str, Any]:
        # factor -> primary (^ factor)? (right-associative exponentiation)
        node = self.parse_primary()
        if self.current() == '^':
            op = self.consume()
            right = self.parse_factor()
            node = {
                'type': 'OPERATOR',
                'value': op,
                'left': node,
                'right': right
            }
        return node

    def parse_primary(self) -> Dict[str, Any]:
        token = self.current()
        if token is None:
            raise SyntaxError("Unexpected end of input")

        if token == '(':
            self.consume('(')
            node = self.parse_expr()
            self.consume(')')
            return node

        if token == '-':
            self.consume('-')
            right = self.parse_primary()
            return {
                'type': 'UNARY_OPERATOR',
                'value': '-',
                'left': None,
                'right': right
            }

        if token == '+':
            self.consume('+')
            return self.parse_primary()

        # Check for numbers
        if re.match(r'^\d+(?:\.\d+)?$', token):
            self.consume()
            return {
                'type': 'NUMBER',
                'value': token,
                'left': None,
                'right': None
            }

        # Check for identifiers (variables/functions)
        if re.match(r'^[a-zA-Z_]\w*$', token):
            self.consume()
            return {
                'type': 'IDENTIFIER',
                'value': token,
                'left': None,
                'right': None
            }

        raise SyntaxError(f"Unexpected token: '{token}'")

def parse(expr: str) -> Dict[str, Any]:
    """
    Parses an infix expression string into an Abstract Syntax Tree (AST).
    Returns a dictionary representing the root of the AST.
    """
    tokens = tokenize(expr)
    if not tokens:
        raise SyntaxError("Empty expression")

    parser = Parser(tokens)
    ast = parser.parse_expr()

    if parser.current() is not None:
        raise SyntaxError(f"Unparsed tokens remaining starting at '{parser.current()}'")

    return ast

