    def _fold(node: dict | None) -> dict | None:
        if node is None:
            return None

        folded_left = _fold(node.get("left"))
        folded_right = _fold(node.get("right"))

        node_type = node.get("type")
        node_value = node.get("value")

        def is_constant(n: dict | None) -> bool:
            if n is None:
                return False
            const_types = {"constant", "number", "integer", "float", "literal", "NUMBER", "INTEGER", "FLOAT"}
            return n.get("type") in const_types and n.get("left") is None and n.get("right") is None

        def get_numeric_value(val_str: str):
            try:
                if '.' in val_str or 'e' in val_str.lower():
                    return float(val_str)
                return int(val_str)
            except ValueError:
                return None

        # Unary operators (+, -)
        if folded_left is None and is_constant(folded_right):
            val = get_numeric_value(folded_right["value"])
            if val is not None and node_value in ("+", "-"):
                try:
                    res = -val if node_value == "-" else +val
                    return {
                        "type": folded_right["type"],
                        "value": str(res),
                        "left": None,
                        "right": None
                    }
                except Exception:
                    pass

        # Binary operators
        if is_constant(folded_left) and is_constant(folded_right):
            left_val = get_numeric_value(folded_left["value"])
            right_val = get_numeric_value(folded_right["value"])
            if left_val is not None and right_val is not None:
                res = None
                try:
                    if node_value == "+":
                        res = left_val + right_val
                    elif node_value == "-":
                        res = left_val - right_val
                    elif node_value == "*":
                        res = left_val * right_val
                    elif node_value == "/":
                        res = left_val / right_val
                    elif node_value == "//":
                        res = left_val // right_val
                    elif node_value == "%":
                        res = left_val % right_val
                    elif node_value == "**":
                        res = left_val ** right_val

