                        # Determine a suitable type for the folded constant
                        folded_type = folded_left.get("type") or "constant"
                        return {
                            "type": folded_type,
                            "value": str(res),
                            "left": None,
                            "right": None
                        }
                except Exception:
                    pass

        return {
            "type": node_type,
            "value": node_value,
            "left": folded_left,
            "right": folded_right
        }

