    'and': 2,
    'not': 3,
    '==': 4, '!=': 4, '<': 4, '<=': 4, '>': 4, '>=': 4,
    '+': 5, '-': 5,
    '*': 6, '/': 6, '//': 6, '%': 6,
    '^': 7, '**': 7
