def validate_dependency_graph(graph: dict[str, list[str]]) -> bool:
    """
    Validates a module dependency graph.
    Returns True if the graph is a Directed Acyclic Graph (DAG) and has valid structure,
    False otherwise (e.g., if there is a cyclic dependency or invalid data types).
    """
    if not isinstance(graph, dict):
        return False

    for k, v in graph.items():
        if not isinstance(k, str):
            return False
        if not isinstance(v, list):
            return False
        if not all(isinstance(dep, str) for dep in v):
            return False

    visited = set()
    rec_stack = set()

    def has_cycle(node: str) -> bool:
        visited.add(node)
        rec_stack.add(node)

        # Dependencies that are not keys in the graph are treated as leaves.
        neighbors = graph.get(node, [])
        for neighbor in neighbors:
            if neighbor not in visited:
                if has_cycle(neighbor):
                    return True
            elif neighbor in rec_stack:
                return True

        rec_stack.remove(node)
        return False

    for node in graph:
        if node not in visited:
            if has_cycle(node):
                return False

    return True

