def resolve(graph: dict[str, list[str]]) -> tuple[bool, list[str], list[list[str]]]:
    if not validate_dependency_graph(graph):
        return False, [], []

    # Gather all nodes to handle nodes that appear only in dependency lists
    all_nodes = set(graph.keys())
    for deps in graph.values():
        all_nodes.update(deps)

    full_graph = {node: graph.get(node, []) for node in all_nodes}

    # Tarjan's algorithm for cycle detection and SCCs
    index = 0
    indices = {}
    lowlink = {}
    on_stack = set()
    stack = []
    sccs = []

    def strongconnect(v):
        nonlocal index
        indices[v] = index
        lowlink[v] = index
        index += 1
        stack.append(v)
        on_stack.add(v)

        for w in full_graph[v]:
            if w not in indices:
                strongconnect(w)
                lowlink[v] = min(lowlink[v], lowlink[w])
            elif w in on_stack:
                lowlink[v] = min(lowlink[v], indices[w])

        if lowlink[v] == indices[v]:
            scc = []
            while True:
                w = stack.pop()
                on_stack.remove(w)
                scc.append(w)
                if w == v:
                    break
            sccs.append(scc)

    for node in full_graph:
        if node not in indices:
            strongconnect(node)

    # Detect cycles (SCC size > 1, or size == 1 with a self-loop)
    has_cycle = False
    cycles = []
    for scc in sccs:
        if len(scc) > 1:
            has_cycle = True
            cycles.append(sorted(scc))
        elif len(scc) == 1:
            node = scc[0]
            if node in full_graph[node]:
                has_cycle = True
                cycles.append(scc)

    if has_cycle:
        # Return sorted list of cycle components for determinism
        return False, [], sorted(cycles)

    # Kahn's algorithm for topological sorting and parallel layer grouping
    in_degree = {node: 0 for node in full_graph}
    adj = {node: [] for node in full_graph}

    for u, deps in full_graph.items():
        for v in deps:
            adj[v].append(u)
            in_degree[u] += 1

    queue = [node for node in full_graph if in_degree[node] == 0]
    topo_order = []
    layers = []

    while queue:
        layers.append(sorted(queue))
        next_queue = []
        for u in sorted(queue):  # Sort for deterministic processing order
            topo_order.append(u)
            for v in adj[u]:
                in_degree[v] -= 1
                if in_degree[v] == 0:
                    next_queue.append(v)
        queue = next_queue

    return True, topo_order, layers

