from typing import Optional

class Node:
    def __init__(self, key: int):
        self.key: int = key
        self.left: Optional[Node] = None
        self.right: Optional[Node] = None

def insert(root: Optional[Node], key: int) -> Node:
    if root is None:
        return Node(key)
    if key < root.key:
        root.left = insert(root.left, key)
    elif key > root.key:
        root.right = insert(root.right, key)
    return root

def find(root: Optional[Node], key: int) -> bool:
    if root is None:
        return False
    if root.key == key:
        return True
    elif key < root.key:
        return find(root.left, key)
    else:
        return find(root.right, key)

def delete(root: Optional[Node], key: int) -> Optional[Node]:
    if root is None:
        return None

    if key < root.key:
        root.left = delete(root.left, key)
    elif key > root.key:
        root.right = delete(root.right, key)
    else:
        if root.left is None:
            return root.right
        elif root.right is None:
            return root.left

        # Node with two children: Get the inorder successor (smallest in the right subtree)
        temp = root.right
        while temp.left is not None:
            temp = temp.left

        root.key = temp.key
        root.right = delete(root.right, temp.key)

    return root

def inorder(root: Optional[Node]) -> list[int]:
    result: list[int] = []
    def _helper(node: Optional[Node]) -> None:
        if node is not None:
            _helper(node.left)
            result.append(node.key)
            _helper(node.right)
    _helper(root)
    return result

