def validate_brackets(text: str) -> bool:
    """
    Validates if the parentheses, brackets, and braces in a given string
    are correctly matched and nested.

    Args:
        text (str): The input string to check.

    Returns:
        bool: True if brackets are correctly matched and nested, False otherwise.
    """
    stack = []
    matching_map = {')': '(', ']': '[', '}': '{'}
    opening_brackets = set(matching_map.values())

    for char in text:
        if char in opening_brackets:
            stack.append(char)
        elif char in matching_map:
            if not stack or stack[-1] != matching_map[char]:
                return False
            stack.pop()

    return len(stack) == 0

