    if not _filepath:
        return {}
    try:
        return load_graph(_filepath)
    except Exception:
        return {}

def _save(data: dict[str, list[str]]) -> None:
    global _filepath
    if _filepath:
        save_graph(_filepath, data)

def initialize_graph(filepath: str) -> None:
    global _filepath
    _filepath = filepath
    try:
        # Attempt to load existing graph to verify/use it
        _load()
    except Exception:
        # If loading fails, initialize an empty graph
        _save({})

def add_vertex(vertex: str) -> bool:
    graph = _load()
    if vertex in graph:
        return False
    graph[vertex] = []
    _save(graph)
    return True

def remove_vertex(vertex: str) -> bool:
    graph = _load()
    if vertex not in graph:
        return False

    # Remove the vertex
    del graph[vertex]

    # Remove all incoming edges pointing to this vertex
    for source in graph:
        graph[source] = [target for target in graph[source] if target != vertex]

    _save(graph)
    return True

def list_vertices() -> list[str]:
    graph = _load()
    return list(graph.keys())

def add_edge(source: str, target: str) -> bool:
    graph = _load()
    if source not in graph or target not in graph:
        return False
    if target in graph[source]:
        return False  # Edge already exists
    graph[source].append(target)
    _save(graph)
    return True

def remove_edge(source: str, target: str) -> bool:
    graph = _load()
    if source not in graph or target not in graph[source]:
        return False
    graph[source].remove(target)
    _save(graph)
    return True

