def add_tag(hierarchy: dict[str, list[str]], tag: str, parent: str | None) -> dict[str, list[str]]:
    if "" not in hierarchy:
        hierarchy[""] = []

    # Ensure tree property: remove tag from any existing parent list
    for p, children in hierarchy.items():
        if tag in children:
            children.remove(tag)

    if parent is None:
        parent_key = ""
    else:
        parent_key = parent
        if parent_key not in hierarchy:
            add_tag(hierarchy, parent_key, None)

    if parent_key not in hierarchy:
        hierarchy[parent_key] = []

    if tag not in hierarchy[parent_key]:
        hierarchy[parent_key].append(tag)

    if tag not in hierarchy:
        hierarchy[tag] = []

    return hierarchy


def delete_tag(hierarchy: dict[str, list[str]], tag: str) -> dict[str, list[str]]:
    all_tags = get_all_tags(hierarchy)
    if tag not in hierarchy and tag not in all_tags:
        return hierarchy

    to_delete = [tag] + get_descendants(hierarchy, tag)
    to_delete_set = set(to_delete)

    for t in to_delete_set:
        if t in hierarchy:
            del hierarchy[t]

    for p, children in list(hierarchy.items()):
        hierarchy[p] = [c for c in children if c not in to_delete_set]

    return hierarchy


def get_all_tags(hierarchy: dict[str, list[str]]) -> list[str]:
    all_tags = set()
    for parent, children in hierarchy.items():
        if parent != "":
            all_tags.add(parent)
        for child in children:
            if child != "":
                all_tags.add(child)
    return list(all_tags)


def get_descendants(hierarchy: dict[str, list[str]], tag: str) -> list[str]:
    descendants = []
    queue = list(hierarchy.get(tag, []))
    visited = set()
    while queue:
        current = queue.pop(0)
        if current not in visited:
            visited.add(current)
            descendants.append(current)
            queue.extend(hierarchy.get(current, []))
    return descendants

