def parse(tokens: list[dict]) -> dict:
    pos = 0

    def peek(offset=0):
        idx = pos + offset
        if idx < len(tokens):
            return tokens[idx]
        return None

    def match_type(types, offset=0):
        tok = peek(offset)
        if not tok:
            return False
        t = tok.get('type', '')
        if isinstance(types, str):
            types = [types]
        types_upper = [x.upper() for x in types]
        return t in types or t.upper() in types_upper

    def match_val(vals, offset=0):
        tok = peek(offset)
        if not tok:
            return False
        v = tok.get('value', '')
        if isinstance(vals, str):
            vals = [vals]
        return v in vals

    def consume():
        nonlocal pos
        tok = peek()
        pos += 1
        return tok

    def parse_primary():
        tok = peek()
        if not tok:
            raise SyntaxError("Unexpected end of input")

        if match_val('(') or match_type(['LPAREN', 'PAREN']):
            consume()  # '('
            expr = parse_expression()
            next_tok = peek()
            if next_tok and (match_val(')') or match_type(['RPAREN', 'PAREN'])):
                consume()  # ')'
            else:
                raise SyntaxError("Expected ')'")
            return expr

        if match_type(['NUMBER', 'NUM', 'INT', 'FLOAT', 'DIGIT']) or (tok.get('value', '').replace('.', '', 1).isdigit()):
            t = consume()
            val_str = t.get('value', '')
            try:
                val = float(val_str) if '.' in val_str else int(val_str)
            except ValueError:
                val = val_str
            return {
                "type": "NumericLiteral",
                "value": val
            }

        if match_type(['STRING', 'STR', 'LITERAL']):
            t = consume()
            return {
                "type": "StringLiteral",
                "value": t.get('value', '')
            }

        if match_type(['IDENTIFIER', 'IDENT', 'ID', 'VAR', 'NAME']):
            t = consume()
            return {
                "type": "Identifier",
                "name": t.get('value', '')
            }

        if tok.get('value', '').isidentifier():
            t = consume()
            return {
                "type": "Identifier",
                "name": t.get('value', '')
            }

        raise SyntaxError(f"Unexpected token: {tok}")

    def parse_unary():
        if match_val(['-', '+', '!']) or match_type(['MINUS', 'PLUS', 'NOT', 'BANG']):
            op_tok = consume()
            op = op_tok.get('value', '')
            argument = parse_unary()
            return {
                "type": "UnaryExpression",
                "operator": op,
                "argument": argument
            }
        return parse_primary()

    def parse_multiplicative():
        expr = parse_unary()
        while True:
            if match_val(['*', '/']) or match_type(['MUL', 'DIV', 'STAR', 'SLASH']):
                op_tok = consume()
                op = op_tok.get('value', '')
                right = parse_unary()
                expr = {
                    "type": "BinaryExpression",
                    "operator": op,
                    "left": expr,
                    "right": right
                }
            else:
                break
        return expr

    def parse_additive():
        expr = parse_multiplicative()
        while True:
            if match_val(['+', '-']) or match_type(['PLUS', 'MINUS']):
                op_tok = consume()
                op = op_tok.get('value', '')
                right = parse_multiplicative()
                expr = {
                    "type": "BinaryExpression",
                    "operator": op,
                    "left": expr,
                    "right": right
                }
            else:
                break
        return expr

    def parse_comparison():
        expr = parse_additive()
        while True:
            if match_val(['==', '!=', '<', '>', '<=', '>=']) or match_type(['EQ', 'NE', 'LT', 'GT', 'LTE', 'GTE', 'COMPARE']):
                op_tok = consume()
                op = op_tok.get('value', '')
                right = parse_additive()
                expr = {
                    "type": "BinaryExpression",
                    "operator": op,
                    "left": expr,
                    "right": right
                }
            else:
                break
        return expr

    def parse_assignment():
        if (match_type(['IDENTIFIER', 'IDENT', 'ID', 'VAR', 'NAME']) or (peek() and peek().get('value', '').isidentifier())) \
           and peek(1) and (peek(1).get('value') == '=' or peek(1).get('type', '').upper() in ['ASSIGN', 'EQUALS']):
            left = parse_primary()
            consume()  # '='
            right = parse_expression()
            return {
                "type": "AssignmentExpression",
                "operator": "=",
                "left": left,
                "right": right
            }
        return parse_comparison()

    def parse_expression():
        return parse_assignment()

    def parse_statement():
        expr = parse_expression()
        if peek() and (peek().get('value') == ';' or peek().get('type', '').upper() == 'SEMICOLON'):
            consume()
        return expr

    body = []
    while pos < len(tokens):
        if match_type(['NEWLINE', 'WHITESPACE', 'SPACE', 'COMMENT']):
            consume()
            continue
        body.append(parse_statement())

    return {
        "type": "Program",
        "body": body
    }

