def evaluate(ast: dict) -> float:
    if not isinstance(ast, dict):
        return float(ast)

    node_type = str(ast.get("type", "")).lower()

    if node_type in ("number", "num", "literal"):
        return float(ast.get("value", ast.get("val", 0)))

    elif node_type in ("binary", "binaryop", "binop"):
        op = ast.get("op", ast.get("operator"))
        left = evaluate(ast["left"])
        right = evaluate(ast["right"])

