def evaluate(node: list | int | float | str) -> int | float:
    if isinstance(node, (int, float)):
        return node

    if isinstance(node, str):
        # Attempt to parse a numeric string, otherwise raise an error
        try:
            if '.' in node or 'e' in node.lower():
                return float(node)
            return int(node)
        except ValueError:
            raise ValueError(f"Unknown variable or invalid numeric string: {node}")

