        args = node[1:]

        if op == '+':
            return sum(evaluate(arg) for arg in args)

        elif op == '-':
            if not args:
                raise ValueError("'-' operator requires at least one argument.")
            evaluated_args = [evaluate(arg) for arg in args]
            if len(evaluated_args) == 1:
                return -evaluated_args[0]
            return evaluated_args[0] - sum(evaluated_args[1:])

