            prod = 1
            for arg in args:
                prod *= evaluate(arg)
            return prod

        elif op == '/':
            if not args:
                raise ValueError("'/' operator requires at least one argument.")
            evaluated_args = [evaluate(arg) for arg in args]
            if len(evaluated_args) == 1:
                return 1 / evaluated_args[0]
            result = evaluated_args[0]
            for val in evaluated_args[1:]:
                result /= val
            return result

        elif op in ('pow', '**'):
            if len(args) != 2:
                raise ValueError("Power operator requires exactly two arguments.")
            return evaluate(args[0]) ** evaluate(args[1])

        elif op in ('mod', '%'):
            if len(args) != 2:
                raise ValueError("Modulo operator requires exactly two arguments.")
            return evaluate(args[0]) % evaluate(args[1])

        else:
            raise ValueError(f"Unknown operator: '{op}'")

    raise TypeError(f"Invalid node type in S-expression: {type(node)}")

