def find_connected_components(adj_list: dict[int, list[int]]) -> list[list[int]]:
    visited = set()
    components = []

    for node in adj_list:
        if node not in visited:
            component = []
            queue = deque([node])
            visited.add(node)

            while queue:
                curr = queue.popleft()
                component.append(curr)

                # Get neighbors, default to empty list if key doesn't exist
                neighbors = adj_list.get(curr, [])
