def normalize_graph(raw_graph: dict[str, list[str]]) -> dict[str, list[str]]:
    """
    Validates and normalizes the dependency graph.

    Ensures that all referenced modules (dependencies) exist as nodes (keys) in the graph.
    If a referenced module does not exist as a key, it is added with an empty list of dependencies.
    Additionally, deduplicates and sorts dependency lists, and returns the graph with keys
    sorted for deterministic ordering.
    """
    normalized: dict[str, list[str]] = {}

    # Process existing nodes, deduplicate and sort their dependencies
    for node, dependencies in raw_graph.items():
        if dependencies is None:
            normalized[node] = []
        else:
            normalized[node] = sorted(list(set(dependencies)))

    # Find all referenced nodes
    referenced_nodes = set()
    for deps in normalized.values():
        referenced_nodes.update(deps)

    # Ensure all referenced nodes exist as keys
    for node in referenced_nodes:
        if node not in normalized:
            normalized[node] = []

    # Return a dictionary sorted by keys for consistency
    return {k: normalized[k] for k in sorted(normalized.keys())}

