def resolve_dependencies(graph: dict[str, list[str]]) -> tuple[bool, list[str], list[str]]:
    # Gather all unique nodes in the graph
    all_nodes = set(graph.keys())
    for deps in graph.values():
        all_nodes.update(deps)

    # State: 0 = unvisited, 1 = visiting, 2 = visited
    state = {node: 0 for node in all_nodes}
    order = []
    cycle = []
    parent = {}

    def dfs(u: str) -> bool:
        state[u] = 1  # visiting
        dependencies = graph.get(u, [])
        for v in dependencies:
            if state[v] == 1:
                # Cycle detected. Reconstruct cycle from u back to v.
                curr = u
                cycle_path = []
                while curr != v:
                    cycle_path.append(curr)
                    curr = parent.get(curr, v)
                cycle_path.append(v)
                cycle_path.reverse()
                cycle.extend(cycle_path)
                return False
            elif state[v] == 0:
                parent[v] = u
                if not dfs(v):
                    return False
        state[u] = 2  # visited
        order.append(u)
        return True

    for node in sorted(all_nodes):
        if state[node] == 0:
            if not dfs(node):
                return False, [], cycle

    return True, order, []

