            if v2 == 0:
                return None, None
            res = v1 // v2
        elif op == "%":
            if v2 == 0:
                return None, None
            res = v1 % v2
        elif op == "**":
            if isinstance(v2, (int, float)) and v2 > 1000:
                return None, None
            res = v1 ** v2
        elif op in ("==", "==="):
            res = v1 == v2
            res_type = "BOOLEAN"
        elif op in ("!=", "!=="):
            res = v1 != v2
            res_type = "BOOLEAN"
        elif op == "<":
            res = v1 < v2
            res_type = "BOOLEAN"
        elif op == "<=":
            res = v1 <= v2
            res_type = "BOOLEAN"
        elif op == ">":
            res = v1 > v2
            res_type = "BOOLEAN"
        elif op == ">=":
            res = v1 >= v2
            res_type = "BOOLEAN"
        elif op in ("and", "&&"):
            res = v1 and v2
            res_type = left_node.get("type") if res == v1 else right_node.get("type")
        elif op in ("or", "||"):
            res = v1 or v2
            res_type = left_node.get("type") if res == v1 else right_node.get("type")
        else:
            return None, None
    except Exception:
        return None, None

    if isinstance(res, bool):
        return str(res).lower(), "BOOLEAN"
    if isinstance(res, float):
        return str(res), "FLOAT"
    if isinstance(res, int):
        return str(res), "INT" if left_node.get("type") == "INT" else "NUMBER"
    if isinstance(res, str):
        v1_raw = left_node.get("value", "")
        has_quotes = len(v1_raw) >= 2 and ((v1_raw[0] == '"' and v1_raw[-1] == '"') or (v1_raw[0] == "'" and v1_raw[-1] == "'"))
        if has_quotes:
            quote_char = v1_raw[0]
            return f"{quote_char}{res}{quote_char}", "STRING"
        return res, "STRING"

    return None, None

def evaluate_unaryop(node: dict, op: str):
    try:
        v = parse_val(node)
    except ValueError:
        return None, None

    res_type = node.get("type", "NUMBER")
    try:
        if op == "-":
            res = -v
        elif op == "+":
            res = +v
        elif op in ("not", "!"):
            res = not v
            res_type = "BOOLEAN"
        elif op == "~":
            res = ~v
        else:
            return None, None
    except Exception:
        return None, None

    if isinstance(res, bool):
        return str(res).lower(), "BOOLEAN"
    if isinstance(res, float):
        return str(res), "FLOAT"
    if isinstance(res, int):
        return str(res), "INT" if node.get("type") == "INT" else "NUMBER"
    return None, None

def fold_constants(tree: dict) -> dict:
    if tree is None:
        return None

    if not isinstance(tree, dict):
        return tree

    processed = {}
    for k, v in tree.items():
        if k in ("left", "right"):
            continue
        if isinstance(v, dict):
            processed[k] = fold_constants(v)
        elif isinstance(v, list):
            processed[k] = [fold_constants(item) if isinstance(item, dict) else item for item in v]
        else:
            processed[k] = v

    left = fold_constants(tree.get("left"))
    right = fold_constants(tree.get("right"))

    new_node = tree.copy()
    new_node.update(processed)
    new_node["left"] = left
    new_node["right"] = right

    if left is not None and right is not None:
        if is_constant(left) and is_constant(right):
            op = tree.get("value")
            if op:
                val, res_type = evaluate_binop(left, right, op)
                if val is not None:
                    folded = new_node.copy()
                    folded.update({
                        "type": res_type,
                        "value": val,
                        "left": None,
                        "right": None
                    })
                    return folded

    op = tree.get("value")
    if op in ("-", "+", "not", "~", "!"):
        child = None
        if left is not None and right is None:
            child = left
        elif right is not None and left is None:
            child = right

        if child is not None and is_constant(child):
            val, res_type = evaluate_unaryop(child, op)
            if val is not None:
                folded = new_node.copy()
                folded.update({
                    "type": res_type,
                    "value": val,
                    "left": None,
                    "right": None
                })
                return folded

    return new_node

