from typing import Dict, Any, Optional

def to_string(tree: Optional[Dict[str, Any]]) -> str:
    if not tree:
        return ""

    PRECEDENCE = {
        '+': 1, '-': 1,
        '*': 2, '/': 2,
        '^': 3,
    }
    RIGHT_ASSOCIATIVE = {'^'}

    def get_precedence(node: Optional[Dict[str, Any]]) -> int:
        if not node:
            return 0
        node_type = node.get("type")
        val = str(node.get("value", ""))
        left = node.get("left")
        right = node.get("right")

        if left is None and right is None:
            return 5  # Leaf node
        if left is None or right is None:
            if node_type in ("function", "func") or (val.isalnum() and not val.isdigit()):
                return 5  # Function call
            return 4  # Unary operator
        return PRECEDENCE.get(val, 1)

    def format_node(node: Optional[Dict[str, Any]]) -> str:
        if not node:
            return ""

        node_type = node.get("type")
        value = str(node.get("value", ""))
        left = node.get("left")
        right = node.get("right")

        # Leaf node
        if left is None and right is None:
            return value

        # Unary node (one child)
        if left is None or right is None:
            child = left if left is not None else right
            child_str = format_node(child)
            is_func = node_type in ("function", "func") or (value.isalpha() and len(value) > 1)
            if is_func:
                return f"{value}({child_str})"
            else:
                child_prec = get_precedence(child)
                if child_prec < 4:
                    return f"{value}({child_str})"
                return f"{value}{child_str}"

        # Binary node
        left_str = format_node(left)
        right_str = format_node(right)

        op = value
        prec = PRECEDENCE.get(op, 1)

        left_prec = get_precedence(left)
        right_prec = get_precedence(right)

        # Parenthesization rules for left child
        if left_prec < prec:
            left_str = f"({left_str})"
        elif left_prec == prec and op in RIGHT_ASSOCIATIVE:
            left_str = f"({left_str})"

        # Parenthesization rules for right child
        if right_prec < prec:
            right_str = f"({right_str})"
        elif right_prec == prec:
            if op not in RIGHT_ASSOCIATIVE:
                right_str = f"({right_str})"

        return f"{left_str} {op} {right_str}"

    return format_node(tree)

