from collections import deque

def find_connected_components(graph: dict[str, list[str]]) -> list[list[str]]:
    """
    Finds the connected components of a graph using Breadth-First Search (BFS).
    The graph is treated as undirected.

    :param graph: Adjacency list representing the graph.
    :return: A list of connected components, where each component is a list of node IDs.
    """
    # Build an undirected representation to ensure connectivity is correctly
    # traversed and all mentioned nodes are accounted for.
    adj = {}
    for u in graph:
        if u not in adj:
            adj[u] = set()
        for v in graph[u]:
            if v not in adj:
                adj[v] = set()
            adj[u].add(v)
            adj[v].add(u)

    visited = set()
    components = []

    for node in adj:
        if node not in visited:
            component = []
            queue = deque([node])
            visited.add(node)

            while queue:
                curr = queue.popleft()
                component.append(curr)
                for neighbor in adj[curr]:
                    if neighbor not in visited:
                        visited.add(neighbor)
                        queue.append(neighbor)
            components.append(component)

    return components

