def summarize_components(components: list[list[str]]) -> list[dict[str, str | int]]:
    summaries = []
    for comp in components:
        if not comp:
            summaries.append({"representative": "", "size": 0})
        else:
            # Deterministically choose the lexicographically smallest node as the representative
            representative = min(comp)
            summaries.append({
                "representative": representative,
                "size": len(comp)
            })
    return summaries

def get_largest_component(
    components: list[list[str]], 
    summaries: list[dict[str, str | int]]
) -> dict[str, str | int | list[str]]:
    if not components or not summaries:
        return {"representative": "", "size": 0, "nodes": []}

    largest_idx = 0
    max_size = -1

    for i, summary in enumerate(summaries):
        size = summary.get("size", 0)
        if isinstance(size, int) and size > max_size:
            max_size = size
            largest_idx = i

    largest_summary = summaries[largest_idx]
    return {
        "representative": largest_summary.get("representative", ""),
        "size": largest_summary.get("size", 0),
        "nodes": components[largest_idx]
    }

