def parse_dependencies(raw_data: dict[str, list[str]]) -> dict[str, list[str]]:
    """
    Validates and normalizes raw dependency declarations into a clean adjacency list.

    - Cleans whitespace from keys and dependency names.
    - Removes duplicate dependencies for a given key while preserving order.
    - Removes self-dependencies.
    - Ensures all referenced dependencies exist as keys in the returned dictionary.
    """
    if not isinstance(raw_data, dict):
        raise TypeError("Input raw_data must be a dictionary")

    normalized: dict[str, list[str]] = {}

    # First pass: Clean keys and their list of dependencies
    for raw_key, raw_deps in raw_data.items():
        if not isinstance(raw_key, str):
            continue

        key = raw_key.strip()
        if not key:
            continue

        if not isinstance(raw_deps, list):
            raw_deps = []

        cleaned_deps = []
        seen = set()
        for dep in raw_deps:
            if not isinstance(dep, str):
                continue
            dep_clean = dep.strip()
            if dep_clean and dep_clean != key and dep_clean not in seen:
                seen.add(dep_clean)
                cleaned_deps.append(dep_clean)

        normalized[key] = cleaned_deps

    # Second pass: Ensure all referenced nodes exist as keys in the adjacency list
    all_referenced = set()
    for deps in normalized.values():
        all_referenced.update(deps)

    for ref in all_referenced:
        if ref not in normalized:
            normalized[ref] = []

    return normalized

