def resolve_build_order(graph: dict[str, list[str]]) -> tuple[list[str], list[list[str]]]:
    # Normalize graph: ensure all dependencies are in the graph as keys
    adj = {}
    for node, deps in graph.items():
        adj[node] = list(deps)
    for deps in graph.values():
        for dep in deps:
            if dep not in adj:
                adj[dep] = []

    visited = {node: 0 for node in adj}  # 0: unvisited, 1: visiting, 2: visited
    order = []
    cycles = []
    path = []

    def dfs(u):
        visited[u] = 1
        path.append(u)

        for v in adj[u]:
            if visited[v] == 1:
                # Cycle detected
                try:
                    idx = path.index(v)
                    cycle = path[idx:] + [v]
                    cycles.append(cycle)
                except ValueError:
                    pass
            elif visited[v] == 0:
                dfs(v)

        path.pop()
        visited[u] = 2
        order.append(u)

    # Sort keys for deterministic output
    for node in sorted(adj.keys()):
        if visited[node] == 0:
            dfs(node)

    if cycles:
        # Deduplicate and normalize cycles
        unique_cycles = []
        seen_cycles = set()
        for cyc in cycles:
            if not cyc:
                continue
            nodes = cyc[:-1]
            if not nodes:
                nodes = [cyc[0]]
            min_idx = nodes.index(min(nodes))
            normalized = tuple(nodes[min_idx:] + nodes[:min_idx])
            if normalized not in seen_cycles:
                seen_cycles.add(normalized)
                unique_cycles.append(list(normalized) + [normalized[0]])
        return [], unique_cycles

    return order, []

