from typing import Any

def insert_key(tree: dict | None, key: int) -> dict:
    if tree is None:
        return {"key": key, "left": None, "right": None}

    if key < tree["key"]:
        return {
            "key": tree["key"],
            "left": insert_key(tree["left"], key),
            "right": tree["right"]
        }
    elif key > tree["key"]:
        return {
            "key": tree["key"],
            "left": tree["left"],
            "right": insert_key(tree["right"], key)
        }
    else:
        # Key already exists, return copy of the tree
        return {
            "key": tree["key"],
            "left": tree["left"],
            "right": tree["right"]
        }

def find_key(tree: dict | None, key: int) -> bool:
    if tree is None:
        return False
    if key == tree["key"]:
        return True
    elif key < tree["key"]:
        return find_key(tree["left"], key)
    else:
        return find_key(tree["right"], key)

def _find_min_key(tree: dict) -> int:
    if tree["left"] is None:
        return tree["key"]
    return _find_min_key(tree["left"])

def delete_key(tree: dict | None, key: int) -> dict | None:
    if tree is None:
        return None

    if key < tree["key"]:
        return {
            "key": tree["key"],
            "left": delete_key(tree["left"], key),
            "right": tree["right"]
        }
    elif key > tree["key"]:
        return {
            "key": tree["key"],
            "left": tree["left"],
            "right": delete_key(tree["right"], key)
        }
    else:
        # Found node to delete
        if tree["left"] is None and tree["right"] is None:
            return None
        elif tree["left"] is None:
            return tree["right"]
        elif tree["right"] is None:
            return tree["left"]
        else:
            # Node with two children: Get the in-order successor (smallest in the right subtree)
            successor_val = _find_min_key(tree["right"])
            return {
                "key": successor_val,
                "left": tree["left"],
                "right": delete_key(tree["right"], successor_val)
            }

def get_in_order(tree: dict | None) -> list[int]:
    if tree is None:
        return []
    return get_in_order(tree["left"]) + [tree["key"]] + get_in_order(tree["right"])

