def check_brackets(text: str) -> bool:
    """
    Checks if the brackets (parentheses, square brackets, and curly braces)
    in the given string are correctly paired and nested.
    """
    stack = []
    bracket_map = {')': '(', ']': '[', '}': '{'}

    for char in text:
        if char in bracket_map.values():
            stack.append(char)
        elif char in bracket_map:
            if not stack or stack[-1] != bracket_map[char]:
                return False
            stack.pop()

    return len(stack) == 0

