import json
import os

def load_data(file_path: str) -> dict[str, list]:
    """
    Loads graph data from a local JSON file.
    If the file does not exist or is invalid, returns an empty structure.
    """
    if not os.path.exists(file_path):
        return {"nodes": [], "edges": []}

    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            data = json.load(f)
            if not isinstance(data, dict):
                return {"nodes": [], "edges": []}
            # Ensure basic structure exists
            if "nodes" not in data or not isinstance(data["nodes"], list):
                data["nodes"] = []
            if "edges" not in data or not isinstance(data["edges"], list):
                data["edges"] = []
            return data
    except (json.JSONDecodeError, IOError):
        return {"nodes": [], "edges": []}

def save_data(file_path: str, data: dict) -> None:
    """
    Saves graph data to a local JSON file.
    Creates containing directories if they do not exist.
    """
    dir_name = os.path.dirname(file_path)
    if dir_name and not os.path.exists(dir_name):
        os.makedirs(dir_name, exist_ok=True)

    with open(file_path, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=4, ensure_ascii=False)

