from __future__ import annotations
import copy

def add_tag(hierarchy: dict[str, list[str]], tag: str, parent: str | None) -> dict[str, list[str]]:
    hierarchy_copy = copy.deepcopy(hierarchy)
    if parent is not None:
        if parent not in hierarchy_copy:
            hierarchy_copy[parent] = []
        if tag not in hierarchy_copy[parent]:
            hierarchy_copy[parent].append(tag)
    if tag not in hierarchy_copy:
        hierarchy_copy[tag] = []
    return hierarchy_copy

def get_descendants(hierarchy: dict[str, list[str]], tag: str) -> list[str]:
    descendants = []
    queue = list(hierarchy.get(tag, []))
    visited = set()
    while queue:
        current = queue.pop(0)
        if current not in visited:
            visited.add(current)
            descendants.append(current)
            for child in hierarchy.get(current, []):
                if child not in visited:
                    queue.append(child)
    return descendants

def delete_tag(hierarchy: dict[str, list[str]], tag: str) -> dict[str, list[str]]:
    hierarchy_copy = copy.deepcopy(hierarchy)
    descendants = get_descendants(hierarchy_copy, tag)
    tags_to_delete = set(descendants)
    tags_to_delete.add(tag)

    for t in tags_to_delete:
        if t in hierarchy_copy:
            del hierarchy_copy[t]

    for parent, children in hierarchy_copy.items():
        hierarchy_copy[parent] = [child for child in children if child not in tags_to_delete]

    return hierarchy_copy

def list_all_tags(hierarchy: dict[str, list[str]]) -> list[str]:
    seen = set()
    result = []
    for key in hierarchy.keys():
        if key not in seen:
            seen.add(key)
            result.append(key)
    for children in hierarchy.values():
        for child in children:
            if child not in seen:
                seen.add(child)
                result.append(child)
    return result

