class _Parser:
    def __init__(self, tokens: list[str]):
        self.tokens = tokens
        self.pos = 0

    def peek(self) -> str | None:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self, expected: str = None) -> str:
        token = self.peek()
        if token is None:
            raise SyntaxError("Unexpected end of input")
        if expected is not None and token != expected:
            raise SyntaxError(f"Expected '{expected}', got '{token}'")
        self.pos += 1
        return token

    def parse(self) -> dict[str, any]:
        statements = []
        while self.peek() is not None:
            statements.append(self.parse_statement())
            if self.peek() == ';':
                self.consume(';')
        if len(statements) == 1:
            return statements[0]
        return {"type": "Program", "body": statements}

    def parse_statement(self) -> dict[str, any]:
        if self.pos + 1 < len(self.tokens) and self.tokens[self.pos + 1] == '=':
            target = self.consume()
            self.consume('=')
            expr = self.parse_expression()
            return {"type": "Assignment", "target": target, "value": expr}
        return self.parse_expression()

    def parse_expression(self) -> dict[str, any]:
        return self.parse_binary_op(self.parse_term, ['+', '-'])

    def parse_term(self) -> dict[str, any]:
        return self.parse_binary_op(self.parse_factor, ['*', '/'])

    def parse_factor(self) -> dict[str, any]:
        token = self.peek()
        if token in ('+', '-'):
            op = self.consume()
            operand = self.parse_factor()
            return {"type": "UnaryOp", "op": op, "operand": operand}
        return self.parse_primary()

    def parse_primary(self) -> dict[str, any]:
        token = self.peek()
        if token == '(':
            self.consume('(')
            expr = self.parse_expression()
            self.consume(')')
            return expr

        token = self.consume()
        # Check if the token is a number
        try:
            if '.' in token:
                val = float(token)
            else:
                val = int(token)
            return {"type": "Number", "value": val}
        except ValueError:
            return {"type": "Identifier", "value": token}

    def parse_binary_op(self, next_parser, ops: list[str]) -> dict[str, any]:
        left = next_parser()
        while self.peek() in ops:
            op = self.consume()
            right = next_parser()
            left = {"type": "BinaryOp", "op": op, "left": left, "right": right}
        return left


def parse(tokens: list[str]) -> dict[str, any]:
    if not tokens:
        return {"type": "Program", "body": []}
    parser = _Parser(tokens)
    return parser.parse()

