import math
from typing import Any

def evaluate(ast: dict[str, Any]) -> float:
    if not ast:
        raise ValueError("Empty AST node")

    node_type = ast.get("type")

    if node_type == "number":
        return float(ast["value"])

    elif node_type == "binary_op":
        op = ast["op"]
        left_val = evaluate(ast["left"])
        right_val = evaluate(ast["right"])

        if op == "+":
            return left_val + right_val
        elif op == "-":
            return left_val - right_val
        elif op == "*":
            return left_val * right_val
        elif op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        elif op in ("^", "**"):
            try:
                return left_val ** right_val
            except OverflowError:
                return float('inf')
        else:
            raise ValueError(f"Unknown binary operator: {op}")

    elif node_type == "unary_op":
        op = ast["op"]
        operand_val = evaluate(ast["operand"])

        if op == "-":
            return -operand_val
        elif op == "+":
            return operand_val
        else:
            raise ValueError(f"Unknown unary operator: {op}")

    elif node_type == "function":
        name = ast["name"].lower()
        args = [evaluate(arg) for arg in ast["args"]]

        if not args:
            raise ValueError(f"Function {name} requires at least one argument")

        if name == "sin":
            return math.sin(args[0])
        elif name == "cos":
            return math.cos(args[0])
        elif name == "tan":
            return math.tan(args[0])
        elif name in ("log", "ln"):
            if len(args) == 2:
                return math.log(args[0], args[1])
            return math.log(args[0])
        elif name == "sqrt":
            if args[0] < 0:
                raise ValueError("Cannot compute the square root of a negative number")
            return math.sqrt(args[0])
        elif name == "abs":
            return abs(args[0])
        elif name == "exp":
            try:
                return math.exp(args[0])
            except OverflowError:
                return float('inf')
        else:
            raise ValueError(f"Unknown function: {name}")

    else:
        raise ValueError(f"Unknown AST node type: {node_type}")

