import re
from typing import List, Union

def tokenize(chars: str) -> List[str]:
    token_re = re.compile(r'"(?:[^"\\]|\\.)*"|\(|\)|[^\s()]+')
    return token_re.findall(chars)

def atom(token: str) -> Union[int, float, str]:
    if token.startswith('"') and token.endswith('"'):
        return token[1:-1].replace('\\"', '"').replace('\\\\', '\\')
    try:
        return int(token)
    except ValueError:
        try:
            return float(token)
        except ValueError:
            return token

def read_from_tokens(tokens: List[str]) -> Union[list, int, float, str]:
    if not tokens:
        raise SyntaxError("unexpected EOF")
    token = tokens.pop(0)
    if token == '(':
        L = []
        while tokens and tokens[0] != ')':
            L.append(read_from_tokens(tokens))
        if not tokens:
            raise SyntaxError("unexpected EOF (missing closing parenthesis)")
        tokens.pop(0)  # pop ')'
        return L
    elif token == ')':
        raise SyntaxError("unexpected )")
    else:
        return atom(token)

def parse(expr: str) -> Union[list, int, float, str]:
    tokens = tokenize(expr)
    if not tokens:
        raise ValueError("Empty expression")
    result = read_from_tokens(tokens)
    if tokens:
        raise SyntaxError("unexpected tokens at end of expression")
    return result

