from typing import Union, List

def _prod(lst: List[Union[int, float]]) -> Union[int, float]:
    p = 1
    for x in lst:
        p *= x
    return p

def evaluate(parsed_expr: Union[List, int, float, str]) -> Union[int, float]:
    if isinstance(parsed_expr, (int, float)):
        return parsed_expr

    if isinstance(parsed_expr, str):
        try:
            if '.' in parsed_expr or 'e' in parsed_expr.lower():
                return float(parsed_expr)
            return int(parsed_expr)
        except ValueError:
            raise ValueError(f"Cannot evaluate string literal: {parsed_expr}")

    if isinstance(parsed_expr, list):
        if not parsed_expr:
            raise ValueError("Cannot evaluate empty list")

        op = parsed_expr[0]
        if not isinstance(op, str):
            raise ValueError(f"Operator must be a string, got {type(op)}")

        args = [evaluate(arg) for arg in parsed_expr[1:]]

        op_lower = op.lower()
        if op_lower in ('add', '+'):
            return sum(args)
        elif op_lower in ('mul', '*'):
            return _prod(args)
        elif op_lower in ('sub', '-'):
            if not args:
                return 0
            if len(args) == 1:
                return -args[0]
            return args[0] - sum(args[1:])
        elif op_lower in ('div', '/'):
            if not args:
                raise ValueError("Division requires at least one operand")
            if len(args) == 1:
                return 1 / args[0]
            result = args[0]
            for val in args[1:]:
                result /= val
            return result
        else:
            raise ValueError(f"Unknown operator: {op}")

    raise TypeError(f"Unsupported type for evaluation: {type(parsed_expr)}")

