def serialize_tree(nodes: list, indent_size: int) -> str:
    lines = []

    def traverse(node_list: list, current_depth: int = 0):
        for node in node_list:
            depth = node.get("cumulative_depth", current_depth)
            indent = " " * (depth * indent_size)
            lines.append(f"{indent}{node['text']}")
            if "children" in node and node["children"]:
