        self.tokens = self._tokenize(expr)
        self.pos = 0

    def _tokenize(self, expr: str) -> List[str]:
        return re.findall(r'\d+(?:\.\d+)?|[a-zA-Z_][a-zA-Z0-9_]*|[\+\-\*/\^\(\)]', expr)

    def peek(self) -> Optional[str]:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self) -> Optional[str]:
        token = self.peek()
        self.pos += 1
        return token

    def parse(self) -> Dict[str, Any]:
        if not self.tokens:
            raise ValueError("Empty expression")
        node = self.expr()
        if self.pos < len(self.tokens):
            raise ValueError(f"Unexpected token: {self.tokens[self.pos]}")
        return node

    def expr(self) -> Dict[str, Any]:
        node = self.term()
        while self.peek() in ('+', '-'):
            op = self.consume()
            right = self.term()
            node = {
                'type': 'operator',
                'value': op,
                'left': node,
                'right': right
            }
        return node

    def term(self) -> Dict[str, Any]:
        node = self.factor()
        while self.peek() in ('*', '/'):
            op = self.consume()
            right = self.factor()
            node = {
                'type': 'operator',
                'value': op,
                'left': node,
                'right': right
            }
        return node

    def factor(self) -> Dict[str, Any]:
        node = self.unary()
        if self.peek() == '^':
            op = self.consume()
            right = self.factor()
            node = {
                'type': 'operator',
                'value': op,
                'left': node,
                'right': right
            }
        return node

    def unary(self) -> Dict[str, Any]:
        if self.peek() in ('+', '-'):
            op = self.consume()
            operand = self.unary()
            return {
                'type': 'operator',
                'value': op,
                'left': None,
                'right': operand
            }
        return self.primary()

    def primary(self) -> Dict[str, Any]:
        token = self.peek()
        if token == '(':
            self.consume()
            node = self.expr()
            if self.peek() == ')':
                self.consume()
            else:
                raise ValueError("Unmatched parenthesis")
            return node

        token = self.consume()
        if token is None:
            raise ValueError("Unexpected end of expression")

        if token.replace('.', '', 1).isdigit():
            return {
                'type': 'number',
                'value': token,
                'left': None,
                'right': None
            }
        else:
            return {
                'type': 'variable',
                'value': token,
                'left': None,
                'right': None
            }

