def tree_to_string(tree: dict | None) -> str:
    """Converts a binary expression tree back into an infix expression string representation."""
    if tree is None:
        return ""

    value = str(tree.get("value", ""))
    left = tree.get("left")
    right = tree.get("right")

    if left is None and right is None:
        return value

    if left is not None and right is not None:
        return f"({tree_to_string(left)} {value} {tree_to_string(right)})"

    if left is not None:
        return f"({tree_to_string(left)}{value})"

    if right is not None:
        right_str = tree_to_string(right)
        if value.isalpha():
            return f"{value}({right_str})"
        return f"({value}{right_str})"

    return value

