    """
    Builds an adjacency list representation of a directed graph from a list of edges.
    Ensures all vertices mentioned in the edges exist as keys in the resulting dictionary.
    """
    adjacency_list: dict[int, list[int]] = {}
    for source, destination in edges:
        if source not in adjacency_list:
            adjacency_list[source] = []
        if destination not in adjacency_list:
            adjacency_list[destination] = []
        adjacency_list[source].append(destination)
