import heapq

def resolve_dependencies(graph: dict[str, list[str]]) -> tuple[list[str], list[list[str]]]:
    # 1. Normalize the graph to include all referenced nodes
    all_nodes = set(graph.keys()) | {dep for deps in graph.values() for dep in deps}
    graph_adj: dict[str, list[str]] = {node: [] for node in all_nodes}
    for node, deps in graph.items():
        graph_adj[node] = list(deps)

    # 2. Find Cycles using Tarjan's Algorithm
    index = 0
    stack: list[str] = []
    indices: dict[str, int] = {}
    lowlink: dict[str, int] = {}
    on_stack: set[str] = set()
    cycles: list[list[str]] = []

    def strongconnect(v: str) -> None:
        nonlocal index
        indices[v] = index
        lowlink[v] = index
        index += 1
        stack.append(v)
        on_stack.add(v)

        for w in graph_adj[v]:
            if w not in indices:
                strongconnect(w)
                lowlink[v] = min(lowlink[v], lowlink[w])
            elif w in on_stack:
                lowlink[v] = min(lowlink[v], indices[w])

        if lowlink[v] == indices[v]:
            scc = []
            while True:
                w = stack.pop()
                on_stack.remove(w)
                scc.append(w)
                if w == v:
                    break

            # Determine if this SCC is a cycle
            if len(scc) > 1:
                cycles.append(sorted(scc))
            elif len(scc) == 1:
                # A single node is a cycle only if it has a self-loop
                node = scc[0]
                if node in graph_adj[node]:
                    cycles.append([node])

    for node in all_nodes:
        if node not in indices:
            strongconnect(node)

    cycles.sort(key=lambda x: x[0] if x else "")

    # 3. Perform Topological Sort on Acyclic / Resolvable Part using Kahn's Algorithm
    # Build in-degrees and reverse adjacency list (edges: dependency -> dependent)
    in_degree: dict[str, int] = {node: 0 for node in all_nodes}
    adj_rev: dict[str, list[str]] = {node: [] for node in all_nodes}

    for u in all_nodes:
        for v in graph_adj[u]:
            # u depends on v, so v must be resolved before u (v -> u)
            adj_rev[v].append(u)
            in_degree[u] += 1

    # Deterministic Kahn's using a min-heap to sort lexicographically when equal
    heap = [node for node in all_nodes if in_degree[node] == 0]
    heapq.heapify(heap)

    ordered_list: list[str] = []
    while heap:
        u = heapq.heappop(heap)
        ordered_list.append(u)
        for neighbor in adj_rev[u]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                heapq.heappush(heap, neighbor)

    return ordered_list, cycles

