def insert(node: dict, key: int) -> dict:
    if not node or "key" not in node:
        return {"key": key, "left": None, "right": None}

    if key < node["key"]:
        node["left"] = insert(node.get("left") or {}, key)
    elif key > node["key"]:
        node["right"] = insert(node.get("right") or {}, key)
    return node


def find(node: dict, key: int) -> bool:
    if not node or "key" not in node:
        return False

    if key == node["key"]:
        return True
    elif key < node["key"]:
        return find(node.get("left") or {}, key)
    else:
        return find(node.get("right") or {}, key)


def delete(node: dict, key: int) -> dict:
    if not node or "key" not in node:
        return {}

    if key < node["key"]:
        node["left"] = delete(node.get("left") or {}, key)
        if not node["left"]:
            node["left"] = None
    elif key > node["key"]:
        node["right"] = delete(node.get("right") or {}, key)
        if not node["right"]:
            node["right"] = None
    else:
        if not node.get("left"):
            return node.get("right") or {}
        elif not node.get("right"):
            return node.get("left") or {}

        successor = node["right"]
        while successor and successor.get("left"):
            successor = successor["left"]

        node["key"] = successor["key"]
        node["right"] = delete(node["right"], successor["key"])
        if not node["right"]:
            node["right"] = None

    return node


def inorder(node: dict) -> list[int]:
    if not node or "key" not in node:
        return []

    left_list = inorder(node.get("left") or {})
    right_list = inorder(node.get("right") or {})
    return left_list + [node["key"]] + right_list

