        if len(tokens) < 2:
            return tree, "Error: delete requires an integer key", False
        try:
            key = int(tokens[1])
            tree = delete(tree, key)
            return tree, f"Deleted {key}", False
        except ValueError:
            return tree, "Error: key must be an integer", False

    elif cmd == "find":
        if len(tokens) < 2:
            return tree, "Error: find requires an integer key", False
