def is_matched(text: str) -> bool:
    matching_brackets = {")": "(", "]": "[", "}": "{"}
    opening_brackets = set(matching_brackets.values())
    closing_brackets = set(matching_brackets.keys())

    stack = []
    for char in text:
        if char in opening_brackets:
            stack.append(char)
        elif char in closing_brackets:
            if not stack or stack[-1] != matching_brackets[char]:
                return False
            stack.pop()

    return len(stack) == 0

