def load_tags(file_path: str) -> dict[str, str | None]:
    """
    Loads the tag hierarchy from a local JSON file.
    If the file does not exist or is invalid, returns an empty dictionary.

    Args:
        file_path (str): The path to the JSON file.

    Returns:
        dict[str, str | None]: A dictionary mapping tags to their parent tags (or None).
