from storage import load_tags, save_tags

DB_FILE = "tags.json"

def get_all_tags() -> dict[str, str | None]:
    """Retrieves all tags and their parent mappings from storage."""
    try:
        tags = load_tags(DB_FILE)
        return tags if tags is not None else {}
    except Exception:
        return {}

def add_tag(tag: str, parent: str | None) -> bool:
    """
    Adds a new tag under an optional parent tag.
    Returns True if successfully added and saved, False otherwise.
    """
    if not tag or not isinstance(tag, str):
        return False

    tag = tag.strip()
    if not tag:
        return False

    tags = get_all_tags()

    # Prevent duplicate tag names
    if tag in tags:
        return False

    # Validate parent if provided
    if parent is not None:
        if not isinstance(parent, str):
            return False
        parent = parent.strip()
        if parent not in tags:
            return False  # Parent must already exist
        if tag == parent:
            return False

    tags[tag] = parent
    try:
        save_tags(DB_FILE, tags)
        return True
    except Exception:
        return False

def get_descendants(tag: str) -> list[str]:
    """
    Returns a list of all descendant tags for the given tag
    using a breadth-first traversal.
    """
    tags = get_all_tags()
    if tag not in tags:
        return []

    descendants = []
    queue = [tag]
    visited = {tag}

    while queue:
        current = queue.pop(0)
        # Find children whose parent is the current tag
        children = [t for t, p in tags.items() if p == current]
        for child in children:
            if child not in visited:
                visited.add(child)
                descendants.append(child)
                queue.append(child)

    return descendants

def delete_tag(tag: str) -> bool:
    """
    Deletes a tag and all of its descendants recursively.
    Returns True if successfully deleted, False if tag not found or save fails.
    """
    tags = get_all_tags()
    if tag not in tags:
        return False

    # Identify all descendants to perform a cascade delete
    descendants = get_descendants(tag)
    targets_to_delete = [tag] + descendants

    for target in targets_to_delete:
        if target in tags:
            del tags[target]

    try:
        save_tags(DB_FILE, tags)
        return True
    except Exception:
        return False

