class Parser:
    def __init__(self, tokens: list[dict[str, str]]):
        self.tokens = tokens
        self.pos = 0

    def current(self) -> dict[str, str] | None:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self, expected_type: str | None = None) -> dict[str, str]:
        tok = self.current()
        if not tok:
            raise SyntaxError("Unexpected end of input")
        if expected_type and self.normalize_type(tok) != expected_type:
            actual = tok.get('type') or tok.get('value', 'unknown')
            raise SyntaxError(f"Expected {expected_type}, got {actual}")
        self.pos += 1
        return tok

    def normalize_type(self, token: dict[str, str] | None) -> str | None:
        if not token:
            return None
        t = str(token.get('type', '')).upper()
        v = str(token.get('value', ''))

        if t in ('PLUS', '+'): return '+'
        if t in ('MINUS', '-'): return '-'
        if t in ('MUL', 'MULTIPLY', '*'): return '*'
        if t in ('DIV', 'DIVIDE', '/'): return '/'
        if t in ('MOD', 'MODULO', '%'): return '%'
        if t in ('POW', 'POWER', '^', '**'): return '^'
        if t in ('LPAREN', '('): return '('
        if t in ('RPAREN', ')'): return ')'
        if t in ('ASSIGN', 'EQUALS', '='): return '='
        if t in ('SEMICOLON', ';'): return ';'
        if t in ('NEWLINE', 'NL'): return 'NEWLINE'
        if t in ('NUMBER', 'NUM', 'INT', 'FLOAT'): return 'NUMBER'
        if t in ('IDENTIFIER', 'IDENT', 'VAR', 'NAME'): return 'IDENTIFIER'

        if v == '+': return '+'
        if v == '-': return '-'
        if v == '*': return '*'
        if v == '/': return '/'
        if v == '%': return '%'
        if v in ('^', '**'): return '^'
        if v == '(': return '('
        if v == ')': return ')'
        if v == '=': return '='
        if v == ';': return ';'
        if v == '\n': return 'NEWLINE'

        return t

    def get_precedence(self, op_type: str | None) -> int:
        if op_type == '=':
            return 5
        if op_type in ('+', '-'):
            return 10
        if op_type in ('*', '/', '%'):
            return 20
        if op_type == '^':
            return 30
        return 0

    def parse_expression(self, precedence: int = 0) -> dict[str, any]:
        token = self.current()
        if not token:
            raise SyntaxError("Unexpected end of input in expression")

        norm_type = self.normalize_type(token)

        if norm_type == 'NUMBER':
            self.consume()
            val_str = token.get('value', '0')
            try:
                val = float(val_str)
                if val.is_integer():
                    val = int(val)
            except ValueError:
                val = val_str
            left = {'type': 'Number', 'value': val}
        elif norm_type == 'IDENTIFIER':
            self.consume()
            left = {'type': 'Identifier', 'name': token.get('value', '')}
        elif norm_type in ('+', '-'):
            self.consume()
            operand = self.parse_expression(100)
            left = {'type': 'UnaryOp', 'op': norm_type, 'right': operand}
        elif norm_type == '(':
            self.consume('(')
            left = self.parse_expression(0)
            self.consume(')')
        else:
            raise SyntaxError(f"Unexpected token: {token.get('value') or token.get('type')}")

        while True:
            next_token = self.current()
            if not next_token:
                break
            next_norm = self.normalize_type(next_token)

            op_prec = self.get_precedence(next_norm)
            if op_prec <= precedence:
                break

            self.consume()

            if next_norm == '=':
                if left['type'] != 'Identifier':
                    raise SyntaxError("Invalid left-hand side in assignment")
                right = self.parse_expression(op_prec - 1)
                left = {
                    'type': 'Assignment',
                    'target': left,
                    'value': right
