            else:
                next_precedence = op_prec
                if next_norm == '^':
                    next_precedence = op_prec - 1
                right = self.parse_expression(next_precedence)
                left = {
                    'type': 'BinaryOp',
                    'op': next_norm,
                    'left': left,
                    'right': right
                }

        return left

    def parse_statement(self) -> dict[str, any]:
        return self.parse_expression(0)

    def parse_program(self) -> dict[str, any]:
        nodes = []
        while self.current() is not None:
            norm = self.normalize_type(self.current())
            if norm in (';', 'NEWLINE'):
                self.consume()
                continue
            node = self.parse_statement()
            nodes.append(node)

        if not nodes:
            return {'type': 'Program', 'body': []}
        if len(nodes) == 1:
            return nodes[0]
        return {
            'type': 'Program',
            'body': nodes
        }


def parse(tokens: list[dict[str, str]]) -> dict[str, any]:
    parser = Parser(tokens)
    return parser.parse_program()

