import re
from typing import List, Union

def tokenize(expr: str) -> List[str]:
    token_re = re.compile(r'\s*([()]|(?:"[^"\\]*(?:\\.[^"\\]*)*")|[^\s()]+)')
    return [m.group(1) for m in token_re.finditer(expr) if m.group(1)]

def parse(tokens: List[str]) -> Union[list, str, int, float]:
    if not tokens:
        raise SyntaxError("Unexpected EOF")

    tokens_copy = list(tokens)

    def atom(token: str) -> Union[str, int, float]:
        if token.startswith('"') and token.endswith('"'):
            return token[1:-1].replace('\\"', '"').replace('\\\\', '\\')
        try:
            return int(token)
        except ValueError:
            try:
                return float(token)
            except ValueError:
                return token

    def parse_inner() -> Union[list, str, int, float]:
        if not tokens_copy:
            raise SyntaxError("Unexpected EOF")
        token = tokens_copy.pop(0)
        if token == '(':
            lst = []
            while tokens_copy and tokens_copy[0] != ')':
                lst.append(parse_inner())
            if not tokens_copy:
                raise SyntaxError("Expected ')' but reached EOF")
            tokens_copy.pop(0)  # pop ')'
            return lst
        elif token == ')':
            raise SyntaxError("Unexpected ')'")
        else:
            return atom(token)

    return parse_inner()

