from __future__ import annotations
import operator
from functools import reduce

def evaluate(node: list | str | int | float) -> int | float:
    if isinstance(node, (int, float)):
        return node

    if isinstance(node, str):
        try:
            if '.' in node:
                return float(node)
            return int(node)
        except ValueError:
            raise ValueError(f"Cannot evaluate symbol or invalid number: '{node}'")

    if isinstance(node, list):
        if not node:
            raise ValueError("Empty S-expression cannot be evaluated")

        op = node[0]
        if not isinstance(op, str):
            raise ValueError(f"Operator must be a string, got {type(op)}")

        args = [evaluate(arg) for arg in node[1:]]

        if op == '+':
            return sum(args)
        elif op == '-':
            if len(args) == 0:
                return 0
            if len(args) == 1:
                return -args[0]
            return reduce(operator.sub, args)
        elif op == '*':
            if len(args) == 0:
                return 1
            return reduce(operator.mul, args)
        elif op == '/':
            if len(args) == 0:
                raise ValueError("Division operator requires at least one argument")
            if len(args) == 1:
                return 1 / args[0]
            return reduce(operator.truediv, args)
        else:
            raise ValueError(f"Unknown operator: '{op}'")

    raise TypeError(f"Unsupported node type: {type(node)}")

