from typing import Dict, Any, Optional, List

def tokenize(expr: str) -> List[str]:
    tokens = []
    i = 0
    n = len(expr)
    while i < n:
        char = expr[i]
        if char.isspace():
            i += 1
            continue
        if char in '+-*/^()':
            tokens.append(char)
            i += 1
        elif char.isdigit() or (char == '.' and i + 1 < n and expr[i+1].isdigit()):
            start = i
            has_dot = False
            while i < n and (expr[i].isdigit() or (expr[i] == '.' and not has_dot)):
                if expr[i] == '.':
                    has_dot = True
                i += 1
            tokens.append(expr[start:i])
        else:
            raise ValueError(f"Unexpected character: {char}")
    return tokens

class Parser:
    def __init__(self, tokens: List[str]):
        self.tokens = tokens
        self.pos = 0

    def peek(self) -> Optional[str]:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self, expected: Optional[str] = None) -> str:
        token = self.peek()
        if token is None:
            raise ValueError("Unexpected end of input")
        if expected is not None and token != expected:
            raise ValueError(f"Expected {expected}, got {token}")
        self.pos += 1
        return token

    def parse(self) -> Optional[Dict[str, Any]]:
        if not self.tokens:
            return None
        node = self.expression()
        if self.pos < len(self.tokens):
            raise ValueError(f"Unexpected trailing tokens starting at: {self.tokens[self.pos]}")
        return node

    def expression(self) -> Dict[str, Any]:
        node = self.term()
        while self.peek() in ('+', '-'):
            op = self.consume()
            right = self.term()
            node = {
                'type': 'operator',
                'value': op,
                'left': node,
                'right': right
            }
        return node

    def term(self) -> Dict[str, Any]:
        node = self.factor()
        while self.peek() in ('*', '/', '^'):
            op = self.consume()
            right = self.factor()
            node = {
                'type': 'operator',
                'value': op,
                'left': node,
                'right': right
            }
        return node

    def factor(self) -> Dict[str, Any]:
        token = self.peek()
        if token in ('+', '-'):
            op = self.consume()
            operand = self.factor()
            return {
                'type': 'operator',
                'value': op,
                'left': None,
                'right': operand
            }
        return self.primary()

    def primary(self) -> Dict[str, Any]:
        token = self.peek()
        if token is None:
            raise ValueError("Unexpected end of input")

        if token == '(':
            self.consume('(')
            node = self.expression()
            self.consume(')')
            return node

        if self.is_number(token):
            self.consume()
            return {
                'type': 'number',
                'value': token,
                'left': None,
                'right': None
            }

        raise ValueError(f"Unexpected token: {token}")

    def is_number(self, token: str) -> bool:
        try:
            float(token)
            return True
        except ValueError:
            return False

def parse_expression(expr: str) -> Optional[Dict[str, Any]]:
    tokens = tokenize(expr)
    parser = Parser(tokens)
    return parser.parse()

