from typing import Dict, Any, Optional

def get_precedence(node: Optional[Dict[str, Any]]) -> int:
    if not node:
        return 999
    if not node.get('left') and not node.get('right'):
        return 999

    val = node.get('value', '')

    if val in ('+', '-'):
        if not node.get('left') and node.get('right'):
            return 4  # Unary negation/plus
        return 1
    elif val in ('*', '/'):
        return 2
    elif val in ('^', '**'):
        return 3

    return 999

def is_right_associative(op: str) -> bool:
    return op in ('^', '**')

def to_string(tree: Optional[Dict[str, Any]]) -> str:
    if not tree:
        return ""

    # Leaf node
    if not tree.get('left') and not tree.get('right'):
        return str(tree.get('value', ''))

    val = str(tree.get('value', ''))

    # Unary Operator or Function Call
    if not tree.get('left') and tree.get('right'):
        right_node = tree['right']
        right_str = to_string(right_node)

        # Check if the operator is alphabetic (like "sin", "cos", "log")
        if val.isalnum() and not val.isdigit():
            return f"{val}({right_str})"

        # Symbolic unary operator (like "-", "+")
        my_prec = 4
        right_prec = get_precedence(right_node)
        if right_prec < my_prec:
            right_str = f"({right_str})"
        return f"{val}{right_str}"

    # Binary Operator
    left_node = tree.get('left')
    right_node = tree.get('right')

    left_str = to_string(left_node)
    right_str = to_string(right_node)

    my_prec = get_precedence(tree)
    left_prec = get_precedence(left_node)
    right_prec = get_precedence(right_node)

    # Left child grouping rule
    if is_right_associative(val):
        if left_prec <= my_prec:
            left_str = f"({left_str})"
    else:
        if left_prec < my_prec:
            left_str = f"({left_str})"

    # Right child grouping rule
    if is_right_associative(val):
        if right_prec < my_prec:
            right_str = f"({right_str})"
    else:
        if right_prec <= my_prec:
            right_str = f"({right_str})"

    return f"{left_str} {val} {right_str}"

