from collections import deque

def analyze_dependencies(adj_list: dict[str, list[str]]) -> tuple[list[str], list[list[str]]]:
    # Collect all unique nodes in the graph
    nodes = set(adj_list.keys())
    for deps in adj_list.values():
        nodes.update(deps)

    # Build in-degree mapping
    in_degree = {u: 0 for u in nodes}
    for u, deps in adj_list.items():
        for v in deps:
            in_degree[v] = in_degree.get(v, 0) + 1

    # Kahn's algorithm for topological sorting
    zero_in = sorted([u for u in nodes if in_degree[u] == 0])
    queue = deque(zero_in)
    topo_order = []

    # Create a local copy of adjacency list with sorted destinations for determinism
    adj = {u: sorted(list(deps)) for u, deps in adj_list.items()}

    while queue:
        u = queue.popleft()
        topo_order.append(u)
        for v in adj.get(u, []):
            in_degree[v] -= 1
            if in_degree[v] == 0:
                queue.append(v)

    # If the topological order contains all nodes, there are no cycles
    if len(topo_order) == len(nodes):
        return topo_order, []

    # Otherwise, detect all cycles using DFS
    visited = {u: 0 for u in nodes}  # 0: unvisited, 1: visiting, 2: visited
    cycles_set = set()
    path = []

    def dfs(u: str) -> None:
        visited[u] = 1
        path.append(u)
        for v in adj.get(u, []):
            if visited.get(v, 0) == 1:
                try:
                    idx = path.index(v)
                    cycle = path[idx:]
                    if cycle:
                        # Canonicalize cycle by rotating to start with the smallest element
                        min_val = min(cycle)
                        min_idx = cycle.index(min_val)
                        canonical = tuple(cycle[min_idx:] + cycle[:min_idx])
                        cycles_set.add(canonical)
                except ValueError:
                    pass
            elif visited.get(v, 0) == 0:
                dfs(v)
        path.pop()
        visited[u] = 2

    # Traverse all nodes in sorted order for deterministic cycle detection
    for u in sorted(nodes):
        if visited[u] == 0:
            dfs(u)

    cycles = [list(c) for c in sorted(cycles_set)]

    return topo_order, cycles

