    if not isinstance(dependencies, dict):
        print("Error: Dependency graph must be a JSON object (dictionary).", file=sys.stderr)
        sys.exit(1)

    # Validate that dependencies structure is dict[str, list[str]]
    validated_dependencies: dict[str, list[str]] = {}
    for key, value in dependencies.items():
        if not isinstance(key, str):
            print(f"Error: Key '{key}' must be a string.", file=sys.stderr)
            sys.exit(1)
        if not isinstance(value, list):
            print(f"Error: Dependencies for '{key}' must be a list of strings.", file=sys.stderr)
