        return {
            "key": tree["key"],
            "left": insert_node(tree["left"], key),
            "right": tree["right"]
        }
    elif key > tree["key"]:
        return {
            "key": tree["key"],
            "left": tree["left"],
            "right": insert_node(tree["right"], key)
        }
    else:
        return tree


def find_node(tree: dict | None, key: int) -> bool:
    if tree is None:
        return False
    if key == tree["key"]:
        return True
    elif key < tree["key"]:
        return find_node(tree["left"], key)
    else:
        return find_node(tree["right"], key)


def _min_value_node(node: dict) -> int:
    current = node
    while current["left"] is not None:
        current = current["left"]
    return current["key"]


def delete_node(tree: dict | None, key: int) -> dict | None:
    if tree is None:
        return None

    if key < tree["key"]:
        return {
            "key": tree["key"],
            "left": delete_node(tree["left"], key),
            "right": tree["right"]
        }
    elif key > tree["key"]:
        return {
            "key": tree["key"],
            "left": tree["left"],
            "right": delete_node(tree["right"], key)
        }
    else:
        if tree["left"] is None and tree["right"] is None:
            return None
        elif tree["left"] is None:
            return tree["right"]
        elif tree["right"] is None:
            return tree["left"]
        else:
            successor_key = _min_value_node(tree["right"])
            return {
                "key": successor_key,
                "left": tree["left"],
                "right": delete_node(tree["right"], successor_key)
            }


def inorder_traverse(tree: dict | None) -> list[int]:
    if tree is None:
        return []
    return inorder_traverse(tree["left"]) + [tree["key"]] + inorder_traverse(tree["right"])

