def check_matching_parentheses(text: str) -> bool:
    """
    Checks if the parentheses, square brackets, and curly braces in the given
    text are correctly paired and nested.
    """
    stack = []
    mapping = {")": "(", "}": "{", "]": "["}
    opening = set(mapping.values())

    for char in text:
        if char in opening:
            stack.append(char)
        elif char in mapping:
            if not stack or stack[-1] != mapping[char]:
                return False
            stack.pop()

    return len(stack) == 0

