from typing import Dict, List

def load_data(file_path: str) -> Dict[str, List[str]]:
    """
    Reads graph data from a local JSON file.
    If the file does not exist or is empty/corrupt, returns an empty dictionary.

    Args:
        file_path: Path to the JSON file.

    Returns:
        A dictionary representing the graph, mapping node IDs (str) to lists of adjacent node IDs (list[str]).
    """
    if not os.path.exists(file_path):
        return {}

    try:
        with open(file_path, "r", encoding="utf-8") as f:
            data = json.load(f)
            if isinstance(data, dict):
                # Normalize keys to str and values to list of str
                normalized_graph: Dict[str, List[str]] = {}
                for key, val in data.items():
                    if isinstance(val, list):
                        normalized_graph[str(key)] = [str(item) for item in val]
                    else:
                        normalized_graph[str(key)] = []
                return normalized_graph
            return {}
    except (json.JSONDecodeError, IOError):
        return {}

def save_data(file_path: str, data: Dict[str, List[str]]) -> None:
    """
    Writes the graph data structure to a local JSON file.
    Creates any missing parent directories.

    Args:
        file_path: Path to the JSON file.
        data: The graph dictionary to be saved.
    """
    try:
        dir_name = os.path.dirname(file_path)
        if dir_name and not os.path.exists(dir_name):
            os.makedirs(dir_name, exist_ok=True)

        with open(file_path, "w", encoding="utf-8") as f:
            json.dump(data, f, ensure_ascii=False, indent=4)
    except IOError as e:
        raise IOError(f"Failed to write graph data to {file_path}: {e}")

