def delete_vertex(graph: dict[str, list[str]], vertex: str) -> dict[str, list[str]]:
    if vertex in graph:
        del graph[vertex]
    for key in graph:
        if vertex in graph[key]:
            graph[key] = [v for v in graph[key] if v != vertex]
    return graph

