def get_all_descendants(data: dict[str, list[str]], tag: str) -> list[str]:
    descendants = []
    descendants_set = set()
    queue = list(data.get(tag, []))

    while queue:
        current = queue.pop(0)
        if current not in descendants_set:
            descendants_set.add(current)
            descendants.append(current)
            if current in data:
                for child in data[current]:
                    if child not in descendants_set:
                        queue.append(child)
    return descendants

def add_relation(data: dict[str, list[str]], parent: str, child: str) -> tuple[dict[str, list[str]], bool]:
    if parent == child:
        return data, False

    # Check if relation already exists
    if parent in data and child in data[parent]:
        return data, False

    # Prevent cycles: if parent is already a descendant of child, we cannot make child a child of parent
    if parent in get_all_descendants(data, child):
        return data, False

    if parent not in data:
        data[parent] = []
    data[parent].append(child)
    return data, True

def remove_relation(data: dict[str, list[str]], parent: str, child: str) -> tuple[dict[str, list[str]], bool]:
    if parent in data and child in data[parent]:
        data[parent].remove(child)
        # Clean up empty parent list to keep data tidy
        if not data[parent]:
            del data[parent]
        return data, True
    return data, False

def list_relations(data: dict[str, list[str]]) -> list[tuple[str, str]]:
    relations = []
    for parent, children in data.items():
        for child in children:
            relations.append((parent, child))
    return relations

