class ExpressionParser:
    def __init__(self, tokens: list[str]):
        self.tokens = tokens
        self.pos = 0

    def current(self) -> str | None:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self, expected: str | None = None) -> str:
        token = self.current()
        if token is None:
            raise ValueError("Unexpected end of input")
        if expected is not None and token != expected:
            raise ValueError(f"Expected '{expected}', got '{token}'")
        self.pos += 1
        return token

    def parse(self) -> dict:
        if not self.tokens:
            return {}
        node = self.expr()
        if self.pos < len(self.tokens):
            raise ValueError(f"Unexpected token at end: {self.tokens[self.pos:]}")
        return node

    def expr(self) -> dict:
        return self.or_expr()

    def or_expr(self) -> dict:
        node = self.and_expr()
        while self.current() == 'or':
            op = self.consume()
            right = self.and_expr()
            node = {"type": "binary_op", "op": op, "left": node, "right": right}
        return node

    def and_expr(self) -> dict:
        node = self.not_expr()
        while self.current() == 'and':
            op = self.consume()
            right = self.not_expr()
            node = {"type": "binary_op", "op": op, "left": node, "right": right}
        return node

    def not_expr(self) -> dict:
        if self.current() == 'not':
            op = self.consume()
            operand = self.not_expr()
            return {"type": "unary_op", "op": op, "operand": operand}
        return self.comparison()

    def comparison(self) -> dict:
        node = self.add_expr()
        comparators = {'==', '!=', '<', '<=', '>', '>='}
        while self.current() in comparators:
            op = self.consume()
            right = self.add_expr()
            node = {"type": "binary_op", "op": op, "left": node, "right": right}
        return node

    def add_expr(self) -> dict:
        node = self.mult_expr()
        while self.current() in ('+', '-'):
            op = self.consume()
            right = self.mult_expr()
            node = {"type": "binary_op", "op": op, "left": node, "right": right}
        return node

    def mult_expr(self) -> dict:
        node = self.unary_expr()
        while self.current() in ('*', '/', '%'):
            op = self.consume()
            right = self.unary_expr()
            node = {"type": "binary_op", "op": op, "left": node, "right": right}
        return node

    def unary_expr(self) -> dict:
        if self.current() in ('+', '-'):
            op = self.consume()
            operand = self.unary_expr()
            return {"type": "unary_op", "op": op, "operand": operand}
        return self.exponent_expr()

    def exponent_expr(self) -> dict:
        node = self.primary()
        if self.current() == '^':
            op = self.consume()
            right = self.unary_expr()
            node = {"type": "binary_op", "op": op, "left": node, "right": right}
        return node

    def primary(self) -> dict:
        token = self.current()
        if token is None:
            raise ValueError("Unexpected end of input")

        if token == '(':
            self.consume('(')
            node = self.expr()
            self.consume(')')
            return node

        self.consume()

        # Boolean and Null literals
        if token.lower() == 'true':
            return {"type": "literal", "value": True}
        elif token.lower() == 'false':
            return {"type": "literal", "value": False}
        elif token.lower() in ('null', 'none'):
            return {"type": "literal", "value": None}

        # String literals
        if (token.startswith('"') and token.endswith('"')) or (token.startswith("'") and token.endswith("'")):
            return {"type": "literal", "value": token[1:-1]}

        # Numeric literals
        try:
            if '.' in token:
                return {"type": "literal", "value": float(token)}
            else:
                return {"type": "literal", "value": int(token)}
        except ValueError:
            pass

        # Identifier
        return {"type": "identifier", "value": token}


def parse(tokens: list[str]) -> dict:
    parser = ExpressionParser(tokens)
    return parser.parse()

