def evaluate(ast) -> float:
    if isinstance(ast, (int, float)):
        return float(ast)
    if not isinstance(ast, dict):
        raise TypeError("AST must be a dictionary or a numeric value")

    node_type = ast.get("type", "").lower()

    if node_type in ("number", "num", "literal", "numeric"):
        for key in ("value", "val"):
            if key in ast:
                return float(ast[key])
        raise ValueError("Malformed number node in AST")

    elif node_type in ("binop", "binary", "operator"):
        op = ast.get("op") or ast.get("operator")
        left_node = ast.get("left")
        right_node = ast.get("right")

        if left_node is None or right_node is None:
            raise ValueError("Binary operator node missing left or right child")

        left = evaluate(left_node)
        right = evaluate(right_node)

        if op == "+":
            return left + right
        elif op == "-":
            return left - right
        elif op == "*":
            return left * right
        elif op == "/":
            if right == 0:
                raise ZeroDivisionError("Division by zero")
            return left / right
        elif op in ("^", "**"):
            return left ** right
        elif op == "%":
            return left % right
        else:
            raise ValueError(f"Unsupported binary operator: {op}")

    elif node_type in ("unop", "unary"):
        op = ast.get("op") or ast.get("operator")
        operand_node = ast.get("operand") or ast.get("value")

        if operand_node is None:
            raise ValueError("Unary operator node missing operand")

        operand = evaluate(operand_node)

        if op == "-":
            return -operand
        elif op == "+":
            return +operand
        else:
            raise ValueError(f"Unsupported unary operator: {op}")

    elif node_type in ("call", "function", "func"):
        name = ast.get("name") or ast.get("func")
        args = ast.get("args") or ast.get("arguments") or []
        if not isinstance(args, list):
            args = [args]

        evaluated_args = [evaluate(arg) for arg in args]

        if not name:
