def tokenize(expr: str) -> list[str]:
    tokens = []
    i = 0
    n = len(expr)
    while i < n:
        c = expr[i]
        if c.isspace():
            i += 1
            continue
        elif c in '()':
            tokens.append(c)
            i += 1
        elif c == '"':
            # Handle string literal
            start = i
            i += 1
            while i < n and expr[i] != '"':
                if expr[i] == '\\' and i + 1 < n:
                    i += 2
                else:
                    i += 1
            if i < n:
                i += 1  # include closing quote
            tokens.append(expr[start:i])
        else:
            # Handle symbol/number
            start = i
            while i < n and not expr[i].isspace() and expr[i] not in '()':
                i += 1
            tokens.append(expr[start:i])
    return tokens

