def parse(tokens: list[str]) -> list | str | int | float:
    if not tokens:
        return []

    index = 0
    bracket_map = {'(': ')', '[': ']'}

    def atom(token: str) -> str | int | float:
        try:
            return int(token)
        except ValueError:
            try:
                return float(token)
            except ValueError:
                # Strip quotes if they surround the token
                if len(token) >= 2 and (
                    (token.startswith('"') and token.endswith('"')) or
                    (token.startswith("'") and token.endswith("'"))
                ):
                    return token[1:-1]
                return token

    def parse_element() -> list | str | int | float:
        nonlocal index
        if index >= len(tokens):
            raise SyntaxError("Unexpected EOF")

        token = tokens[index]
        if token in bracket_map:
            closing_bracket = bracket_map[token]
            index += 1  # consume opening bracket
            lst = []
            while index < len(tokens) and tokens[index] != closing_bracket:
                lst.append(parse_element())
            if index >= len(tokens):
                raise SyntaxError(f"Expected '{closing_bracket}' but reached EOF")
            index += 1  # consume closing bracket
            return lst
        elif token in bracket_map.values():
            raise SyntaxError(f"Unexpected closing bracket: '{token}'")
        else:
            index += 1
            return atom(token)

    results = []
    while index < len(tokens):
        results.append(parse_element())

    if len(results) == 1:
        return results[0]
    return results

