from typing import List, Union

def evaluate(node: Union[list, str, int, float]) -> Union[int, float]:
    if isinstance(node, (int, float)):
        return node

    if isinstance(node, str):
        try:
            if '.' in node:
                return float(node)
            return int(node)
        except ValueError:
            raise ValueError(f"Cannot evaluate unbound symbol or non-numeric string: {node}")

    if isinstance(node, list):
        if not node:
            raise ValueError("Empty S-expression cannot be evaluated")

        op = node[0]
        if not isinstance(op, str):
            raise ValueError(f"First element of S-expression must be an operator string, got: {op}")

        args = node[1:]

        if op == '+':
            return sum(evaluate(arg) for arg in args)
        elif op == '*':
            prod = 1
            for arg in args:
                prod *= evaluate(arg)
            return prod
        elif op == '-':
            if not args:
                raise ValueError("Operator '-' requires at least one argument")
            evaluated_args = [evaluate(arg) for arg in args]
            if len(evaluated_args) == 1:
                return -evaluated_args[0]
            res = evaluated_args[0]
            for val in evaluated_args[1:]:
                res -= val
            return res
        elif op == '/':
            if not args:
                raise ValueError("Operator '/' requires at least one argument")
            evaluated_args = [evaluate(arg) for arg in args]
            if len(evaluated_args) == 1:
                val = evaluated_args[0]
                if val == 0:
                    raise ZeroDivisionError("Division by zero")
                return 1 / val
            res = evaluated_args[0]
            for val in evaluated_args[1:]:
                if val == 0:
                    raise ZeroDivisionError("Division by zero")
                res /= val
            return res
        else:
            raise ValueError(f"Unknown operator: {op}")

    raise TypeError(f"Invalid node type: {type(node)}")

