def parse_indentation(text: str) -> list[dict]:
    if not text:
        return []

    lines = text.splitlines()
    parsed_lines = []
    for line in lines:
        if not line.strip():
            continue
        stripped = line.lstrip()
        indent = len(line) - len(stripped)
        name = stripped.rstrip()
        parsed_lines.append((indent, name))

    if not parsed_lines:
        return []

    roots = []
    stack = []

    for indent, name in parsed_lines:
        node = create_node(name, [])

        while stack and stack[-1][0] >= indent:
            stack.pop()

        if not stack:
            roots.append(node)
        else:
            parent_node = stack[-1][1]
            if "children" not in parent_node or parent_node["children"] is None:
                parent_node["children"] = []
            parent_node["children"].append(node)

        stack.append((indent, node))

    def set_depths(nodes: list[dict], current_depth: int = 0) -> None:
        for node in nodes:
            node["depth"] = current_depth
            children = node.get("children")
            if children:
                set_depths(children, current_depth + 1)

    set_depths(roots, 0)
    return roots

