import re

def tokenize(expression: str):
    token_specification = [
        ('NUMBER',     r'\d+(\.\d*)?'),             # Integer or decimal number
        ('IDENTIFIER', r'[a-zA-Z_][a-zA-Z0-9_]*'),  # Variables or function names
        ('OP',         r'[+\-*/]'),                 # Arithmetic operators
        ('LPAREN',     r'\('),                      # Left parenthesis
        ('RPAREN',     r'\)'),                      # Right parenthesis
        ('SKIP',       r'[ \t\r\n]+'),              # Skip spaces and newlines
        ('MISMATCH',   r'.'),                       # Any other character
    ]
    tok_regex = '|'.join('(?P<%s>%s)' % pair for pair in token_specification)
    tokens = []
    for mo in re.finditer(tok_regex, expression):
        kind = mo.lastgroup
        value = mo.group()
        if kind == 'NUMBER':
            tokens.append((kind, value))
        elif kind == 'IDENTIFIER':
            tokens.append((kind, value))
        elif kind == 'OP':
            tokens.append((kind, value))
        elif kind == 'LPAREN':
            tokens.append((kind, value))
        elif kind == 'RPAREN':
            tokens.append((kind, value))
        elif kind == 'SKIP':
            continue
        elif kind == 'MISMATCH':
            raise SyntaxError(f'Unexpected character {value!r}')
    return tokens

class Parser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def peek(self):
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self, expected_kind=None):
        tok = self.peek()
        if tok is None:
            raise SyntaxError("Unexpected end of input")
        if expected_kind and tok[0] != expected_kind:
            raise SyntaxError(f"Expected {expected_kind}, got {tok[0]}")
        self.pos += 1
        return tok

    def parse(self):
        if not self.tokens:
            raise SyntaxError("Empty expression")
        node = self.expr()
        if self.pos < len(self.tokens):
            raise SyntaxError(f"Unexpected token {self.tokens[self.pos][1]}")
        return node

    def expr(self):
        node = self.term()
        while True:
            tok = self.peek()
            if tok and tok[0] == 'OP' and tok[1] in ('+', '-'):
                op = self.consume()
                right = self.term()
                node = create_node("operator", op[1], node, right)
            else:
                break
        return node

    def term(self):
        node = self.factor()
        while True:
            tok = self.peek()
            if tok and tok[0] == 'OP' and tok[1] in ('*', '/'):
                op = self.consume()
                right = self.factor()
                node = create_node("operator", op[1], node, right)
            else:
                break
        return node

    def factor(self):
        tok = self.peek()
        if tok and tok[0] == 'OP' and tok[1] in ('+', '-'):
            op = self.consume()
            operand = self.factor()
            return create_node("operator", op[1], None, operand)
        return self.primary()

    def primary(self):
        tok = self.peek()
        if tok is None:
            raise SyntaxError("Unexpected end of input")
        if tok[0] == 'NUMBER':
            self.consume()
            return create_node("number", tok[1], None, None)
        elif tok[0] == 'IDENTIFIER':
            self.consume()
            return create_node("variable", tok[1], None, None)
        elif tok[0] == 'LPAREN':
            self.consume()
            node = self.expr()
            self.consume('RPAREN')
            return node
        else:
            raise SyntaxError(f"Unexpected token {tok[1]}")

def parse(expression: str) -> dict:
    tokens = tokenize(expression)
    parser = Parser(tokens)
    return parser.parse()

