def serialize(node: Union[Dict[str, Any], None]) -> str:
    if node is None:
        return ""

    value = str(node.get("value", ""))
    left = node.get("left")
    right = node.get("right")

    # Leaf node (Number or Variable)
    if left is None and right is None:
        return value

    # Unary operator or Function call
    if left is not None and right is None:
        if value.isalpha():
            return f"{value}({serialize(left)})"
        return f"({value}{serialize(left)})"

    if left is None and right is not None:
        if value.isalpha():
            return f"{value}({serialize(right)})"
        return f"({value}{serialize(right)})"

    # Binary operator
    return f"({serialize(left)} {value} {serialize(right)})"

