import collections
import heapq

def analyze_dependencies(graph: dict[str, list[str]]) -> tuple[list[str], list[list[str]]]:
    # Normalize the graph to include all referenced nodes
    full_graph = {node: list(deps) for node, deps in graph.items()}
    for deps in graph.values():
        for dep in deps:
            if dep not in full_graph:
                full_graph[dep] = []

    # Kahn's algorithm for topological sorting and cycle detection
    # An edge represents "v must run before u", so the directed edge is v -> u.
    # Therefore, in-degree of u is the number of dependencies of u.
    in_degree = {node: len(deps) for node, deps in full_graph.items()}
    dependents = collections.defaultdict(list)
    for u, deps in full_graph.items():
        for v in deps:
            dependents[v].append(u)

    # Use a priority queue (min-heap) to ensure a deterministic topological order
    queue = [node for node, deg in in_degree.items() if deg == 0]
    heapq.heapify(queue)

    topo_order = []
    while queue:
        v = heapq.heappop(queue)
        topo_order.append(v)
        for u in dependents[v]:
            in_degree[u] -= 1
            if in_degree[u] == 0:
                heapq.heappush(queue, u)

    # If the topological order contains all nodes, there are no cycles
    if len(topo_order) == len(full_graph):
        return topo_order, []

    # If cycles exist, find Strongly Connected Components (SCCs) using Tarjan's algorithm
    index_counter = [0]
    stack = []
    lowlink = {}
    index = {}
    on_stack = set()
    sccs = []

    def strongconnect(node):
        index[node] = index_counter[0]
        lowlink[node] = index_counter[0]
        index_counter[0] += 1
        stack.append(node)
        on_stack.add(node)

        for neighbor in full_graph.get(node, []):
            if neighbor not in index:
                strongconnect(neighbor)
                lowlink[node] = min(lowlink[node], lowlink[neighbor])
            elif neighbor in on_stack:
                lowlink[node] = min(lowlink[node], index[neighbor])

        if lowlink[node] == index[node]:
            scc = []
            while True:
                w = stack.pop()
                on_stack.remove(w)
                scc.append(w)
                if w == node:
                    break
            sccs.append(scc)

    for node in full_graph:
        if node not in index:
            strongconnect(node)

    # Extract components that actually form cycles
    detected_cycles = []
    for scc in sccs:
        # An SCC is a cycle if its size is > 1, OR if it's size 1 and has a self-loop
        if len(scc) > 1 or (len(scc) == 1 and scc[0] in full_graph[scc[0]]):
            detected_cycles.append(sorted(scc))

    detected_cycles.sort()
    return [], detected_cycles

