def check_brackets(text: str) -> bool:
    """
    Checks if the brackets in the input text are balanced and properly nested.
    Supports standard brackets: (), [], and {}.

    :param text: The input string to validate.
    :return: True if brackets are balanced and correctly ordered, False otherwise.
    """
    stack = []
    mapping = {")": "(", "]": "[", "}": "{"}
    opening_brackets = set(mapping.values())

    for char in text:
        if char in opening_brackets:
            stack.append(char)
        elif char in mapping:
            if not stack or stack[-1] != mapping[char]:
                return False
            stack.pop()

    return len(stack) == 0

