import json
import os
from typing import Dict, Optional

def load_tags(file_path: str) -> Dict[str, Optional[str]]:
    """
    Loads the tag hierarchy from a local JSON file.
    If the file does not exist or is empty, returns an empty dictionary.
    """
    if not os.path.exists(file_path):
        return {}

    try:
        with open(file_path, "r", encoding="utf-8") as f:
            data = json.load(f)
            if isinstance(data, dict):
                return {str(k): (str(v) if v is not None else None) for k, v in data.items()}
            return {}
    except (json.JSONDecodeError, OSError):
        return {}

def save_tags(file_path: str, tag_map: Dict[str, Optional[str]]) -> None:
    """
    Saves the tag hierarchy data to a local JSON file.
    """
    try:
        dir_name = os.path.dirname(file_path)
        if dir_name and not os.path.exists(dir_name):
            os.makedirs(dir_name, exist_ok=True)

        with open(file_path, "w", encoding="utf-8") as f:
            json.dump(tag_map, f, indent=4, ensure_ascii=False)
    except OSError as e:
        raise IOError(f"Failed to save tags to {file_path}: {e}")

