def add_tag(file_path: str, tag_name: str, parent_name: str | None) -> bool:
    if not tag_name:
        return False
    tag_map = load_tags(file_path)
    if tag_map is None:
        tag_map = {}
    if tag_name in tag_map:
        return False
    if parent_name is not None:
        if parent_name not in tag_map:
            return False
        # Cycle detection
        curr = parent_name
        visited = set()
        while curr is not None:
            if curr == tag_name:
                return False
            if curr in visited:
                break
            visited.add(curr)
            curr = tag_map.get(curr)

    tag_map[tag_name] = parent_name
    save_tags(file_path, tag_map)
    return True

def delete_tag(file_path: str, tag_name: str) -> bool:
    tag_map = load_tags(file_path)
    if tag_map is None or tag_name not in tag_map:
        return False

    del tag_map[tag_name]
    # Orphan children of the deleted tag
    for t, p in tag_map.items():
        if p == tag_name:
            tag_map[t] = None

    save_tags(file_path, tag_map)
    return True

def list_tags(file_path: str) -> list[dict[str, str | None]]:
    tag_map = load_tags(file_path)
    if tag_map is None:
        return []
    return [{"name": tag, "parent": parent} for tag, parent in tag_map.items()]

def get_all_sub_tags(file_path: str, tag_name: str) -> list[str]:
    tag_map = load_tags(file_path)
    if tag_map is None or tag_name not in tag_map:
        return []

    sub_tags = []
    queue = [tag_name]
    visited = {tag_name}

    while queue:
        curr = queue.pop(0)
        for t, p in tag_map.items():
            if p == curr and t not in visited:
                visited.add(t)
                sub_tags.append(t)
                queue.append(t)

    return sub_tags

