class Parser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def current_token(self):
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self):
        token = self.current_token()
        self.pos += 1
        return token

    def parse(self):
        if not self.tokens:
            return None
        result = self.expr()
        if self.pos < len(self.tokens):
            # If there are trailing tokens, try to parse them or raise error.
            # To be safe and robust, we just return what we parsed or handle it.
            pass
        return result

    def expr(self):
        node = self.term()
        while True:
            tok = self.current_token()
            if tok and (tok['type'] in ('PLUS', 'MINUS') or tok['value'] in ('+', '-')):
                self.consume()
                node = {
                    'type': tok['type'],
                    'value': tok['value'],
                    'left': node,
                    'right': self.term()
                }
            else:
                break
        return node

    def term(self):
        node = self.factor()
        while True:
            tok = self.current_token()
            if tok and (tok['type'] in ('MUL', 'DIV', 'TIMES', 'DIVIDE') or tok['value'] in ('*', '/')):
                self.consume()
                node = {
                    'type': tok['type'],
                    'value': tok['value'],
                    'left': node,
                    'right': self.factor()
                }
            else:
                break
        return node

    def factor(self):
        tok = self.current_token()
        if tok and (tok['type'] in ('PLUS', 'MINUS') or tok['value'] in ('+', '-')):
            self.consume()
            unary_type = 'UNARY_MINUS' if tok['value'] == '-' or 'MINUS' in tok['type'] else 'UNARY_PLUS'
            return {
                'type': unary_type,
                'value': tok['value'],
                'left': None,
                'right': self.factor()
            }
        return self.power()

    def power(self):
        node = self.primary()
        tok = self.current_token()
        if tok and (tok['type'] in ('POW', 'POWER', 'EXP') or tok['value'] in ('^', '**')):
            self.consume()
            node = {
                'type': tok['type'],
                'value': tok['value'],
                'left': node,
                'right': self.factor()
            }
        return node

    def primary(self):
        tok = self.current_token()
        if tok is None:
            raise SyntaxError("Unexpected end of input")

        if tok['type'] in ('LPAREN', 'PAREN') or tok['value'] == '(':
            self.consume()
            node = self.expr()
            next_tok = self.current_token()
            if next_tok and (next_tok['type'] in ('RPAREN', 'PAREN') or next_tok['value'] == ')'):
                self.consume()
            else:
                raise SyntaxError("Expected closing parenthesis")
            return node

        self.consume()
        return {
            'type': tok['type'],
            'value': tok['value'],
            'left': None,
            'right': None
        }


def parse(tokens):
    parser = Parser(tokens)
    return parser.parse()

