def evaluate(ast_node: dict) -> float:
    if not ast_node:
        raise ValueError("Empty AST node")

    node_type = ast_node.get('type')
    value = ast_node.get('value')

    if node_type == 'number':
        return float(value)

    elif node_type == 'unary_op':
        operand = ast_node.get('left') or ast_node.get('right')
        if operand is None:
            raise ValueError("Unary operator missing operand")
        operand_val = evaluate(operand)
        if value == '-':
            return -operand_val
        elif value == '+':
            return operand_val
        else:
            raise ValueError(f"Unsupported unary operator: {value}")

    elif node_type in ('binary_op', 'operator'):
        left_node = ast_node.get('left')
        right_node = ast_node.get('right')
        if left_node is None or right_node is None:
            raise ValueError(f"Binary operator {value} missing operands")

        left_val = evaluate(left_node)
        right_val = evaluate(right_node)

        if value == '+':
            return left_val + right_val
        elif value == '-':
            return left_val - right_val
        elif value == '*':
            return left_val * right_val
        elif value == '/':
            if right_val == 0.0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        elif value in ('^', '**'):
            return left_val ** right_val
        else:
            raise ValueError(f"Unsupported binary operator: {value}")

    else:
        if value is not None:
            try:
                return float(value)
            except ValueError:
                pass
        raise ValueError(f"Unknown AST node type or format: {ast_node}")

