def parse(tokens: list[str]) -> list | int | float | str:
    if not tokens:
        return []

    iterator = iter(tokens)

    def parse_atom(token: str) -> int | float | str:
        if token.lower() in ('nan', 'inf', '-inf', '+inf'):
            return token

        try:
            return int(token)
        except ValueError:
            pass

        try:
            return float(token)
        except ValueError:
            pass

        if (token.startswith('"') and token.endswith('"')) or (token.startswith("'") and token.endswith("'")):
            if len(token) >= 2:
                return token[1:-1]
        return token

    def parse_expr(token: str) -> list | int | float | str:
        if token in ('(', '['):
            closing = ')' if token == '(' else ']'
            elements = []
            while True:
                try:
                    next_token = next(iterator)
                except StopIteration:
                    raise ValueError(f"Expected '{closing}', reached EOF")
                if next_token == closing:
                    return elements
                elements.append(parse_expr(next_token))
        elif token in (')', ']'):
            raise ValueError(f"Unexpected '{token}'")
        else:
            return parse_atom(token)

    results = []
    while True:
        try:
            token = next(iterator)
            results.append(parse_expr(token))
        except StopIteration:
            break

    if len(results) == 1:
        return results[0]
    return results

