from typing import List, Union

def evaluate(node: Union[list, int, float, str]) -> Union[int, float]:
    if isinstance(node, (int, float)):
        return node

    if isinstance(node, str):
        normalized = node.lower()
        if normalized == 'pi':
            return math.pi
        elif normalized == 'e':
            return math.e
        else:
            raise ValueError(f"Unknown symbol: {node}")

    if isinstance(node, list):
        if not node:
            raise ValueError("Empty expression")

        op = node[0]
        if not isinstance(op, str):
            raise ValueError(f"Operator must be a string symbol, got {type(op)}")

        args = [evaluate(arg) for arg in node[1:]]
        op = op.lower()

        if op == '+':
            return sum(args)
        elif op == '-':
            if not args:
                raise ValueError("- requires at least one argument")
            if len(args) == 1:
                return -args[0]
            return args[0] - sum(args[1:])
        elif op == '*':
            if not args:
                return 1
            res = 1
            for arg in args:
                res *= arg
            return res
        elif op == '/':
            if not args:
                raise ValueError("/ requires at least one argument")
            if len(args) == 1:
                return 1 / args[0]
            res = args[0]
            for arg in args[1:]:
                res /= arg
            return res
        elif op == '//':
            if len(args) < 2:
                raise ValueError("// requires at least two arguments")
            res = args[0]
            for arg in args[1:]:
                res //= arg
            return res
        elif op in ('**', 'pow'):
            if len(args) != 2:
                raise ValueError("pow requires exactly two arguments")
            return args[0] ** args[1]
        elif op == 'mod':
            if len(args) != 2:
                raise ValueError("mod requires exactly two arguments")
            return args[0] % args[1]
        elif op == 'abs':
            if len(args) != 1:
                raise ValueError("abs requires exactly one argument")
            return abs(args[0])
        elif op == 'min':
            if not args:
                raise ValueError("min requires at least one argument")
            return min(args)
        elif op == 'max':
            if not args:
                raise ValueError("max requires at least one argument")
            return max(args)
        elif op == 'sqrt':
            if len(args) != 1:
                raise ValueError("sqrt requires exactly one argument")
            return math.sqrt(args[0])
        else:
            raise ValueError(f"Unknown operator: {op}")

    raise ValueError(f"Cannot evaluate node of type {type(node)}")

