    stack = []  # Elements are tuples: (indent_level, node_dict)

    for line in text.splitlines():
        # Skip empty lines or lines containing only whitespace
        if not line.strip():
            continue

        # Count leading spaces
        leading_spaces = len(line) - len(line.lstrip(' '))
        level = leading_spaces // indent_size
        node_text = line.strip()

        node = {
            'text': node_text,
            'children': []
        }

        # Find the parent in the stack. 
        # The parent must have a strictly lower indent level.
        while stack and stack[-1][0] >= level:
            stack.pop()

        if not stack:
            # No parent found, this is a root node
            roots.append(node)
        else:
            # Parent is the current top of the stack
            stack[-1][1]['children'].append(node)

        stack.append((level, node))

    return roots

