import re
from typing import Any, List
from nodes import create_node

class Token:
    def __init__(self, type_: str, value: str):
        self.type = type_
        self.value = value

TOKEN_SPECIFICATION = [
    ('NUMBER',   r'\d+(?:\.\d+)?'),
    ('IDENT',    r'[a-zA-Z_][a-zA-Z0-9_]*'),
    ('PLUS',     r'\+'),
    ('MINUS',    r'-'),
    ('MUL',      r'\*'),
    ('DIV',      r'/'),
    ('POW',      r'\^'),
    ('LPAREN',   r'\('),
    ('RPAREN',   r'\)'),
    ('SKIP',     r'[ \t\n\r]+'),
    ('MISMATCH', r'.'),
]

def tokenize(expression: str) -> List[Token]:
    tok_regex = '|'.join(f'(?P<{name}>{pattern})' for name, pattern in TOKEN_SPECIFICATION)
    tokens = []
    for mo in re.finditer(tok_regex, expression):
        kind = mo.lastgroup
        value = mo.group()
        if kind == 'SKIP':
            continue
        elif kind == 'MISMATCH':
            raise ValueError(f'Unexpected character: {value!r}')
        else:
            tokens.append(Token(kind, value))
    tokens.append(Token('EOF', ''))
    return tokens

class Parser:
    def __init__(self, tokens: List[Token]):
        self.tokens = tokens
        self.pos = 0

    def current_token(self) -> Token:
        return self.tokens[self.pos]

    def consume(self, expected_type: str = None) -> Token:
        tok = self.current_token()
        if expected_type and tok.type != expected_type:
            raise ValueError(f"Expected {expected_type} but got {tok.type}")
        self.pos += 1
        return tok

    def parse(self) -> Any:
        node = self.expr()
        if self.current_token().type != 'EOF':
            raise ValueError(f"Unexpected token at end: {self.current_token().value}")
        return node

    def expr(self) -> Any:
        return self.add_sub()

    def add_sub(self) -> Any:
        node = self.mul_div()
        while self.current_token().type in ('PLUS', 'MINUS'):
            op_tok = self.consume()
            right = self.mul_div()
            node = create_node('BINARY_OP', op_tok.value, node, right)
        return node

    def mul_div(self) -> Any:
        node = self.pow()
        while self.current_token().type in ('MUL', 'DIV'):
            op_tok = self.consume()
            right = self.pow()
            node = create_node('BINARY_OP', op_tok.value, node, right)
        return node

    def pow(self) -> Any:
        node = self.unary()
        if self.current_token().type == 'POW':
            op_tok = self.consume()
            right = self.pow()
            node = create_node('BINARY_OP', op_tok.value, node, right)
        return node

    def unary(self) -> Any:
        if self.current_token().type in ('PLUS', 'MINUS'):
            op_tok = self.consume()
            expr_node = self.unary()
            return create_node('UNARY_OP', op_tok.value, expr_node, None)
        return self.primary()

    def primary(self) -> Any:
        tok = self.current_token()
        if tok.type == 'NUMBER':
            self.consume()
            return create_node('NUMBER', tok.value, None, None)
        elif tok.type == 'IDENT':
            self.consume()
            return create_node('VARIABLE', tok.value, None, None)
        elif tok.type == 'LPAREN':
            self.consume('LPAREN')
            node = self.expr()
            self.consume('RPAREN')
            return node
        else:
            raise ValueError(f"Unexpected token: {tok.value}")

def parse(expression: str) -> Any:
    tokens = tokenize(expression)
    parser = Parser(tokens)
    return parser.parse()

