from nodes import create_node, Node

def fold(tree: Node) -> Node:
    if tree is None:
        return None

    left = getattr(tree, 'left', None)
    right = getattr(tree, 'right', None)

    folded_left = fold(left) if left is not None else None
    folded_right = fold(right) if right is not None else None

    def is_number(n) -> bool:
        if n is None:
            return False
        if getattr(n, 'left', None) is not None or getattr(n, 'right', None) is not None:
            return False
        try:
            float(n.value)
            return True
        except (ValueError, TypeError, AttributeError):
            return False

    def get_val(n):
        v = n.value
        if '.' in v or 'e' in v.lower():
            return float(v)
        try:
            return int(v)
        except ValueError:
            return float(v)

    if folded_left is not None and folded_right is not None:
        if is_number(folded_left) and is_number(folded_right):
            op = tree.value
            if op in ('+', '-', '*', '/', '//', '%', '**'):
                try:
                    v1 = get_val(folded_left)
                    v2 = get_val(folded_right)
                    if op == '+': res = v1 + v2
                    elif op == '-': res = v1 - v2
                    elif op == '*': res = v1 * v2
                    elif op == '/': res = v1 / v2
                    elif op == '//': res = v1 // v2
                    elif op == '%': res = v1 % v2
                    elif op == '**': res = v1 ** v2
                    else: res = None

                    if res is not None:
                        return create_node(folded_left.type, str(res), None, None)
                except Exception:
                    pass

    elif (folded_left is not None) ^ (folded_right is not None):
        child = folded_left if folded_left is not None else folded_right
        if is_number(child):
            op = tree.value
            if op in ('+', '-'):
                try:
                    v = get_val(child)
                    res = -v if op == '-' else v
                    return create_node(child.type, str(res), None, None)
                except Exception:
                    pass

    return create_node(tree.type, tree.value, folded_left, folded_right)

