from typing import Optional
from nodes import Node

def serialize(tree: Node) -> str:
    PRECEDENCE = {
        '+': 1, '-': 1,
        '*': 2, '/': 2,
        '^': 3, '**': 3
    }

    RIGHT_ASSOCIATIVE = {'^', '**'}

    def is_operator(node: Node) -> bool:
        if node is None:
            return False
        return (node.left is not None or node.right is not None) and node.value in PRECEDENCE

    def helper(node: Optional[Node]) -> str:
        if node is None:
            return ""

        if not is_operator(node):
            return str(node.value)

        op = node.value

        # Unary operator handling
        if node.left is None and node.right is not None:
            content = helper(node.right)
            if is_operator(node.right):
                rp = PRECEDENCE.get(node.right.value, 0)
                # Unary minus has higher precedence than binary operators
                if rp < 4:
                    content = f"({content})"
            return f"{op}{content}"

        left_str = helper(node.left)
        right_str = helper(node.right)

        # Process left child parentheses
        left_node = node.left
        if left_node and is_operator(left_node):
            lp = PRECEDENCE.get(left_node.value, 0)
            pp = PRECEDENCE.get(op, 0)
            if lp < pp:
                left_str = f"({left_str})"
            elif lp == pp:
                if op in RIGHT_ASSOCIATIVE:
                    left_str = f"({left_str})"

        # Process right child parentheses
        right_node = node.right
        if right_node and is_operator(right_node):
            rp = PRECEDENCE.get(right_node.value, 0)
            pp = PRECEDENCE.get(op, 0)
            if rp < pp:
                right_str = f"({right_str})"
            elif rp == pp:
                if op not in RIGHT_ASSOCIATIVE:
                    right_str = f"({right_str})"

        return f"{left_str} {op} {right_str}"

    return helper(tree)

