def resolve_dependencies(graph: dict[str, list[str]]) -> tuple[list[str], list[list[str]]]:
    all_nodes = sorted(list(set(graph.keys()) | {dep for deps in graph.values() for dep in deps}))
    adj = {node: graph.get(node, []) for node in all_nodes}

    index = {}
    lowlink = {}
    on_stack = {}
    stack = []
    idx = 0
    sccs = []

    def strongconnect(v):
        nonlocal idx
        index[v] = idx
        lowlink[v] = idx
        idx += 1
        stack.append(v)
        on_stack[v] = True

        for w in sorted(adj[v]):
            if w not in index:
                strongconnect(w)
                lowlink[v] = min(lowlink[v], lowlink[w])
            elif on_stack[w]:
                lowlink[v] = min(lowlink[v], index[w])

        if lowlink[v] == index[v]:
            scc = []
            while True:
                w = stack.pop()
                on_stack[w] = False
                scc.append(w)
                if w == v:
                    break
            sccs.append(scc[::-1])

    for node in all_nodes:
        if node not in index:
            strongconnect(node)

    cycles = []
    for scc in sccs:
        if len(scc) > 1 or (len(scc) == 1 and scc[0] in adj[scc[0]]):
            cycles.append(scc)

    if cycles:
        return [], cycles

    topo_order = [node for scc in sccs for node in scc]
    return topo_order, []

