def insert(root: dict | None, key: int) -> dict:
    if root is None:
        return {"key": key, "left": None, "right": None}

    if key < root["key"]:
        root["left"] = insert(root["left"], key)
    elif key > root["key"]:
        root["right"] = insert(root["right"], key)

    return root


def find(root: dict | None, key: int) -> bool:
    if root is None:
        return False

    if key == root["key"]:
        return True
    elif key < root["key"]:
        return find(root["left"], key)
    else:
        return find(root["right"], key)


def _min_value_node(node: dict) -> dict:
    current = node
    while current["left"] is not None:
        current = current["left"]
    return current


def delete(root: dict | None, key: int) -> dict | None:
    if root is None:
        return None

    if key < root["key"]:
        root["left"] = delete(root["left"], key)
    elif key > root["key"]:
        root["right"] = delete(root["right"], key)
    else:
        # Node with only one child or no child
        if root["left"] is None:
            return root["right"]
        elif root["right"] is None:
            return root["left"]

        # Node with two children: Get the inorder successor (smallest in the right subtree)
        temp = _min_value_node(root["right"])
        root["key"] = temp["key"]
        root["right"] = delete(root["right"], temp["key"])

    return root


def inorder(root: dict | None) -> list[int]:
    if root is None:
        return []
    return inorder(root["left"]) + [root["key"]] + inorder(root["right"])

