def check_balance(text: str) -> bool:
    """
    Checks if the parentheses, square brackets, and curly braces in the text are balanced.

    Args:
        text (str): The input string to validate.

    Returns:
        bool: True if the brackets are balanced, False otherwise.
    """
    stack = []
    bracket_map = {")": "(", "]": "[", "}": "{"}
    opening_brackets = set(bracket_map.values())
    closing_brackets = set(bracket_map.keys())

    for char in text:
        if char in opening_brackets:
            stack.append(char)
        elif char in closing_brackets:
            if not stack or stack[-1] != bracket_map[char]:
                return False
            stack.pop()

    return len(stack) == 0

