import json
import os
from typing import Dict, List

def load_graph(file_path: str) -> Dict[str, List[str]]:
    """
    Loads a graph structure from a local JSON file.
    Returns an empty dictionary if the file does not exist or cannot be read.
    """
    if not os.path.exists(file_path):
        return {}
    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            data = json.load(f)
            if isinstance(data, dict):
                # Ensure the loaded structure matches dict[str, list[str]]
                validated_graph: Dict[str, List[str]] = {}
                for key, value in data.items():
                    if isinstance(value, list):
                        validated_graph[str(key)] = [str(item) for item in value]
                    else:
                        validated_graph[str(key)] = []
                return validated_graph
            return {}
    except (json.JSONDecodeError, OSError, TypeError):
        return {}

def save_graph(file_path: str, graph_data: Dict[str, List[str]]) -> bool:
    """
    Saves the graph structure to a local JSON file.
    Returns True if successful, False otherwise.
    """
    try:
        # Ensure target directory exists
        directory = os.path.dirname(file_path)
        if directory and not os.path.exists(directory):
            os.makedirs(directory, exist_ok=True)

        with open(file_path, 'w', encoding='utf-8') as f:
            json.dump(graph_data, f, indent=4, ensure_ascii=False)
        return True
    except (OSError, TypeError):
        return False

