        graph[vertex] = []
    return graph

def delete_vertex(graph: dict[str, list[str]], vertex: str) -> dict[str, list[str]]:
    if vertex in graph:
        del graph[vertex]
    for u in graph:
        if vertex in graph[u]:
            graph[u] = [v for v in graph[u] if v != vertex]
    return graph

def add_edge(graph: dict[str, list[str]], u: str, v: str) -> dict[str, list[str]]:
    if u not in graph:
        graph[u] = []
    if v not in graph:
        graph[v] = []
    if v not in graph[u]:
        graph[u].append(v)
    return graph

def delete_edge(graph: dict[str, list[str]], u: str, v: str) -> dict[str, list[str]]:
    if u in graph and v in graph[u]:
        graph[u].remove(v)
    return graph

def get_vertices(graph: dict[str, list[str]]) -> list[str]:
