import os
import json

def load_tags(file_path: str) -> dict[str, str | None]:
    """
    Loads tag data from a JSON file.
    If the file does not exist or is corrupted, returns an empty dictionary.
    """
    if not os.path.exists(file_path):
        return {}
    try:
        with open(file_path, "r", encoding="utf-8") as f:
            data = json.load(f)
            if isinstance(data, dict):
                return {str(k): (str(v) if v is not None else None) for k, v in data.items()}
            return {}
    except (json.JSONDecodeError, IOError, ValueError):
        return {}

def save_tags(file_path: str, tags: dict[str, str | None]) -> None:
    """
    Saves tag data to a JSON file.
    Creates any necessary parent directories automatically.
    """
    dir_name = os.path.dirname(file_path)
    if dir_name and not os.path.exists(dir_name):
        os.makedirs(dir_name, exist_ok=True)

    with open(file_path, "w", encoding="utf-8") as f:
        json.dump(tags, f, indent=4, ensure_ascii=False)

