TAGS_FILE = "tags.json"

def list_tags() -> dict[str, str | None]:
    try:
        return load_tags(TAGS_FILE)
    except Exception:
        return {}

def add_tag(name: str, parent: str | None) -> bool:
    if not name:
        return False
    tags = list_tags()
    if name in tags:
        return False
    if parent is not None and parent not in tags:
        return False
    tags[name] = parent
    try:
        save_tags(TAGS_FILE, tags)
        return True
    except Exception:
        return False

def delete_tag(name: str) -> bool:
    tags = list_tags()
    if name not in tags:
        return False

    descendants = get_descendants(name)
    for d in descendants:
        if d in tags:
            del tags[d]

    if name in tags:
        del tags[name]

    try:
        save_tags(TAGS_FILE, tags)
        return True
    except Exception:
        return False

def get_descendants(name: str) -> list[str]:
    tags = list_tags()
    if name not in tags:
        return []

    descendants = []
    queue = [name]
    while queue:
        current = queue.pop(0)
        children = [child for child, parent in tags.items() if parent == current]
        for child in children:
            descendants.append(child)
            queue.append(child)

    return descendants

