def parse(tokens: list[dict]) -> dict:
    idx = 0

    def peek() -> dict | None:
        if idx < len(tokens):
            return tokens[idx]
        return None

    def consume() -> dict:
        nonlocal idx
        tok = peek()
        if tok is None:
            raise SyntaxError("Unexpected end of input")
        idx += 1
        return tok

    def primary() -> dict:
        tok = peek()
        if tok is None:
            raise SyntaxError("Unexpected end of input in primary expression")

        # Parentheses
        if tok.get("type") == "LPAREN" or tok.get("value") == "(":
            consume()
            node = expr()
            next_tok = peek()
            if next_tok and (next_tok.get("type") == "RPAREN" or next_tok.get("value") == ")"):
                consume()
            else:
                raise SyntaxError("Expected closing parenthesis")
            return node

        # Numbers, Identifiers, and generic leaf values
        if tok.get("type") in ("NUMBER", "IDENTIFIER", "INT", "FLOAT", "VAR", "STRING") or (tok.get("value") and tok.get("value").isalnum()):
            consume()
            return {
                "type": tok.get("type", "VALUE"),
                "value": tok.get("value", ""),
                "left": None,
                "right": None
            }

        # Fallback leaf
        consume()
        return {
            "type": tok.get("type", "UNKNOWN"),
            "value": tok.get("value", ""),
            "left": None,
            "right": None
        }

    def unary() -> dict:
        tok = peek()
        if tok and tok.get("value") in ("+", "-"):
            consume()
            right = unary()
            return {
                "type": "UNARY_OP",
                "value": tok.get("value", ""),
                "left": None,
                "right": right
            }
        return primary()

    def exponent() -> dict:
        node = unary()
        tok = peek()
        if tok and tok.get("value") == "^":
            consume()
            right = exponent()
            node = {
                "type": "BINARY_OP",
                "value": "^",
                "left": node,
                "right": right
            }
        return node

    def term() -> dict:
        node = exponent()
        while True:
            tok = peek()
            if tok and tok.get("value") in ("*", "/", "%"):
                consume()
                right = exponent()
                node = {
                    "type": "BINARY_OP",
                    "value": tok.get("value", ""),
                    "left": node,
                    "right": right
                }
            else:
                break
        return node

    def expr() -> dict:
        node = term()
        while True:
            tok = peek()
            if tok and tok.get("value") in ("+", "-"):
                consume()
                right = term()
                node = {
                    "type": "BINARY_OP",
                    "value": tok.get("value", ""),
                    "left": node,
                    "right": right
                }
            else:
                break
        return node

    if not tokens:
        raise ValueError("Empty token list")

    ast = expr()
    if idx < len(tokens):
        # Remaining trailing tokens that couldn't be parsed as part of the expression
        raise SyntaxError(f"Unparsed tokens remaining: {tokens[idx:]}")
    return ast

