def evaluate(ast: dict) -> float:
    if ast is None:
        raise ValueError("Cannot evaluate None AST node")

    node_type = ast.get("type")
    node_value = ast.get("value")
    left = ast.get("left")
    right = ast.get("right")

    # If it is a leaf numeric node
    if node_type in ("number", "literal", "NUM", "int", "float") or (left is None and right is None):
        try:
            return float(node_value)
        except (ValueError, TypeError) as e:
            raise ValueError(f"Invalid numeric value: {node_value}") from e

    # Determine the operator
    op = node_value if node_value in ("+", "-", "*", "/", "^", "**") else node_type

    if op == "+":
        left_val = evaluate(left) if left is not None else 0.0
        right_val = evaluate(right) if right is not None else 0.0
        return left_val + right_val
    elif op == "-":
        left_val = evaluate(left) if left is not None else 0.0
        right_val = evaluate(right) if right is not None else 0.0
        return left_val - right_val
    elif op == "*":
        if left is None or right is None:
            raise ValueError("Multiplication requires both left and right operands")
        return evaluate(left) * evaluate(right)
    elif op == "/":
        if left is None or right is None:
            raise ValueError("Division requires both left and right operands")
        denom = evaluate(right)
        if denom == 0.0:
            raise ZeroDivisionError("division by zero")
        return evaluate(left) / denom
    elif op in ("^", "**"):
        if left is None or right is None:
            raise ValueError("Exponentiation requires both left and right operands")
        return evaluate(left) ** evaluate(right)

    # Alternative checks for generic operator nodes
    if node_type in ("operator", "binary_op", "unary_op"):
        op_char = node_value
        if op_char == "+":
            left_val = evaluate(left) if left is not None else 0.0
            return left_val + evaluate(right)
        elif op_char == "-":
            left_val = evaluate(left) if left is not None else 0.0
            return left_val - evaluate(right)
        elif op_char == "*":
            return evaluate(left) * evaluate(right)
        elif op_char == "/":
            denom = evaluate(right)
            if denom == 0.0:
                raise ZeroDivisionError("division by zero")
            return evaluate(left) / denom
        elif op_char in ("^", "**"):
            return evaluate(left) ** evaluate(right)

    raise ValueError(f"Unknown AST node or operator: {ast}")

