def parse(tokens: list[str]) -> list | str | int | float:
    if not tokens:
        return []

    index = 0

    def atom(token: str) -> str | int | float:
        try:
            return int(token)
        except ValueError:
            try:
                return float(token)
            except ValueError:
                if len(token) >= 2 and (
                    (token[0] == '"' and token[-1] == '"') or
                    (token[0] == "'" and token[-1] == "'")
                ):
                    return token[1:-1]
                return token

    def parse_expression() -> list | str | int | float:
        nonlocal index
        if index >= len(tokens):
            raise SyntaxError("Unexpected EOF")

        token = tokens[index]
        index += 1

        if token == '(':
            lst = []
            while index < len(tokens) and tokens[index] != ')':
                lst.append(parse_expression())
            if index >= len(tokens):
                raise SyntaxError("Expected ')' but reached EOF")
            index += 1  # consume ')'
            return lst
        elif token == ')':
            raise SyntaxError("Unexpected ')'")
        else:
            return atom(token)

    top_level = []
    while index < len(tokens):
        top_level.append(parse_expression())

    if len(top_level) == 1:
        return top_level[0]
    return top_level

