def evaluate(node: Union[list, str, int, float]) -> Union[int, float]:
    if isinstance(node, (int, float)):
        return node

    if isinstance(node, str):
        try:
            if '.' in node or 'e' in node.lower():
                return float(node)
            return int(node)
        except ValueError:
            raise ValueError(f"Unknown or invalid numeric symbol: '{node}'")

    if isinstance(node, list):
        if not node:
            raise ValueError("Cannot evaluate an empty S-expression.")

        op = node[0]
        if not isinstance(op, str):
            raise ValueError(f"S-expression operator must be a string, got: {type(op)}")

        args = [evaluate(arg) for arg in node[1:]]

        if op == '+':
            return sum(args)
        elif op == '-':
            if not args:
                raise ValueError("Operator '-' requires at least one argument.")
            if len(args) == 1:
                return -args[0]
            return args[0] - sum(args[1:])
        elif op == '*':
            prod = 1
            for x in args:
                prod *= x
            return prod
        elif op == '/':
            if not args:
                raise ValueError("Operator '/' requires at least one argument.")
            if len(args) == 1:
                return 1 / args[0]
            res = args[0]
            for x in args[1:]:
                res /= x
            return res
        elif op in ('^', '**', 'pow'):
            if len(args) != 2:
                raise ValueError(f"Operator '{op}' requires exactly 2 arguments, got {len(args)}")
            return args[0] ** args[1]
        elif op in ('mod', '%'):
            if len(args) != 2:
                raise ValueError(f"Operator '{op}' requires exactly 2 arguments, got {len(args)}")
            return args[0] % args[1]
        elif op == 'abs':
            if len(args) != 1:
                raise ValueError("Operator 'abs' requires exactly 1 argument.")
            return abs(args[0])
        elif op == 'min':
            if not args:
                raise ValueError("Operator 'min' requires at least one argument.")
            return min(args)
        elif op == 'max':
            if not args:
                raise ValueError("Operator 'max' requires at least one argument.")
            return max(args)
        else:
            raise ValueError(f"Unknown operator: '{op}'")

    raise TypeError(f"Invalid AST node type: {type(node)}")

