def parse_to_tree(text: str) -> dict:
    lines = text.splitlines()
    parsed_lines = []
    for line in lines:
        if not line.strip():
            continue
        # Standardize tabs to 4 spaces for consistent indentation calculation
        expanded = line.expandtabs(4)
        expanded_right_stripped = expanded.rstrip()
        indent = len(expanded_right_stripped) - len(expanded_right_stripped.lstrip(' '))
        content = expanded_right_stripped.lstrip()
        parsed_lines.append((indent, content))

    if not parsed_lines:
        return {'text': '', 'depth': 0, 'children': []}

    # Map physical indentations to logical depths
    indent_levels = []
    nodes_with_depth = []
    for indent, content in parsed_lines:
        if not indent_levels:
            indent_levels.append(indent)
            depth = 0
        elif indent > indent_levels[-1]:
            indent_levels.append(indent)
            depth = len(indent_levels) - 1
        elif indent < indent_levels[-1]:
            while indent_levels and indent < indent_levels[-1]:
                indent_levels.pop()
            if not indent_levels or indent_levels[-1] != indent:
                indent_levels.append(indent)
            depth = len(indent_levels) - 1
        else:
            depth = len(indent_levels) - 1
        nodes_with_depth.append((depth, content))

    # Build the hierarchy using a stack
    root = {'text': 'Root', 'depth': -1, 'children': []}
    stack = [root]

    for depth, content in nodes_with_depth:
        node = {'text': content, 'depth': depth, 'children': []}
        while len(stack) > 1 and stack[-1]['depth'] >= depth:
            stack.pop()
        stack[-1]['children'].append(node)
        stack.append(node)

    # If there is only a single top-level node, return it directly to simplify the tree
    if len(root['children']) == 1:
        return root['children'][0]
    return root

