def serialize_tree(tree: dict, indent_char: str) -> str:
    if not tree:
        return ""

    lines = []

    def traverse(node: dict):
        depth = node.get('depth', 0)
        text = node.get('text', '')

        # If depth is negative, we treat it as a virtual/dummy root and do not render it
        if depth >= 0:
            indent = indent_char * depth
            lines.append(f"{indent}{text}")

