Token = Tuple[str, Union[float, str, None]]

def tokenize(expression: str) -> Generator[Token, None, None]:
    token_specification = [
        ('NUMBER',   r'\d+(?:\.\d+)?'),
        ('OP',       r'[+\-*/^]'),
        ('LPAREN',   r'\Stack(' or r'\('),
        ('RPAREN',   r'\)'),
        ('SKIP',     r'\s+'),
        ('MISMATCH', r'.'),
    ]
    # Simple compilation of patterns
    # We replace LPAREN with exact '(' because standard regex for paren is simple
    token_specification = [
        ('NUMBER',   r'\d+(?:\.\d+)?'),
        ('OP',       r'[+\-*/^]'),
        ('LPAREN',   r'\('),
        ('RPAREN',   r'\)'),
        ('SKIP',     r'\s+'),
        ('MISMATCH', r'.'),
    ]
    tok_regex = '|'.join(f'(?P<{name}>{pattern})' for name, pattern in token_specification)
    for mo in re.finditer(tok_regex, expression):
        kind = mo.lastgroup
        value = mo.group()
        if kind == 'NUMBER':
            yield ('NUMBER', float(value))
        elif kind == 'OP':
            yield ('OP', value)
        elif kind == 'LPAREN':
            yield ('LPAREN', value)
        elif kind == 'RPAREN':
            yield ('RPAREN', value)
        elif kind == 'SKIP':
            pass
        elif kind == 'MISMATCH':
            raise ValueError(f'Unexpected character: {value}')
    yield ('EOF', None)

class Parser:
