            _, op_val = self.consume()
            right = self.term()
            node = {
                'type': 'binary_op',
                'value': None,
                'op': op_val,
                'left': node,
                'right': right
            }
        return node

    def term(self) -> Dict[str, Any]:
        # term -> factor ( ( '*' | '/' ) factor )*
        node = self.factor()
        while self.peek()[0] == 'OP' and self.peek()[1] in ('*', '/'):
            _, op_val = self.consume()
            right = self.factor()
            node = {
                'type': 'binary_op',
                'value': None,
                'op': op_val,
                'left': node,
                'right': right
            }
