    def factor(self) -> Dict[str, Any]:
        # factor -> unary [ '^' factor ]
        node = self.unary()
        if self.peek()[0] == 'OP' and self.peek()[1] == '^':
            _, op_val = self.consume()
            right = self.factor()
            node = {
                'type': 'binary_op',
                'value': None,
                'op': op_val,
                'left': node,
                'right': right
            }
        return node

    def unary(self) -> Dict[str, Any]:
        # unary -> ( '+' | '-' ) unary | primary
        tok_type, tok_val = self.peek()
        if tok_type == 'OP' and tok_val in ('+', '-'):
            self.consume()
            operand = self.unary()
            return {
                'type': 'unary_op',
                'value': None,
                'op': tok_val,
                'left': operand,
                'right': None
            }
        return self.primary()

    def primary(self) -> Dict[str, Any]:
        tok_type, tok_val = self.peek()
        if tok_type == 'NUMBER':
            self.consume()
