    '^': 3,
}

RIGHT_ASSOCIATIVE = {'^'}

def is_binary(node: dict) -> bool:
    return bool(node and node.get('left') is not None and node.get('right') is not None)

def is_unary(node: dict) -> bool:
    if not node:
        return False
    op = node.get('op')
    has_left = node.get('left') is not None
    has_right = node.get('right') is not None
    return bool(op and (has_left != has_right))

def get_precedence(node: dict) -> float:
    if not node:
        return 100
    op = node.get('op')
    if is_binary(node):
        return PRECEDENCE.get(op, 0)
    elif is_unary(node):
        if op in ('+', '-'):
            return 2.5
        return 100
    return 100

def tree_to_string(tree: dict) -> str:
    if not tree:
        return ""

    # Leaf node check
    if not tree.get('left') and not tree.get('right'):
        val = tree.get('value')
        if val is None:
            val = tree.get('op', '')
        if isinstance(val, float) and val.is_integer():
            return str(int(val))
        return str(val)

    # Unary node check
    if is_unary(tree):
        op = tree.get('op', '')
        child = tree.get('right') if tree.get('right') is not None else tree.get('left')
        child_str = tree_to_string(child)

        if op in ('+', '-'):
            child_prec = get_precedence(child)
            parent_prec = 2.5
            if child_prec < parent_prec:
                return f"{op}({child_str})"
            else:
                return f"{op}{child_str}"
        else:
            return f"{op}({child_str})"

    # Binary node check
    if is_binary(tree):
        op = tree.get('op', '')
        left = tree['left']
        right = tree['right']

        left_str = tree_to_string(left)
        right_str = tree_to_string(right)

        parent_prec = PRECEDENCE.get(op, 0)

        # Determine if left needs parentheses
        left_prec = get_precedence(left)
        left_needs_paren = False
        if left_prec < parent_prec:
            left_needs_paren = True
        elif left_prec == parent_prec:
            if op in RIGHT_ASSOCIATIVE:
                left_needs_paren = True

        # Determine if right needs parentheses
        right_prec = get_precedence(right)
        right_needs_paren = False
        if right_prec < parent_prec:
            right_needs_paren = True
        elif right_prec == parent_prec:
            if op not in RIGHT_ASSOCIATIVE:
                right_needs_paren = True

        if left_needs_paren:
            left_str = f"({left_str})"
        if right_needs_paren:
            right_str = f"({right_str})"

        return f"{left_str} {op} {right_str}"

    # Fallback to avoid empty output
    return str(tree.get('value', tree.get('op', '')))

