def build_adjacency_list(raw_dependencies: dict[str, list[str]]) -> dict[str, list[str]]:
    """
    Validates and structures raw dependency data into an adjacency list representation of a directed graph.
    Ensures all keys and values are valid strings, and all referenced nodes exist as keys in the output.
    """
    if not isinstance(raw_dependencies, dict):
        raise TypeError("raw_dependencies must be a dictionary")

    adj_list: dict[str, list[str]] = {}

    # First pass: Validate types and populate defined nodes
    for node, deps in raw_dependencies.items():
        if not isinstance(node, str):
            raise TypeError(f"Graph node must be a string, got {type(node).__name__}")
        if not isinstance(deps, list):
            raise TypeError(f"Dependencies for node '{node}' must be a list, got {type(deps).__name__}")

        cleaned_deps = []
        for dep in deps:
            if not isinstance(dep, str):
                raise TypeError(f"Dependency of node '{node}' must be a string, got {type(dep).__name__}")
            cleaned_deps.append(dep)

        # Remove duplicate dependencies while preserving order
        adj_list[node] = list(dict.fromkeys(cleaned_deps))

    # Second pass: Ensure all referenced dependency nodes exist as keys in the adjacency list
    referenced_nodes = set()
    for deps in adj_list.values():
        for dep in deps:
            referenced_nodes.add(dep)

    for ref_node in referenced_nodes:
        if ref_node not in adj_list:
            adj_list[ref_node] = []

    return adj_list

