import heapq

def resolve_dependencies(adj_list: dict[str, list[str]]) -> tuple[list[str], list[list[str]]]:
    # Identify all nodes in the graph
    all_nodes = set(adj_list.keys()) | {dep for deps in adj_list.values() for dep in deps}

    # Build in-degree map and list of dependents
    in_degree = {node: 0 for node in all_nodes}
    dependents = {node: [] for node in all_nodes}

    for u, deps in adj_list.items():
        for v in deps:
            dependents[v].append(u)
            in_degree[u] += 1

    # Kahn's algorithm with a min-heap for lexicographically deterministic topological sort
    queue = [node for node in all_nodes if in_degree[node] == 0]
    heapq.heapify(queue)

    order = []
    while queue:
        curr = heapq.heappop(queue)
        order.append(curr)
        for dep in dependents[curr]:
            in_degree[dep] -= 1
            if in_degree[dep] == 0:
                heapq.heappush(queue, dep)

    # If all nodes are resolved, there are no cycles
    if len(order) == len(all_nodes):
        return order, []

    # Otherwise, find strongly connected components (cycles) using Tarjan's algorithm
    index = 0
    indices = {}
    lowlink = {}
    on_stack = set()
    stack = []
    sccs = []

    def strongconnect(v):
        nonlocal index
        indices[v] = index
        lowlink[v] = index
        index += 1
        stack.append(v)
        on_stack.add(v)

        for w in adj_list.get(v, []):
            if w not in indices:
                strongconnect(w)
                lowlink[v] = min(lowlink[v], lowlink[w])
            elif w in on_stack:
                lowlink[v] = min(lowlink[v], indices[w])

        if lowlink[v] == indices[v]:
            scc = []
            while True:
                w = stack.pop()
                on_stack.remove(w)
                scc.append(w)
                if w == v:
                    break
            sccs.append(scc)

    for node in sorted(all_nodes):
        if node not in indices:
            strongconnect(node)

    # Filter out trivial components of size 1 that have no self-loops
    cycles = []
    for scc in sccs:
        if len(scc) > 1:
            cycles.append(sorted(scc))
        elif len(scc) == 1:
            node = scc[0]
            if node in adj_list.get(node, []):
                cycles.append([node])

    cycles.sort()
    return [], cycles

