from typing import Any

def insert_node(tree: dict | None, key: int) -> dict:
    if tree is None:
        return {"key": key, "left": None, "right": None}

    if key < tree["key"]:
        tree["left"] = insert_node(tree["left"], key)
    elif key > tree["key"]:
        tree["right"] = insert_node(tree["right"], key)

    return tree

def find_node(tree: dict | None, key: int) -> bool:
    if tree is None:
        return False

    if tree["key"] == key:
        return True
    elif key < tree["key"]:
        return find_node(tree["left"], key)
    else:
        return find_node(tree["right"], key)

def delete_node(tree: dict | None, key: int) -> dict | None:
    if tree is None:
        return None

    if key < tree["key"]:
        tree["left"] = delete_node(tree["left"], key)
    elif key > tree["key"]:
        tree["right"] = delete_node(tree["right"], key)
    else:
        if tree["left"] is None:
            return tree["right"]
        elif tree["right"] is None:
            return tree["left"]

        # Node with two children: Get the inorder successor
        successor = tree["right"]
        while successor["left"] is not None:
            successor = successor["left"]

        tree["key"] = successor["key"]
        tree["right"] = delete_node(tree["right"], successor["key"])

    return tree

def inorder_traversal(tree: dict | None) -> list[int]:
    if tree is None:
        return []

    return inorder_traversal(tree["left"]) + [tree["key"]] + inorder_traversal(tree["right"])

