def check_matching_parentheses(text: str) -> bool:
    """
    Checks if the parentheses in the given string are balanced.
    Supports standard parentheses (), square brackets [], and curly braces {}.
    """
    stack = []
    mapping = {")": "(", "}": "{", "]": "["}

    for char in text:
        if char in mapping.values():
            stack.append(char)
        elif char in mapping:
            if not stack or stack[-1] != mapping[char]:
                return False
            stack.pop()

    return len(stack) == 0

