def add_vertex(graph: dict[str, list], vertex: str) -> dict[str, list]:
    new_graph = {k: list(v) for k, v in graph.items()}
    if vertex not in new_graph:
        new_graph[vertex] = []
    return new_graph

def delete_vertex(graph: dict[str, list], vertex: str) -> dict[str, list]:
    new_graph = {}
    for k, v in graph.items():
        if k == vertex:
            continue
        new_graph[k] = [neighbor for neighbor in v if neighbor != vertex]
    return new_graph

def add_edge(graph: dict[str, list], source: str, target: str) -> dict[str, list]:
    new_graph = {k: list(v) for k, v in graph.items()}
    if source not in new_graph:
        new_graph[source] = []
    if target not in new_graph:
        new_graph[target] = []
    if target not in new_graph[source]:
        new_graph[source].append(target)
    return new_graph

def delete_edge(graph: dict[str, list], source: str, target: str) -> dict[str, list]:
    new_graph = {k: list(v) for k, v in graph.items()}
    if source in new_graph:
        new_graph[source] = [neighbor for neighbor in new_graph[source] if neighbor != target]
    return new_graph

