        return False

    tags = _load()

    if name in tags:
        return False

    if parent is not None:
        if parent not in tags:
            return False

        # Cycle detection
        curr = parent
        while curr is not None:
            if curr == name:
                return False
            curr = tags.get(curr)

    tags[name] = parent
    _save(tags)
    return True

def delete_tag(name: str) -> bool:
    tags = _load()
    if name not in tags:
        return False

    # Reparent direct children of the deleted tag to None
    for tag, parent in tags.items():
        if parent == name:
            tags[tag] = None

    del tags[name]
    _save(tags)
    return True

