    tags = _load()
    if name not in tags:
        return []

    subtags: list[str] = []
    queue = [name]
    while queue:
        curr = queue.pop(0)
        children = [tag for tag, parent in tags.items() if parent == curr]
        for child in children:
            subtags.append(child)
            queue.append(child)

    return subtags

def get_hierarchy() -> dict[str, list[str]]:
    tags = _load()
    hierarchy: dict[str, list[str]] = {tag: [] for tag in tags}
    for tag, parent in tags.items():
        if parent in hierarchy:
            hierarchy[parent].append(tag)
    return hierarchy

