import math

def evaluate(ast: dict) -> float:
    """
    Evaluates the Abstract Syntax Tree (AST) representation of an expression
    and returns the computed float result.
    """
    if ast is None:
        raise ValueError("AST is empty or None")

    if not isinstance(ast, dict):
        return float(ast)

    node_type = ast.get("type", "").lower()

    # Numeric Leaf Node
    if node_type in ("number", "num", "literal", "numericliteral") or ("value" in ast and "left" not in ast and "right" not in ast):
        return float(ast["value"])

    # Binary Operations
    if node_type in ("binop", "binaryop", "binaryexpression") or ("left" in ast and "right" in ast):
        op = ast.get("op") or ast.get("operator")
        left = evaluate(ast["left"])
        right = evaluate(ast["right"])

        if op == "+":
            return left + right
        elif op == "-":
            return left - right
        elif op == "*":
            return left * right
        elif op == "/":
            if right == 0:
                raise ZeroDivisionError("Division by zero")
            return left / right
        elif op in ("^", "**"):
            return left ** right
        else:
            raise ValueError(f"Unknown binary operator: {op}")

    # Unary Operations
    if node_type in ("unaryop", "unaryexpression", "unary") or (("op" in ast or "operator" in ast) and ("operand" in ast or "right" in ast)):
        op = ast.get("op") or ast.get("operator")
        operand_node = ast.get("operand") or ast.get("right") or ast.get("value")
        operand = evaluate(operand_node)

        if op == "-":
            return -operand
        elif op == "+":
            return operand
        else:
            raise ValueError(f"Unknown unary operator: {op}")

    # Function Calls (e.g., sin, cos, tan, sqrt, log)
    if node_type in ("function", "call", "func") or ("name" in ast and "args" in ast):
        name = ast.get("name", "").lower()
        args_list = ast.get("args", [])
        if not args_list:
            raise ValueError(f"Function {name} requires at least one argument")

        evaluated_args = [evaluate(arg) for arg in args_list]

        if name == "sin":
            return math.sin(evaluated_args[0])
        elif name == "cos":
            return math.cos(evaluated_args[0])
        elif name == "tan":
            return math.tan(evaluated_args[0])
        elif name == "sqrt":
            if evaluated_args[0] < 0:
                raise ValueError("Cannot take the square root of a negative number")
            return math.sqrt(evaluated_args[0])
        elif name == "log":
            if evaluated_args[0] <= 0:
                raise ValueError("Logarithm argument must be greater than zero")
            return math.log(evaluated_args[0])
        elif name == "abs":
            return abs(evaluated_args[0])
        elif name == "exp":
            return math.exp(evaluated_args[0])
        else:
            raise ValueError(f"Unknown function: {name}")

    raise ValueError(f"Unable to evaluate AST node: {ast}")

