import re

def tokenize(expr: str) -> list[str]:
    # Match strings (with support for escaped quotes), brackets, braces, parentheses, or non-whitespace sequences
    pattern = re.compile(r'"(?:[^"\\]|\\.)*"|\(|\)|\[|\]|\{|\}|[^\s()\[\]{}]+')
    return pattern.findall(expr)

def parse(tokens: list[str]) -> list | int | float | str:
    if not tokens:
        raise ValueError("No tokens to parse")

    pointer = 0

    def parse_atom(token: str):
        try:
            return int(token)
        except ValueError:
            pass
        try:
            return float(token)
        except ValueError:
            pass
        if len(token) >= 2 and token[0] == '"' and token[-1] == '"':
            # Strip outer quotes and resolve common escapes
            return token[1:-1].replace('\\"', '"').replace('\\\\', '\\')
        return token

    def parse_element():
        nonlocal pointer
        if pointer >= len(tokens):
            raise ValueError("Unexpected end of tokens")

        token = tokens[pointer]
        pointer += 1

        if token in ('(', '[', '{'):
            closing_map = {'(': ')', '[': ']', '{': '}'}
            closing_char = closing_map[token]
            lst = []
            while pointer < len(tokens) and tokens[pointer] != closing_char:
                lst.append(parse_element())
            if pointer >= len(tokens):
                raise ValueError(f"Expected '{closing_char}', found end of tokens")
            pointer += 1  # consume closing symbol
            return lst
        elif token in (')', ']', '}'):
            raise ValueError(f"Unexpected '{token}'")
        else:
            return parse_atom(token)

    return parse_element()

def parse_expression(expr: str) -> list | int | float | str:
    tokens = tokenize(expr)
    return parse(tokens)

