    elif op == '/':
        if len(args) == 2:
            return args[0] / args[1]
        raise ValueError(f"Division expects 2 arguments, got {len(args)}")
    elif op == '//':
        if len(args) == 2:
            return args[0] // args[1]
        raise ValueError(f"Floor division expects 2 arguments, got {len(args)}")
    elif op in ('%', 'mod'):
        if len(args) == 2:
            return args[0] % args[1]
        raise ValueError(f"Modulo expects 2 arguments, got {len(args)}")
    elif op in ('**', '^'):
        if len(args) == 2:
            return args[0] ** args[1]
