def parse_indented_text(text: str, indent_size: int = 4) -> list[dict]:
    if not text:
        return []

    lines = text.splitlines()
    root_nodes = []
    stack = []  # Elements are (level, node_dict)

    for line in lines:
        if not line.strip():
            continue

        # Count leading spaces to determine indentation level
        stripped_line = line.lstrip(' ')
        leading_spaces = len(line) - len(stripped_line)
        level = leading_spaces // indent_size
        value = stripped_line.strip()

        node = {"value": value, "children": []}

        # Adjust the stack to find the correct parent
        while stack and stack[-1][0] >= level:
            stack.pop()

        if not stack:
            root_nodes.append(node)
        else:
            parent_node = stack[-1][1]
            parent_node["children"].append(node)

        stack.append((level, node))

    return root_nodes

