    token_specification = [
        ('NUMBER',   r'\d+(\.\d*)?|\.\d+'),
        ('OP',       r'[+\-*/]'),
        ('LPAREN',   r'\('),
        ('RPAREN',   r'\)'),
        ('SKIP',     r'[ \t]+'),
        ('MISMATCH', r'.'),
    ]
    tok_regex = '|'.join('(?P<%s>%s)' % pair for pair in token_specification)
    tokens = []
