        kind = mo.lastgroup
        value = mo.group()
        if kind == 'NUMBER':
            val = float(value) if '.' in value else int(value)
            tokens.append(('NUMBER', val))
        elif kind in ('OP', 'LPAREN', 'RPAREN'):
            tokens.append((kind, value))
        elif kind == 'SKIP':
            continue
        else:
            raise ValueError(f'Unexpected character: {value!r}')
    return tokens

class Parser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def current_token(self):
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self, expected_kind=None, expected_val=None):
        tok = self.current_token()
        if tok is None:
            raise ValueError("Unexpected end of input")
        kind, val = tok
        if expected_kind and kind != expected_kind:
            raise ValueError(f"Expected {expected_kind}, got {kind}")
        if expected_val and val != expected_val:
            raise ValueError(f"Expected {expected_val}, got {val}")
        self.pos += 1
        return val

    def parse(self):
        node = self.expr()
        if self.pos < len(self.tokens):
            raise ValueError(f"Unexpected token at position {self.pos}: {self.tokens[self.pos]}")
        return node

    def expr(self):
        node = self.term()
        while True:
            tok = self.current_token()
            if tok and tok[0] == 'OP' and tok[1] in ('+', '-'):
                op = self.consume()
                right = self.term()
                node = create_operator_node(op, node, right)
            else:
                break
