    def term(self):
        node = self.factor()
        while True:
            tok = self.current_token()
            if tok and tok[0] == 'OP' and tok[1] in ('*', '/'):
                op = self.consume()
                right = self.factor()
                node = create_operator_node(op, node, right)
            else:
                break
        return node

    def factor(self):
        tok = self.current_token()
        if tok and tok[0] == 'OP' and tok[1] in ('+', '-'):
            op = self.consume()
            right = self.factor()
            return create_operator_node(op, create_number_node(0), right)
        return self.primary()

    def primary(self):
        tok = self.current_token()
        if tok is None:
            raise ValueError("Unexpected end of input in primary")
        kind, val = tok
        if kind == 'NUMBER':
            self.consume()
            return create_number_node(val)
        elif kind == 'LPAREN':
            self.consume()
            node = self.expr()
            self.consume('RPAREN')
            return node
        else:
            raise ValueError(f"Unexpected token in primary: {tok}")

