            "size": size
        })
    return summaries

def extract_largest_component(summaries: list[dict[str, int | str]], components: list[list[str]]) -> list[str]:
    if not summaries or not components:
        return []

    largest_index = 0
    largest_size = -1

    for i, summary in enumerate(summaries):
        size = summary.get("size", 0)
        if isinstance(size, str):
            try:
                size = int(size)
            except ValueError:
                size = 0
        if size > largest_size:
            largest_size = size
            largest_index = i

    if largest_index < len(components):
        return components[largest_index]
    return []

