import json

def parse_dependencies(raw_input: str) -> dict[str, list[str]]:
    """
    Parses and validates raw input data into a structured adjacency list representation
    of a dependency graph.

    Supports:
    - JSON format representing a dictionary of lists.
    - Plain text formats with delimiters like '->', ':', or '=' (e.g., "A -> B, C").
    - Plain text format with space-separated values where the first word is the node (e.g., "A B C").

    Returns a dictionary mapping each node to its list of unique dependencies.
    """
    cleaned = raw_input.strip()
    if not cleaned:
        return {}

    # Try parsing as JSON first
    if (cleaned.startswith('{') and cleaned.endswith('}')) or (cleaned.startswith('[') and cleaned.endswith(']')):
        try:
            data = json.loads(cleaned)
            if isinstance(data, dict):
                result: dict[str, list[str]] = {}
                for k, v in data.items():
                    key_str = str(k).strip()
                    if not key_str:
                        continue
                    if isinstance(v, list):
                        deps = [str(x).strip() for x in v if str(x).strip()]
                    elif isinstance(v, str):
                        deps = [x.strip() for x in v.replace(',', ' ').split() if x.strip()]
                    else:
                        deps = []
                    result[key_str] = list(dict.fromkeys(deps))
                return result
        except json.JSONDecodeError:
            pass

    # Fallback to line-by-line parsing
    dependencies: dict[str, list[str]] = {}
    for line in cleaned.splitlines():
        line = line.strip()
        if not line or line.startswith('#'):
            continue

        node = ""
        deps_str = ""

        # Check for explicit delimiters
        for delim in ('->', ':', '='):
            if delim in line:
                parts = line.split(delim, 1)
                node = parts[0].strip()
                deps_str = parts[1].strip()
                break
        else:
            # No delimiter: assume space-separated where first token is the node
            parts = line.split()
            if parts:
                node = parts[0].strip()
                deps_str = " ".join(parts[1:])

        if not node:
            continue

        # Normalize separators in dependency string (commas, semicolons to spaces)
        deps_str_clean = deps_str.replace(',', ' ').replace(';', ' ')
        deps = [d.strip() for d in deps_str_clean.split() if d.strip()]

        if node in dependencies:
            dependencies[node].extend(deps)
        else:
            dependencies[node] = deps

    # Deduplicate dependencies while preserving their order
    for node in dependencies:
        dependencies[node] = list(dict.fromkeys(dependencies[node]))

    return dependencies

