def resolve_dependencies(graph: dict[str, list[str]]) -> dict[str, any]:
    # Find all unique nodes in the graph
    all_nodes = set(graph.keys())
    for deps in graph.values():
        all_nodes.update(deps)

    index = 0
    stack = []
    indices = {}
    lowlink = {}
    on_stack = set()
    sccs = []

    def strongconnect(v):
        nonlocal index
        indices[v] = index
        lowlink[v] = index
        index += 1
        stack.append(v)
        on_stack.add(v)

        dependencies = graph.get(v, [])
        for w in dependencies:
            if w not in indices:
                strongconnect(w)
                lowlink[v] = min(lowlink[v], lowlink[w])
            elif w in on_stack:
                lowlink[v] = min(lowlink[v], indices[w])

        if lowlink[v] == indices[v]:
            scc = []
            while True:
                w = stack.pop()
                on_stack.remove(w)
                scc.append(w)
                if w == v:
                    break
            sccs.append(scc)

    for node in sorted(all_nodes):
        if node not in indices:
            strongconnect(node)

    # Check for cycles
    for scc in sccs:
        if len(scc) > 1:
            return {
                "success": False,
                "error": f"Cyclic dependency detected: {' -> '.join(scc)} -> {scc[0]}",
                "cycle": scc,
                "order": []
            }
        elif len(scc) == 1:
            node = scc[0]
            if node in graph.get(node, []):
                return {
                    "success": False,
                    "error": f"Cyclic dependency detected: {node} -> {node}",
                    "cycle": [node],
                    "order": []
                }

    # If no cycles, order is the flat sccs list
    order = [node for scc in sccs for node in scc]
    return {
        "success": True,
        "error": None,
        "cycle": None,
        "order": order
    }

