def check_brackets(text: str) -> bool:
    bracket_map = {')': '(', ']': '[', '}': '{'}
    open_brackets = set(bracket_map.values())

    stack = []
    for char in text:
        if char in open_brackets:
            stack.append(char)
        elif char in bracket_map:
            if not stack or stack[-1] != bracket_map[char]:
                return False
            stack.pop()

    return len(stack) == 0

