import json
import os

def load_graph(file_path: str) -> dict:
    """
    Loads graph data from a local JSON file.
    Returns:
        dict: {'vertices': list[str], 'edges': list[list[str]]}
    """
    if not os.path.exists(file_path):
        return {'vertices': [], 'edges': []}

    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            data = json.load(f)
            vertices = data.get('vertices', [])
            edges = data.get('edges', [])
            # Normalize to ensure correct types match the signature
            normalized_vertices = [str(v) for v in vertices]
            normalized_edges = [[str(e[0]), str(e[1])] for e in edges if isinstance(e, list) and len(e) >= 2]
            return {
                'vertices': normalized_vertices,
                'edges': normalized_edges
            }
    except (json.JSONDecodeError, OSError):
        return {'vertices': [], 'edges': []}

def save_graph(file_path: str, data: dict) -> None:
    """
    Saves graph data to a local JSON file.
    Args:
        file_path (str): Path to the target JSON file.
        data (dict): {'vertices': list[str], 'edges': list[list[str]]}
    """
    dir_name = os.path.dirname(file_path)
    if dir_name and not os.path.exists(dir_name):
        os.makedirs(dir_name, exist_ok=True)

    with open(file_path, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=4)

