DATA_FILE = "tags.json"


def _get_descendants_internal(tag_name: str, data: dict[str, str | None]) -> list[str]:
    descendants = []
    queue = [tag_name]
    while queue:
        current = queue.pop(0)
        children = [t for t, p in data.items() if p == current]
        descendants.extend(children)
        queue.extend(children)
    return descendants


def add_tag(tag_name: str, parent_name: str | None) -> bool:
    data = load_data(DATA_FILE)
    if tag_name in data:
        return False
    if parent_name is not None and parent_name not in data:
        return False
    data[tag_name] = parent_name
    save_data(DATA_FILE, data)
    return True


def delete_tag(tag_name: str) -> bool:
    data = load_data(DATA_FILE)
    if tag_name not in data:
        return False

    descendants = _get_descendants_internal(tag_name, data)
    to_delete = [tag_name] + descendants
    for t in to_delete:
        if t in data:
            del data[t]

    save_data(DATA_FILE, data)
    return True


def list_tags() -> dict[str, list[str]]:
    data = load_data(DATA_FILE)
    hierarchy: dict[str, list[str]] = {"": []}
    for tag in data:
        hierarchy[tag] = []

    for tag, parent in data.items():
        if parent is None:
            hierarchy[""].append(tag)
        else:
            if parent in hierarchy:
                hierarchy[parent].append(tag)
    return hierarchy


def get_all_descendants(tag_name: str) -> list[str]:
    data = load_data(DATA_FILE)
    if tag_name not in data:
        return []
    return _get_descendants_internal(tag_name, data)

