import re
from typing import List, Dict

def tokenize(expression: str) -> List[Dict[str, str]]:
    token_specification = [
        ('NUMBER',   r'\d+(\.\d*)?([eE][+-]?\d+)?|\.\d+([eE][+-]?\d+)?'),
        ('OPERATOR', r'\*\*|[+\-*/^]'),
        ('LPAREN',   r'\('),
        ('RPAREN',   r'\)'),
        ('SKIP',     r'[ \t\r\n]+'),
        ('MISMATCH', r'.'),
    ]
    tok_regex = '|'.join(f'(?P<{name}>{pattern})' for name, pattern in token_specification)

    tokens = []
    for mo in re.finditer(tok_regex, expression):
        kind = mo.lastgroup
        value = mo.group()
        if kind == 'NUMBER':
            tokens.append({'type': 'NUMBER', 'value': value})
        elif kind == 'OPERATOR':
            tokens.append({'type': 'OPERATOR', 'value': value})
        elif kind == 'LPAREN':
            tokens.append({'type': 'LPAREN', 'value': value})
        elif kind == 'RPAREN':
            tokens.append({'type': 'RPAREN', 'value': value})
        elif kind == 'SKIP':
            continue
        elif kind == 'MISMATCH':
            raise ValueError(f'Unexpected character: {value!r}')

    return tokens

