PRECEDENCE = {
    '+': 10,
    '-': 10,
    '*': 20,
    '/': 20,
    '^': 30,
}

def parse(tokens: list[dict]) -> dict:
    if not tokens:
        raise ValueError("Cannot parse an empty list of tokens.")

    idx = 0

    def peek() -> dict | None:
        if idx < len(tokens):
            return tokens[idx]
        return None

    def consume(expected_type: str | None = None, expected_value: str | None = None) -> dict:
        nonlocal idx
        t = peek()
        if not t:
            raise SyntaxError("Unexpected end of input")
        if expected_type and t.get('type') != expected_type:
            raise SyntaxError(f"Expected token type {expected_type}, got {t.get('type')}")
        if expected_value and t.get('value') != expected_value:
            raise SyntaxError(f"Expected token value '{expected_value}', got '{t.get('value')}'")
        idx += 1
        return t

    def get_precedence(token: dict | None) -> int:
        if token and token.get('type') in ('OPERATOR', 'OP'):
            return PRECEDENCE.get(token.get('value', ''), 0)
        return 0

    def parse_primary() -> dict:
        t = peek()
        if not t:
            raise SyntaxError("Unexpected end of expression")

        # Handle grouping/parentheses
        is_lparen = (
            t.get('type') in ('LPAREN', 'PAREN', 'PUNCTUATION') 
            and t.get('value') == '('
        )
        if is_lparen:
            consume()  # Consume '('
            expr = parse_expr(0)

            r_token = peek()
            is_rparen = (
                r_token is not None 
                and r_token.get('type') in ('RPAREN', 'PAREN', 'PUNCTUATION') 
                and r_token.get('value') == ')'
            )
            if is_rparen:
                consume()  # Consume ')'
            else:
                raise SyntaxError("Unmatched parenthesis: expected ')'")
            return expr

        # Handle unary operators (e.g., -5, +x)
        if t.get('type') in ('OPERATOR', 'OP') and t.get('value') in ('+', '-'):
            op_token = consume()
            operand = parse_expr(40)  # High precedence for unary ops
            return {
                'type': 'UNARY_OPERATOR',
                'value': op_token.get('value', ''),
                'left': operand,
                'right': None
            }

        # Terminal/Leaf Node (NUMBER, IDENTIFIER, etc.)
        node_token = consume()
        return {
            'type': node_token.get('type', 'UNKNOWN'),
            'value': node_token.get('value', ''),
            'left': None,
            'right': None
        }

    def parse_expr(min_prec: int) -> dict:
        left = parse_primary()

        while True:
            next_token = peek()
            if not next_token:
                break

            if next_token.get('type') not in ('OPERATOR', 'OP'):
                break

            prec = get_precedence(next_token)
            if prec < min_prec:
                break

            op_token = consume()

            # Exponentiation (^) is right-associative, others are left-associative
            next_min_prec = prec if op_token.get('value') == '^' else prec + 1
            right = parse_expr(next_min_prec)

            left = {
                'type': op_token.get('type', 'OPERATOR'),
                'value': op_token.get('value', ''),
                'left': left,
                'right': right
            }

        return left

    result = parse_expr(0)
    if idx < len(tokens):
        raise SyntaxError(f"Unexpected token at index {idx}: {tokens[idx]}")
    return result

