from typing import Any

def evaluate(ast: dict) -> float:
    if ast is None:
        raise ValueError("AST node cannot be None")

    node_type = ast.get('type')
    value = ast.get('value')
    left = ast.get('left')
    right = ast.get('right')

    node_type_lower = node_type.lower() if node_type else ""

    if node_type_lower in ("number", "literal", "num", "float", "int"):
        return float(value)

    # Handles standard binary and unary operators
    if node_type_lower in ("operator", "binary", "binop") or value in ("+", "-", "*", "/", "^", "**"):
        if left is not None and right is not None:
            left_val = evaluate(left)
            right_val = evaluate(right)
            if value == "+":
                return left_val + right_val
            elif value == "-":
                return left_val - right_val
            elif value == "*":
                return left_val * right_val
            elif value == "/":
                if right_val == 0:
                    raise ZeroDivisionError("division by zero")
                return left_val / right_val
            elif value in ("^", "**"):
                return left_val ** right_val
            else:
                raise ValueError(f"Unknown binary operator: {value}")

        elif left is not None or right is not None:
            operand = left if left is not None else right
            val = evaluate(operand)
            if value == "-":
                return -val
            elif value == "+":
                return +val
            else:
                raise ValueError(f"Invalid unary operation: {value}")

    if node_type_lower in ("unary", "unop"):
        operand = right if right is not None else left
        if operand is None:
            raise ValueError("Unary operator missing operand")
        val = evaluate(operand)
        if value == "-":
            return -val
        elif value == "+":
            return +val
        else:
            raise ValueError(f"Unknown unary operator: {value}")

    if left is None and right is None:
        try:
            return float(value)
        except (ValueError, TypeError):
            pass

    raise ValueError(f"Could not evaluate AST node: {ast}")

