import re

def tokenize(expr: str) -> list[str]:
    pattern = r'"(?:[^"\\]|\\.)*"|\(|\)|[^\s()]+'
    return re.findall(pattern, expr)

def _atom(token: str) -> str | int | float:
    try:
        return int(token)
    except ValueError:
        pass
    try:
        return float(token)
    except ValueError:
        pass
    if len(token) >= 2 and token.startswith('"') and token.endswith('"'):
        return token[1:-1].replace('\\"', '"').replace('\\\\', '\\')
    return token

def parse(expr: str) -> list | str | int | float:
    tokens = tokenize(expr)
    if not tokens:
        raise ValueError("Empty expression")

    def parse_tokens(token_list: list[str]) -> list | str | int | float:
        if not token_list:
            raise SyntaxError("Unexpected EOF")
        token = token_list.pop(0)
        if token == '(':
            L = []
            while token_list and token_list[0] != ')':
                L.append(parse_tokens(token_list))
            if not token_list:
                raise SyntaxError("Expected ')' but reached EOF")
            token_list.pop(0)  # pop ')'
            return L
        elif token == ')':
            raise SyntaxError("Unexpected ')'")
        else:
            return _atom(token)

    result = parse_tokens(tokens)
    if tokens:
        raise SyntaxError("Unexpected tokens after expression parsing completed")
    return result

