from __future__ import annotations
import operator
from functools import reduce

def evaluate(ast: list | str | int | float) -> int | float:
    if isinstance(ast, (int, float)):
        return ast

    if isinstance(ast, str):
        try:
            if '.' in ast or 'e' in ast.lower():
                return float(ast)
            return int(ast)
        except ValueError:
            raise ValueError(f"Unknown symbol or invalid number: {ast}")

    if isinstance(ast, list):
        if not ast:
            raise ValueError("Empty S-expression cannot be evaluated")

        op = ast[0]
        if not isinstance(op, str):
            raise ValueError(f"Operator must be a string, got {type(op)}")

        args = [evaluate(x) for x in ast[1:]]

        if op == '+':
            return sum(args)
        elif op == '-':
            if not args:
                raise ValueError("- requires at least one argument")
            if len(args) == 1:
                return -args[0]
            return reduce(operator.sub, args)
        elif op == '*':
            if not args:
                return 1
            return reduce(operator.mul, args)
        elif op == '/':
            if not args:
                raise ValueError("/ requires at least one argument")
            if len(args) == 1:
                return 1 / args[0]
            return reduce(operator.truediv, args)
        elif op == '//':
            if len(args) < 2:
                raise ValueError("// requires at least two arguments")
            return reduce(operator.floordiv, args)
        elif op == '%':
            if len(args) != 2:
                raise ValueError("% requires exactly two arguments")
            return args[0] % args[1]
        elif op == '**':
            if len(args) < 2:
                raise ValueError("** requires at least two arguments")
            return reduce(operator.pow, args)
        else:
            raise ValueError(f"Unknown operator: {op}")

    raise ValueError(f"Invalid AST node type: {type(ast)}")

