def serialize_tree_to_text(nodes: list[dict]) -> str:
    if not nodes:
        return ""

    lines = []

    def _traverse(node_list: list[dict]) -> None:
        for node in node_list:
            depth = node.get("depth", 0)
            value = node.get("value", "")
            indent = " " * depth
            lines.append(f"{indent}{value}")
            _traverse(node.get("children", []))

