import re

def parse(expression: str) -> dict:
    # Tokenize the expression
    # Supports integers, decimals, operators (+, -, *, /, ^), and parentheses
    token_pattern = re.compile(r'\s*(\d+(?:\.\d+)?|[+\-*/^()])')
    tokens = []
    pos = 0
    while pos < len(expression):
        match = token_pattern.match(expression, pos)
        if not match:
            if expression[pos:].isspace():
                break
            raise ValueError(f"Unexpected character at position {pos}: {expression[pos]}")
        tokens.append(match.group(1))
        pos = match.end()

    if not tokens:
        raise ValueError("Empty expression")

    index = 0

    def peek():
        if index < len(tokens):
            return tokens[index]
        return None

    def consume(expected=None):
        nonlocal index
        if index >= len(tokens):
            raise ValueError("Unexpected end of input")
        val = tokens[index]
        if expected and val != expected:
            raise ValueError(f"Expected {expected}, got {val}")
        index += 1
        return val

    def parse_expr() -> dict:
        node = parse_term()
        while peek() in ('+', '-'):
            op = consume()
            right = parse_term()
            node = {
                "type": "operator",
                "value": op,
                "left": node,
                "right": right
            }
        return node

    def parse_term() -> dict:
        node = parse_factor()
        while peek() in ('*', '/'):
            op = consume()
            right = parse_factor()
            node = {
                "type": "operator",
                "value": op,
                "left": node,
                "right": right
            }
        return node

    def parse_factor() -> dict:
        return parse_unary()

    def parse_unary() -> dict:
        if peek() in ('+', '-'):
            op = consume()
            operand = parse_unary()
            return {
                "type": "operator",
                "value": op,
                "left": operand,
                "right": None
            }
        return parse_power()

    def parse_power() -> dict:
        node = parse_primary()
        if peek() == '^':
            op = consume()
            right = parse_factor()
            node = {
                "type": "operator",
                "value": op,
                "left": node,
                "right": right
            }
        return node

    def parse_primary() -> dict:
        tok = peek()
        if tok == '(':
            consume('(')
            node = parse_expr()
            consume(')')
            return node

        if tok is not None and re.match(r'^\d+(?:\.\d+)?$', tok):
            consume()
            return {
                "type": "number",
                "value": tok,
                "left": None,
                "right": None
            }

        if tok is None:
            raise ValueError("Unexpected end of input")
        raise ValueError(f"Unexpected token: {tok}")

    result = parse_expr()
    if index < len(tokens):
        raise ValueError(f"Unexpected trailing tokens: {' '.join(tokens[index:])}")
    return result

