def resolve_dependencies(graph: dict[str, list[str]]) -> tuple[list[str], list[list[str]]]:
    # Normalize graph so every referenced node is present as a key
    all_nodes = set(graph.keys())
    for deps in graph.values():
        all_nodes.update(deps)

    full_graph = {node: graph.get(node, []) for node in all_nodes}

    index = 0
    stack = []
    indices = {}
    lowlink = {}
    on_stack = set()
    sccs = []

    def strongconnect(node):
        nonlocal index
        indices[node] = index
        lowlink[node] = index
        index += 1
        stack.append(node)
        on_stack.add(node)

        for neighbor in full_graph[node]:
            if neighbor not in indices:
                strongconnect(neighbor)
                lowlink[node] = min(lowlink[node], lowlink[neighbor])
            elif neighbor in on_stack:
                lowlink[node] = min(lowlink[node], indices[neighbor])

        if lowlink[node] == indices[node]:
            scc = []
            while True:
                w = stack.pop()
                on_stack.remove(w)
                scc.append(w)
                if w == node:
                    break
            sccs.append(scc)

    # Sort starting nodes to guarantee deterministic DFS traversal order
    for node in sorted(full_graph.keys()):
        if node not in indices:
            strongconnect(node)

    # Detect cycles (SCCs with size > 1, or size == 1 with a self-loop)
    cycles = []
    for scc in sccs:
        if len(scc) > 1:
            cycles.append(sorted(scc))
        elif len(scc) == 1:
            node = scc[0]
            if node in full_graph[node]:
                cycles.append([node])

    cycles.sort(key=lambda x: x[0])

    # Build the final flat order. Tarjan's naturally returns SCCs in reverse
    # topological order (dependencies resolved first).
    flat_order = []
    for scc in sccs:
        flat_order.extend(sorted(scc))

    return flat_order, cycles

