def validate_brackets(text: str) -> bool:
    stack = []
    mapping = {")": "(", "]": "[", "}": "{", ">": "<"}
    for char in text:
        if char in mapping.values():
            stack.append(char)
        elif char in mapping:
            if not stack or stack[-1] != mapping[char]:
                return False
            stack.pop()
    return len(stack) == 0

