def add_tag(hierarchy: dict[str, list[str]], tag: str) -> dict[str, list[str]]:
    """Adds a new tag to the hierarchy if it does not already exist."""
    new_hierarchy = {k: list(v) for k, v in hierarchy.items()}
    if tag not in new_hierarchy:
        new_hierarchy[tag] = []
    return new_hierarchy


def add_relation(hierarchy: dict[str, list[str]], parent: str, child: str) -> dict[str, list[str]]:
    """Establishes a parent-child relationship between two tags."""
    new_hierarchy = {k: list(v) for k, v in hierarchy.items()}
    if parent not in new_hierarchy:
        new_hierarchy[parent] = []
    if child not in new_hierarchy:
        new_hierarchy[child] = []
    if child not in new_hierarchy[parent]:
        new_hierarchy[parent].append(child)
    return new_hierarchy


def delete_tag(hierarchy: dict[str, list[str]], tag: str) -> dict[str, list[str]]:
    """Removes a tag from the hierarchy and all its parent relations."""
    new_hierarchy = {}
    for k, v in hierarchy.items():
        if k == tag:
            continue
        new_hierarchy[k] = [child for child in v if child != tag]
    return new_hierarchy


def get_children(hierarchy: dict[str, list[str]], parent: str) -> list[str]:
    """Retrieves the direct children of a parent tag."""
    return list(hierarchy.get(parent, []))


def get_all_descendants(hierarchy: dict[str, list[str]], tag: str) -> list[str]:
    """Recursively retrieves all descendants of a tag, avoiding circular references."""
    descendants: list[str] = []
    visited: set[str] = set()

    def dfs(current_tag: str) -> None:
        for child in hierarchy.get(current_tag, []):
            if child not in visited:
                visited.add(child)
                descendants.append(child)
                dfs(child)

    dfs(tag)
    return descendants

