def parse(tokens: list[dict[str, str]]) -> dict:
    pos = 0

    def peek() -> dict[str, str]:
        if pos < len(tokens):
            return tokens[pos]
        return {'type': 'EOF', 'value': ''}

    def consume() -> dict[str, str]:
        nonlocal pos
        tok = peek()
        pos += 1
        return tok

