        tok = peek()
        if tok.get('value') == '=' or tok.get('type', '').upper() == 'ASSIGN':
            consume()
            right = parse_assignment()
            return {
                'type': 'AssignmentExpression',
                'operator': '=',
                'left': expr,
                'right': right
            }
        return expr

    def parse_logical_or() -> dict:
