        while True:
            tok = peek()
            val = tok.get('value', '')
            t_type = tok.get('type', '').upper()
            if val in ('||', 'or') or t_type == 'OR':
                consume()
                right = parse_logical_and()
                expr = {
                    'type': 'LogicalExpression',
                    'operator': val,
                    'left': expr,
                    'right': right
                }
            else:
                break
        return expr

