            tok = peek()
            val = tok.get('value', '')
            t_type = tok.get('type', '').upper()
            if val in ('&&', 'and') or t_type == 'AND':
                consume()
                right = parse_equality()
                expr = {
                    'type': 'LogicalExpression',
                    'operator': val,
                    'left': expr,
                    'right': right
