            val = tok.get('value', '')
            t_type = tok.get('type', '').upper()
            if val in ('+', '-') or t_type in ('PLUS', 'MINUS'):
                consume()
                right = parse_multiplicative()
                expr = {
                    'type': 'BinaryExpression',
                    'operator': val,
                    'left': expr,
                    'right': right
                }
            else:
                break
        return expr

    def parse_multiplicative() -> dict:
        expr = parse_exponential()
        while True:
            tok = peek()
            val = tok.get('value', '')
            t_type = tok.get('type', '').upper()
            if val in ('*', '/', '%') or t_type in ('MUL', 'DIV', 'MOD'):
                consume()
                right = parse_exponential()
                expr = {
                    'type': 'BinaryExpression',
                    'operator': val,
                    'left': expr,
                    'right': right
                }
            else:
                break
        return expr

    def parse_exponential() -> dict:
        expr = parse_unary()
        tok = peek()
        val = tok.get('value', '')
        t_type = tok.get('type', '').upper()
        if val in ('^', '**') or t_type == 'POW':
            consume()
            right = parse_exponential()
            expr = {
                'type': 'BinaryExpression',
                'operator': val,
                'left': expr,
                'right': right
            }
        return expr

    def parse_unary() -> dict:
        tok = peek()
        val = tok.get('value', '')
        t_type = tok.get('type', '').upper()
        if val in ('-', '+', '!', 'not') or t_type in ('MINUS', 'PLUS', 'NOT', 'BANG'):
            consume()
            argument = parse_unary()
            return {
                'type': 'UnaryExpression',
                'operator': val,
                'argument': argument
            }
