            }

        if t_val == '(' or t_type == 'LPAREN':
            consume()
            expr = parse_expression()
            next_tok = peek()
            if next_tok.get('value') == ')' or next_tok.get('type', '').upper() == 'RPAREN':
                consume()
            return expr

        consume()
        return {
            'type': 'Identifier',
            'name': t_val
        }

    statements = []
    while pos < len(tokens):
        tok = peek()
        if tok.get('value') == ';' or tok.get('type', '').upper() == 'SEMICOLON':
            consume()
            continue
        if tok.get('type', '').upper() == 'EOF':
            break
        statements.append(parse_expression())

    if len(statements) == 1:
        return statements[0]
    return {
        'type': 'Program',
        'body': statements
    }

