import math

def evaluate(ast: dict) -> float:
    if not isinstance(ast, dict):
        if isinstance(ast, (int, float)):
            return float(ast)
        raise ValueError(f"Invalid AST node: {ast}")

    node_type = ast.get("type")

    if node_type in ("number", "num", "literal"):
        return float(ast["value"])

    elif node_type in ("binary_op", "binop", "binary"):
        op = ast["op"]
        left_val = evaluate(ast["left"])
        right_val = evaluate(ast["right"])

        if op == "+":
            return left_val + right_val
        elif op == "-":
            return left_val - right_val
        elif op == "*":
