def parse(tokens: list[str]) -> list | int | float | str:
    if not tokens:
        return []

    def atom(token: str):
        try:
            return int(token)
        except ValueError:
            pass
        try:
            return float(token)
        except ValueError:
            pass
        if len(token) >= 2 and (
            (token.startswith('"') and token.endswith('"')) or 
            (token.startswith("'") and token.endswith("'"))
        ):
            return token[1:-1]
        return token

    index = 0

    def parse_next() -> list | int | float | str:
        nonlocal index
        if index >= len(tokens):
            raise SyntaxError("Unexpected EOF")

        token = tokens[index]
        index += 1

        if token in ('(', '['):
            sub_list = []
            while index < len(tokens) and tokens[index] not in (')', ']'):
                sub_list.append(parse_next())
            if index >= len(tokens):
                raise SyntaxError("Expected closing parenthesis")
            index += 1  # consume closing paren
            return sub_list
        elif token in (')', ']'):
            raise SyntaxError("Unexpected closing parenthesis")
        else:
            return atom(token)

    result = parse_next()

    if index < len(tokens):
        results = [result]
        while index < len(tokens):
            results.append(parse_next())
        return results

    return result

