import functools
import operator
import math
from typing import List, Union

def evaluate(node: Union[list, int, float, str]) -> Union[int, float]:
    if isinstance(node, (int, float)):
        return node

    if isinstance(node, str):
        # Try to parse numeric strings first
        try:
            if '.' in node or 'e' in node.lower():
                return float(node)
            return int(node)
        except ValueError:
            pass

        # Handle known constants
        if node.lower() == "pi":
            return math.pi
        if node.lower() == "e":
            return math.e
        raise ValueError(f"Unknown symbol/variable: {node}")

    if isinstance(node, list):
        if not node:
            raise ValueError("Empty S-expression cannot be evaluated")

        op = node[0]
        if not isinstance(op, str):
            raise ValueError(f"First element of S-expression must be an operator string, got {type(op)}")

        # Evaluate all arguments recursively
        args = [evaluate(arg) for arg in node[1:]]

        # Handle standard operators
        if op == '+':
            return sum(args)
        elif op == '-':
            if not args:
                raise ValueError("'-' operator requires at least one argument")
            if len(args) == 1:
                return -args[0]
            return functools.reduce(operator.sub, args)
        elif op == '*':
            if not args:
                return 1
            return functools.reduce(operator.mul, args)
        elif op == '/':
            if not args:
                raise ValueError("'/' operator requires at least one argument")
            if len(args) == 1:
                return 1 / args[0]
            return functools.reduce(operator.truediv, args)
        elif op in ('pow', '**'):
            if len(args) != 2:
                raise ValueError(f"'{op}' operator requires exactly 2 arguments, got {len(args)}")
            return args[0] ** args[1]
        elif op in ('mod', '%'):
            if len(args) != 2:
                raise ValueError(f"'{op}' operator requires exactly 2 arguments, got {len(args)}")
            return args[0] % args[1]
        elif op == 'abs':
            if len(args) != 1:
                raise ValueError(f"'abs' operator requires exactly 1 argument, got {len(args)}")
            return abs(args[0])
        else:
            # Fallback to math module functions if matching
            if hasattr(math, op) and callable(getattr(math, op)):
                func = getattr(math, op)
                try:
                    return func(*args)
                except TypeError as e:
                    raise ValueError(f"Error calling math.{op} with arguments {args}: {e}")
            raise ValueError(f"Unknown operator/function: '{op}'")

    raise TypeError(f"Invalid node type in S-expression: {type(node)}")

