def parse_to_tree(text: str) -> list[dict]:
    if not text:
        return []

    lines = text.splitlines()
    tree = []
    stack = []  # elements are tuples: (indent_level, node_dict)

    for line in lines:
        if not line.strip():
            continue

        # Normalize tabs to spaces to handle mixed indentation consistently
        expanded_line = line.expandtabs(4)
        indent_level = len(expanded_line) - len(expanded_line.lstrip(' '))
        value = line.strip()

        node = {
            "value": value,
            "indent_level": indent_level,
            "children": []
        }

        # Pop from stack until we find a potential parent (strictly less indent)
        while stack and stack[-1][0] >= indent_level:
            stack.pop()

        if not stack:
            tree.append(node)
        else:
            stack[-1][1]["children"].append(node)

        stack.append((indent_level, node))

    return tree

