import re
from models import create_node

def tokenize(expr: str):
    token_specification = [
        ('NUMBER',   r'\d+(\.\d*)?'),
        ('VAR',      r'[a-zA-Z_][a-zA-Z0-9_]*'),
        ('OP',       r'[+\-*/^]'),
        ('LPAREN',   r'\('),
        ('RPAREN',   r'\)'),
        ('SKIP',     r'[ \t]+'),
        ('MISMATCH', r'.'),
    ]
    tok_regex = '|'.join('(?P<%s>%s)' % pair for pair in token_specification)
    tokens = []
    for mo in re.finditer(tok_regex, expr):
        kind = mo.lastgroup
        value = mo.group()
        if kind == 'SKIP':
            continue
        elif kind == 'MISMATCH':
            raise ValueError(f'Unexpected character {value!r}')
        else:
            tokens.append((kind, value))
    return tokens

class Parser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def peek(self):
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self, expected_kind=None):
        tok = self.peek()
        if not tok:
            raise ValueError("Unexpected end of input")
        if expected_kind and tok[0] != expected_kind:
            raise ValueError(f"Expected {expected_kind}, got {tok[0]}")
        self.pos += 1
        return tok

    def parse(self):
        if not self.tokens:
            raise ValueError("Empty expression")
        result = self.expr()
        if self.pos < len(self.tokens):
            raise ValueError(f"Unexpected token {self.tokens[self.pos][1]} at end of expression")
        return result

    def expr(self):
        node = self.term()
        while True:
            tok = self.peek()
            if tok and tok[0] == 'OP' and tok[1] in ('+', '-'):
                self.consume()
                right = self.term()
                node = create_node("operator", tok[1], node, right)
            else:
                break
        return node

    def term(self):
        node = self.factor()
        while True:
            tok = self.peek()
            if tok and tok[0] == 'OP' and tok[1] in ('*', '/'):
                self.consume()
                right = self.factor()
                node = create_node("operator", tok[1], node, right)
            else:
                break
        return node

    def factor(self):
        tok = self.peek()
        if tok and tok[0] == 'OP' and tok[1] in ('+', '-'):
            self.consume()
            operand = self.factor()
            return create_node("operator", tok[1], None, operand)
        return self.primary()

    def primary(self):
        tok = self.peek()
        if not tok:
            raise ValueError("Unexpected end of input in expression")
        if tok[0] == 'NUMBER':
            self.consume()
            return create_node("number", tok[1], None, None)
        elif tok[0] == 'VAR':
            self.consume()
            return create_node("variable", tok[1], None, None)
        elif tok[0] == 'LPAREN':
            self.consume()
            node = self.expr()
            self.consume('RPAREN')
            return node
        else:
            raise ValueError(f"Unexpected token {tok[1]}")

def parse(expression: str) -> dict:
    tokens = tokenize(expression)
    parser = Parser(tokens)
    return parser.parse()

