def find_connected_components(graph: dict[int, list[int]]) -> list[list[int]]:
    # Build a fully symmetric adjacency list to ensure robustness 
    # for undirected graph representation (handles cases where edges might be directed in the input)
    adj = {}
    for u, neighbors in graph.items():
        if u not in adj:
            adj[u] = set()
        for v in neighbors:
            if v not in adj:
                adj[v] = set()
            adj[u].add(v)
            adj[v].add(u)

    visited = set()
    components = []

    # Sort the nodes to ensure deterministic traversal order
    for node in sorted(adj.keys()):
        if node not in visited:
            component = []
            queue = [node]
            visited.add(node)
            head = 0
            while head < len(queue):
                curr = queue[head]
                head += 1
                component.append(curr)
                # Sort neighbors to maintain deterministic BFS order
                for neighbor in sorted(adj[curr]):
                    if neighbor not in visited:
                        visited.add(neighbor)
                        queue.append(neighbor)
            components.append(sorted(component))

    # Return components sorted by their first (smallest) element
    return sorted(components, key=lambda x: x[0] if x else 0)

