def find_cycles(graph: dict[str, list[str]]) -> list[list[str]]:
    cycles = []
    nodes_set = set(graph.keys())
    for neighbors in graph.values():
        nodes_set.update(neighbors)
    nodes = sorted(list(nodes_set))

    for start_node in nodes:
        path = []
        visited = set()

        def dfs(node):
            path.append(node)
            visited.add(node)
            for neighbor in graph.get(node, []):
                if neighbor == start_node:
                    cycles.append(list(path))
                elif neighbor not in visited and neighbor > start_node:
                    dfs(neighbor)
            path.pop()
            visited.remove(node)

        dfs(start_node)
    return cycles

def topological_sort(graph: dict[str, list[str]]) -> list[str]:
    all_nodes = set(graph.keys())
    for neighbors in graph.values():
        all_nodes.update(neighbors)

    in_degree = {u: 0 for u in all_nodes}
    for u in graph:
        for v in graph[u]:
            in_degree[v] = in_degree.get(v, 0) + 1

    queue = sorted([u for u in all_nodes if in_degree[u] == 0])
    result = []

    while queue:
        u = queue.pop(0)
        result.append(u)
        for v in graph.get(u, []):
            in_degree[v] -= 1
            if in_degree[v] == 0:
                queue.append(v)
        queue.sort()

    if len(result) < len(all_nodes):
        return []
    return result

