except ImportError:
    Node = Any

def insert(root: Optional[Node], key: int) -> Node:
    if root is None:
        return create_node(key)
    if key < root.key:
        root.left = insert(root.left, key)
    elif key > root.key:
        root.right = insert(root.right, key)
    return root

def find(root: Optional[Node], key: int) -> bool:
    if root is None:
        return False
    if root.key == key:
        return True
    if key < root.key:
        return find(root.left, key)
    return find(root.right, key)

def _min_value_node(node: Node) -> Node:
    current = node
    while current.left is not None:
        current = current.left
    return current

def delete(root: Optional[Node], key: int) -> Optional[Node]:
    if root is None:
        return None
    if key < root.key:
        root.left = delete(root.left, key)
    elif key > root.key:
        root.right = delete(root.right, key)
    else:
        if root.left is None:
            return root.right
        elif root.right is None:
            return root.left

        temp = _min_value_node(root.right)
        root.key = temp.key
        root.right = delete(root.right, temp.key)
    return root

def inorder(root: Optional[Node]) -> List[int]:
    if root is None:
        return []
    return inorder(root.left) + [root.key] + inorder(root.right)

