def is_valid_parentheses(text: str) -> bool:
    """
    Checks if the parentheses, brackets, and braces in the given string
    are correctly paired and nested. Non-bracket characters are ignored.
    """
    stack = []
    mapping = {")": "(", "]": "[", "}": "{"}

    for char in text:
        if char in mapping.values():
            stack.append(char)
        elif char in mapping:
            if not stack or stack[-1] != mapping[char]:
                return False
            stack.pop()

    return len(stack) == 0

