from storage import load_hierarchy, save_hierarchy

def _find_parent(hierarchy: dict[str, list[str]], tag: str) -> str | None:
    for parent, children in hierarchy.items():
        if tag in children:
            return parent
    return None

def _get_descendants(hierarchy: dict[str, list[str]], tag: str) -> list[str]:
    if tag not in hierarchy:
        return []
    descendants = []
    queue = list(hierarchy.get(tag, []))
    visited = set(queue)
    while queue:
        current = queue.pop(0)
        descendants.append(current)
        for child in hierarchy.get(current, []):
            if child not in visited:
                visited.add(child)
                queue.append(child)
    return descendants

def add_tag(file_path: str, tag: str, parent: str | None) -> bool:
    hierarchy = load_hierarchy(file_path)
    if hierarchy is None:
        hierarchy = {}

    if tag in hierarchy:
        return False

    if parent is not None:
        if parent not in hierarchy:
            return False
        hierarchy[parent].append(tag)

    hierarchy[tag] = []
    save_hierarchy(file_path, hierarchy)
    return True

def delete_tag(file_path: str, tag: str) -> bool:
    hierarchy = load_hierarchy(file_path)
    if hierarchy is None or tag not in hierarchy:
        return False

    to_delete = [tag] + _get_descendants(hierarchy, tag)

    parent = _find_parent(hierarchy, tag)
    if parent is not None and parent in hierarchy:
        if tag in hierarchy[parent]:
            hierarchy[parent].remove(tag)

    for t in to_delete:
        hierarchy.pop(t, None)

    save_hierarchy(file_path, hierarchy)
    return True

def list_tags(file_path: str) -> list[dict[str, str | None]]:
    hierarchy = load_hierarchy(file_path)
    if hierarchy is None:
        return []

    result = []
    for tag in hierarchy:
        parent = _find_parent(hierarchy, tag)
        result.append({"tag": tag, "parent": parent})
    return result

def get_descendants(file_path: str, tag: str) -> list[str]:
    hierarchy = load_hierarchy(file_path)
    if hierarchy is None:
        return []
    return _get_descendants(hierarchy, tag)

