import re

def tokenize(expression: str) -> list[dict[str, str]]:
    token_specification = [
        ('NUMBER',   r'\d+\.\d+|\d+|\.\d+'),  # Integer or decimal number
        ('PLUS',     r'\+'),                  # Addition
        ('MINUS',    r'-'),                   # Subtraction
        ('POWER',    r'\*\*|\^'),             # Exponentiation
        ('MULTIPLY', r'\*'),                  # Multiplication
        ('DIVIDE',   r'/'),                   # Division
        ('LPAREN',   r'\ Cust'),              # Left Parenthesis (handled below via exact char match)
        ('RPAREN',   r'\)'),                  # Right Parenthesis
        ('LPAREN_CH', r'\('),                 # Actual Left Parenthesis
        ('SKIP',     r'[ \t\r\n]+'),          # Skip whitespace
        ('MISMATCH', r'.'),                   # Any other character
    ]

    # We want to map LPAREN_CH to LPAREN
    tok_regex = '|'.join(f'(?P<{pair[0]}>{pair[1]})' for pair in token_specification)
    tokens = []

    for mo in re.finditer(tok_regex, expression):
        kind = mo.lastgroup
        value = mo.group()
        if kind == 'NUMBER':
            tokens.append({'type': 'NUMBER', 'value': value})
        elif kind == 'PLUS':
            tokens.append({'type': 'PLUS', 'value': value})
        elif kind == 'MINUS':
            tokens.append({'type': 'MINUS', 'value': value})
        elif kind == 'POWER':
            tokens.append({'type': 'POWER', 'value': value})
        elif kind == 'MULTIPLY':
            tokens.append({'type': 'MULTIPLY', 'value': value})
        elif kind == 'DIVIDE':
            tokens.append({'type': 'DIVIDE', 'value': value})
        elif kind == 'LPAREN_CH':
            tokens.append({'type': 'LPAREN', 'value': value})
        elif kind == 'RPAREN':
            tokens.append({'type': 'RPAREN', 'value': value})
        elif kind == 'SKIP':
            continue
        elif kind == 'MISMATCH':
            raise ValueError(f'Unexpected character {value!r} in expression')

    return tokens

