from typing import Any

def parse(tokens: list[dict[str, str]]) -> dict[str, Any]:
    if not tokens:
        return {}

    pos = 0

    def peek() -> dict[str, str] | None:
        if pos < len(tokens):
            return tokens[pos]
        return None

    def consume() -> dict[str, str] | None:
        nonlocal pos
        tok = peek()
        if tok:
            pos += 1
        return tok

    def parse_primary() -> dict[str, Any]:
        tok = peek()
        if not tok:
            raise ValueError("Unexpected end of input")

        # Handle Parentheses
        if tok.get('type') == 'LPAREN' or tok.get('value') == '(':
            consume()  # Consume '('
            node = parse_expr()
            next_tok = peek()
            if next_tok and (next_tok.get('type') == 'RPAREN' or next_tok.get('value') == ')'):
                consume()  # Consume ')'
            else:
                raise ValueError("Mismatched parentheses")
            return node

        # Handle Numbers
        is_num_type = tok.get('type') in ('NUMBER', 'INT', 'FLOAT') or (tok.get('type', '').startswith('NUM'))
        is_num_val = False
        val_str = tok.get('value', '')
        try:
            float(val_str)
            is_num_val = True
        except ValueError:
            pass

        if is_num_type or is_num_val:
            consume()
            try:
                val = int(val_str)
            except ValueError:
                val = float(val_str)
            return {"type": "Number", "value": val}

        raise ValueError(f"Unexpected token: {tok}")

    def parse_unary() -> dict[str, Any]:
        tok = peek()
        if tok and (tok.get('type') in ('PLUS', 'MINUS') or tok.get('value') in ('+', '-')):
            op_tok = consume()
            op = op_tok.get('value')
            operand = parse_unary()
            return {"type": "UnaryOp", "op": op, "operand": operand}
        return parse_primary()

    def parse_factor() -> dict[str, Any]:
        node = parse_unary()
        tok = peek()
        if tok and (tok.get('type') in ('POW', 'POWER') or tok.get('value') in ('^', '**')):
            op_tok = consume()
            op = op_tok.get('value')
            right = parse_factor()  # Right-associative
            return {"type": "BinOp", "op": op, "left": node, "right": right}
        return node

    def parse_term() -> dict[str, Any]:
        node = parse_factor()
        while True:
            tok = peek()
            if tok and (tok.get('type') in ('MUL', 'MULTIPLY', 'DIV', 'DIVIDE') or tok.get('value') in ('*', '/')):
                op_tok = consume()
                op = op_tok.get('value')
                right = parse_factor()
                node = {"type": "BinOp", "op": op, "left": node, "right": right}
            else:
                break
        return node

    def parse_expr() -> dict[str, Any]:
        node = parse_term()
        while True:
            tok = peek()
            if tok and (tok.get('type') in ('PLUS', 'MINUS') or tok.get('value') in ('+', '-')):
                op_tok = consume()
                op = op_tok.get('value')
                right = parse_term()
                node = {"type": "BinOp", "op": op, "left": node, "right": right}
            else:
                break
        return node

    ast = parse_expr()
    if pos < len(tokens):
        raise ValueError(f"Unparsed tokens remaining at position {pos}: {tokens[pos:]}")
    return ast

