def evaluate(ast: dict[str, Any]) -> float:
    if not ast:
        raise ValueError("Empty AST node")

    node_type = str(ast.get('type', '')).lower()

    # Number / Constant node
    if node_type in ('number', 'num', 'literal', 'constant', 'float', 'int'):
        return float(ast['value'])

    # Binary operator node
    elif node_type in ('binaryop', 'binop', 'binary', 'op'):
        op = ast.get('op') or ast.get('operator')
        left = evaluate(ast['left'])
        right = evaluate(ast['right'])

        if op == '+':
            return left + right
        elif op == '-':
            return left - right
        elif op == '*':
            return left * right
        elif op == '/':
            if right == 0:
                raise ZeroDivisionError("Division by zero")
            return left / right
        elif op in ('^', '**'):
            return float(math.pow(left, right))
        else:
            raise ValueError(f"Unknown binary operator: {op}")

    # Unary operator node
    elif node_type in ('unaryop', 'unary'):
        op = ast.get('op') or ast.get('operator')
        operand_node = ast.get('operand') or ast.get('target') or ast.get('right')
        if not operand_node:
            raise ValueError("Unary operation missing operand")
        operand = evaluate(operand_node)

        if op == '-':
            return -operand
        elif op == '+':
            return operand
        else:
            raise ValueError(f"Unknown unary operator: {op}")

    # Fallback heuristic if 'type' is missing or non-standard
    else:
        if 'value' in ast and 'left' not in ast and 'right' not in ast:
            return float(ast['value'])
        elif 'left' in ast and 'right' in ast:
            op = ast.get('op') or ast.get('operator') or ast.get('type')
