import re
from typing import List, Union

def tokenize(s: str) -> List[str]:
    pattern = r'\s*(?:("[^"\\]*(?:\\.[^"\\]*)*")|(\()|(\))|([^\s()]+))'
    tokens = []
    for match in re.finditer(pattern, s):
        string, lparen, rparen, symbol = match.groups()
        if string is not None:
            tokens.append(string)
        elif lparen is not None:
            tokens.append('(')
        elif rparen is not None:
            tokens.append(')')
        elif symbol is not None:
            tokens.append(symbol)
    return tokens

def atom(token: str) -> Union[str, int, float]:
    if token.startswith('"') and token.endswith('"'):
        return token[1:-1].replace('\\"', '"').replace('\\\\', '\\')
    try:
        return int(token)
    except ValueError:
        try:
            return float(token)
        except ValueError:
            return token

def parse_tokens(tokens: List[str]) -> Union[list, str, int, float]:
    if not tokens:
        raise SyntaxError("Unexpected EOF")
    token = tokens.pop(0)
    if token == '(':
        L = []
        while tokens and tokens[0] != ')':
            L.append(parse_tokens(tokens))
        if not tokens:
            raise SyntaxError("Expected ')' but reached EOF")
        tokens.pop(0)  # pop ')'
        return L
    elif token == ')':
        raise SyntaxError("Unexpected ')'")
    else:
        return atom(token)

def parse(expr: str) -> Union[list, str, int, float]:
    tokens = tokenize(expr)
    if not tokens:
        raise SyntaxError("Empty expression")
    result = parse_tokens(tokens)
    if tokens:
        raise SyntaxError("Unexpected tokens at end of expression")
    return result

