def parse_to_tree(text: str) -> dict:
    if not text or not text.strip():
        return {"text": "", "level": 0, "children": []}

    def _shift_levels(node: dict, delta: int):
        node["level"] += delta
        for child in node["children"]:
            _shift_levels(child, delta)

    lines = text.splitlines()
    virtual_root = {"text": "", "level": -1, "children": []}
    stack = [(-1, virtual_root)]

    for line in lines:
        if not line.strip():
            continue

        # Normalize tabs to 4 spaces for consistent indentation calculation
        normalized_line = line.replace('\t', '    ')
        indent = len(normalized_line) - len(normalized_line.lstrip())
        stripped = normalized_line.strip()

        # Pop from stack until the top node has strictly less indentation
        while stack and stack[-1][0] >= indent:
            stack.pop()

        parent = stack[-1][1] if stack else virtual_root
        level = parent["level"] + 1

        node = {"text": stripped, "level": level, "children": []}
        parent["children"].append(node)
        stack.append((indent, node))

    if len(virtual_root["children"]) == 1:
        return virtual_root["children"][0]
    else:
        _shift_levels(virtual_root, 1)
        return virtual_root

