def serialize_tree(tree: dict) -> str:
    """
    Serializes the annotated tree structure back into an indented text format 
    with depth details (level and cumulative depth).

    Input shape: {"text": str, "level": int, "cumulative_depth": int, "children": list[dict]}
    """
    lines = []

    def visit(node: dict):
        if not node:
            return

        # Determine if this is a dummy root node (often used to group forest trees)
        is_dummy = node.get("level", -1) < 0 or node.get("text") == "<root>"

        if not is_dummy:
            level = node.get("level", 0)
            cum_depth = node.get("cumulative_depth", 0)
            text = node.get("text", "")
            indent = "  " * level
            lines.append(f"{indent}{text} [level={level}, cumulative_depth={cum_depth}]")

        for child in node.get("children", []):
            visit(child)

    visit(tree)
    return "\n".join(lines)

