import re
from typing import Dict, Any, List, Tuple, Optional

def tokenize(expression: str) -> List[Tuple[str, str]]:
    token_specification = [
        ('NUMBER',   r'\d+(\.\d+)?'),
        ('VAR',      r'[a-zA-Z_][a-zA-Z0-9_]*'),
        ('OP',       r'[\+\-\*\/\^]'),
        ('LPAREN',   r'\Custom('),
        ('RPAREN',   r'\)'),
        ('SKIP',     r'[ \t\r\n]+'),
        ('MISMATCH', r'.'),
    ]
    # Replace parenthesis with escaped versions for regex safely
    token_specification[3] = ('LPAREN', r'\(')

    tok_regex = '|'.join(f'(?P<{pair[0]}>{pair[1]})' for pair in token_specification)
    tokens: List[Tuple[str, str]] = []
    for mo in re.finditer(tok_regex, expression):
        kind = mo.lastgroup
        value = mo.group()
        if kind == 'SKIP':
            continue
        elif kind == 'MISMATCH':
            raise ValueError(f"Unexpected character: {value!r}")
        elif kind is not None:
            tokens.append((kind, value))
    return tokens

class Parser:
    def __init__(self, tokens: List[Tuple[str, str]]):
        self.tokens = tokens
        self.pos = 0

    def current_token(self) -> Optional[Tuple[str, str]]:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self, expected_kind: Optional[str] = None) -> Tuple[str, str]:
        tok = self.current_token()
        if tok is None:
            raise ValueError("Unexpected end of input")
        if expected_kind and tok[0] != expected_kind:
            raise ValueError(f"Expected {expected_kind}, got {tok[0]}")
        self.pos += 1
        return tok

    def parse(self) -> Dict[str, Any]:
        node = self.expr()
        if self.pos < len(self.tokens):
            raise ValueError(f"Unexpected trailing tokens at position {self.pos}: {self.tokens[self.pos:]}")
        return node

    def expr(self) -> Dict[str, Any]:
        node = self.term()
        while True:
            tok = self.current_token()
            if tok and tok[0] == 'OP' and tok[1] in ('+', '-'):
                self.consume()
                node = {
                    'type': 'OPERATOR',
                    'value': tok[1],
                    'left': node,
                    'right': self.term()
                }
            else:
                break
        return node

    def term(self) -> Dict[str, Any]:
        node = self.factor()
        while True:
            tok = self.current_token()
            if tok and tok[0] == 'OP' and tok[1] in ('*', '/'):
                self.consume()
                node = {
                    'type': 'OPERATOR',
                    'value': tok[1],
                    'left': node,
                    'right': self.factor()
                }
            else:
                break
        return node

    def factor(self) -> Dict[str, Any]:
        node = self.unary()
        tok = self.current_token()
        if tok and tok[0] == 'OP' and tok[1] == '^':
            self.consume()
            node = {
                'type': 'OPERATOR',
                'value': '^',
                'left': node,
                'right': self.factor()
            }
        return node

    def unary(self) -> Dict[str, Any]:
        tok = self.current_token()
        if tok and tok[0] == 'OP' and tok[1] in ('+', '-'):
            self.consume()
            operand = self.unary()
            return {
                'type': 'UNARY_OPERATOR',
                'value': tok[1],
                'left': operand,
                'right': None
            }
        return self.primary()

    def primary(self) -> Dict[str, Any]:
        tok = self.current_token()
        if tok is None:
            raise ValueError("Unexpected end of expression")

        if tok[0] == 'NUMBER':
            self.consume()
            return {
                'type': 'NUMBER',
                'value': tok[1],
                'left': None,
                'right': None
            }
        elif tok[0] == 'VAR':
            self.consume()
            return {
                'type': 'VARIABLE',
                'value': tok[1],
                'left': None,
                'right': None
            }
        elif tok[0] == 'LPAREN':
            self.consume('LPAREN')
            node = self.expr()
            self.consume('RPAREN')
            return node
        else:
            raise ValueError(f"Expected number, variable, or parenthesis, got {tok[1]!r}")

def parse_to_tree(expression: str) -> Dict[str, Any]:
    """
    Parses an infix mathematical expression string into an Abstract Syntax Tree (AST).

    Args:
        expression: The mathematical expression string.

    Returns:
        A nested dictionary representing the AST.
    """
    tokens = tokenize(expression)
    if not tokens:
        raise ValueError("Empty expression")
    parser = Parser(tokens)
    return parser.parse()

