def tree_to_string(tree: dict | None) -> str:
    """Converts an AST back into an infix expression string."""
    if not tree:
        return ""

    precedence = {
        '+': 1, '-': 1,
        '*': 2, '/': 2,
        '^': 3
    }

    def get_precedence(op: str) -> int:
        return precedence.get(op, 0)

    def to_str(node: dict | None) -> str:
        if not node:
            return ""

        val = str(node.get('value', ''))
        left = node.get('left')
        right = node.get('right')

        # Leaf node
        if left is None and right is None:
            return val

        # Unary Operator (e.g., negative numbers or prefix operators)
        if left is None and right is not None:
            r_str = to_str(right)
            if right.get('left') is not None or right.get('right') is not None:
                r_str = f"({r_str})"
            return f"{val}{r_str}"

        if left is not None and right is None:
            l_str = to_str(left)
            if left.get('left') is not None or left.get('right') is not None:
                l_str = f"({l_str})"
            return f"{l_str}{val}"

        # Binary Operator
        op = val
        l_str = to_str(left)
        r_str = to_str(right)

        # Determine if left child needs parentheses
        if left and (left.get('left') is not None or left.get('right') is not None):
            left_op = str(left.get('value', ''))
            if get_precedence(left_op) < get_precedence(op):
                l_str = f"({l_str})"

        # Determine if right child needs parentheses
        if right and (right.get('left') is not None or right.get('right') is not None):
            right_op = str(right.get('value', ''))
            right_prec = get_precedence(right_op)
            current_prec = get_precedence(op)
            if right_prec < current_prec:
                r_str = f"({r_str})"
            elif right_prec == current_prec:
                # Right side of subtraction, division, or exponentiation needs parens to preserve associativity
                if op in ('-', '/', '^') or right_op in ('-', '/', '^'):
                    r_str = f"({r_str})"

        return f"{l_str} {op} {r_str}"

    return to_str(tree)

