def build_adjacency_list(edges: list[tuple[str, str]]) -> dict[str, list[str]]:
    """
    Builds a directed adjacency list from a list of raw edges.
    Ensures that all nodes mentioned in the edge list are represented
    as keys in the returned dictionary, even if they have no outgoing edges.
    """
    adj_list: dict[str, list[str]] = {}
    for u, v in edges:
        if u not in adj_list:
            adj_list[u] = []
        if v not in adj_list:
            adj_list[v] = []
        adj_list[u].append(v)
    return adj_list

