from collections import deque

def find_connected_components(adj_list: dict[str, list[str]]) -> list[list[str]]:
    all_vertices = set(adj_list.keys())
    for neighbors in adj_list.values():
        for neighbor in neighbors:
            all_vertices.add(neighbor)

    undirected: dict[str, set[str]] = {v: set() for v in all_vertices}
    for u, neighbors in adj_list.items():
        for v in neighbors:
            undirected[u].add(v)
            undirected[v].add(u)

    visited = set()
    components = []

    for node in sorted(all_vertices):
        if node not in visited:
            component = []
            queue = deque([node])
            visited.add(node)
            while queue:
                curr = queue.popleft()
                component.append(curr)
                for neighbor in sorted(undirected[curr]):
                    if neighbor not in visited:
                        visited.add(neighbor)
                        queue.append(neighbor)
            components.append(sorted(component))

    return sorted(components)

