def build_graph(raw_dependencies: dict[str, list[str]]) -> dict[str, list[str]]:
    """
    Validates and standardizes the graph structure representation.
    Ensures all referenced modules exist as nodes in the graph.

    Args:
        raw_dependencies: A dictionary mapping module names to their dependencies.

    Returns:
        A standardized graph representation where every referenced node exists
        as a key, and dependency lists are deduplicated and sorted.
    """
    if not isinstance(raw_dependencies, dict):
        raise TypeError("raw_dependencies must be a dictionary")

    graph: dict[str, list[str]] = {}
    all_nodes = set()

    # Validate structure and collect all nodes
    for source, targets in raw_dependencies.items():
        if not isinstance(source, str):
            raise TypeError(f"Graph keys must be strings, found {type(source).__name__}")
        if not isinstance(targets, list):
            raise TypeError(f"Dependency list for '{source}' must be a list, found {type(targets).__name__}")

        all_nodes.add(source)
        for target in targets:
            if not isinstance(target, str):
                raise TypeError(f"Dependency of '{source}' must be a string, found {type(target).__name__}")
            all_nodes.add(target)

    # Build standardized graph
    for node in sorted(all_nodes):
        if node in raw_dependencies:
            # Deduplicate and sort dependencies to ensure a standardized representation
            graph[node] = sorted(list(set(raw_dependencies[node])))
        else:
            # Node was referenced but not defined; standardizing ensures it has a key with empty dependencies
            graph[node] = []

    return graph

