def resolve_dependencies(graph: dict[str, list[str]]) -> dict:
    """
    Performs topological sorting and detects cycles (strongly connected components)
    within the graph.

    Input:
        graph: dict[str, list[str]] where keys are nodes and values are their dependencies.
               (e.g., A depends on B means graph['A'] = ['B'])

    Output:
        {
            "has_cycle": bool,
            "build_order": list[str],
            "cycles": list[list[str]]
        }
    """
    # Normalize graph to ensure all referenced nodes exist as keys
    full_graph = {node: list(deps) for node, deps in graph.items()}
    for deps in graph.values():
        for dep in deps:
            if dep not in full_graph:
                full_graph[dep] = []

    # Tarjan's algorithm for Strongly Connected Components (SCCs)
    index_counter = [0]
    stack = []
    lowlink = {}
    index = {}
    on_stack = set()
    sccs = []

    def strongconnect(node):
        index[node] = index_counter[0]
        lowlink[node] = index_counter[0]
        index_counter[0] += 1
        stack.append(node)
        on_stack.add(node)

        for neighbor in full_graph.get(node, []):
            if neighbor not in index:
                strongconnect(neighbor)
                lowlink[node] = min(lowlink[node], lowlink[neighbor])
            elif neighbor in on_stack:
                lowlink[node] = min(lowlink[node], index[neighbor])

        if lowlink[node] == index[node]:
            scc = []
            while True:
                w = stack.pop()
                on_stack.remove(w)
                scc.append(w)
                if w == node:
                    break
            sccs.append(scc)

    for node in sorted(full_graph.keys()):
        if node not in index:
            strongconnect(node)

    # Detect cycles from SCCs
    cycles = []
    has_cycle = False
    for scc in sccs:
        if len(scc) > 1:
            cycles.append(sorted(scc))
            has_cycle = True
        elif len(scc) == 1:
            node = scc[0]
            if node in full_graph[node]:  # Self-loop
                cycles.append([node])
                has_cycle = True

    # Ensure output cycles are sorted deterministically
    cycles.sort(key=lambda x: (len(x), x[0] if x else ""))

    # If there are cycles, build order is not fully determinable
    build_order = []
    if not has_cycle:
        visited = set()

        def dfs(node):
            visited.add(node)
            for neighbor in full_graph.get(node, []):
                if neighbor not in visited:
                    dfs(neighbor)
            build_order.append(node)

        # Sort keys to ensure deterministic topological sort order
        for node in sorted(full_graph.keys()):
            if node not in visited:
                dfs(node)

    return {
        "has_cycle": has_cycle,
        "build_order": build_order,
        "cycles": cycles
    }

