            if key < curr.key:
                if curr.left is None:
                    curr.left = Node(key)
                    return
                curr = curr.left
            elif key > curr.key:
                if curr.right is None:
                    curr.right = Node(key)
                    return
                curr = curr.right
            else:
                # Key already exists; do nothing
                return

    def find(self, key: int) -> bool:
        curr = self.root
        while curr is not None:
            if key == curr.key:
                return True
            elif key < curr.key:
                curr = curr.left
            else:
                curr = curr.right
        return False

    def delete(self, key: int) -> None:
        self.root = self._delete_helper(self.root, key)

    def _delete_helper(self, root: Node | None, key: int) -> Node | None:
        if root is None:
            return None

        if key < root.key:
            root.left = self._delete_helper(root.left, key)
        elif key > root.key:
            root.right = self._delete_helper(root.right, key)
        else:
            # Node with only one child or no child
            if root.left is None:
                return root.right
            elif root.right is None:
                return root.left

            # Node with two children: Get the inorder successor
            temp = self._min_value_node(root.right)
            root.key = temp.key
            root.right = self._delete_helper(root.right, temp.key)

        return root

    def _min_value_node(self, node: Node) -> Node:
        current = node
        while current.left is not None:
            current = current.left
        return current

    def in_order(self) -> list[int]:
        result: list[int] = []
        self._in_order_helper(self.root, result)
        return result

    def _in_order_helper(self, root: Node | None, result: list[int]) -> None:
        if root is not None:
            self._in_order_helper(root.left, result)
            result.append(root.key)
            self._in_order_helper(root.right, result)

