import json
import os

def load_data(file_path: str) -> dict[str, list[str]]:
    """
    Reads the tag hierarchy data from a local JSON file.
    If the file does not exist, returns an empty dictionary.
    """
    if not os.path.exists(file_path):
        return {}
    try:
        with open(file_path, "r", encoding="utf-8") as f:
            content = f.read().strip()
            if not content:
                return {}
            data = json.loads(content)
            if isinstance(data, dict):
                validated_data: dict[str, list[str]] = {}
                for key, value in data.items():
                    if isinstance(value, list):
                        validated_data[str(key)] = [str(item) for item in value]
                    else:
                        validated_data[str(key)] = []
                return validated_data
            return {}
    except (json.JSONDecodeError, IOError):
        return {}

def save_data(file_path: str, data: dict[str, list[str]]) -> None:
    """
    Writes the tag hierarchy data to a local JSON file.
    Creates any directories in the file path if they do not exist.
    """
    dir_name = os.path.dirname(file_path)
    if dir_name and not os.path.exists(dir_name):
        os.makedirs(dir_name, exist_ok=True)
    with open(file_path, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=4, ensure_ascii=False)

