from typing import Dict, List, Optional, Set
from storage import load_data, save_data

_file_path: Optional[str] = None
_hierarchy: Dict[str, List[str]] = {}

def load_hierarchy(file_path: str) -> None:
    global _file_path, _hierarchy
    _file_path = file_path
    _hierarchy = load_data(file_path)

def save_hierarchy() -> None:
    if _file_path is not None:
        save_data(_file_path, _hierarchy)

def add_relation(parent: str, child: str) -> bool:
    if parent == child:
        return False

    # Cycle detection: If parent is already a descendant of child, adding child as a descendant of parent creates a cycle
    if parent in get_all_descendants(child):
        return False

    if parent not in _hierarchy:
        _hierarchy[parent] = []

    if child in _hierarchy[parent]:
        return False  # Already exists

    _hierarchy[parent].append(child)
    return True

def delete_relation(parent: str, child: str) -> bool:
    if parent not in _hierarchy:
        return False

    if child in _hierarchy[parent]:
        _hierarchy[parent].remove(child)
        # Clean up empty parent list to keep hierarchy tidy
        if not _hierarchy[parent]:
            del _hierarchy[parent]
        return True

    return False

def list_relations() -> Dict[str, List[str]]:
    return {parent: list(children) for parent, children in _hierarchy.items()}

def get_all_descendants(tag: str) -> List[str]:
    descendants: Set[str] = set()
    queue = [tag]
    visited = {tag}

    while queue:
        current = queue.pop(0)
        children = _hierarchy.get(current, [])
        for child in children:
            if child not in visited:
                visited.add(child)
                descendants.add(child)
                queue.append(child)

    return sorted(list(descendants))

