class Parser:
    def __init__(self, tokens: list[tuple[str, str]]):
        self.tokens = tokens
        self.pos = 0

    def current(self) -> tuple[str, str] | None:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def is_type(self, tok: tuple[str, str] | None, families: list[str]) -> bool:
        if not tok:
            return False
        t, v = tok
        t_upper = t.upper()
        v_str = str(v)

        for fam in families:
            if fam == 'NUMBER':
                if t_upper in ('NUMBER', 'NUM', 'INT', 'FLOAT', 'DIGIT'):
                    return True
            elif fam == 'IDENTIFIER':
                if t_upper in ('IDENTIFIER', 'ID', 'VAR', 'NAME', 'WORD'):
                    return True
            elif fam == 'STRING':
                if t_upper in ('STRING', 'STR', 'LITERAL'):
                    return True
            elif fam in ('BOOLEAN', 'BOOL'):
                if t_upper in ('BOOLEAN', 'BOOL'):
                    return True
            elif fam == 'PLUS':
                if t_upper in ('PLUS', 'ADD') or v_str == '+':
                    return True
            elif fam == 'MINUS':
                if t_upper in ('MINUS', 'SUB') or v_str == '-':
                    return True
            elif fam == 'MUL':
                if t_upper in ('MUL', 'MULTIPLY', 'STAR', 'TIMES') or v_str == '*':
                    return True
            elif fam == 'DIV':
                if t_upper in ('DIV', 'DIVIDE', 'SLASH') or v_str == '/':
                    return True
            elif fam == 'POW':
                if t_upper in ('POW', 'POWER', 'EXP', 'CARET') or v_str in ('^', '**'):
                    return True
            elif fam == 'LPAREN':
                if t_upper in ('LPAREN', 'LPAR', 'PAREN_L', 'OPEN_PAREN') or v_str == '(':
                    return True
            elif fam == 'RPAREN':
                if t_upper in ('RPAREN', 'RPAR', 'PAREN_R', 'CLOSE_PAREN') or v_str == ')':
                    return True
            elif fam == 'COMMA':
                if t_upper in ('COMMA', 'COM') or v_str == ',':
                    return True
        return False

    def is_match(self, families: list[str]) -> bool:
        return self.is_type(self.current(), families)

    def consume(self, families: list[str]) -> tuple[str, str]:
        tok = self.current()
        if not tok:
            raise SyntaxError("Unexpected end of input")
        if not self.is_type(tok, families):
            raise SyntaxError(f"Expected token type in {families}, got {tok}")
        self.pos += 1
        return tok

