            op_tok = self.current()
            self.pos += 1
            right = self.term()
            node = {
                "type": "BinOp",
                "op": op_tok[1],
                "left": node,
                "right": right
            }
        return node

    def term(self) -> dict[str, any]:
        node = self.factor()
        while self.is_match(['MUL', 'DIV']):
            op_tok = self.current()
            self.pos += 1
            right = self.factor()
            node = {
                "type": "BinOp",
                "op": op_tok[1],
                "left": node,
                "right": right
            }
        return node

    def factor(self) -> dict[str, any]:
        node = self.unary()
        if self.is_match(['POW']):
            op_tok = self.current()
            self.pos += 1
            right = self.factor()
            node = {
                "type": "BinOp",
                "op": op_tok[1],
                "left": node,
                "right": right
            }
        return node

    def unary(self) -> dict[str, any]:
        if self.is_match(['PLUS', 'MINUS']):
            op_tok = self.current()
            self.pos += 1
            operand = self.unary()
            return {
                "type": "UnaryOp",
                "op": op_tok[1],
                "operand": operand
            }
        return self.primary()

    def primary(self) -> dict[str, any]:
        tok = self.current()
        if not tok:
            raise SyntaxError("Unexpected end of input")

        if self.is_type(tok, ['NUMBER']):
            self.pos += 1
            val_str = tok[1]
            try:
                val = float(val_str)
                if val.is_integer():
                    val = int(val)
