                val = val_str
            return {
                "type": "Number",
                "value": val
            }

        elif self.is_type(tok, ['STRING']):
            self.pos += 1
            return {
                "type": "String",
                "value": tok[1]
            }

        elif self.is_type(tok, ['BOOLEAN']):
            self.pos += 1
            val = str(tok[1]).lower() in ('true', '1', 't', 'yes', 'y')
            return {
                "type": "Boolean",
                "value": val
            }

        elif self.is_type(tok, ['IDENTIFIER']):
