import math
from typing import Any, Dict

def evaluate(ast: Dict[str, Any]) -> float:
    """
    Evaluates the Abstract Syntax Tree (AST) recursively to compute the numerical result.

    Expected AST node shapes:
    - Number/Literal: {"type": "number", "value": 42.0}
    - Binary Operation: {"type": "binary", "operator": "+", "left": {...}, "right": {...}}
    - Unary Operation: {"type": "unary", "operator": "-", "operand": {...}}
    - Function Call: {"type": "function", "name": "sin", "args": [...] or "arguments": [...]}
    - Variable/Constant: {"type": "variable", "name": "pi"}
    """
    if not isinstance(ast, dict):
        raise TypeError("AST node must be a dictionary")

    node_type = ast.get("type")

    if node_type in ("number", "literal"):
        return float(ast["value"])

    elif node_type in ("binary", "binop"):
        operator = ast["operator"]
        left_val = evaluate(ast["left"])
        right_val = evaluate(ast["right"])

        if operator == "+":
            return left_val + right_val
        elif operator == "-":
            return left_val - right_val
        elif operator == "*":
            return left_val * right_val
        elif operator == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        elif operator in ("^", "**"):
            return left_val ** right_val
        else:
