from typing import Union, List

def parse(tokens: List[str]) -> Union[str, int, float, list]:
    if not tokens:
        raise ValueError("Unexpected EOF: No tokens to parse")

    class TokenStream:
        def __init__(self, tokens_list: List[str]):
            self.tokens = tokens_list
            self.index = 0

        def peek(self) -> Union[str, None]:
            if self.index < len(self.tokens):
                return self.tokens[self.index]
            return None

        def next(self) -> str:
            if self.index < len(self.tokens):
                val = self.tokens[self.index]
                self.index += 1
                return val
            raise ValueError("Unexpected EOF")

        def has_more(self) -> bool:
            return self.index < len(self.tokens)

    stream = TokenStream(tokens)

    def parse_element() -> Union[str, int, float, list]:
        token = stream.next()
        if token == '(':
            lst = []
            while stream.peek() != ')':
                if stream.peek() is None:
                    raise ValueError("Expected ')' but reached EOF")
                lst.append(parse_element())
            stream.next()  # Consume the closing ')'
            return lst
        elif token == ')':
            raise ValueError("Unexpected ')'")
        else:
            # Parse Atom
            try:
                return int(token)
            except ValueError:
                try:
                    return float(token)
                except ValueError:
                    # Strip outer quotes if they exist
                    if len(token) >= 2 and (
                        (token.startswith('"') and token.endswith('"')) or
                        (token.startswith("'") and token.endswith("'"))
                    ):
                        return token[1:-1]
                    return token

    result = parse_element()
    if stream.has_more():
        raise ValueError("Unexpected extra tokens at the end of expression")
    return result

