import math

def evaluate(node: Union[str, int, float, list]) -> Union[int, float]:
    if isinstance(node, (int, float)):
        return node

    if isinstance(node, str):
        try:
            if '.' in node or 'e' in node.lower():
                return float(node)
            return int(node)
        except ValueError:
            normalized = node.lower()
            if normalized == "pi":
                return math.pi
            elif normalized == "e":
                return math.e
            raise ValueError(f"Cannot evaluate identifier: {node}")

    if isinstance(node, list):
        if not node:
            raise ValueError("Empty node list encountered")

        operators = {'+', '-', '*', '/', '^', '**', '%', '//'}

        if len(node) == 1:
            return evaluate(node[0])

        if len(node) == 2:
            op = node[0]
            val = evaluate(node[1])
            if op == '-':
                return -val
            elif op == '+':
                return +val
            else:
                raise ValueError(f"Unsupported unary operator: {op}")

        if len(node) == 3:
            if isinstance(node[1], str) and node[1] in operators:
                op = node[1]
                left = evaluate(node[0])
                right = evaluate(node[2])
            elif isinstance(node[0], str) and node[0] in operators:
                op = node[0]
                left = evaluate(node[1])
                right = evaluate(node[2])
            else:
                op = node[0]
                left = evaluate(node[1])
                right = evaluate(node[2])

            return _apply_op(op, left, right)

        raise ValueError(f"List node has unsupported length {len(node)}: {node}")

    raise TypeError(f"Unsupported node type: {type(node)}")

def _apply_op(op: str, left: Union[int, float], right: Union[int, float]) -> Union[int, float]:
    if op == '+':
        return left + right
    elif op == '-':
        return left - right
    elif op == '*':
        return left * right
    elif op == '/':
        return left / right
    elif op in ('^', '**'):
        return left ** right
    elif op == '%':
        return left % right
    elif op == '//':
        return left // right
    else:
        raise ValueError(f"Unsupported binary operator: {op}")

