def parse_indented_text(text: str) -> list[dict]:
    """
    Parses an indented text string into a hierarchical list of tree nodes.
    Each node in the list is a dictionary: {"value": str, "children": list}
    """
    if not text:
        return []

    root_nodes = []
    stack = []  # Elements are tuples of (indent_level, node_dict)

    for line in text.splitlines():
        # Handle tab expansion for consistent indentation measurement
        expanded_line = line.expandtabs(4)
        stripped = expanded_line.lstrip()

        if not stripped:
            continue  # Skip empty or whitespace-only lines

        indent_level = len(expanded_line) - len(stripped)
        value = line.strip()

        node = {
            "value": value,
            "children": []
        }

        # Pop from stack until we find the parent (which must have a strictly smaller indent level)
        while stack and stack[-1][0] >= indent_level:
            stack.pop()

        if not stack:
            root_nodes.append(node)
        else:
            stack[-1][1]["children"].append(node)

        stack.append((indent_level, node))

    return root_nodes

