def parse_expression(expr: str) -> dict:
    # Tokenize the expression into numbers, operators, and parentheses
    tokens = re.findall(r'\d+\.\d+|\.\d+|\d+|[+\-*/()]', expr)
    pos = 0

    def peek():
        nonlocal pos
        if pos < len(tokens):
            return tokens[pos]
        return None

    def consume(expected=None):
        nonlocal pos
        token = peek()
        if expected is not None and token != expected:
            raise ValueError(f"Expected {expected}, got {token}")
        if token is not None:
            pos += 1
        return token

    def parse_expr():
        node = parse_term()
        while True:
            op = peek()
            if op in ('+', '-'):
                consume()
                right = parse_term()
                node = create_operator_node(op, node, right)
            else:
                break
        return node

    def parse_term():
        node = parse_factor()
        while True:
            op = peek()
            if op in ('*', '/'):
                consume()
                right = parse_factor()
                node = create_operator_node(op, node, right)
            else:
                break
        return node

    def parse_factor():
        op = peek()
        if op in ('+', '-'):
            consume()
            right = parse_factor()
            if op == '-':
                # Represent unary negative as subtraction from zero
                return create_operator_node('-', create_numeric_node(0.0), right)
            else:
                return right
        return parse_primary()

    def parse_primary():
        token = peek()
        if token == '(':
            consume('(')
            node = parse_expr()
            consume(')')
            return node
        elif token is not None:
            try:
                val = float(token)
                consume()
                return create_numeric_node(val)
            except ValueError:
                raise ValueError(f"Unexpected token: {token}")
        else:
            raise ValueError("Unexpected end of input")

    if not tokens:
        raise ValueError("Empty expression")

    result = parse_expr()
    if pos < len(tokens):
        raise ValueError(f"Extraneous tokens at the end: {tokens[pos:]}")
    return result

