        # Handle literals, numbers, variables, and identifiers
        if node_type in ("number", "literal", "numeric", "variable", "identifier"):
            return str(node.get("value", ""))

        # Handle binary operators
        elif node_type in ("binary", "binary_op"):
            op = node.get("operator") or node.get("op") or ""
            left = node.get("left")
            right = node.get("right")

            prec = get_precedence(op)
            left_str = recurse(left, prec, is_right=False)
            right_str = recurse(right, prec, is_right=True)

            # Determine if parentheses are needed based on operator precedence and associativity
            need_parens = False
            if prec < parent_prec:
                need_parens = True
            elif prec == parent_prec:
                is_right_assoc = op in ('^', '**')
                if is_right_assoc:
                    if not is_right:
                        need_parens = True
                else:
                    if is_right:
                        need_parens = True

            expr = f"{left_str} {op} {right_str}"
            return f"({expr})" if need_parens else expr

        # Handle unary operators
        elif node_type in ("unary", "unary_op"):
            op = node.get("operator") or node.get("op") or ""
            operand = node.get("operand") or node.get("value")

            operand_str = recurse(operand, parent_prec=99)

            child_type = ""
