                child_type = str(operand.get("type", "")).lower()

            # Parenthesize binary expression inside a unary operation for clarity
            if child_type in ("binary", "binary_op"):
                operand_str = f"({operand_str})"

            return f"{op}{operand_str}"

        # Handle function calls
        elif node_type in ("function", "call"):
            name = node.get("name") or node.get("value") or ""
            args = node.get("arguments") or node.get("args") or []
            if not isinstance(args, list):
                args = [args]
            args_str = ", ".join(recurse(arg) for arg in args)
            return f"{name}({args_str})"

        # Fallback for generic node structures
        if "value" in node:
            return str(node["value"])
        return ""

    return recurse(tree)

