def _create_node(key: int) -> dict:
    return {'key': key, 'left': None, 'right': None}

def insert(tree_node: Optional[dict], key: int) -> dict:
    if tree_node is None:
        return _create_node(key)
    if key < tree_node['key']:
        tree_node['left'] = insert(tree_node['left'], key)
    elif key > tree_node['key']:
        tree_node['right'] = insert(tree_node['right'], key)
    return tree_node

def find(tree_node: Optional[dict], key: int) -> bool:
    if tree_node is None:
        return False
    if key == tree_node['key']:
        return True
    elif key < tree_node['key']:
        return find(tree_node['left'], key)
    else:
        return find(tree_node['right'], key)

def delete(tree_node: Optional[dict], key: int) -> Optional[dict]:
    if tree_node is None:
        return None
    if key < tree_node['key']:
        tree_node['left'] = delete(tree_node['left'], key)
    elif key > tree_node['key']:
        tree_node['right'] = delete(tree_node['right'], key)
    else:
        if tree_node['left'] is None:
            return tree_node['right']
        elif tree_node['right'] is None:
            return tree_node['left']
        else:
            successor = tree_node['right']
            while successor['left'] is not None:
                successor = successor['left']
            tree_node['key'] = successor['key']
            tree_node['right'] = delete(tree_node['right'], successor['key'])
    return tree_node

def inorder(tree_node: Optional[dict]) -> List[int]:
    if tree_node is None:
        return []
    return inorder(tree_node['left']) + [tree_node['key']] + inorder(tree_node['right'])

