def validate_parentheses(text: str) -> bool:
    """
    Validates if the parentheses in the given text are properly balanced.
    Supports standard parentheses (), square brackets [], and curly braces {}.
    Non-bracket characters are ignored.
    """
    stack = []
    brackets_map = {')': '(', ']': '[', '}': '{'}
    opening_brackets = set(brackets_map.values())

    for char in text:
        if char in opening_brackets:
            stack.append(char)
        elif char in brackets_map:
            if not stack:
                return False
            top_element = stack.pop()
            if brackets_map[char] != top_element:
                return False

    return len(stack) == 0

