import json
import os


def load_data(file_path: str) -> dict[str, list[str]]:
    """Loads the tag hierarchy structure from a JSON file.

    If the file does not exist, is empty, or is invalid, returns an empty dictionary.
    """
    if not os.path.exists(file_path):
        return {}
    try:
        with open(file_path, "r", encoding="utf-8") as f:
            content = f.read().strip()
            if not content:
                return {}
            data = json.loads(content)
            if isinstance(data, dict):
                # Ensure the structure is dict[str, list[str]]
                return {
                    str(k): [str(item) for item in v] if isinstance(v, list) else []
                    for k, v in data.items()
                }
            return {}
    except (json.JSONDecodeError, IOError, TypeError):
        return {}


