_tags: set[str] = set()
_relations: dict[str, set[str]] = {}

def _has_path(start: str, end: str) -> bool:
    visited = set()
    queue = [start]
    while queue:
        curr = queue.pop(0)
        if curr == end:
            return True
        if curr in visited:
            continue
        visited.add(curr)
        if curr in _relations:
            queue.extend(_relations[curr])
    return False

def add_tag(tag: str) -> bool:
    if tag in _tags:
        return False
    _tags.add(tag)
    return True

def add_relation(parent: str, child: str) -> bool:
    if parent == child:
        return False

    # Ensure both tags exist
    if parent not in _tags:
        _tags.add(parent)
    if child not in _tags:
        _tags.add(child)

    if parent not in _relations:
        _relations[parent] = set()

    if child in _relations[parent]:
        return False

    # Cycle prevention
    if _has_path(child, parent):
        return False

    _relations[parent].add(child)
    return True

def delete_tag(tag: str) -> bool:
    if tag not in _tags:
        return False

    _tags.remove(tag)

    if tag in _relations:
        del _relations[tag]

    for p in list(_relations.keys()):
        _relations[p].discard(tag)
        if not _relations[p]:
            del _relations[p]

    return True

def delete_relation(parent: str, child: str) -> bool:
    if parent not in _relations or child not in _relations[parent]:
        return False
    _relations[parent].remove(child)
    if not _relations[parent]:
        del _relations[parent]
    return True

def list_tags() -> list[str]:
    return sorted(list(_tags))

def get_descendants(tag: str) -> list[str]:
    if tag not in _tags:
        return []

    visited = set()
    queue = [tag]
    descendants = set()

    while queue:
        curr = queue.pop(0)
        if curr != tag:
            descendants.add(curr)
        if curr in _relations:
            for child in _relations[curr]:
                if child not in visited:
                    visited.add(child)
                    queue.append(child)

    return sorted(list(descendants))

def import_hierarchy(data: dict[str, list[str]]) -> None:
    _tags.clear()
    _relations.clear()

    for parent, children in data.items():
        _tags.add(parent)
        if children:
            if parent not in _relations:
                _relations[parent] = set()
            for child in children:
                _tags.add(child)
                _relations[parent].add(child)

def export_hierarchy() -> dict[str, list[str]]:
    result = {}
    for parent, children in _relations.items():
        if children:
            result[parent] = sorted(list(children))
    return result

