import typing

def evaluate(ast: typing.Optional[dict]) -> float:
    """
    Recursively evaluates the Abstract Syntax Tree (AST) to compute the final numeric result.

    AST Node structure:
    {
        "type": str,          # e.g., "number", "operator", "unary"
        "value": str,         # e.g., "3.14", "+", "-", "*", "/"
        "left": dict | None,  # Left child node
        "right": dict | None  # Right child node
    }
    """
    if ast is None:
        return 0.0

    node_type = ast.get("type")
    value = ast.get("value")
    left = ast.get("left")
    right = ast.get("right")

    # Handle numeric leaf nodes
    if node_type in ("number", "literal", "numeric", "num") or (left is None and right is None):
        try:
            return float(value)
        except (ValueError, TypeError):
            raise ValueError(f"Invalid numeric value in AST: {value}")

    # Handle unary operators (e.g., -5, +3)
    if left is None and right is not None:
        right_val = evaluate(right)
        if value == "-":
            return -right_val
        elif value == "+":
            return right_val
        raise ValueError(f"Unsupported unary operator: {value}")

    # Handle binary operators
    if left is not None and right is not None:
        left_val = evaluate(left)
        right_val = evaluate(right)

        if value == "+":
            return left_val + right_val
        elif value == "-":
            return left_val - right_val
        elif value == "*":
            return left_val * right_val
        elif value == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        elif value in ("^", "**"):
            return left_val ** right_val
        raise ValueError(f"Unsupported binary operator: {value}")

    raise ValueError(f"Malformed AST node: {ast}")

