def tokenize(expr: str) -> list[str]:
    """
    Splits the S-expression string into individual token strings,
    handling parentheses, whitespaces, and string literals.
    """
    tokens = []
    i = 0
    n = len(expr)
    while i < n:
        char = expr[i]
        if char.isspace():
            i += 1
        elif char == '(' or char == ')':
            tokens.append(char)
            i += 1
        elif char == '"':
            # Handle string literals, including escaped double quotes
            start = i
            i += 1
            while i < n and expr[i] != '"':
                if expr[i] == '\\' and i + 1 < n:
                    i += 2
                else:
                    i += 1
            if i < n:
                i += 1  # Include the closing double quote
            tokens.append(expr[start:i])
        else:
            # Handle symbols, numbers, and identifiers
            start = i
            while i < n and not expr[i].isspace() and expr[i] not in '()':
                i += 1
            tokens.append(expr[start:i])
    return tokens

