def parse(tokens: list[str]) -> list | str | int | float:
    if not tokens:
        return []

    def atom(token: str) -> str | int | float:
        if (token.startswith('"') and token.endswith('"')) or (token.startswith("'") and token.endswith("'")):
            if len(token) >= 2:
                return token[1:-1]
        try:
            return int(token)
        except ValueError:
            try:
                return float(token)
            except ValueError:
                return token

    def parse_helper(token_list: list[str]) -> list | str | int | float:
        if not token_list:
            return []
        token = token_list.pop(0)
        if token == '(':
            L = []
            while token_list and token_list[0] != ')':
                L.append(parse_helper(token_list))
            if token_list:
                token_list.pop(0)  # remove ')'
            return L
        elif token == '[':
            L = []
            while token_list and token_list[0] != ']':
                L.append(parse_helper(token_list))
            if token_list:
                token_list.pop(0)  # remove ']'
            return L
        elif token in (')', ']'):
            return token
        else:
            return atom(token)

    working_tokens = list(tokens)
    results = []
    while working_tokens:
        results.append(parse_helper(working_tokens))

    if len(results) == 1:
        return results[0]
    return results

