from functools import reduce

def evaluate(node: list | str | int | float) -> int | float:
    if isinstance(node, (int, float)):
        return node

    if isinstance(node, str):
        try:
            if '.' in node or 'e' in node.lower():
                return float(node)
            return int(node)
        except ValueError:
            raise ValueError(f"Cannot evaluate string symbol: {node}")

    if isinstance(node, list):
        if not node:
            raise ValueError("Empty S-expression cannot be evaluated")

        op = node[0]
        if not isinstance(op, str):
            raise ValueError(f"First element of an S-expression must be an operator string, got: {type(op)}")

        args = [evaluate(x) for x in node[1:]]

        if op == '+':
            return sum(args)
        elif op == '-':
            if len(args) == 0:
                raise ValueError("Subtraction operator '-' requires at least one argument")
            if len(args) == 1:
                return -args[0]
            return reduce(lambda x, y: x - y, args)
        elif op == '*':
            return reduce(lambda x, y: x * y, args, 1)
        elif op == '/':
            if len(args) == 0:
                raise ValueError("Division operator '/' requires at least one argument")
            if len(args) == 1:
                return 1 / args[0]
            return reduce(lambda x, y: x / y, args)
        elif op in ('pow', '**'):
            if len(args) != 2:
                raise ValueError("Power operator ('pow' or '**') requires exactly 2 arguments")
            return args[0] ** args[1]
        elif op in ('mod', '%'):
            if len(args) != 2:
                raise ValueError("Modulo operator ('mod' or '%') requires exactly 2 arguments")
            return args[0] % args[1]
        else:
            raise ValueError(f"Unknown operator: {op}")

    raise TypeError(f"Unsupported node type: {type(node)}")

