def serialize_to_text(nodes: list) -> str:
    """
    Serializes a list of hierarchical nodes back into an indented text string.
    Each node in the list has the structure:
    {"value": str, "cumulative_depth": int, "children": list}
    """
    if not nodes:
        return ""

    lines = []

    def _traverse(node: dict) -> None:
        depth = node.get("cumulative_depth", 0)
        val = node.get("value", "")
        indent = " " * depth
        lines.append(f"{indent}{val}")

        for child in node.get("children", []):
            _traverse(child)

    for node in nodes:
        _traverse(node)

    return "\n".join(lines)

