import re
from nodes import create_node

def tokenize(expression: str) -> list:
    tokens = []
    # Match numbers (including decimals), operators, or parentheses, ignoring leading whitespace
    pattern = re.compile(r'\s*(?:(\d+(?:\.\d+)?)|([+\-*/^])|(\()|(\)))')
    pos = 0
    while pos < len(expression):
        if expression[pos:].isspace():
            break
        match = pattern.match(expression, pos)
        if not match:
            raise ValueError(f"Invalid character at position {pos}: {expression[pos]}")

        if match.group(1) is not None:
            tokens.append(('NUMBER', match.group(1)))
        elif match.group(2) is not None:
            tokens.append(('OP', match.group(2)))
        elif match.group(3) is not None:
            tokens.append(('LPAREN', '('))
        elif match.group(4) is not None:
            tokens.append(('RPAREN', ')'))

        pos = match.end()
    return tokens

class Parser:
    def __init__(self, tokens: list):
        self.tokens = tokens
        self.pos = 0

    def peek(self) -> tuple | None:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self, expected_type: str = None) -> tuple:
        tok = self.peek()
        if tok is None:
            raise ValueError("Unexpected end of input")
        if expected_type and tok[0] != expected_type:
            raise ValueError(f"Expected {expected_type}, got {tok[0]}")
        self.pos += 1
        return tok

    def parse_expression(self) -> dict:
        return self.parse_additive()

    def parse_additive(self) -> dict:
        node = self.parse_multiplicative()
        while True:
            tok = self.peek()
            if tok and tok[0] == 'OP' and tok[1] in ('+', '-'):
                self.consume()
                right = self.parse_multiplicative()
                node = create_node("operator", tok[1], node, right)
            else:
                break
        return node

    def parse_multiplicative(self) -> dict:
        node = self.parse_exponent()
        while True:
            tok = self.peek()
            if tok and tok[0] == 'OP' and tok[1] in ('*', '/'):
                self.consume()
                right = self.parse_exponent()
                node = create_node("operator", tok[1], node, right)
            else:
                break
        return node

    def parse_exponent(self) -> dict:
        node = self.parse_primary()
        tok = self.peek()
        if tok and tok[0] == 'OP' and tok[1] == '^':
            self.consume()
            right = self.parse_exponent()  # exponentiation is right-associative
            node = create_node("operator", "^", node, right)
        return node

    def parse_primary(self) -> dict:
        tok = self.peek()
        if tok is None:
            raise ValueError("Unexpected end of input")

        if tok[0] == 'OP' and tok[1] in ('+', '-'):
            self.consume()
            operand = self.parse_primary()
            return create_node("operator", tok[1], None, operand)

        if tok[0] == 'NUMBER':
            self.consume()
            return create_node("number", tok[1], None, None)

        if tok[0] == 'LPAREN':
            self.consume()
            node = self.parse_expression()
            self.consume('RPAREN')
            return node

        raise ValueError(f"Unexpected token: {tok}")

def parse(expression: str) -> dict:
    tokens = tokenize(expression)
    if not tokens:
        raise ValueError("Empty expression")
    parser = Parser(tokens)
    ast = parser.parse_expression()
    if parser.peek() is not None:
        raise ValueError(f"Unexpected trailing tokens starting at {parser.peek()}")
    return ast

