from nodes import create_node

def is_constant(node: dict) -> bool:
    if node is None:
        return False
    if node.get("left") is None and node.get("right") is None:
        try:
            float(node.get("value", ""))
            return True
        except ValueError:
            return False
    return False

def get_numeric_value(node: dict):
    val = node.get("value", "")
    if '.' in val or 'e' in val.lower():
        return float(val)
    try:
        return int(val)
    except ValueError:
        return float(val)

def evaluate(op: str, left_val, right_val):
    if op == '+': return left_val + right_val
    if op == '-': return left_val - right_val
    if op == '*': return left_val * right_val
    if op == '/':
        if right_val == 0:
            raise ZeroDivisionError()
        return left_val / right_val
    if op == '//':
        if right_val == 0:
            raise ZeroDivisionError()
        return left_val // right_val
    if op == '%':
        if right_val == 0:
            raise ZeroDivisionError()
        return left_val % right_val
    if op == '**': return left_val ** right_val
    raise ValueError(f"Unknown operator {op}")

def fold_constants(tree: dict) -> dict:
    if tree is None:
        return None

    left = tree.get("left")
    right = tree.get("right")

    if left is None and right is None:
        return tree

    folded_left = fold_constants(left) if left is not None else None
    folded_right = fold_constants(right) if right is not None else None

    node_type = tree.get("type")
    value = tree.get("value")

    # Binary operator folding
    if folded_left is not None and folded_right is not None:
        if is_constant(folded_left) and is_constant(folded_right):
            try:
                left_val = get_numeric_value(folded_left)
                right_val = get_numeric_value(folded_right)
                res = evaluate(value, left_val, right_val)
                res_type = folded_left.get("type", "number")
                return create_node(res_type, str(res), None, None)
            except (ZeroDivisionError, ValueError, TypeError, OverflowError):
                pass

    # Unary operator folding (e.g., -5, +3)
    if folded_left is None and folded_right is not None:
        if is_constant(folded_right) and value in ('+', '-'):
            try:
                val = get_numeric_value(folded_right)
                res = -val if value == '-' else val
                res_type = folded_right.get("type", "number")
                return create_node(res_type, str(res), None, None)
            except (ValueError, TypeError):
                pass

    return create_node(node_type, value, folded_left, folded_right)

