def to_string(tree: dict | None) -> str:
    if tree is None:
        return ""

    node_type = tree.get("type")
    value = str(tree.get("value", ""))
    left = tree.get("left")
    right = tree.get("right")

    if node_type in ("number", "variable", "literal") or (left is None and right is None):
        return value

    if node_type == "function":
        return f"{value}({to_string(right)})"

    if left is None and right is not None:
        # Unary operator, e.g., -x
        # We can wrap in parentheses if needed, but usually negative numbers/variables are clear.
        # Let's keep it simple: -x.
        return f"{value}{to_string(right)}"

    if left is not None and right is not None:
        return f"({to_string(left)} {value} {to_string(right)})"

    return value

