def find_connected_components(graph: dict[str, list[str]]) -> list[list[str]]:
    # Build an explicit undirected adjacency representation to ensure completeness
    adj = {node: set() for node in graph}
    for node, neighbors in graph.items():
        for neighbor in neighbors:
            if neighbor not in adj:
                adj[neighbor] = set()
            adj[node].add(neighbor)
            adj[neighbor].add(node)

    visited = set()
    components = []

    for node in adj:
        if node not in visited:
            component = []
            queue = [node]
            visited.add(node)

            head = 0
            while head < len(queue):
                curr = queue[head]
                head += 1
                component.append(curr)

                for neighbor in adj[curr]:
                    if neighbor not in visited:
                        visited.add(neighbor)
                        queue.append(neighbor)

            components.append(sorted(component))

    # Sort components by their first element to provide deterministic output
    return sorted(components, key=lambda x: (x[0] if x else ""))

