import json
import re

def parse_dependency_graph(raw_input: str) -> dict[str, list[str]]:
    """
    Parses a raw dependency structure string into a standardized dictionary format.
    Supports JSON format or line-based plaintext format (e.g., "A -> B, C" or "A: B C").

    Returns:
        dict[str, list[str]]: A dictionary mapping nodes to their list of dependencies.
    """
    raw_input = raw_input.strip()
    if not raw_input:
        return {}

    def clean_deps(deps: list) -> list[str]:
        seen = set()
        cleaned = []
        for dep in deps:
            if dep is not None:
                dep_str = str(dep).strip()
                if dep_str and dep_str not in seen:
                    seen.add(dep_str)
                    cleaned.append(dep_str)
        return cleaned

    # Try parsing as JSON first
    try:
        data = json.loads(raw_input)
        if isinstance(data, dict):
            parsed: dict[str, list[str]] = {}
            for k, v in data.items():
                key = str(k).strip()
                if isinstance(v, list):
                    parsed[key] = clean_deps(v)
                elif isinstance(v, str):
                    if v.strip():
                        raw_deps = [d.strip() for d in re.split(r'[\s,]+', v.strip()) if d.strip()]
                        parsed[key] = clean_deps(raw_deps)
                    else:
                        parsed[key] = []
                elif v is None:
                    parsed[key] = []
                else:
                    raise ValueError(f"Unsupported dependency type for key '{k}': {type(v)}")
            return parsed
    except json.JSONDecodeError:
        pass

    # Fallback to line-based parsing
    parsed: dict[str, list[str]] = {}
    lines = raw_input.splitlines()
    for line in lines:
        line = line.strip()
        if not line or line.startswith('#'):
            continue

        # Split key and dependencies using common delimiters: '->', ':', '='
        match = re.split(r'->|:=|:|:=|=', line, maxsplit=1)
        if len(match) == 2:
            key_part, deps_part = match
            key = key_part.strip()
            # Split dependencies by commas or whitespace
            deps = [d.strip() for d in re.split(r'[\s,]+', deps_part.strip()) if d.strip()]
        else:
            key = line.strip()
            deps = []

        if not key:
            continue

        cleaned_deps = clean_deps(deps)
        if key in parsed:
            # Merge dependencies preserving order and uniqueness
            merged = parsed[key] + [d for d in cleaned_deps if d not in parsed[key]]
            parsed[key] = merged
        else:
            parsed[key] = cleaned_deps

    return parsed

