def topological_sort(graph: dict[str, list[str]]) -> tuple[list[str], list[list[str]]]:
    # Normalize graph to ensure all nodes are keys
    nodes = set(graph.keys())
    for targets in graph.values():
        for target in targets:
            nodes.add(target)

    full_graph = {node: graph.get(node, []) for node in nodes}

    visited = {node: 0 for node in full_graph}
    order = []
    cycles = []
    path = []

    def dfs(node: str) -> None:
        visited[node] = 1
        path.append(node)

        # Sort neighbors to make the traversal deterministic
        for neighbor in sorted(full_graph[node]):
            state = visited.get(neighbor, 0)
            if state == 1:
                # Cycle detected
                try:
                    idx = path.index(neighbor)
                    cycle = path[idx:] + [neighbor]
                    cycles.append(cycle)
                except ValueError:
                    pass
            elif state == 0:
                dfs(neighbor)

        path.pop()
        visited[node] = 2
        order.append(node)

    # Process nodes in a deterministic order
    for node in sorted(full_graph.keys()):
        if visited[node] == 0:
            dfs(node)

    if cycles:
        return [], cycles

    order.reverse()
    return order, []

